BEGIN;

-- === afib-rvr (18 nodes) ===
UPDATE decision_nodes SET body = E'[A-Fib RVR Management Steps](#/info/afib-summary) — quick-reference for rate control, cardioversion, and anticoagulation.\n\nAtrial fibrillation with rapid ventricular response (RVR) is characterized by an irregularly irregular rhythm with a ventricular rate typically 120–180 bpm. Confirm with 12-lead ECG.\n\nCOMMON PRECIPITANTS\n• Electrolyte abnormalities (K⁺, Mg²⁺)\n• Sepsis / infection\n• Pulmonary embolism\n• Thyrotoxicosis\n• Alcohol use / withdrawal\n• Pain / agitation\n• Respiratory failure / hypoxia\n• Underlying cardiac disease (valvular, ischemic, HF)\n\nAlways treat underlying causes alongside rate control. A-Fib RVR is often a symptom of another process — rate control alone may be insufficient if the precipitant is not addressed.' WHERE id = 'afib-start' AND tree_id = 'afib-rvr';
UPDATE decision_nodes SET body = E'Is there evidence of WPW / pre-excitation syndrome?\n\nLook for: irregular wide-complex tachycardia, rate >200, variable QRS morphology, delta waves on prior ECG. WPW + A-Fib is a life-threatening emergency.' WHERE id = 'afib-unstable-wpw' AND tree_id = 'afib-rvr';
UPDATE decision_nodes SET body = E'WPW with atrial fibrillation is a life-threatening emergency.\n\nAV nodal blocking agents are ABSOLUTELY CONTRAINDICATED — including beta-blockers, calcium channel blockers, digoxin, and IV amiodarone. These agents may paradoxically accelerate ventricular response through the accessory pathway and precipitate ventricular fibrillation.' WHERE id = 'afib-wpw-result' AND tree_id = 'afib-rvr';
UPDATE decision_nodes SET body = E'SYNCHRONIZED CARDIOVERSION PROTOCOL\n\n1. PREPARATION\n• Confirm synchronization is enabled on defibrillator\n• Apply pads: anterior/lateral placement preferred (EPIC trial)\n• Hyperinflation may impair conduction — cardiovert at end-expiration if possible\n\n2. SEDATION\n• Midazolam 3–5 mg IV bolus, additional 2 mg q2min PRN to adequate sedation\n• Alternative: MidaKet for patients resistant to midazolam\n• Flumazenil 0.5–1 mg IV available for reversal\n\n3. CARDIOVERSION\n• Start at 200J biphasic (use maximal energy available)\n• Escalate energy if initial attempt unsuccessful\n\n4. POST-CARDIOVERSION\n• Consider [Amiodarone](#/drug/amiodarone) to maintain sinus rhythm (150mg IV bolus, then 1 mg/min infusion)\n• Consider IV [Magnesium Sulfate](#/drug/magnesium-sulfate) 2–4g to enhance cardioversion success\n• If cardioversion not immediately feasible, IV [Amiodarone](#/drug/amiodarone) may be used as temporizing measure' WHERE id = 'afib-cardioversion-protocol' AND tree_id = 'afib-rvr';
UPDATE decision_nodes SET body = E'FIRST-LINE AGENTS FOR RATE CONTROL\n\nBeta-Blockers (Class 1 recommendation):\n• [Metoprolol](#/drug/metoprolol) — 2.5–5 mg IV q5min, up to 15 mg total\n• [Esmolol](#/drug/esmolol) — Ultra-short-acting, ideal when rapid titration needed\n• Safe in COPD (multiple studies confirm no adverse respiratory effects)\n• Preferred in CAD or compensated HFrEF\n• Use cautiously in decompensated heart failure\n\nCalcium Channel Blockers:\n• [Diltiazem](#/drug/diltiazem) — 0.25 mg/kg IV bolus, onset within minutes\n• [Verapamil](#/drug/verapamil) — Alternative CCB, less commonly used\n• 90% rate control vs 74% with amiodarone or digoxin\n• ⚠️ CONTRAINDICATED if EF ≤40% or decompensated HF (Class 3: Harm)\n• Obtain echo or check history for EF if unknown\n\nAdjunctive:\n• IV [Magnesium Sulfate](#/drug/magnesium-sulfate) — Reasonable to add (Class 2a). Blocks slow Ca channels at AV node with minimal toxicity.\n\n⚠️ Do NOT combine beta-blockers with calcium channel blockers — risk of synergistic hypotension.' WHERE id = 'afib-stable-drugs' AND tree_id = 'afib-rvr';
UPDATE decision_nodes SET body = E'Is the ventricular rate now controlled?\n\nTarget heart rate:\n• ICU / critically ill: <130 bpm may be reasonable\n• Outpatient / stable: <100–110 bpm (RACE II trial)\n• Titrate primarily to control symptoms rather than strict targets\n• Some patients may benefit from mild compensatory tachycardia — do not aggressively normalize if rate is due to underlying process' WHERE id = 'afib-rate-controlled' AND tree_id = 'afib-rvr';
UPDATE decision_nodes SET body = E'Select second-line intervention for refractory rate control.\n\nFirst-line agent was insufficient. Re-evaluate for underlying causes (sepsis, hypovolemia, pain, PE). Ensure adequate trial of first-line agent before escalating.\n\n⚠️ Avoid combining beta-blockers with calcium channel blockers.' WHERE id = 'afib-refractory' AND tree_id = 'afib-rvr';
UPDATE decision_nodes SET body = E'IV [Magnesium Sulfate](#/drug/magnesium-sulfate)\n\n• 2–4 grams IV bolus, may follow with continuous infusion\n• Blocks slow calcium channels in SA and AV nodes\n• Minimal toxicity — one meta-analysis detected no adverse events\n• Even if cardioversion doesn’t occur, magnesium reduces heart rate and augments efficacy of other antiarrhythmics\n• Contraindicated if GFR <30 mL/min or oliguria — use intermittent boluses instead\n• Target serum level ~3–4 mg/dL for optimal antiarrhythmic effect' WHERE id = 'afib-refractory-mg' AND tree_id = 'afib-rvr';
UPDATE decision_nodes SET body = E'[Digoxin](#/drug/digoxin)\n\n• Useful when hypotension limits further titration of beta-blockers or CCBs\n• Slow onset: ~3 hours to achieve rate control (vs 5 min for diltiazem)\n• Limited efficacy during exertion — slows primarily resting heart rate\n• ⚠️ Post hoc analyses associate digoxin with increased mortality in A-Fib\n• Use at low doses, typically in combination with other AV nodal agents\n• May be particularly useful in patients with concurrent heart failure' WHERE id = 'afib-refractory-dig' AND tree_id = 'afib-rvr';
UPDATE decision_nodes SET body = E'[Amiodarone](#/drug/amiodarone)\n\n• Load with 150 mg IV bolus over 10 min, then 1 mg/min infusion\n• May need to re-bolus 150 mg x2–3 (total 150–450 mg in boluses)\n• More hemodynamically stable than beta-blockers or CCBs\n• May achieve chemical cardioversion — beneficial if rhythm control desired\n• 74% rate control achieved in clinical trials\n• ⚠️ Do not conclude amiodarone has failed without adequate re-bolusing\n• If cardioversion occurs, continue infusion until critical illness resolves' WHERE id = 'afib-refractory-amio' AND tree_id = 'afib-rvr';
UPDATE decision_nodes SET body = E'RHYTHM CONTROL STRATEGY\n\nConsider when rate control strategy has failed or in new-onset AF where conversion is desirable.\n\nStepwise approach:\n1. IV [Magnesium Sulfate](#/drug/magnesium-sulfate) infusion (front-line, excellent safety)\n2. [Amiodarone](#/drug/amiodarone) if magnesium alone insufficient\n3. DC cardioversion (especially in intubated patients)\n\nFactors favoring rhythm control:\n• New-onset AF (NOAF) — likely to revert\n• Pulmonary hypertension, mitral stenosis, diastolic dysfunction\n• Heart failure with reduced EF\n• Failure of rate control\n\nFactors favoring rate control:\n• Chronic/longstanding AF\n• Onset >48 hours without anticoagulation\n• Ongoing severe physiological stress' WHERE id = 'afib-rhythm-control' AND tree_id = 'afib-rvr';
UPDATE decision_nodes SET body = E'Is this new-onset AF or known/chronic AF?\n\nDistinguishing onset is important for anticoagulation decisions and rhythm control candidacy.\n\nNew-onset AF (NOAF): First episode, occurring during current hospitalization or acute illness. Often reverts spontaneously as underlying cause resolves.\n\nKnown/Chronic AF: Pre-existing AF documented prior to current presentation, or AF duration >48 hours.' WHERE id = 'afib-onset-assessment' AND tree_id = 'afib-rvr';
UPDATE decision_nodes SET body = E'NEW-ONSET AF IN CRITICAL ILLNESS\n\nAnticoagulation is generally NOT recommended for NOAF:\n• Retrospective studies show anticoagulation increases bleeding risk without reducing stroke incidence\n• Most patients with NOAF will revert to sinus rhythm as critical illness resolves\n• Survey of UK intensivists: 64% do not routinely anticoagulate NOAF\n\nExceptions — consider anticoagulation if:\n• AF persists >48 hours\n• High stroke risk with low bleeding risk\n• AF continues beyond resolution of acute illness\n\nIf AF persists for weeks, reassess with [CHA₂DS₂-VASc scoring](#/calculator/cha2ds2vasc) as chronic AF management becomes appropriate.' WHERE id = 'afib-noaf-anticoag' AND tree_id = 'afib-rvr';
UPDATE decision_nodes SET body = E'ANTICOAGULATION FOR KNOWN/CHRONIC AF\n\nAssess stroke risk using [CHA₂DS₂-VASc score](#/calculator/cha2ds2vasc):\n\nAnticoagulation Recommendations:\n• Score ≥2 (men) or ≥3 (women) → Anticoagulate (strong recommendation)\n• Score 1 (men) or 2 (women) → Consider anticoagulation\n• Score 0 (men) or 1 (women) → May omit anticoagulation\n\nPreferred agents: [Apixaban](#/drug/apixaban/atrial fibrillation), [Rivaroxaban](#/drug/rivaroxaban/atrial fibrillation) (DOACs preferred over warfarin)\n\n⚠️ If AF duration >48 hours and patient is NOT anticoagulated:\n• Consider TEE to exclude left atrial appendage thrombus before cardioversion\n• Or initiate anticoagulation for ≥3 weeks before elective cardioversion' WHERE id = 'afib-cha2ds2vasc' AND tree_id = 'afib-rvr';
UPDATE decision_nodes SET body = E'DISPOSITION CONSIDERATIONS\n\n• Continue rate control agent that achieved control\n• Target resting HR <100–110 bpm for outpatient management\n• Assess heart rate response during exertion (ambulatory monitoring or brisk walk)\n• Ensure electrolytes are corrected (K⁺, Mg²⁺)\n• Address underlying precipitants\n• Cardiology follow-up for: new-onset AF, rhythm control consideration, AV node ablation candidacy\n• For patients with refractory symptoms despite optimal medical therapy, AV node ablation with permanent pacemaker may be considered' WHERE id = 'afib-disposition' AND tree_id = 'afib-rvr';

-- === aub (22 nodes) ===
UPDATE decision_nodes SET body = E'Emergency management of **acute AUB in nonpregnant reproductive-aged women**.\n\nAcute AUB refers to heavy bleeding requiring immediate intervention to prevent further blood loss. May occur spontaneously or within the context of chronic AUB (present >6 months).\n\n**Etiologies classified by PALM-COEIN:**\n• **PALM** (structural) — Polyp, Adenomyosis, Leiomyoma, Malignancy/hyperplasia\n• **COEIN** (non-structural) — Coagulopathy, Ovulatory dysfunction, Endometrial, Iatrogenic, Not classified\n\nUp to **13% of women** with heavy menstrual bleeding have von Willebrand disease; up to **20%** have an underlying coagulopathy.' WHERE id = 'aub-start' AND tree_id = 'aub';
UPDATE decision_nodes SET body = E'Assess vitals for signs of hemodynamic instability:\n• **Tachycardia** (HR >100)\n• **Hypotension** (SBP <90)\n• **Orthostatic changes** (SBP drop >20 or HR rise >20 on standing)\n• **Altered mental status**\n\nSigns of significant hemorrhage: pallor, diaphoresis, delayed capillary refill, cool extremities.' WHERE id = 'aub-hemodynamic' AND tree_id = 'aub';
UPDATE decision_nodes SET body = E'**Immediate resuscitation:**\n• 2 large-bore IVs, IV crystalloid bolus\n• **Type & crossmatch** — prepare for PRBC transfusion\n• Activate MTP if massive hemorrhage\n• **hCG stat** — must rule out pregnancy\n\n**Acute hemostatic therapy:**\n• [Tranexamic Acid](#/drug/tranexamic-acid/aub) 1 g IV over 10 min\n• [Conjugated Estrogen (Premarin)](#/drug/conjugated-estrogen/unstable aub) 25 mg IV q4-6h\n• **Emergent GYN consult**\n\n**If GYN unavailable — intrauterine tamponade:**\n• 26F Foley catheter — inflate balloon with **30 mL saline** in uterine cavity\n• Bakri balloon (up to 300 mL) if available or uterus enlarged\n• Alternative: gauze packing impregnated with **5000 units thrombin** in 5 mL sterile saline\n• Stabilize cervix with tenaculum or ring forceps before insertion\n• Thread balloon/gauze through cervical os into uterus' WHERE id = 'aub-unstable' AND tree_id = 'aub';
UPDATE decision_nodes SET body = E'**Pregnancy MUST be ruled out** before initiating any hormonal therapy.\n\n• Urine hCG (qualitative) — rapid screening\n• Serum beta-hCG (quantitative) — if clinical suspicion despite negative urine test\n\nAll hormonal treatments for AUB (estrogen, progestins, OCPs) are **contraindicated in pregnancy**.' WHERE id = 'aub-pregnancy' AND tree_id = 'aub';
UPDATE decision_nodes SET body = E'This AUB consult covers **nonpregnant reproductive-aged women** only.\n\nFor vaginal bleeding in pregnancy, evaluate per trimester:\n• **1st trimester:** Ectopic pregnancy, threatened/missed abortion, molar pregnancy\n• **2nd/3rd trimester:** Placenta previa, placental abruption, preterm labor\n\nSee [Pregnancy Bleeding](#/tree/pregnancy-bleeding) consult (coming soon).\n\nObtain **OB consultation**. Consider Rh status (RhoGAM if Rh-negative).' WHERE id = 'aub-pregnant-exit' AND tree_id = 'aub';
UPDATE decision_nodes SET body = E'**Bleeding history:**\n• Amount — pads/tampons per hour, passage of clots\n• Duration — days of current episode\n• Timing — relation to menstrual cycle, LMP\n• Chronic vs acute — AUB >6 months is chronic\n\n**Screen for coagulopathy:**\n• Heavy menstrual bleeding since menarche?\n• PPH, surgical/dental bleeding?\n• Easy bruising, epistaxis, family history of bleeding disorder?\n\n**Associated symptoms:**\n• Fever/chills → infection (PID, UTI)\n• Pelvic pain → ovarian cyst, torsion, adenomyosis\n• Weight gain, hirsutism, irregular periods → **PCOS**\n• Fatigue, cold intolerance, constipation → hypothyroidism\n\n**Medications:** anticoagulants, HRT, OCPs, IUD, tamoxifen\n\n**Pelvic exam:**\n• **Speculum** — identify source of bleeding, cervical lesions, foreign body, discharge\n• **Bimanual** — uterine size/contour, adnexal mass/tenderness, CMT' WHERE id = 'aub-history' AND tree_id = 'aub';
UPDATE decision_nodes SET body = E'**Core labs:**\n• **CBC** with platelets — assess anemia severity\n• **Type & screen**\n• **Pregnancy test** (if not already done)\n• **TSH** — thyroid dysfunction is common contributor\n• **Iron studies** (ferritin) — if anemia present\n• **Chlamydia** screening\n\n**If coagulopathy suspected:**\n• PT / PTT / INR / fibrinogen\n• [Coagulopathy Screening Tool](#/info/aub-coag-screen) — ACOG structured screening questions\n• If screen positive → **vWF antigen**, **ristocetin cofactor**, **Factor VIII**\n\n**Consider:** LFTs (liver disease), prolactin (pituitary), serum hCG (quantitative)' WHERE id = 'aub-labs' AND tree_id = 'aub';
UPDATE decision_nodes SET body = E'**Transvaginal ultrasound** — first-line imaging to evaluate for structural causes (fibroids, polyps, endometrial thickness, adnexal pathology).\n\n**Endometrial biopsy** indications (ACOG):\n• Age **≥45** — first-line test for all AUB\n• Age **<45** with: obesity, PCOS, chronic anovulation (unopposed estrogen), failed medical management, or persistent AUB\n\n[Endometrial Cancer Risk Factors](#/info/aub-endo-cancer-risk)' WHERE id = 'aub-imaging' AND tree_id = 'aub';
UPDATE decision_nodes SET body = E'**Endometrial biopsy** is indicated to rule out hyperplasia or malignancy.\n\n[Endometrial Cancer Risk Factors](#/info/aub-endo-cancer-risk) — risk factor table with relative risks\n\n**ED considerations:**\n• If active heavy bleeding, sampling may be deferred until bleeding is controlled\n• Office endometrial biopsy (Pipelle) if available in ED\n• Otherwise, arrange **urgent GYN referral** for biopsy\n• Do NOT delay acute bleeding management for biopsy\n\n**Ensure GYN follow-up** for pathology results and definitive management.' WHERE id = 'aub-endometrial-sampling' AND tree_id = 'aub';
UPDATE decision_nodes SET body = E'Classify the most likely etiology to guide treatment.\n\n[PALM-COEIN Classification](#/info/aub-palm-coein) — full classification with clinical features\n\n**Structural causes (PALM)** often need procedural intervention.\n**Non-structural causes (COEIN)** are typically managed medically.\n\n**Ovulatory dysfunction** (AUB-O) is the **most common cause** of non-structural AUB — responsible for ~80% of dysfunctional uterine bleeding. Common in obesity, PCOS, extremes of reproductive age.' WHERE id = 'aub-classify' AND tree_id = 'aub';
UPDATE decision_nodes SET body = E'**Polyp (AUB-P):**\nEndometrial or cervical polyps. Hysteroscopic polypectomy is definitive treatment. Often found incidentally on US.\n\n**Adenomyosis (AUB-A):**\nEndometrial tissue within myometrium. Presents with dysmenorrhea + heavy bleeding. Diffuse uterine enlargement on exam. Medical management or hysterectomy for refractory cases.\n\n**Leiomyoma (AUB-L):**\n**Submucosal fibroids** most likely to cause AUB. Size and location guide management. May require myomectomy or uterine artery embolization.\n\n**Malignancy/Hyperplasia (AUB-M):**\nEndometrial biopsy is **mandatory**. Risk factors: age >45, obesity, PCOS, unopposed estrogen, tamoxifen, Lynch syndrome. **GYN oncology referral** if malignancy confirmed.\n\nAll structural causes warrant **GYN referral** for definitive management. In the ED, control acute bleeding medically, then arrange follow-up.' WHERE id = 'aub-structural' AND tree_id = 'aub';
UPDATE decision_nodes SET body = E'Up to **20% of women** with heavy menstrual bleeding have an underlying bleeding disorder. **von Willebrand disease** is most common (up to 13%).\n\n**Testing:**\n• vWF antigen, ristocetin cofactor activity, Factor VIII\n• Consult hematology for interpretation\n\n**Treatment of AUB with coagulopathy:**\n• [Tranexamic Acid](#/drug/tranexamic-acid/aub) — first-line adjunct, reduces bleeding 30-55%\n• **Desmopressin (DDAVP)** 0.3 mcg/kg IV — for known vWD responders. Use with caution: risk of fluid retention and hyponatremia. Do NOT give with massive hemorrhage + IV fluid resuscitation.\n• Recombinant factor VIII and vWF concentrate for severe vWD\n• Hormonal therapy (OCPs, progestins) also effective\n• **Avoid NSAIDs** — impair platelet aggregation\n\n**Hematology consult** recommended for all confirmed coagulopathies.' WHERE id = 'aub-coagulopathy' AND tree_id = 'aub';
UPDATE decision_nodes SET body = E'Reassess hemodynamics after initial resuscitation and IV conjugated estrogen.\n\n**If bleeding controlled:** transition to oral medical management.\n**If refractory** despite IV estrogen and tamponade: emergent procedural intervention needed.' WHERE id = 'aub-treatment-unstable' AND tree_id = 'aub';
UPDATE decision_nodes SET body = E'Medical therapy is the **preferred initial treatment** for most patients with acute AUB.\n\n[AUB Treatment Regimens](#/info/aub-treatment-table) — comparison table with dosing, efficacy, and contraindications\n\nChoose regimen based on severity, contraindications, and patient factors. All hormonal therapies require **pregnancy exclusion** (already confirmed).' WHERE id = 'aub-treatment-medical' AND tree_id = 'aub';
UPDATE decision_nodes SET body = E'[Conjugated Estrogen](#/drug/conjugated-estrogen/unstable aub) **25 mg IV** q4-6h for up to **24 hours** (max 6 doses).\n\n**Efficacy:** 72% stop bleeding within 8 hours.\n\nOnly FDA-approved treatment for acute AUB.\n\n**MUST follow with progestin** — [Medroxyprogesterone](#/drug/medroxyprogesterone/post-estrogen stabilization) 10 mg PO daily × 10 days after bleeding controlled. Unopposed estrogen risks endometrial hyperplasia and rebound bleeding.\n\n**Start antiemetic prophylactically** (ondansetron) — IV estrogen causes significant nausea.\n\n**Contraindications:**\n• Active or past VTE/PE\n• Breast cancer (estrogen-receptor positive)\n• Active hepatic disease\n• Known thrombophilia\n\nUse with **caution** in patients with cardiovascular or thromboembolic risk factors.' WHERE id = 'aub-rx-estrogen' AND tree_id = 'aub';
UPDATE decision_nodes SET body = E'Monophasic OCP containing **35 mcg ethinyl estradiol** — **1 tablet TID × 7 days**, then taper to 1 tablet daily.\n\n**Efficacy:** 88% stop bleeding within median 3 days.\n\nPreferred for **ovulatory dysfunction AUB** — provides cycle regulation as well as acute control. Can transition directly to daily OCP use for long-term maintenance.\n\n**Contraindications (CDC MEC):**\n• Age >35 + cigarette smoking\n• Uncontrolled hypertension\n• History of DVT/PE or known thrombophilia\n• Migraine with aura\n• Current or past breast cancer\n• Severe liver disease\n• Major surgery with prolonged immobilization\n\nConsult CDC Medical Eligibility Criteria (MEC) for comprehensive list.' WHERE id = 'aub-rx-ocp' AND tree_id = 'aub';
UPDATE decision_nodes SET body = E'[Medroxyprogesterone](#/drug/medroxyprogesterone/aub) **20 mg PO TID × 7 days**.\n\n**Efficacy:** 76% stop bleeding within median 3 days.\n\n**Preferred when estrogen is contraindicated:**\n• History of VTE/PE\n• Migraine with aura\n• Smoker age >35\n• Known thrombophilia\n\n**Especially appropriate for obese/PCOS patients** — anovulation is the mechanism, and progesterone withdrawal stabilizes the endometrium.\n\n**Contraindications:**\n• Active VTE/PE\n• Current or past breast cancer\n• Severe hepatic disease\n• Known or suspected pregnancy\n\nOther progestins (norethindrone acetate) may also be effective.' WHERE id = 'aub-rx-mpa' AND tree_id = 'aub';
UPDATE decision_nodes SET body = E'[Tranexamic Acid](#/drug/tranexamic-acid/aub) — antifibrinolytic that prevents fibrin degradation.\n\n**Dosing:**\n• **Oral:** 1.3 g PO TID × 5 days\n• **IV:** 10 mg/kg IV (max 600 mg/dose) q8h\n\n**Efficacy:** Reduces menstrual blood loss **30-55%**.\n\nCan be used **alone** if hormonal therapy is contraindicated, or as **adjunct** to hormonal regimens for more rapid hemostasis.\n\nDoes not affect fertility or cycle regularity.\n\n**Contraindications:**\n• Active thromboembolic disease (DVT, PE)\n• Impaired color vision\n• Subarachnoid hemorrhage\n\n**Caution:** Uncertain thrombotic risk — use carefully in patients with thrombosis history. Concurrent OCP use requires careful consideration of additive thrombotic risk.' WHERE id = 'aub-rx-txa' AND tree_id = 'aub';
UPDATE decision_nodes SET body = E'[Surgical Management Options](#/info/aub-surgical) — procedure comparison table\n\n**Indications for surgical management:**\n• Hemodynamically unstable despite medical therapy\n• Failure of medical management\n• Suspected structural pathology requiring tissue diagnosis\n• Contraindications to all medical therapies\n\n**Options (GYN to determine):**\n• **D&C with hysteroscopy** — diagnostic + therapeutic, preferred if intrauterine pathology suspected\n• **Endometrial ablation** — only if childbearing complete and malignancy excluded\n• **Uterine artery embolization (UAE)** — for fibroids or refractory bleeding\n• **Hysterectomy** — definitive treatment for refractory cases\n\nD&C alone (without hysteroscopy) is inadequate for evaluation and provides only temporary reduction in bleeding.' WHERE id = 'aub-surgical' AND tree_id = 'aub';
UPDATE decision_nodes SET body = E'**Admit if:**\n• Hemodynamic instability\n• Hgb <7 g/dL (or symptomatic anemia requiring transfusion)\n• Failed outpatient management\n• Need for procedural intervention\n• Suspected malignancy requiring urgent workup\n\n**Discharge if:**\n• Hemodynamically stable\n• Bleeding controlled or significantly improved\n• Hgb stable and adequate\n• Reliable GYN follow-up available\n\n[Long-term Maintenance Options](#/info/aub-maintenance) — levonorgestrel IUD, cyclic OCPs, progestins' WHERE id = 'aub-disposition' AND tree_id = 'aub';
UPDATE decision_nodes SET body = E'**Admission orders:**\n• GYN consult (or Medicine with GYN consult)\n• Continue medical management (IV estrogen, TXA, progestins as indicated)\n• Serial CBC q6-8h\n• Type & crossmatch — keep active\n• Transfuse PRBCs if Hgb <7 or symptomatic\n• Reassess need for procedural intervention\n• Hematology consult if coagulopathy identified\n• VTE prophylaxis once hemostasis achieved' WHERE id = 'aub-admit' AND tree_id = 'aub';
UPDATE decision_nodes SET body = E'[AUB Discharge Instructions](#/info/aub-discharge) — shareable patient handout\n\n**Discharge with:**\n• Prescription for chosen oral regimen (OCP or MPA) — **complete full 7-day course**\n• **Iron supplementation** — ferrous sulfate 325 mg PO daily if anemic\n• GYN follow-up within **1-2 weeks**\n• All patients with significant anemia should be started on iron\n\n**Return precautions:**\n• Soaking >1 pad/hour for 2+ consecutive hours\n• Lightheadedness, dizziness, or syncope\n• Persistent heavy bleeding despite completing prescribed regimen\n• Fever\n\n**Obese/PCOS patients:** Emphasize need for long-term hormonal management to prevent endometrial hyperplasia and reduce cancer risk.' WHERE id = 'aub-discharge' AND tree_id = 'aub';

-- === bronchiolitis (19 nodes) ===
UPDATE decision_nodes SET body = E'**Inclusion Criteria:**\n• Age >28 days and <24 months\n• Clinical symptoms: increased work of breathing, persistent cough, feeding difficulty, ± fever\n• First episode of wheezing OR diagnosis of bronchiolitis\n\nIf respiratory arrest is imminent, triage and initiate care in the resuscitation room.\n\nUse the [BAS Calculator](#/calculator/bas) for objective severity scoring.\n\nSee [NOT Recommended Interventions](#/info/bronch-not-recommended) — CXR, viral testing, albuterol, steroids, and antibiotics have no role in standard bronchiolitis.' WHERE id = 'bronch-start' AND tree_id = 'bronchiolitis';
UPDATE decision_nodes SET body = E'Does the patient have **any** of the following?\n\n• Chronic lung disease or cystic fibrosis\n• Congenital heart disease\n• Immunodeficiency\n• Toxic appearance or shock\n• Neuromuscular disease\n• Artificial or abnormal airway\n• Recurrent wheezing (>3 episodes)\n• Respiratory failure requiring mechanical ventilation' WHERE id = 'bronch-exclude' AND tree_id = 'bronchiolitis';
UPDATE decision_nodes SET body = E'This pathway applies to previously healthy infants with first-episode bronchiolitis. Patients with significant comorbidities require **individualized evaluation and management**.\n\nConsider:\n• Subspecialty consultation\n• Alternative diagnoses (reactive airway disease, pertussis, foreign body)\n• Management guided by underlying condition' WHERE id = 'bronch-excluded' AND tree_id = 'bronchiolitis';
UPDATE decision_nodes SET body = E'Classify severity using clinical findings. Use the [BAS Calculator](#/calculator/bas) for objective scoring.\n\n**Document BAS score before and after all interventions.**' WHERE id = 'bronch-severity' AND tree_id = 'bronchiolitis';
UPDATE decision_nodes SET body = E'**Interventions:**\n• Nasal suction using nasal aspirator (gentle, superficial — **NOT** deep suction beyond nasopharynx)\n• Reposition for comfort\n• Assess hydration status and encourage PO fluids\n\n**Document BAS score before and after interventions.**\n\nObserve for 1–2 hours, then reassess.\n\nSee [NOT Recommended Interventions](#/info/bronch-not-recommended).' WHERE id = 'bronch-mild' AND tree_id = 'bronchiolitis';
UPDATE decision_nodes SET body = E'**NOTIFY PROVIDER**\n\n**Interventions:**\n• Nasal suction using nasal aspirator\n• Rehydration (IV if unable to tolerate PO)\n• Supplemental O₂ via nasal cannula or simple mask\n• Target SpO₂ ≥90% awake or ≥88% asleep\n\n**Document BAS score before and after interventions.**\n\nSee [NOT Recommended Interventions](#/info/bronch-not-recommended).' WHERE id = 'bronch-moderate' AND tree_id = 'bronchiolitis';
UPDATE decision_nodes SET body = E'**NOTIFY PROVIDER IMMEDIATELY**\n\n**Interventions:**\n• Nasal suction using nasal aspirator\n• Supplemental O₂ — prepare for HFNC initiation\n• Assess dehydration — IV fluid resuscitation if needed\n• Continuous monitoring\n• Place PIV if not already done\n\nProceed directly to HFNC initiation.' WHERE id = 'bronch-severe' AND tree_id = 'bronchiolitis';
UPDATE decision_nodes SET body = E'Reassess after 1–2 hours of supportive care.\n\nCheck: SpO₂, RR, work of breathing, ability to feed, hydration status.\n\nUse [BAS Calculator](#/calculator/bas) for objective scoring.' WHERE id = 'bronch-mild-reassess' AND tree_id = 'bronchiolitis';
UPDATE decision_nodes SET body = E'Reassess after nasal suction and supplemental O₂.\n\nAre **oxygen needs AND work of breathing** adequately managed?' WHERE id = 'bronch-resp-check' AND tree_id = 'bronchiolitis';
UPDATE decision_nodes SET body = E'**Starting Flow Rates:**\n• <7 kg: **4 LPM**\n• ≥7 kg: **6 LPM**\n\nStart FiO₂ at 21%, titrate to maintain SpO₂ ≥90%.\n\nPatient must be watched for at least **30 minutes** in the ED after starting HFNC.\n\nContinuous pulse oximetry required.\n\n**Feeding:** NPO for ~1 hour to assess response.\n\nSee [HFNC Protocol Reference](#/info/bronch-hfnc-protocol) for full details including contraindications and max flow rates.' WHERE id = 'bronch-hfnc-init' AND tree_id = 'bronchiolitis';
UPDATE decision_nodes SET body = E'Assess BAS every 15 minutes after HFNC initiation.\n\nIf BAS ≥9: **suction first**, then reassess. If still ≥9 after suction, contact primary team.\n\nUse [BAS Calculator](#/calculator/bas) for scoring.' WHERE id = 'bronch-hfnc-assess' AND tree_id = 'bronchiolitis';
UPDATE decision_nodes SET body = E'**Monitoring:**\n• Continuous pulse oximetry\n• BAS Q4h or per PEWS score\n• Document HR, RR, pulse ox\n• Suction PRN + BAS Q4h\n\n**Feeding:**\n• Mild BAS → May resume PO (first feed observed by staff)\n• Moderate to severe BAS → Consider NG feeds\n\nMust be **stable for ≥4 hours** on maintenance phase before weaning.\n\nSee [HFNC Weaning Protocol](#/info/bronch-hfnc-weaning) and [Feeding Guidelines](#/info/bronch-feeding).' WHERE id = 'bronch-hfnc-stable' AND tree_id = 'bronchiolitis';
UPDATE decision_nodes SET body = E'Patient not improving on HFNC.\n\n**If NOT at max flow:** Increase by 2 LPM.\n• Max: 2 LPM/kg for ≤7 kg, **14 LPM** for >7 kg\n• Monitor for signs of excess flow\n\n**Critical care consult triggers:**\n• Worsening after 60 minutes on HFNC\n• Severe respiratory distress on HFNC\n• FiO₂ >50%\n• Flow rates above recommended maximum\n• Apnea\n• Severe dehydration or shock' WHERE id = 'bronch-hfnc-escalate' AND tree_id = 'bronchiolitis';
UPDATE decision_nodes SET body = E'Has the patient been stable on current HFNC settings for **≥4 hours**?\n\nSee [HFNC Weaning & Holiday Protocol](#/info/bronch-hfnc-weaning) for detailed criteria and weaning steps.' WHERE id = 'bronch-wean-check' AND tree_id = 'bronchiolitis';
UPDATE decision_nodes SET body = E'**ALL discharge criteria must be met:**\n• SpO₂ ≥90% on room air\n• Respirations <60/min and/or minimal to no increased WOB\n• Tolerating oral feeding at a level to maintain hydration\n• Parents comfortable with providing home care\n• Parent/guardian education complete\n\n**Parent Education:**\n• [Bronchiolitis: Home Care (English)](#/info/bronch-parent-en)\n• [Bronquiolitis: Cuidados en el Hogar (Español)](#/info/bronch-parent-es)\n\n**Return precautions:** Feeding decreases >50%, worsening breathing, signs of dehydration (fewer wet diapers, no tears, dry mouth), fever ≥100.4°F in infants <3 months.\n\n**Follow up with pediatrician in 1–2 days.**' WHERE id = 'bronch-ed-dc' AND tree_id = 'bronchiolitis';
UPDATE decision_nodes SET body = E'**Admission criteria:**\n• Routine bronchiolitis management\n• FiO₂ <50% to maintain SaO₂ ≥90%\n• HFNC at standard flow rates\n• Continuation of care from higher acuity unit\n\n**Orders:**\n• BAS Q4h\n• Nasal suction PRN\n• Continuous or intermittent pulse oximetry\n• Assess hydration and feeding tolerance\n\nSee [Admission Criteria](#/info/bronch-admission-criteria) and [HFNC Weaning Protocol](#/info/bronch-hfnc-weaning).\n\n**Inpatient Discharge Criteria:** SpO₂ ≥90% on room air for **≥2 continuous hours**, RR <60, minimal WOB, tolerating PO, parents demonstrate suction technique, education complete.\n\n**Parent Education:**\n• [Bronchiolitis: Home Care (English)](#/info/bronch-parent-en)\n• [Bronquiolitis: Cuidados en el Hogar (Español)](#/info/bronch-parent-es)' WHERE id = 'bronch-admit-acu' AND tree_id = 'bronchiolitis';
UPDATE decision_nodes SET body = E'**High acuity criteria:**\n• Significant cardiac or pulmonary comorbidities\n• Moderate to severe symptoms (BAS 4–12)\n• Worsening clinical status despite increasing flow rates\n• Comorbidities requiring closer monitoring\n\nContinuous monitoring. Lower threshold for PICU transfer.\n\nSee [Admission Criteria](#/info/bronch-admission-criteria).' WHERE id = 'bronch-admit-high' AND tree_id = 'bronchiolitis';
UPDATE decision_nodes SET body = E'**PICU admission indications:**\n• Worsening clinical status after **60 minutes** of HFNC\n• Requiring positive pressure ventilation\n• Witnessed episode of apnea\n• Flow rates above maximum recommended levels\n• FiO₂ >50% to maintain SpO₂\n• Severe dehydration or shock\n\n**NICU consideration:**\n• <44 weeks corrected gestational age\n• Prematurity ≤32 weeks and <44 weeks post-menstrual age\n\nPrepare for potential intubation. Ensure IV access. Fluid resuscitation if dehydrated.' WHERE id = 'bronch-picu' AND tree_id = 'bronchiolitis';
UPDATE decision_nodes SET body = E'**ALL must be met:**\n• SpO₂ ≥90% on room air for **≥2 continuous hours** (not a single reading)\n• Respirations <60/min and age-appropriate\n• Minimal to no increased work of breathing\n• Tolerating PO feeding at a level to maintain hydration\n• Parents comfortable with home care\n• Parents demonstrate nasal suction technique\n• Return precautions reviewed and understood\n\n**Follow up with pediatrician in 1–2 days.** Symptoms may persist 1–2 weeks — parents should expect gradual improvement.\n\n**Parent Education:**\n• [Bronchiolitis: Home Care (English)](#/info/bronch-parent-en)\n• [Bronquiolitis: Cuidados en el Hogar (Español)](#/info/bronch-parent-es)' WHERE id = 'bronch-inpt-dc' AND tree_id = 'bronchiolitis';

-- === burns (49 nodes) ===
UPDATE decision_nodes SET body = E'[Burns Steps Summary](#/info/burns-summary) — stepwise approach to burn assessment and management.\n\nThis consult covers the **7-module approach** to burn management: initial assessment, TBSA calculation, fluid resuscitation, airway and inhalation injury, escharotomy, chemical burns, and wound care with disposition planning.\n\n**Burns are trauma patients first.** Complete a primary survey (ABCDE) before focusing on burn-specific assessment. Up to 10% of burn patients have associated traumatic injuries that may take priority. Maintain a low threshold for intubation with any signs of airway involvement — edema progresses rapidly and the window for safe intubation closes within hours.' WHERE id = 'burn-start' AND tree_id = 'burns';
UPDATE decision_nodes SET body = E'Identify the mechanism of injury. Mechanism determines the initial management pathway and anticipates specific complications.\n\nThermal burns are most common (>80%). Chemical and electrical burns require agent-specific and mechanism-specific protocols. Radiation burns are rare and require specialized consultation.\n\n**Consider toxic inhalation in ALL burns** — especially enclosed-space fires. CO and cyanide exposure can occur without visible airway injury:\n• [CO Poisoning Assessment](#/node/burn-co-assess) — co-oximetry required (pulse ox unreliable)\n• [Cyanide Poisoning Assessment](#/node/burn-cyanide) — suspect if lactate >8, AMS, hemodynamic instability' WHERE id = 'burn-type' AND tree_id = 'burns';
UPDATE decision_nodes SET body = E'**Electrical burns cause internal damage far exceeding external appearance.** Current follows the path of least resistance: nerve > blood vessel > muscle > skin > tendon > fat > bone.\n\n**High voltage (>1000V):**\n• Entry/exit wounds — look for both\n• Deep tissue necrosis along current path\n• Rhabdomyolysis — aggressive IVF, target UOP 1-1.5 mL/kg/hr\n• Compartment syndrome risk (especially forearm, leg)\n• Cardiac: dysrhythmias, myocardial injury\n• Vascular thrombosis — delayed presentation possible\n• Spinal cord injury (transient or permanent)\n\n**Low voltage (<1000V):**\n• Household current (120-240V) — typically hand contact burns\n• Cardiac monitoring × 4-6h if any LOC, abnormal ECG, or arrhythmia\n• Oral commissure burns in children (biting cords) — delayed labial artery hemorrhage at 5-7 days\n\n**Lightning:**\n• Flashover effect — current travels over body surface\n• Cardiac arrest: **asystole > VF** (reverse of typical arrest)\n• Tympanic membrane rupture (50%)\n• Fixed dilated pupils from autonomic dysfunction — do NOT use as prognostic sign\n• Keraunoparalysis (transient lower extremity paralysis)\n\n**Labs:** CK, myoglobin, BMP (hyperkalemia from rhabdo), lactate, UA (myoglobinuria), troponin, 12-lead ECG.\n\nIf rhabdomyolysis with hyperkalemia → [Potassium Disorders](#/tree/potassium)' WHERE id = 'burn-electrical' AND tree_id = 'burns';
UPDATE decision_nodes SET body = E'**Radiation burns are rare in the ED.** Localized radiation injury typically presents with delayed onset (hours to days after exposure). Severity depends on dose, duration, and type of radiation.\n\n**Immediate actions:**\n• Contact **REAC/TS (Radiation Emergency Assistance Center): 865-576-1005** — 24/7 consultation\n• **Decontaminate BEFORE treating** — external contamination is the priority\n• Remove all clothing (removes ~90% of external contamination)\n• Irrigate skin with copious water, paying attention to body folds\n• Bag and label all removed clothing and materials\n\n**PPE for providers:** Standard precautions are generally adequate for external contamination. Double glove, gown, shoe covers. Radiation injury itself is NOT contagious.\n\n**Wound management:** Treat the wound as you would a thermal burn of equivalent depth. Monitor for delayed effects — erythema may worsen over days to weeks.' WHERE id = 'burn-radiation' AND tree_id = 'burns';
UPDATE decision_nodes SET body = E'**A — Airway:** Facial burns, soot in nares/oropharynx, singed nasal/facial hair, hoarse voice, stridor → **early intubation.** Airway edema peaks at 12-24h. If you are considering intubation, do it now — the airway will only get worse.\n\n**B — Breathing:** Circumferential chest burns may restrict ventilation → escharotomy. Assess for inhalation injury. Auscultate for wheezing, stridor.\n\n**C — Circulation:** Establish large-bore IV access — can go through burned skin if necessary. IO access if IV not obtainable. Begin fluid resuscitation early. Circumferential extremity burns → monitor pulses.\n\n**D — Disability:** Enclosed space → suspect CO and cyanide poisoning. Assess GCS. Hypoxia may present as agitation.\n\n**E — Exposure/Environment:** Remove ALL clothing and jewelry (rings, watches — edema will make removal impossible later). Cover with clean dry sheets. **Prevent hypothermia** — burns patients lose thermoregulation. Warm IV fluids, warm room, blankets.\n\n[Prehospital Burn Considerations](#/info/burns-prehospital)' WHERE id = 'burn-primary-survey' AND tree_id = 'burns';
UPDATE decision_nodes SET body = E'**High-risk signs for inhalation injury:**\n• Enclosed space fire\n• Facial burns, singed facial/nasal hair\n• Soot in nares, mouth, or sputum\n• Carbonaceous sputum\n• Hoarse voice, stridor, dyspnea\n• Wheezing or rales\n• Hypoxia or altered mental status\n\n**Inhalation injury significantly worsens prognosis** — increases mortality by 20-60% and fluid requirements by 30-50%. It is the strongest predictor of mortality in burn patients, independent of TBSA and age.\n\nDirect laryngoscopy or bronchoscopy can confirm the diagnosis but should not delay treatment if clinical suspicion is high.' WHERE id = 'burn-inhalation-screen' AND tree_id = 'burns';
UPDATE decision_nodes SET body = E'[Burn Depth Classification Guide](#/info/burns-depth-guide)\n\n**Five-tier burn depth classification:**\n\n**1. Epidermal (Superficial):** Red, painful, no blisters, blanches with pressure. Sunburn. Heals 3-5 days. **NOT counted in TBSA.**\n\n**2. Superficial Partial Thickness (2nd degree):** Blisters, moist pink base, very painful, brisk capillary refill. Heals 7-14 days with minimal scarring.\n\n**3. Deep Partial Thickness (2nd degree):** Blisters (may have ruptured), pale/mottled base, decreased sensation, sluggish capillary refill. Heals 14-35 days with scarring. May require excision and grafting.\n\n**4. Full Thickness (3rd degree):** White, waxy, or charred. Leathery, insensate. No capillary refill. No blisters. Requires surgical excision and grafting.\n\n**5. 4th Degree:** Extends into muscle, tendon, or bone. Charred. Requires amputation or extensive reconstruction.\n\n**Key assessment tip:** Speed of capillary refill is the single most useful bedside test. Brisk = superficial partial. Sluggish = deep partial. Absent = full thickness.\n\n**Important:** Optimal depth assessment is at 3-5 days post-burn — initial assessment frequently underestimates depth. Early surgical consultation for burns that may be deep partial or full thickness.' WHERE id = 'burn-depth' AND tree_id = 'burns';
UPDATE decision_nodes SET body = E'Select the appropriate TBSA estimation method based on patient age.\n\n**Only count partial thickness (2nd degree) and full thickness (3rd/4th degree) burns in TBSA.** Epidermal/superficial burns (e.g., sunburn) are NOT included in TBSA calculations.\n\nAccurate TBSA estimation is critical — it drives fluid resuscitation volumes, burn center transfer decisions, and prognosis.' WHERE id = 'burn-tbsa-age' AND tree_id = 'burns';
UPDATE decision_nodes SET body = E'**Rule of 9''s — Adult Body Surface Area:**\n\n• **Head & neck:** 9%\n• **Each upper extremity:** 9% (entire arm)\n• **Anterior trunk:** 18%\n• **Posterior trunk:** 18%\n• **Each lower extremity:** 18% (entire leg)\n• **Perineum/genitalia:** 1%\n• **Total:** 100%\n\n**Palm method:** The patient''s palm (fingers together) ≈ **1% TBSA**. Useful for scattered or irregular burn patterns. For scattered burns, use the palm method to supplement the Rule of 9''s.\n\n**Obesity caveat:** The Rule of 9''s underestimates TBSA in obese patients. The trunk accounts for a greater percentage and extremities a lesser percentage. Consider using serial halving or digital planimetry for BMI >30.' WHERE id = 'burn-tbsa-adult' AND tree_id = 'burns';
UPDATE decision_nodes SET body = E'**Children have proportionally larger heads and smaller legs** than adults. The Rule of 9''s is inaccurate for patients ≤14 years. Use the **Lund-Browder chart** for age-adjusted TBSA estimation.\n\n**Age-adjusted percentages (Lund-Browder):**\n\n| Region | 0-1 yr | 1-4 yr | 5-9 yr | 10-14 yr |\n|--------|--------|--------|--------|----------|\n| Head | 19% | 17% | 13% | 11% |\n| Neck | 2% | 2% | 2% | 2% |\n| Ant. trunk | 13% | 13% | 13% | 13% |\n| Post. trunk | 13% | 13% | 13% | 13% |\n| Each buttock | 2.5% | 2.5% | 2.5% | 2.5% |\n| Genitalia | 1% | 1% | 1% | 1% |\n| Each upper arm | 4% | 4% | 4% | 4% |\n| Each forearm | 3% | 3% | 3% | 3% |\n| Each hand | 2.5% | 2.5% | 2.5% | 2.5% |\n| Each thigh | 5.5% | 6.5% | 8% | 8.5% |\n| Each leg | 5% | 5% | 5.5% | 6% |\n| Each foot | 3.5% | 3.5% | 3.5% | 3.5% |\n\n**Key point:** As children age, the head proportion decreases and leg proportion increases, converging toward adult values by age 15.\n\nFor infants and toddlers, the palm method (1% TBSA) can supplement Lund-Browder for scattered burns.' WHERE id = 'burn-tbsa-peds' AND tree_id = 'burns';
UPDATE decision_nodes SET body = E'Based on your TBSA calculation, select the appropriate fluid resuscitation pathway.\n\nFormal fluid resuscitation formulas are generally indicated for adults with **≥20% TBSA** and children with **≥10% TBSA**. Smaller burns can usually be managed with oral hydration and maintenance IV fluids.' WHERE id = 'burn-tbsa-result' AND tree_id = 'burns';
UPDATE decision_nodes SET body = E'**No formal resuscitation formula is needed** for minor burns (adults <20% TBSA, children <10% TBSA).\n\n**Fluid strategy:**\n• Encourage **oral fluid intake** — patients with intact GI function and small burns can self-hydrate\n• IV maintenance fluids if NPO or unable to tolerate PO\n• Standard maintenance rate: 4-2-1 rule (4 mL/kg/hr first 10kg, 2 mL/kg/hr next 10kg, 1 mL/kg/hr thereafter)\n\n**Monitoring:**\n• Urine output goal: 0.5-1 mL/kg/hr (adults), 1-1.5 mL/kg/hr (children)\n• Monitor oral intake — dehydration risk is underappreciated in minor burns\n• If patient cannot maintain adequate PO intake, consider IV supplementation\n\n**Note:** Patients with inhalation injury, extremes of age, or significant comorbidities may require more aggressive hydration even with smaller TBSA burns.' WHERE id = 'burn-minor-fluids' AND tree_id = 'burns';
UPDATE decision_nodes SET body = E'**The patient''s palm (including fingers) approximates 1% TBSA.** This method supplements the Rule of 9''s for scattered or irregular burn patterns.\n\n**When to use:**\n• Burns covering <15% TBSA — count the number of palms the burn area covers\n• Burns covering >85% TBSA — count unburned areas and subtract from 100%\n• Scattered or patchy burns where Rule of 9''s regional estimates are imprecise\n\n**Technique:**\n• Use the **patient''s** palm size, not the examiner''s\n• Include all fingers held together\n• Mentally "stamp" the palm over burned areas and count\n\n**Limitations:** Interobserver variability is moderate. Most accurate when used consistently by one examiner. Digital apps (e.g., EasyTBSA) may improve accuracy.' WHERE id = 'burn-palms-scatter' AND tree_id = 'burns';
UPDATE decision_nodes SET body = E'**All fluid resuscitation formulas calculate the first 24 hours from the TIME OF BURN, not time of ED arrival.** If the patient arrives 4 hours post-burn, the first 8-hour window has already partially elapsed — adjust accordingly.\n\n**General principles:**\n• Use **Lactated Ringer''s (LR)** — isotonic, buffered, less hyperchloremic acidosis than NS\n• All formulas are **starting points** — titrate to urine output\n• **UOP target:** 0.5-1 mL/kg/hr (adults), 1-1.5 mL/kg/hr (children)\n• Place a Foley catheter for all patients receiving formula-based resuscitation\n\nSelect a resuscitation formula:' WHERE id = 'burn-fluids-moderate' AND tree_id = 'burns';
UPDATE decision_nodes SET body = E'**Burns ≥40% TBSA require extremely high fluid volumes** and carry significant risk of **fluid creep** — iatrogenic over-resuscitation leading to compartment syndrome (abdominal, extremity, orbital), pulmonary edema, and cerebral edema.\n\n**Key considerations for severe burns:**\n• Higher initial fluid rates needed, but must titrate aggressively downward\n• Consider **early colloid** (albumin or FFP) at 8-12h to reduce total crystalloid volume\n• Monitor for abdominal compartment syndrome (bladder pressures)\n• Vasopressors may be needed if fluid refractory — this is a marker of very poor prognosis\n• ICU admission mandatory\n\nSelect a resuscitation formula:' WHERE id = 'burn-fluids-severe' AND tree_id = 'burns';
UPDATE decision_nodes SET body = E'**The Rule of 10''s is the simplest burn resuscitation formula** — designed for rapid initiation in the ED or prehospital setting.\n\n**Step 1:** %TBSA × 10 = **initial LR rate in mL/hr**\n• Example: 30% TBSA → 30 × 10 = 300 mL/hr LR\n\n**Step 2:** For patients **>80 kg**, add 100 mL/hr for every 10 kg above 80 kg\n• Example: 100 kg patient with 30% TBSA → 300 + 200 = 500 mL/hr\n\n**Titration:** Adjust rate q1-2h to maintain UOP 0.5-1 mL/kg/hr. Increase by 20% if UOP below target, decrease by 20% if above target.\n\n**Advantages:** Simple mental math, no calculator needed, easy to initiate in the field. Produces volumes comparable to Parkland but avoids over-resuscitation in the first 8 hours.\n\n**Limitations:** Less precise than Parkland for very large or very small patients. Not validated for pediatric use.' WHERE id = 'burn-rule-of-10' AND tree_id = 'burns';
UPDATE decision_nodes SET body = E'**Parkland (Baxter) Formula — the most widely used burn resuscitation formula:**\n\n**4 mL × %TBSA × weight (kg) = total volume over first 24 hours**\n\n**Administration:**\n• **First 8 hours (from time of burn):** Give **half** of the 24h total\n• **Next 16 hours:** Give the remaining **half**\n• Use **Lactated Ringer''s** exclusively\n\n**Example:** 80 kg patient, 40% TBSA\n→ 4 × 40 × 80 = 12,800 mL in 24h\n→ First 8h: 6,400 mL (800 mL/hr)\n→ Next 16h: 6,400 mL (400 mL/hr)\n\n**Known issues:**\n• The Parkland formula frequently leads to **over-resuscitation** — the original 4 mL/kg/% was derived as an average, but has become a minimum in practice\n• Higher initial formula volumes (>4 mL) correlate with higher 24h totals and worse outcomes\n• Always titrate to UOP — the formula is a **starting point**, not a target\n• Consider colloid supplementation at 8-12h if crystalloid requirements are exceeding predicted volumes' WHERE id = 'burn-parkland' AND tree_id = 'burns';
UPDATE decision_nodes SET body = E'[Dell-Seton (DSMC-UT) Burn Protocol](#/info/burns-dsmc-protocol)\n\n**The Dell-Seton (DSMC-UT) institutional protocol** uses a modified Parkland approach with early colloid integration and structured titration.\n\n**For TBSA 20-39%:**\n• **Initial crystalloid:** 2 mL × %TBSA × weight (kg) = first 8h LR volume\n• **Colloid (5% albumin):** Begins at hour 8 if crystalloid requirements remain high\n• **Titration:** UOP-based with mandatory q1h nursing documentation\n• **Target UOP:** 0.5-1.0 mL/kg/hr (adults)\n\n**Advantages of this protocol:**\n• Lower initial crystalloid volumes reduce fluid creep\n• Early colloid reduces total 24h fluid volume\n• Structured titration prevents both under- and over-resuscitation\n• Institution-specific nursing protocols improve compliance' WHERE id = 'burn-dsmc-moderate' AND tree_id = 'burns';
UPDATE decision_nodes SET body = E'[Dell-Seton (DSMC-UT) Burn Protocol](#/info/burns-dsmc-protocol)\n\n**For TBSA ≥40%, the Dell-Seton protocol initiates FFP from the start** alongside crystalloid to combat the massive capillary leak seen in severe burns.\n\n**Protocol:**\n• **Crystalloid (LR):** 2 mL × %TBSA × weight (kg) over first 8h\n• **FFP:** Initiated simultaneously — 0.5-1.0 mL × %TBSA × weight (kg) over first 8h\n• **Titration:** Aggressive UOP-based adjustments q1h\n• **Target UOP:** 0.5-1.0 mL/kg/hr (adults)\n\n**Rationale for early FFP:**\n• Burns ≥40% TBSA produce massive capillary leak with loss of plasma proteins\n• Crystalloid alone leads to progressive edema and compartment syndrome\n• Early FFP replaces lost plasma proteins and maintains oncotic pressure\n• Studies show reduced total 24h fluid volumes and fewer escharotomies\n\n**Blood bank considerations:** FFP requires thawing (30-45 min). Notify blood bank early for severe burns. Type-specific preferred but AB universal donor if emergent.' WHERE id = 'burn-dsmc-severe' AND tree_id = 'burns';
UPDATE decision_nodes SET body = E'**Urine output is the primary endpoint** for titrating burn resuscitation. All formulas are starting points — clinical response determines the actual rate.\n\n**UOP targets:**\n• Adults: **0.5-1.0 mL/kg/hr**\n• Children: **1.0-1.5 mL/kg/hr**\n• Electrical burns / myoglobinuria: **1.0-1.5 mL/kg/hr** (adults) to prevent renal tubular obstruction\n\n**Titration rules:**\n• UOP below target → increase rate by **20%** q1h\n• UOP above target → decrease rate by **20%** q1h\n• Do NOT bolus crystalloid to "catch up" — this drives fluid creep\n• If UOP remains <0.5 despite 150% predicted volume → consider colloid, vasopressors, or reassess TBSA\n\n**Fluid creep warning signs:**\n• Rising bladder pressures (>20 mmHg = intra-abdominal hypertension)\n• Increasing peak airway pressures in ventilated patients\n• Progressive extremity edema with loss of pulses\n• Orbital compartment syndrome (proptosis, elevated IOP)\n\n**Laboratory monitoring (q4-6h):**\n• BMP (sodium, potassium, bicarb)\n• Lactate (trending improvement = adequate resuscitation)\n• Hematocrit (rising Hct = hemoconcentration from inadequate resuscitation)\n• Glucose (especially pediatric patients)\n• Base deficit (trending)' WHERE id = 'burn-fluids-monitoring' AND tree_id = 'burns';
UPDATE decision_nodes SET body = E'**Children <30 kg require BOTH maintenance fluids AND resuscitation fluids** — they have limited glycogen stores and are at high risk for hypoglycemia during large-volume crystalloid resuscitation.\n\n**Maintenance fluids (in addition to resuscitation):**\n• Use **D5 ½NS** (dextrose-containing) at standard 4-2-1 maintenance rate:\n  - First 10 kg: 4 mL/kg/hr\n  - 10-20 kg: add 2 mL/kg/hr\n  - >20 kg: add 1 mL/kg/hr\n• Run maintenance through a separate line from resuscitation LR\n\n**Resuscitation:**\n• Parkland formula applies: 4 mL × %TBSA × weight (kg)\n• Use LR for resuscitation (no dextrose in resuscitation fluid)\n• Target UOP: **1.0-1.5 mL/kg/hr** (higher than adults)\n\n**Glucose monitoring:**\n• Check glucose on arrival and q2-4h during resuscitation\n• Infants and toddlers are especially vulnerable to hypoglycemia\n• D10 bolus (2-4 mL/kg) for glucose <60 mg/dL\n\n**Non-accidental trauma (NAT) screening:**\n• **Mandatory consideration in all pediatric burns**, especially:\n  - Scald burns with stocking/glove distribution\n  - Burns with sharp lines of demarcation\n  - Bilateral symmetric burns\n  - Delay in presentation (>2 hours)\n  - Story inconsistent with burn pattern or developmental age\n  - Prior injuries or ED visits\n• Document skin exam, photo-document burns, involve social work' WHERE id = 'burn-fluids-peds' AND tree_id = 'burns';
UPDATE decision_nodes SET body = E'**Hard signs of impending airway compromise** (intubate immediately):\n• Stridor or progressive hoarseness\n• Full-thickness facial/neck burns\n• Massive oropharyngeal edema on direct visualization\n• Respiratory distress (accessory muscle use, tachypnea)\n• Altered mental status with facial burns\n• Copious secretions with soot\n\n**Soft signs** (close monitoring, prepare for intubation):\n• Facial burns without voice changes\n• Singed nasal/facial hair\n• Soot in nares without respiratory symptoms\n• Mild erythema of oropharynx\n• Burns in enclosed space but currently asymptomatic\n\n**If in doubt, intubate early.** Airway edema peaks at 12-24 hours. A patient with soft signs at hour 1 may develop complete obstruction by hour 6. The consequences of unnecessary intubation are far less than the consequences of a lost airway.' WHERE id = 'burn-airway-assess' AND tree_id = 'burns';
UPDATE decision_nodes SET body = E'**Use the largest ETT that will pass** — expect significant secretions and potential for mucosal sloughing. A larger tube facilitates suctioning and bronchoscopy.\n\n**Preparation:**\n• Video laryngoscopy preferred (edematous landmarks)\n• Have **surgical airway kit at bedside** — can''t-intubate-can''t-oxygenate is a real risk\n• Suction ready — expect copious carbonaceous secretions\n• Bougie available\n\n**Induction:** [Ketamine](#/drug/ketamine/burns) 1-2 mg/kg IV is preferred — maintains hemodynamic stability and provides bronchodilation. Avoid agents that drop blood pressure in patients who are already volume-depleted.\n\n**Paralytic:** Succinylcholine is safe in the **first 24 hours** after burn. **After 24 hours, succinylcholine is CONTRAINDICATED** — upregulation of extrajunctional acetylcholine receptors causes massive potassium release and cardiac arrest. Use rocuronium instead.\n\n**Securing the tube:** Secure with **cloth ties or commercial tube holders** — tape will not adhere to burned or edematous skin. Mark ETT depth. Document and verify position with end-tidal CO2 and CXR.\n\n**Post-intubation:**\n• Expect to increase fluid resuscitation by **30-50%** over predicted volumes\n• Early bronchoscopy for diagnosis and therapeutic lavage\n• HOB 30° to reduce facial/airway edema\n• Low tidal volume ventilation (6-8 mL/kg IBW) — inhalation injury causes ARDS' WHERE id = 'burn-intubation' AND tree_id = 'burns';
UPDATE decision_nodes SET body = E'**Serial airway exams are mandatory** when soft signs are present without indication for immediate intubation.\n\n**Monitoring protocol:**\n• Re-examine airway **q30-60 minutes** for the first 6-12 hours\n• Direct visualization of oropharynx — assess for progressive edema\n• Voice quality changes (hoarseness, muffled voice)\n• Work of breathing, stridor, wheezing\n• Pulse oximetry (continuous) and serial ABGs\n\n**Peak edema occurs at 12-24 hours.** Patients may appear stable initially but deteriorate rapidly. Airway edema from fluid resuscitation compounds thermal edema.\n\n**Keep intubation equipment at bedside:**\n• Video laryngoscopy\n• Multiple ETT sizes\n• Bougie\n• Surgical airway kit\n• Suction\n\n**Head of bed at 30°** — reduces facial and airway edema.\n\n**Transition to intubation if ANY of:**\n• Progressive voice changes\n• New stridor\n• Increasing work of breathing\n• Worsening oropharyngeal edema on exam\n• Anticipated transport (intubate before transfer if any concern)' WHERE id = 'burn-airway-soft' AND tree_id = 'burns';
UPDATE decision_nodes SET body = E'**Carbon monoxide (CO) binds hemoglobin with 240× the affinity of oxygen**, forming carboxyhemoglobin (COHb). It causes cellular hypoxia by displacing O2 and shifting the oxyhemoglobin dissociation curve leftward.\n\n**Diagnosis requires co-oximetry** — standard pulse oximetry is **UNRELIABLE** because it cannot distinguish COHb from oxyhemoglobin. PaO2 on ABG is also normal (measures dissolved O2, not bound).\n\n**COHb levels (co-oximetry):**\n• Non-smoker baseline: <3%\n• Smoker baseline: up to 10%\n• Symptomatic: usually >15-20%\n• Severe: >25%\n• Lethal: >60-70%\n\n**Note:** COHb levels may be falsely low if the patient received high-flow O2 during transport.\n\n[CO & Cyanide Toxicity Reference](#/info/burns-co-cyanide)' WHERE id = 'burn-co-assess' AND tree_id = 'burns';
UPDATE decision_nodes SET body = E'**Immediate treatment: 100% FiO2 via NRB mask or ventilator.**\n\n**CO half-life by oxygen delivery:**\n• Room air (21% O2): ~320 minutes (5+ hours)\n• 100% O2 NRB: ~90 minutes\n• Hyperbaric oxygen (HBO) at 3 ATA: ~23 minutes\n\n**Hyperbaric oxygen (HBO) criteria** — consider if available within reasonable transport time:\n• COHb >25% (>15% in pregnancy)\n• Loss of consciousness at any point\n• Neurologic deficit (confusion, ataxia, seizure)\n• Cardiac ischemia or arrhythmia\n• Persistent symptoms despite 4h of 100% O2\n• Pregnancy with COHb >15% or any fetal distress\n\n**HBO controversy:** Evidence is mixed. The Weaver trial showed reduced cognitive sequelae at 6 weeks and 12 months with HBO. However, HBO requires transport, is not universally available, and is impractical for critically ill burn patients who need ongoing resuscitation.\n\n**Delayed neuropsychiatric syndrome (DNS):**\n• Occurs in 15-40% of significant CO poisonings\n• Onset: 2-40 days after exposure\n• Symptoms: cognitive impairment, personality changes, movement disorders, focal deficits\n• HBO may reduce risk — strongest indication for HBO referral\n\n**Cardiac monitoring:** CO causes direct myocardial toxicity. Troponin, ECG, and telemetry for all patients with COHb >15% or cardiac symptoms.' WHERE id = 'burn-co-treatment' AND tree_id = 'burns';
UPDATE decision_nodes SET body = E'**Treatment: 100% O2 via non-rebreather mask for at least 6 hours** or until COHb normalizes (<3% non-smoker, <10% smoker).\n\n**Monitoring:**\n• Repeat co-oximetry every 2 hours until normalized\n• Continuous cardiac monitoring\n• Serial neurologic exams — assess orientation, cognition, gait\n\n**Expected symptom resolution timeline:**\n• Headache: usually resolves within 4-6h of O2 therapy\n• Nausea/dizziness: resolves within 2-4h\n• Confusion: if present, should clear within 4-6h — persistent confusion warrants reassessment\n\n**Disposition considerations:**\n• If symptoms resolve and COHb normalizes: can be managed as part of overall burn disposition\n• If symptoms persist despite 4-6h of 100% O2: consider HBO referral\n• Counsel all patients about delayed neuropsychiatric syndrome (DNS) — return for cognitive changes, personality changes, or new neurologic symptoms over the next 2-6 weeks' WHERE id = 'burn-co-mild' AND tree_id = 'burns';
UPDATE decision_nodes SET body = E'**Suspect cyanide poisoning in ALL enclosed-space fire victims.** Cyanide is produced by combustion of synthetic materials (plastics, wool, silk, nylon, polyurethane). It inhibits cytochrome oxidase, blocking cellular oxygen utilization.\n\n**Key findings:**\n• Persistent hemodynamic instability despite fluid resuscitation\n• **Lactate >8 mmol/L** (highly suggestive — cells can''t use O2)\n• Altered mental status out of proportion to COHb level\n• Seizures\n• Cardiac arrest (especially with combined CO + cyanide)\n\n**This is a CLINICAL DIAGNOSIS.** Cyanide levels are NOT available in a useful timeframe (send but don''t wait). Whole blood cyanide >1 mg/L is toxic; >3 mg/L is potentially lethal.\n\n**Concurrent CO + cyanide is synergistic** — worse outcomes than either alone. Treat both simultaneously.' WHERE id = 'burn-cyanide' AND tree_id = 'burns';
UPDATE decision_nodes SET body = E'**First-line antidote: [Hydroxocobalamin](#/drug/hydroxocobalamin/cyanide) (Cyanokit)**\n• Adult dose: **5 g IV over 15 minutes**\n• May repeat × 1 if clinical response is inadequate\n• Pediatric dose: **70 mg/kg IV** (max 5 g)\n\n**Mechanism:** Hydroxocobalamin (vitamin B12a) binds cyanide directly to form cyanocobalamin (vitamin B12), which is renally excreted. Does not affect oxygen-carrying capacity — safe to use with concurrent CO poisoning.\n\n**Side effects:**\n• Turns skin and urine **deep RED** for 2-5 days — warn the patient and staff\n• Interferes with colorimetric lab assays (total bilirubin, creatinine, glucose) — **draw labs BEFORE administration** when possible\n• Hypertension (usually transient)\n\n**Alternative: Sodium thiosulfate**\n• 12.5 g (50 mL of 25% solution) IV over 10-20 min\n• Slower onset than hydroxocobalamin\n• Use as adjunct or when hydroxocobalamin unavailable\n\n**AVOID sodium nitrite in concurrent CO poisoning** — nitrite induces methemoglobinemia, which combined with COHb critically reduces oxygen delivery. Hydroxocobalamin is the preferred agent specifically because it does not form methemoglobin.' WHERE id = 'burn-cyanide-rx' AND tree_id = 'burns';
UPDATE decision_nodes SET body = E'**Circumferential deep partial-thickness or full-thickness burns create a tourniquet effect** as the inelastic eschar cannot expand with progressive tissue edema beneath it. This compromises perfusion (extremities) or ventilation (chest).\n\n**Assessment timing:** Compartment syndrome from circumferential burns typically develops **4-6 hours post-burn** as resuscitation fluids drive tissue edema. Serial assessment is mandatory during the resuscitation phase.\n\n**Does the patient have circumferential or near-circumferential deep partial/full-thickness burns?**' WHERE id = 'burn-eschar-screen' AND tree_id = 'burns';
UPDATE decision_nodes SET body = E'[Escharotomy Technique](#/info/burns-escharotomy)\n\n**The 6 P''s of compartment syndrome** (though in burn eschar, pain may be absent due to nerve damage):\n• **Pain** — pain out of proportion, pain with passive stretch (unreliable in full-thickness)\n• **Pressure** — tense, firm compartment\n• **Paresthesias** — numbness, tingling (early sign)\n• **Pallor** — pale or cyanotic distal extremity\n• **Pulselessness** — LATE finding. Do not wait for this.\n• **Paralysis** — LATE finding indicating muscle ischemia\n\n**Objective measures:**\n• **Doppler ultrasound** — loss of arterial signal in digital arteries is the most reliable non-invasive indicator\n• **Pulse oximetry** — loss of plethysmographic waveform in a burned digit\n• **Compartment pressure** — >30 mmHg or within 30 mmHg of diastolic\n• **Capillary refill** — >3 seconds in burned tissue (difficult to assess)\n\n**Indications for escharotomy:**\n• Absent or diminishing distal pulses/Doppler signals\n• Progressive paresthesias or neurologic deficit\n• Compartment pressures >30 mmHg\n• Increasing pain (if sensation preserved)\n\n**Do NOT wait for pulselessness** — by the time pulses are lost, irreversible ischemia may have occurred.' WHERE id = 'burn-eschar-extremity' AND tree_id = 'burns';
UPDATE decision_nodes SET body = E'[Escharotomy Technique](#/info/burns-escharotomy)\n\n**Escharotomy is an emergency bedside procedure** — performed through insensate full-thickness eschar. If the patient has full-thickness burns, the incision should be painless (no local anesthesia needed in the eschar). Provide sedation/analgesia for patient comfort.\n\n**Incision lines — medial and lateral mid-axial lines:**\n\n**Upper extremity:**\n• Lateral: axilla → lateral epicondyle → dorsal wrist\n• Medial: axilla → medial epicondyle → volar wrist\n• Avoid the ulnar nerve at the medial epicondyle\n• If hand involved: incisions on dorsum between metacarpals, NOT on palmar surface\n\n**Lower extremity:**\n• Lateral: groin → lateral malleolus\n• Medial: groin → medial malleolus (posterior to medial malleolus to avoid saphenous vein/nerve)\n• Avoid the common peroneal nerve at the fibular head\n\n**Technique:**\n1. Incise through eschar down to subcutaneous fat — the wound should visibly open/separate\n2. Use electrocautery or scalpel\n3. Extend incisions proximally and distally until eschar releases\n4. If crossing a joint, use a Z-incision or S-curve to prevent contracture\n5. Hemostasis with electrocautery or topical hemostatic agents\n6. Cover with silver sulfadiazine or moist dressings\n\n**Post-procedure:** Reassess with Doppler every 15 min × 1 hr. If no improvement → consider **fasciotomy** (deeper decompression requiring OR).' WHERE id = 'burn-eschar-technique' AND tree_id = 'burns';
UPDATE decision_nodes SET body = E'[Escharotomy Technique](#/info/burns-escharotomy)\n\n**Circumferential chest burns restrict chest wall excursion**, leading to progressive respiratory failure. In ventilated patients, this manifests as rising peak airway pressures and decreasing tidal volumes.\n\n**Indications:**\n• Rising peak airway pressures (ventilated patients)\n• Decreased chest wall compliance\n• Hypoxia or hypercarbia despite adequate ventilator settings\n• Visible restriction of chest wall movement\n\n**Technique — bilateral anterior axillary line incisions:**\n1. **Bilateral vertical incisions** along the anterior axillary lines from the clavicle to the costal margin\n2. **Transverse connecting incision** along the costal margin (creating an "H" or clamshell pattern)\n3. For severe restriction, add a **transverse subclavicular incision** connecting the two vertical incisions\n4. Incise through eschar to subcutaneous fat — the chest wall should visibly expand\n5. Immediately reassess ventilation (tidal volumes, peak pressures, SpO2)\n\n**If abdomen is also involved:** Extend incisions inferiorly to the inguinal ligaments to decompress the abdominal wall — abdominal compartment syndrome from burn edema + massive fluid resuscitation.' WHERE id = 'burn-eschar-chest' AND tree_id = 'burns';
UPDATE decision_nodes SET body = E'**Escharotomy releases skin-level constriction. Fasciotomy addresses deep compartment pressure** — these are distinct procedures.\n\n**Fasciotomy is indicated when:**\n• Escharotomy fails to restore distal perfusion\n• **Electrical burns** with deep tissue injury (current travels through muscle — eschar release alone is insufficient)\n• Compartment pressures remain **>30 mmHg** (or within 30 mmHg of diastolic) after adequate escharotomy\n• Crush injury or prolonged extrication with circumferential burn\n\n**Fasciotomy requires:**\n• Operating room or procedural suite\n• Surgical consultation (burn surgery, orthopedic surgery, or general surgery)\n• Full-length compartment release — all compartments in the affected extremity\n• Forearm: volar and dorsal compartments\n• Lower leg: all 4 compartments (anterior, lateral, deep posterior, superficial posterior)\n\n**Post-fasciotomy management:** Open wound with wet dressings, delayed primary closure or skin grafting at 48-72h, aggressive physical therapy.' WHERE id = 'burn-eschar-fasciotomy' AND tree_id = 'burns';
UPDATE decision_nodes SET body = E'**Universal first step for chemical burns: copious water irrigation for ≥20-30 minutes** (with specific exceptions noted below). Begin irrigation IMMEDIATELY — do not delay for agent identification.\n\n**Exceptions to water irrigation:**\n• **Elemental metals (Na, K, Li)** — react violently with water → remove mechanically first, then irrigate\n• **Dry powder** — brush off before irrigating\n• **Cement** — brush off dry powder, then irrigate\n\n**Provider safety:** Wear appropriate PPE. Chemical burns can injure providers through secondary contact. Irrigate in a well-ventilated area. Contain runoff.\n\n[Chemical Burns Agent-Specific Guide](#/info/burns-chemical-detail)' WHERE id = 'burn-chem-start' AND tree_id = 'burns';
UPDATE decision_nodes SET body = E'**Acids cause coagulation necrosis** — proteins denature and form a coagulum that limits penetration depth. This is why acid burns are generally less destructive than alkali burns of equivalent concentration.\n\n**Treatment:**\n• **Copious water irrigation for 20-30 minutes** — begin immediately\n• **Do NOT attempt to neutralize** — exothermic reaction will cause additional thermal injury\n• Monitor wound pH with litmus paper — irrigate until tissue pH is **7.0-7.5**\n• Remove all contaminated clothing during irrigation\n\n**Specific acids:**\n• **Sulfuric acid (H2SO4):** Battery acid, drain cleaners. Exothermic on water contact — irrigate copiously despite heat generation\n• **Hydrochloric acid (HCl):** Pool chemicals, masonry. Standard irrigation protocol\n• **Nitric acid (HNO3):** Industrial. Yellow-stained tissue (xanthoproteic reaction). Standard irrigation\n• **Phenol (carbolic acid):** Industrial solvent. Poorly water-soluble — irrigate with low-molecular-weight PEG (polyethylene glycol) if available, otherwise copious water. Risk of systemic toxicity (seizures, cardiac dysrhythmias, hepatorenal failure)\n\n**Ocular acid exposure:** Irrigate with NS or balanced salt solution for at least 30 minutes. Check pH at 10-minute intervals. Emergency ophthalmology consult.' WHERE id = 'burn-chem-acid' AND tree_id = 'burns';
UPDATE decision_nodes SET body = E'**Alkali burns cause liquefaction necrosis — more dangerous and penetrating than acid burns.** Alkalis saponify fats and dissolve proteins, allowing progressive deep tissue penetration. The injury continues to deepen until the agent is completely removed.\n\n**Treatment:**\n• **Prolonged irrigation: 30-60+ minutes** (longer than acid burns)\n• Alkali binds to tissue — copious, prolonged irrigation is essential to wash out residual chemical\n• Monitor pH — irrigate until tissue pH reaches **7.0-7.5**\n• Multiple irrigation cycles may be needed — recheck pH 15 minutes after stopping\n\n**Specific alkalis:**\n• **Sodium hydroxide (NaOH/lye):** Oven cleaners, drain openers. Extremely destructive. Prolonged irrigation.\n• **Calcium hydroxide (cement/lime):** Construction workers. **Brush off dry cement FIRST**, then irrigate. Cement continues to burn while wet against skin. Chrome content can cause contact dermatitis.\n• **Ammonia (NH3):** Industrial, cleaning products. Highly volatile — inhalation injury risk. Irrigate eyes and skin copiously.\n• **Sodium hypochlorite (bleach):** Household concentration (3-6%) usually causes only irritation. Industrial concentration (10-15%) can cause significant burns.\n\n**Ocular alkali exposure is an EMERGENCY** — alkali penetrates rapidly through the cornea. Irrigate immediately and continuously for ≥30 min with NS. Emergency ophthalmology consult. Worse prognosis than acid exposure.' WHERE id = 'burn-chem-alkali' AND tree_id = 'burns';
UPDATE decision_nodes SET body = E'**HF acid is uniquely dangerous** — the fluoride ion penetrates tissue and binds calcium and magnesium, causing both deep tissue destruction and potentially fatal systemic toxicity (hypocalcemia, hypomagnesemia, hyperkalemia → cardiac arrest).\n\n**Concentration determines presentation:**\n• >50% HF: immediate pain and tissue destruction\n• 20-50% HF: delayed 1-8 hours\n• <20% HF: may be delayed up to 24 hours — patients may not seek care until significant damage has occurred\n\n**Treatment ladder:**\n\n**Step 1 — Immediate irrigation:** Copious water for 15-30 minutes\n\n**Step 2 — Topical calcium gluconate:** [Calcium Gluconate 2.5% Gel](#/drug/calcium-gluconate-gel/hf burn) applied liberally to the burn and surrounding area, massaged in with a gloved hand. Reapply every 15-30 min. Can be made by mixing 3.5g calcium gluconate powder in 150mL water-soluble lubricant (e.g., KY jelly).\n\n**Step 3 — Subcutaneous/intradermal injection:** If pain persists despite topical therapy: 5% calcium gluconate (dilute 10% to 5%) injected **0.5 mL per cm²** of affected skin using a 27-30g needle. Maximum 0.5 mL per injection site.\n\n**Step 4 — Intra-arterial calcium:** For hand/digit burns unresponsive to above: [Calcium Gluconate](#/drug/calcium-gluconate/hf burn) 10 mL of 10% in 40 mL NS infused via radial artery catheter over 4 hours. Requires vascular access and monitoring.\n\n**Step 5 — Surgical:** Excision of necrotic tissue if all above measures fail.\n\n**Systemic monitoring (MANDATORY for burns >25 cm² or >50% HF):**\n• Continuous cardiac monitoring — watch for QT prolongation, widened QRS, bradycardia\n• Serial calcium, magnesium, potassium q2-4h\n• Replace calcium aggressively: calcium gluconate 10% IV if serum Ca <8 or symptomatic\n• Replace magnesium\n• Treat hyperkalemia per standard protocol → [Potassium Disorders](#/tree/potassium)' WHERE id = 'burn-chem-hf' AND tree_id = 'burns';
UPDATE decision_nodes SET body = E'**Elemental metals react violently with water** — standard irrigation can worsen the injury. Agent-specific management is critical.\n\n**Sodium (Na), Potassium (K), Lithium (Li):**\n• **WATER REACTIVE** — produces exothermic reaction, hydrogen gas (explosion risk), and alkali byproduct\n• **Step 1:** Cover with **mineral oil** to prevent further reaction with air moisture\n• **Step 2:** Mechanically remove all visible metal fragments with forceps while submerged in mineral oil\n• **Step 3:** Once ALL metal is removed, THEN irrigate copiously with water\n• Do NOT irrigate until metal is removed\n\n**White phosphorus:**\n• **Burns in air** — self-ignites when dry\n• **Keep wound SUBMERGED in water** or covered with saline-soaked dressings continuously\n• Remove visible particles with forceps under water — they will glow in a darkened room\n• **1% copper sulfate solution** can be applied briefly to aid identification (turns particles black) — limit exposure to prevent copper toxicity\n• Debridement under water immersion in OR\n• Risk of systemic phosphorus toxicity: hepatorenal failure, hypocalcemia\n\n**Magnesium:**\n• Burns intensely, reacts with water (produces hydrogen gas)\n• **Smother with sand, dry chemical, or Class D fire extinguisher**\n• Once burning stops, irrigate with copious water\n• Risk of systemic hypomagnesemia paradoxically low (metal form, not ionic)' WHERE id = 'burn-chem-metals' AND tree_id = 'burns';
UPDATE decision_nodes SET body = E'**When the chemical agent is unknown, default to copious water irrigation** — this is the safest approach for the vast majority of chemical exposures.\n\n**Immediate actions:**\n1. **PPE for providers** — double glove, gown, eye protection, N95 minimum. If vapor hazard suspected, move to well-ventilated area or use PAPR.\n2. **Remove all clothing** — bag and label for hazmat identification\n3. **Copious water irrigation for 30+ minutes** — assume the worst-case scenario until agent is identified\n4. **Monitor pH** of wound surface — continue irrigating until pH 7.0-7.5\n\n**Agent identification resources:**\n• **Poison Control: 1-800-222-1222** — 24/7, can assist with chemical identification and treatment guidance\n• SDS (Safety Data Sheets) — request from employer/workplace if occupational exposure\n• Container labels, if available\n• CHEMTREC: 1-800-424-9300 (hazmat transport emergencies)\n\n**The only time to withhold water:** If you strongly suspect elemental reactive metals (Na, K, Li) — these will be obvious as the metal reacts visibly with water. In all other cases, irrigate first and identify later.' WHERE id = 'burn-chem-unknown' AND tree_id = 'burns';
UPDATE decision_nodes SET body = E'**After thorough decontamination, manage the chemical burn wound as you would a thermal burn of equivalent depth.**\n\n**Important considerations specific to chemical burns:**\n\n**Depth may be underestimated initially.** Chemical burns often appear superficial on presentation but progress significantly over **24-72 hours**, especially alkali burns. Reassess depth at 48-72h before final wound management decisions.\n\n**Document the agent, concentration, duration of contact, and area involved.** This information is critical for burn center consultation and ongoing management.\n\n**Wound assessment after decontamination:**\n• Assess burn depth using same criteria as thermal burns\n• Calculate TBSA (same rules — only count partial/full thickness)\n• If TBSA meets resuscitation threshold → fluid resuscitation as per thermal burn protocols\n\n**Systemic toxicity screen** — some chemicals have significant systemic effects beyond the local burn:\n• HF acid → hypocalcemia, hypomagnesemia, hyperkalemia\n• Phenol → hepatorenal toxicity, seizures, cardiac dysrhythmias\n• Phosphorus → hepatorenal failure, hypocalcemia\n• Chromic acid → renal failure\n• Formic acid → metabolic acidosis, hemolysis\n\nProceed to wound care and dressing selection.' WHERE id = 'burn-chem-wound-care' AND tree_id = 'burns';
UPDATE decision_nodes SET body = E'[Burn Dressing Guide](#/info/burns-dressing-guide)\n\n**Step 1 — Cool the burn:** Apply cool (not ice-cold) running water for **20 minutes** within the first 3 hours of injury. This is the **single most effective first aid measure** — reduces pain, limits burn depth progression, and improves outcomes at 30 days. Do NOT use ice (causes vasoconstriction and frostbite risk).\n\n**Step 2 — Clean the wound:**\n• Gentle irrigation with NS or clean lukewarm water\n• Remove loose debris and necrotic tissue\n• Debride ruptured blisters — leave intact blisters that are small, tense, and not in a functional area\n• Large, flaccid, or contaminated blisters should be debrided\n• Gentle scrub with gauze if needed\n\n**Step 3 — Avoid harmful home remedies:**\n• **No butter, toothpaste, egg whites, or "folk" remedies** — these trap heat and introduce bacteria\n• **No ice application** — causes vasoconstriction and secondary injury\n• **No adhesive bandages directly on burns** — use nonadherent dressings only\n\n**Tetanus prophylaxis:** Update if >5 years since last dose or unknown status. Tdap preferred if not previously received.' WHERE id = 'burn-wound-care' AND tree_id = 'burns';
UPDATE decision_nodes SET body = E'[Burn Dressing Guide](#/info/burns-dressing-guide)\n\n**Dressing selection by burn depth:**\n\n**Epidermal (superficial):** No dressing needed. Moisturizing lotion (aloe vera is reasonable). Will heal in 3-5 days.\n\n**Superficial partial thickness:** Topical antimicrobial + nonadherent dressing. Options:\n• [Bacitracin](#/drug/bacitracin/burns) ointment + nonadherent gauze (Adaptic/Xeroform) — simple, inexpensive, preferred for face and small burns\n• Biosynthetic dressings (Biobrane, Suprathel) — reduce pain and dressing changes, good for pediatric scalds\n• Honey-based dressings (Medihoney) — antimicrobial properties, evidence for superficial partial burns\n\n**Deep partial thickness:** Requires more protective dressing. Options:\n• [Silver Sulfadiazine](#/drug/silver-sulfadiazine/burns) (SSD) 1% cream — broad-spectrum antimicrobial, easy to apply. **Avoid on the face** (cosmetic staining) and **avoid on superficial burns** (may impair healing). Requires daily dressing changes.\n• Silver-containing foam dressings (Mepilex Ag, Aquacel Ag) — can stay in place 3-7 days, reduce dressing changes, good for outpatient management\n• Referral for surgical consultation (may need excision and grafting)\n\n**Full thickness:** Clean dry dressings pending surgical management. SSD or antimicrobial dressing. These burns require excision and grafting — wound care is bridging to definitive surgery.\n\n**Tetanus:** Update if >5 years or unknown. Burns are tetanus-prone wounds.' WHERE id = 'burn-dressings' AND tree_id = 'burns';
UPDATE decision_nodes SET body = E'**Burns are among the most painful injuries encountered in the ED.** Adequate pain control is not optional — undertreated pain impairs wound care, increases anxiety, and worsens outcomes.\n\n**Mild burns (superficial, small partial):**\n• **Ibuprofen** 400-800 mg PO q6-8h + **Acetaminophen** 1000 mg PO q6-8h\n• Cooling, elevation, and appropriate dressings significantly reduce pain\n• Topical lidocaine preparations for small areas\n\n**Moderate-severe burns:**\n• [Morphine](#/drug/morphine/burns) 0.1 mg/kg IV q2-4h PRN — titrate to effect\n• [Ketamine](#/drug/ketamine/burns) 0.1-0.3 mg/kg IV (sub-dissociative) — excellent for burns, reduces opioid requirements, does not cause respiratory depression at sub-dissociative doses\n• Combine opioid + ketamine for synergistic effect with lower total doses of each\n\n**Procedural pain (dressing changes, debridement):**\n• [Ketamine](#/drug/ketamine/burns) 1-2 mg/kg IV for dissociative sedation\n• Procedural sedation for major debridement\n\n**Anxiolysis:**\n• [Midazolam](#/drug/midazolam/burns) 0.5-2 mg IV — for procedure-related anxiety\n• Burns cause intense psychological distress — address anxiety alongside pain\n\n**Pediatric pain management:**\n• [Fentanyl](#/drug/fentanyl/burns) IN (intranasal) 1.5 mcg/kg — needle-free, rapid onset (5-10 min), ideal for initial pain control in children\n• Oral sucrose for infants during dressing changes\n• Distraction techniques (tablets, videos) as adjunct\n\n**Key principle:** Treat pain aggressively early. It is much easier to maintain comfort than to regain it once pain is out of control.' WHERE id = 'burn-pain' AND tree_id = 'burns';
UPDATE decision_nodes SET body = E'**American Burn Association (ABA) criteria for burn center referral:**\n\n1. **Partial thickness burns >10% TBSA**\n2. **Burns involving face, hands, feet, genitalia, perineum, or major joints**\n3. **Full thickness (3rd degree) burns of any size**\n4. **Electrical burns** (including lightning)\n5. **Chemical burns**\n6. **Inhalation injury**\n7. **Burns in patients with significant comorbidities** (diabetes, immunosuppression, etc.)\n8. **Burns with concomitant trauma** where the burn is the greater risk\n9. **Burns in children** at hospitals without pediatric burn capability\n10. **Burns requiring social, emotional, or rehabilitative intervention** (suspected abuse, psychiatric, long-term rehab)\n\n**Contact the burn center early** — even before all initial assessment is complete. Early communication facilitates bed availability and transport coordination.\n\n**Pre-transfer management:**\n• Continue IV fluid resuscitation — do NOT stop or reduce during transport\n• **Clean, dry dressings** for transport (no wet dressings — hypothermia risk during transport)\n• Warming measures — warm blankets, warm IV fluids, warm ambulance\n• Elevate burned extremities above heart level\n• Document all medications, fluids given, urine output, and interventions\n• Send copies of labs, imaging, and clinical notes' WHERE id = 'burn-transfer' AND tree_id = 'burns';
UPDATE decision_nodes SET body = E'Based on the patient''s burn severity, associated injuries, and social situation, determine the appropriate disposition.\n\nConsider: TBSA, burn depth, burn location, mechanism, age, comorbidities, social factors (ability to perform dressing changes, follow-up access, abuse concerns), and inhalation injury status.' WHERE id = 'burn-disposition' AND tree_id = 'burns';
UPDATE decision_nodes SET body = E'**Initiate burn center transfer per ABA criteria.** Contact the nearest verified burn center early for bed availability and transport coordination.\n\n**Pre-transfer checklist:**\n• Secure airway if any concern for inhalation injury (intubate BEFORE transport)\n• Continue IV LR resuscitation — document rate and total volume given\n• Place Foley catheter — document urine output for receiving team\n• Clean, dry dressings — **no wet dressings during transport** (hypothermia risk)\n• Warming measures: warm blankets, warm IV fluids, heated ambulance\n• Analgesia — ensure adequate pain control for transport\n• NG/OG tube for burns >20% TBSA (ileus risk)\n• Elevate burned extremities\n• Send documentation: labs, imaging, medication list, fluid totals, I/O record, interventions performed' WHERE id = 'burn-transfer-result' AND tree_id = 'burns';
UPDATE decision_nodes SET body = E'**Admit for ongoing monitoring and management when burn center transfer is not indicated or not immediately available.**\n\n**Admission indications:**\n• Continued fluid resuscitation with UOP monitoring\n• Serial wound assessment — burn depth frequently worsens over 24-72 hours\n• IV pain management requirements\n• Inhalation injury observation (even soft signs)\n• Circumferential burns requiring serial neurovascular checks\n• Social concerns (suspected NAT, inability to manage outpatient care)\n• Extremes of age with moderate burns\n\n**Inpatient orders:**\n• Fluid resuscitation protocol with q1h UOP documentation\n• Serial neurovascular checks for circumferential burns\n• Wound care: daily dressing changes with antimicrobial agent\n• Pain regimen: scheduled NSAID + acetaminophen, PRN opioid\n• Surgical consult for deep partial/full thickness burns\n• Nutrition consult — burn patients are hypermetabolic (may need 2-3× baseline caloric intake)\n• Occupational/physical therapy for burns involving joints or hands\n• DVT prophylaxis\n• Stress ulcer prophylaxis for severe burns' WHERE id = 'burn-admit-result' AND tree_id = 'burns';
UPDATE decision_nodes SET body = E'**Appropriate for superficial or small partial-thickness burns <5% TBSA** in patients with reliable follow-up, adequate social support, and ability to perform dressing changes.\n\n**Discharge criteria:**\n• Pain controlled with oral medications\n• Patient/family demonstrates ability to perform dressing changes\n• No signs of inhalation injury\n• No circumferential burns\n• No concern for NAT\n• Adequate follow-up arranged\n\n**Discharge instructions:**\n• **Daily dressing changes:** Gentle wash with soap and water, apply bacitracin ointment, cover with nonadherent dressing and gauze wrap\n• **Keep burned area elevated** above heart level when possible\n• **Pain management:** Ibuprofen 400-800mg q6-8h + acetaminophen 1000mg q6-8h around the clock for first 48-72h\n• **Avoid sun exposure** on healing burns for 12 months (permanent hyperpigmentation)\n\n**Return precautions:**\n• Increasing pain, redness, or swelling around the burn\n• Purulent drainage or foul odor\n• Fever >100.4°F (38°C)\n• Burn appearance worsening (deepening)\n• Inability to manage pain at home\n\n**Follow-up:** 24-48 hours for wound reassessment. Earlier if concern for deepening. Tetanus update if >5 years or unknown.\n\n[Discharge Instructions](#/info/burns-discharge) — shareable patient handout' WHERE id = 'burn-discharge-result' AND tree_id = 'burns';

-- === chest-tube (40 nodes) ===
UPDATE decision_nodes SET body = E'This consult covers pneumothorax management and chest tube thoracostomy — from indications through insertion technique and post-procedure care.\n\nChest tubes were once a bedrock procedure for EM, resuscitation, and critical care. They are becoming increasingly unnecessary as evidence supports conservative management in many scenarios previously considered automatic indications.\n\nKEY EVIDENCE SHIFTING PRACTICE\n• Traumatic PTX: observation safe for <35 mm on CT in stable patients not on positive pressure ventilation [3]\n• Spontaneous PTX: conservative management non-inferior to intervention for moderate PSP (Brown et al, NEJM 2020) [1]\n• Occult PTX on ventilator: selective observation supported (OPTICC trial) [4]\n• Hemothorax: pigtail catheters comparable to large-bore in select cases (PCAT trial) [5]\n• Empyema: small-bore tubes have similar outcomes to large-bore [7]\n\nFor ultrasound diagnosis of pneumothorax, see [Pneumothorax POCUS](#/tree/pneumothorax).' WHERE id = 'ctube-start' AND tree_id = 'chest-tube';
UPDATE decision_nodes SET body = E'Clinical diagnosis — do NOT delay for imaging.\n\nSigns: hypotension, tachycardia, JVD, tracheal deviation (late sign), absent breath sounds, decreased SpO2, obstructive shock.\n\nNEEDLE DECOMPRESSION (temporizing)\n• 14-16 gauge angiocatheter\n• 2nd intercostal space, midclavicular line (traditional) OR 4th-5th intercostal space, anterior axillary line (preferred — thinner chest wall, higher success rate)\n• Insert perpendicular over superior rib edge\n• Rush of air confirms tension\n• Leave catheter in place\n\nFINGER THORACOSTOMY (more reliable)\n• Same site as chest tube (5th ICS, mid-axillary line, triangle of safety)\n• Blunt dissection into pleural space with finger sweep\n• Provides more reliable decompression than needle\n\nProceed immediately to definitive chest tube placement.' WHERE id = 'ctube-tension' AND tree_id = 'chest-tube';
UPDATE decision_nodes SET body = E'Evidence supports observation for small traumatic pneumothoraces in stable patients. Can observe <35 mm on CT scan in patients not requiring positive pressure ventilation [3].\n\nFor occult pneumothorax (visible on CT but not CXR) in mechanically ventilated patients, the OPTICC trial demonstrated that selective observation is safe, though close monitoring is required [4].' WHERE id = 'ctube-traumatic' AND tree_id = 'chest-tube';
UPDATE decision_nodes SET body = E'Positive pressure ventilation increases risk of tension physiology. The OPTICC trial supports selective observation of small occult pneumothoraces even on ventilator, but close monitoring is essential.\n\nConsider: size of pneumothorax, ventilator settings (high PEEP increases risk), clinical trajectory, ability to monitor closely.' WHERE id = 'ctube-ventilator' AND tree_id = 'chest-tube';
UPDATE decision_nodes SET body = E'Conservative management is increasingly favored for PSP.\n\nKEY EVIDENCE\n• Brown et al (NEJM 2020): Conservative management non-inferior to interventional treatment for moderate-sized first-episode PSP. At 8 weeks, 98.5% resolution without intervention [1].\n• BTS/ERS guidelines support aspiration as first-line for symptomatic PSP before chest tube [20].\n• Ambulatory management with Heimlich valve feasible for selected patients [20].' WHERE id = 'ctube-psp' AND tree_id = 'chest-tube';
UPDATE decision_nodes SET body = E'NEEDLE ASPIRATION — first-line for symptomatic PSP per BTS/ERS guidelines.\n\nPROCEDURE\n1. Position: sitting upright or supine with head elevated 45°\n2. Site: 2nd intercostal space, midclavicular line (preferred) or safe triangle\n3. Prep, drape, local anesthesia with 1% lidocaine\n4. Insert 16-18 gauge IV catheter over superior rib edge\n5. Connect to 3-way stopcock + 60 mL syringe\n6. Aspirate until resistance (lung re-expansion) or 2.5 L aspirated\n7. Post-aspiration CXR\n\nSuccess = lung re-expansion + symptom improvement.' WHERE id = 'ctube-aspiration' AND tree_id = 'chest-tube';
UPDATE decision_nodes SET body = E'Chest tube indicated for hemothorax. The PCAT trial demonstrated pigtail catheters may be comparable to large-bore tubes in select cases, but large-bore (28-36 Fr) remains standard for traumatic hemothorax to ensure adequate drainage of blood and clot.\n\nTube size: 28 Fr minimum for hemothorax. 28-36 Fr recommended.' WHERE id = 'ctube-hemothorax' AND tree_id = 'chest-tube';
UPDATE decision_nodes SET body = E'Chest tube indicated for empyema/parapneumonic effusion requiring drainage. Small-bore tubes (10-14 Fr) have similar clinical outcomes to large-bore for pleural infection drainage (Rahman et al). BTS Pleural Disease Guideline 2010 supports image-guided small-bore catheter as first-line.\n\nIf loculated: consider intrapleural fibrinolytics (tPA + DNase) or VATS.' WHERE id = 'ctube-empyema' AND tree_id = 'chest-tube';
UPDATE decision_nodes SET body = E'THE TRIANGLE OF SAFETY\nThe safe zone for chest tube insertion is bounded by:\n• Anterior: lateral edge of pectoralis major\n• Posterior: anterior border of latissimus dorsi\n• Inferior: line of the 5th intercostal space (nipple level in males)\n• Superior: base of the axilla\n\nINSERTION SITE\n4th or 5th intercostal space, mid-axillary line (within the safe triangle).\n\nMID-ARM POINT (MAP) TECHNIQUE\nAn alternative landmark: the point on the chest wall at the level of the mid-arm when the arm is adducted identifies a safe insertion site within the triangle of safety [9].\n\nNEUROVASCULAR BUNDLE\nThe intercostal neurovascular bundle classically runs along the inferior rib edge — but anatomic studies show it can run aberrantly within the interspace. Always insert over the SUPERIOR edge of the rib to minimize risk, but be aware the bundle position is variable.\n\nAVOID\n• Below 6th ICS (risk of intra-abdominal placement — liver on right, spleen on left)\n• Posterior to mid-axillary line (latissimus dorsi makes dissection difficult)\n• Too medial (internal mammary artery)\n\nANTICOAGULATION\nChest tube insertion is probably safe in anticoagulated patients [10].' WHERE id = 'ctube-anatomy' AND tree_id = 'chest-tube';
UPDATE decision_nodes SET body = E'Select tube size based on indication.\n\nPNEUMOTHORAX (air only):\n• Small-bore pigtail catheter: 10-14 Fr (Seldinger technique)\n• Standard: 20-24 Fr\n\nHEMOTHORAX / HEMOPNEUMOTHORAX:\n• Large-bore: 28-36 Fr (28 Fr minimum for blood drainage)\n\nEMPYEMA:\n• Small-bore (10-14 Fr) with image guidance — similar outcomes to large-bore [7]\n\nSmall-bore pigtail catheters have equivalent outcomes to large-bore for simple pneumothorax with less pain and fewer complications.' WHERE id = 'ctube-tube-size' AND tree_id = 'chest-tube';
UPDATE decision_nodes SET body = E'Small-bore pigtail catheters (10-14 Fr) placed via modified Seldinger technique (e.g., Thal-Quik).\n\nADVANTAGES\n• Less pain on insertion and while indwelling\n• Equivalent efficacy for simple pneumothorax\n• Faster insertion\n• Lower complication rate\n\nPROCEDURE\n1. Position, prep, drape (same landmarks as standard)\n2. Local anesthesia to skin, subcutaneous tissue, periosteum, parietal pleura\n3. Small skin incision (just enough for catheter)\n4. Insert introducing needle with syringe attached\n5. Aspirate as you advance — rush of air confirms pleural space entry\n6. Advance guidewire through needle, remove needle\n7. Dilate tract over guidewire\n8. Thread pigtail catheter over guidewire into pleural space\n9. Remove guidewire, confirm pigtail is curled\n10. Connect to drainage system (water seal or Heimlich valve)\n11. Secure with suture and occlusive dressing\n12. Confirm placement with CXR\n\nNOT appropriate for: hemothorax, empyema with thick fluid, or bronchopleural fistula.' WHERE id = 'ctube-pigtail' AND tree_id = 'chest-tube';
UPDATE decision_nodes SET body = E'EQUIPMENT FOR TUBE THORACOSTOMY\n\nSet up on a large surface — not a mayo stand.\n\nSTERILE SUPPLIES\n• Chest tube (selected size)\n• Scalpel (#10 blade)\n• Large curved Kelly clamp\n• Needle driver and pickups with teeth\n• Size 2 Ethibond suture or 0-silk\n• Sterile chlorhexidine prep and drapes\n• Sterile gloves + gown\n\nANESTHESIA\n• 30 mL bottle of 2% lidocaine with epinephrine\n• 20 mL syringe with draw needle\n• 22-gauge 1.5" needle for injection\n\nDRAINAGE\n• Pleur-Evac or equivalent closed drainage system (prepared and ready)\n\nOTHER\n• Soft restraint (for arm positioning)\n• Roll of 2-3" cloth or silk tape\n• 2 medium Tegaderms\n• Multiple 4x4 gauze pads' WHERE id = 'ctube-equipment' AND tree_id = 'chest-tube';
UPDATE decision_nodes SET body = E'POSITIONING\n• Bring patient to the edge of the bed (ipsilateral side)\n• Incision site near the level of the xiphoid process\n• Ipsilateral arm up: restrain or have patient place hand behind head (exposes axilla and triangle of safety)\n• Sit up to 45° if possible (supine acceptable for unstable patients)\n\nPREP AND DRAPE\n• Wide prep with chlorhexidine\n• Drape to maintain visibility of landmarks after sterile field is established — confirm you can still see your landmarks after draping\n• Account for breast tissue in female patients — it may shift the apparent landmarks' WHERE id = 'ctube-positioning' AND tree_id = 'chest-tube';
UPDATE decision_nodes SET body = E'LOCAL ANESTHESIA — FIELD BLOCK\nInadequate anesthesia is the most common reason for procedural difficulty.\n\nTECHNIQUE\n1. Skin wheal: 22-gauge needle, raise a wheal at the incision site with 2% lidocaine with epinephrine\n2. Subcutaneous tissue: infiltrate generously along the planned dissection tract\n3. Intercostal muscles: fan lidocaine through the muscle layers\n4. Periosteum: anesthetize the rib periosteum above AND below — this is extremely painful if missed\n5. Parietal pleura: advance needle over the superior rib edge while aspirating. When air is aspirated (confirming pleural space), inject 5-10 mL along the parietal pleura — this is the most sensitive layer\n\nTotal: up to 30 mL of 2% lidocaine with epinephrine (max 7 mg/kg with epi).\n\nPROCEDURAL SEDATION\nConsider sedation (ketamine, propofol, etomidate) for awake patients if clinical situation allows.' WHERE id = 'ctube-anesthesia' AND tree_id = 'chest-tube';
UPDATE decision_nodes SET body = E'PPE\n• Double glove\n• Face and eye protection\n• Hat and gown if available (always for non-emergent cases)\n\nMENTAL PREPARATION\n• Pause. Breathe.\n• Visualize each step before beginning. If you cannot visualize it, review the steps before proceeding.\n• This is a controlled procedure — deliberate technique prevents complications.' WHERE id = 'ctube-ppe' AND tree_id = 'chest-tube';
UPDATE decision_nodes SET body = E'SCALPEL TECHNIQUE\n• Hold scalpel like a pencil for control\n• Make a 3-4 cm transverse incision through the skin\n\nKEY POINTS\n• Make the skin incision ONE intercostal space BELOW the intended pleural entry point. This creates a subcutaneous tunnel that reduces air leak after tube removal.\n• In female patients, account for breast tissue — it may shift the apparent intercostal space.\n• In obese patients, a longer incision may be needed to reach the chest wall. Anticipate a deeper dissection tract.' WHERE id = 'ctube-cut' AND tree_id = 'chest-tube';
UPDATE decision_nodes SET body = E'TECHNIQUE: PUSH IN, SPREAD, CHECK\n\nUsing the curved Kelly clamp:\n1. Dissect through subcutaneous tissue toward the superior edge of the rib ONE space above the skin incision\n2. Advance the CLOSED clamp through the intercostal muscles directly over the top of the rib\n3. Stay ABOVE the rib to avoid the neurovascular bundle (though it runs variably)\n4. Push through the parietal pleura with controlled force — you will feel a distinct pop\n5. Open the clamp widely to create the tract\n6. Rush of air or fluid confirms entry into the pleural space' WHERE id = 'ctube-dissection' AND tree_id = 'chest-tube';
UPDATE decision_nodes SET body = E'FINGER SWEEP\nInsert a gloved finger through the tract into the pleural space. Sweep gently to confirm:\n1. You are in the pleural space (not subcutaneous, not subdiaphragmatic)\n2. No adhesions that would impede tube passage\n3. No organs palpable (lung, diaphragm, liver/spleen)\n\nRIB FRACTURES = DANGER\nIn trauma patients with rib fractures at the insertion site, fractured rib edges can lacerate the finger or impede safe dissection. Exercise extreme caution. Consider an adjacent interspace if needed.' WHERE id = 'ctube-finger-sweep' AND tree_id = 'chest-tube';
UPDATE decision_nodes SET body = E'DO NOT USE TROCARS — EVER.\nTrocar insertion has an unacceptable rate of visceral injury. All chest tubes should be placed by blunt dissection.\n\nTUBE PREPARATION\n1. Place two clamps on the tube\n2. Cut the distal end at a slant (if not pre-cut)\n\nINSERTION\n• Clamp the tube tip with Kelly clamp OR guide with finger (with or without finger guidance — both are acceptable)\n• Direct the tube POSTERIORLY and APICALLY for pneumothorax (air rises anteriorly)\n• Direct POSTERIORLY and INFERIORLY for hemothorax (fluid layers dependently)\n• Advance until the last hole (proximal/sentinel hole) is well inside the chest wall\n• Chest tube depth is marked from the proximal hole — note insertion depth at the skin\n\nANGLE MATTERS\nIncreased angle of insertion (perpendicular to chest wall rather than tangential) is associated with higher complication rates [18]. Aim for a tangential trajectory along the chest wall.\n\nBOUGIE OR TUBE EXCHANGER\nCan be used to guide tube insertion through a difficult tract.' WHERE id = 'ctube-tube-insert' AND tree_id = 'chest-tube';
UPDATE decision_nodes SET body = E'CHECK PLEURAL ENTRY\n• Re-insert finger alongside tube to confirm the tube is in the pleural space\n\nMAC SPIN TEST FOR KINKING\nGrasp the external portion of the tube and rotate clockwise 180°, then release [19]:\n• If the tube spins back to its previous position → the tube is kinked (reposition)\n• If it stays in the new position → the tube is NOT kinked (proceed)\n\nINITIAL SIGNS OF FUNCTION\n• Respiratory swing (tidaling) in the tubing\n• Fogging of the tube with respiration\n• Air or fluid drainage' WHERE id = 'ctube-confirm' AND tree_id = 'chest-tube';
UPDATE decision_nodes SET body = E'SUTURE\n• Use a large horizontal mattress suture (size 2 Ethibond or 0-silk) through the skin adjacent to the tube\n• Tie securely, leaving long tails\n• Wrap the tails around the tube and tie again (Roman sandal / mesentery technique)\n• Place a separate drain stitch (stay suture) for wound closure after tube removal\n\nDRESSING\n• Petroleum gauze around the tube at the skin entry (air-tight seal)\n• Cover with 4x4 gauze pads\n• Secure with 2-3" silk/cloth tape\n• Apply Tegaderms over the dressing edges\n• Write date, time, and insertion depth on the dressing with marker\n\nCONNECT DRAINAGE\n• Connect to Pleur-Evac or equivalent closed drainage system\n• Ensure all connections are tight\n• Verify air and/or fluid drainage\n• Never clamp a functioning chest tube without explicit attending instruction' WHERE id = 'ctube-secure' AND tree_id = 'chest-tube';
UPDATE decision_nodes SET body = E'Obtain a STAT portable CXR after chest tube placement to confirm:\n• Tube position (all holes intrathoracic, tip directed appropriately)\n• Lung re-expansion\n• No malposition, kinking, or new complication\n\nTube resting location (anteroapical vs posterolateral) does NOT matter — function, not trajectory, dictates need for reintervention [11, 13]. AIS (injury severity) is the only significant independent factor in chest tube complications [12].' WHERE id = 'ctube-post-cxr' AND tree_id = 'chest-tube';
UPDATE decision_nodes SET body = E'Chest tube malposition on CXR.\n\nCommon issues:\n• Tube advanced too far (tip in mediastinum or kinked)\n• Sentinel hole outside chest wall (subcutaneous air leak)\n• Tube in the fissure (may still function)\n• Too shallow insertion\n\nIMPORTANT: Never advance a tube that has already been placed — risk of introducing infection. A tube that is too deep can be pulled back under sterile technique. If the tube is too shallow, place a new tube rather than pushing the existing one in.' WHERE id = 'ctube-malposition' AND tree_id = 'chest-tube';
UPDATE decision_nodes SET body = E'MASSIVE HEMOTHORAX\n\nCriteria for emergent thoracotomy:\n• Initial drainage >1500 mL, OR\n• >200 mL/hr for 2-4 consecutive hours\n\nAUTOTRANSFUSION\nBlood from the chest cavity lacks clotting factors and has a slightly lower hematocrit than venous blood, but autotransfusion of hemothorax blood is safe and effective in trauma [14].' WHERE id = 'ctube-massive-hemothorax' AND tree_id = 'chest-tube';
UPDATE decision_nodes SET body = E'CHEST TUBE DRAINAGE SYSTEMS — 3-BOTTLE CONCEPT\n\nAll modern drainage units (Pleur-Evac, Atrium) are based on the classic 3-bottle system:\n1. Collection chamber: measures fluid output\n2. Water seal chamber: one-way valve — allows air out, prevents re-entry. Fluid level at 2 cm.\n3. Suction regulation chamber: controls negative pressure (typically -20 cmH2O when used)\n\nRECOMMENDED SYSTEM\nGetinge Atrium Express — features negative pressure relief valve, no evaporation of water seal/suction fluid, and is safe and functional if knocked over.\n\nMONITORING\nMark the collection chamber with date, time, and output level using a marker directly on the device at each assessment.' WHERE id = 'ctube-drainage' AND tree_id = 'chest-tube';
UPDATE decision_nodes SET body = E'SUCTION IS NOT ROUTINELY NECESSARY\n\n• You do not need suction for initial management, CT transport, or patient transfer\n• Suction should be reserved for: failure of lung re-expansion on water seal, persistent large air leak, or specific clinical situations\n• When used: low-pressure suction, typically -20 cmH2O\n\nBY INDICATION\n• Primary spontaneous PTX: water seal or Heimlich valve first. Suction only if lung fails to re-expand [1, 20]\n• Traumatic PTX: low-pressure suction may reduce hospital stay and tube duration. Especially important if patient is on positive pressure ventilation [21]\n• Secondary spontaneous PTX: evidence limited, clinical judgment\n\nSWITCHING OUT SYSTEMS\nShould be able to swap to a new Pleur-Evac at the level of the drainage system connection without losing the tube.' WHERE id = 'ctube-suction' AND tree_id = 'chest-tube';
UPDATE decision_nodes SET body = E'AIR LEAK QUANTIFICATION\nThe water seal chamber has graded markings to quantify the size of an air leak.\n\nCHECK FOR TIDALING\nTurn off suction and observe if the water column (or ball indicator) moves up and down with respiration. Tidaling = patent tube with communication to the pleural space. Absent tidaling = tube may be blocked, kinked, or lung fully expanded.\n\nTESTING FOR AIR LEAK\n1. Clamp the suction tubing (disconnect from vacuum)\n2. Ask the patient to cough (generates negative intrathoracic pressure)\n3. Release and observe the water seal chamber\n4. Bubbles = active air leak\n\nTROUBLESHOOTING\n• If air leak is at the system rather than the lung: clamp or kink tube at the chest wall — if bubbling stops, the leak is in the external system; if it continues, the leak is pulmonary\n• Check all connections for loose fittings\n\nDO NOT STRIP THE CHEST TUBE\nStripping (milking) generates excessive negative pressure (-300 to -400 cmH2O) and can cause lung injury. There is no evidence it improves drainage.\n\nDO NOT CLAMP the chest tube without explicit instruction from the primary team. Clamping a tube with an ongoing air leak risks tension pneumothorax.' WHERE id = 'ctube-air-leak' AND tree_id = 'chest-tube';
UPDATE decision_nodes SET body = E'PROPHYLACTIC ANTIBIOTICS\nProbably beneficial for trauma thoracostomies. The EAST 2022 practice management guideline conditionally recommends antibiotic prophylaxis for tube thoracostomy placed for trauma [17].\n\nNot routinely indicated for non-traumatic chest tubes.\n\nONGOING MANAGEMENT\n• Record output (volume, color, character) each nursing shift\n• Monitor for signs of infection at insertion site\n• Chest tube site care: keep dressing clean and dry, change if soiled\n• Daily reassessment: air leak, tidaling, output trend, CXR as indicated' WHERE id = 'ctube-antibiotics' AND tree_id = 'chest-tube';
UPDATE decision_nodes SET body = E'CRITERIA FOR CHEST TUBE REMOVAL — all must be met:\n1. Lung fully re-expanded on CXR\n2. No air leak (no bubbling in water seal)\n3. Fluid output <100 mL/day\n4. Patient clinically stable\n\nWATER SEAL TRIAL\n• Place tube to water seal (disconnect suction) for a trial period\n• A normal CXR obtained 3 hours after placing on water seal effectively excludes development of a clinically significant pneumothorax [16]\n• If lung remains expanded and no air leak recurs: proceed to removal\n\nTIMING\nNo significant difference in recurrence of pneumothorax based on respiratory cycle timing of removal (end-expiration vs end-inspiration) [15]. One small study showed no difference.' WHERE id = 'ctube-removal-criteria' AND tree_id = 'chest-tube';
UPDATE decision_nodes SET body = E'REMOVAL PROCEDURE\n1. Pre-medicate with analgesia\n2. Remove dressing and cut securing suture (leave stay suture intact)\n3. Have petroleum gauze ready at bedside\n4. Instruct patient: take a deep breath and bear down (Valsalva) — creates positive intrathoracic pressure, preventing air entry\n5. Pull tube out in one smooth, swift motion\n6. IMMEDIATELY apply petroleum gauze + occlusive dressing\n7. Close the stay suture\n8. Obtain CXR 1-2 hours post-removal' WHERE id = 'ctube-removal' AND tree_id = 'chest-tube';
UPDATE decision_nodes SET body = E'AFTER SUCCESSFUL TUBE REMOVAL\n• Confirm lung remains expanded on post-removal CXR\n• If recurrent pneumothorax on post-removal film: small and asymptomatic may observe; large or symptomatic requires new tube\n\nDISCHARGE PLANNING\n• Wound care: keep dressing clean and dry, remove in 48 hours\n• Activity: avoid heavy lifting or straining for 1-2 weeks\n• No air travel until confirmed resolution (minimum 2 weeks post)\n• No scuba diving until pulmonology clearance\n• Smoking cessation counseling\n\nRECURRENCE\n• PSP: ~30% at 1 year, ~50% lifetime\n• SSP: ~40-50% recurrence\n• After 2nd ipsilateral episode: strongly recommend pleurodesis (VATS with mechanical pleurodesis or stapled bullectomy)\n\nFOLLOW-UP\n• Outpatient CXR in 2-4 weeks\n• Pulmonology referral for: SSP, recurrent PSP, pleurodesis discussion\n\n[Discharge Instructions](#/info/chest-tube-discharge) — shareable patient handout' WHERE id = 'ctube-disposition' AND tree_id = 'chest-tube';

-- === croup (13 nodes) ===
UPDATE decision_nodes SET body = E'**Croup (laryngotracheobronchitis)** is a parainfluenza viral infection causing subglottic inflammation.\n\n**Classic presentation:**\n• Barking "seal-like" cough\n• Inspiratory stridor\n• Hoarseness\n• Low-grade fever\n• URI prodrome (1-3 days)\n\n**Epidemiology:** 3% of children aged 6 months to 3 years. Peak incidence 1-2 years. Male:female 1.4:1. Most common in fall/winter.\n\n**Most cases are mild and self-limited** — only 1-8% require hospitalization, <3% of admitted patients require intubation.' WHERE id = 'croup-start' AND tree_id = 'croup';
UPDATE decision_nodes SET body = E'Classify croup severity based on clinical findings. The **Westley Croup Score** guides management.\n\nAssess: stridor, retractions, air entry, cyanosis, and level of consciousness.\n\n**Key distinction:** Stridor at rest vs. only with agitation determines the threshold for epinephrine.' WHERE id = 'croup-severity' AND tree_id = 'croup';
UPDATE decision_nodes SET body = E'**Single dose glucocorticoid is standard of care for ALL severities of croup.**\n\n**First-line:**\n• [Dexamethasone](#/drug/dexamethasone) **0.6 mg/kg PO** (max 16 mg) — single dose\n\n**Non-inferior alternatives:**\n• [Dexamethasone](#/drug/dexamethasone) **0.15 mg/kg PO** — lower dose equally effective [3][6]\n• [Prednisolone](#/drug/prednisolone) **1 mg/kg PO** — non-inferior for symptom relief and 7-day outcomes [6]\n\n**If unable to tolerate oral:**\n• [Budesonide](#/drug/budesonide-neb) **2 mg nebulized** — effective alternative [5][9]\n• [Dexamethasone](#/drug/dexamethasone) **0.6 mg/kg IM**\n\n**NNT = 7** to prevent one return visit. Reduces return visits/readmissions by ~50%. Safe single-dose profile.' WHERE id = 'croup-mild-tx' AND tree_id = 'croup';
UPDATE decision_nodes SET body = E'**Step 1: Glucocorticoid**\n• [Dexamethasone](#/drug/dexamethasone) **0.6 mg/kg PO/IM** (max 16 mg) — single dose\n\n**Step 2: Nebulized Epinephrine**\n• [Racemic Epinephrine](#/drug/racemic-epinephrine) **0.5 mL of 2.25%** in 4.5 mL normal saline\n• OR L-epinephrine **0.5 mL/kg of 1:1000** (max 5 mL) nebulized\n\nEpinephrine provides rapid but **temporary** relief (onset minutes, duration 1-2 hours). Must observe minimum 2 hours after administration.\n\n**Keep child calm** — agitation worsens airway obstruction.' WHERE id = 'croup-mod-tx' AND tree_id = 'croup';
UPDATE decision_nodes SET body = E'**Step 1: Glucocorticoid**\n• [Dexamethasone](#/drug/dexamethasone) **0.6 mg/kg PO/IM** (max 16 mg) — single dose\n\n**Step 2: Nebulized Epinephrine**\n• [Racemic Epinephrine](#/drug/racemic-epinephrine) **0.5 mL of 2.25%** in 4.5 mL NS\n• OR L-epinephrine **0.5 mL/kg of 1:1000** (max 5 mL) neb\n• **May repeat epinephrine** — repeated doses can prevent intubation in many cases [4]\n\n**Additional considerations:**\n• Heliox (70:30 He:O₂) — may provide short-term benefit when combined with dex, but limited evidence [11]\n• Continuous monitoring with pulse oximetry\n• **Minimize interventions that cause agitation** — crying worsens obstruction\n• Have airway equipment at bedside' WHERE id = 'croup-severe-tx' AND tree_id = 'croup';
UPDATE decision_nodes SET body = E'**This is a clinical emergency — activate airway team.**\n\n**Immediate interventions:**\n• [Dexamethasone](#/drug/dexamethasone) **0.6 mg/kg IM** (if not already given)\n• [Racemic Epinephrine](#/drug/racemic-epinephrine) nebulized — may repeat\n• **Blow-by oxygen** — do NOT agitate the child\n• **Call anesthesia/ENT for airway backup**\n\n**Airway management:**\n• Use endotracheal tube **0.5-1.0 size smaller** than age-predicted (subglottic narrowing)\n• Oral intubation preferred — may need smaller tube than expected\n• Have surgical airway equipment available\n\n**Rule out alternative diagnoses:** bacterial tracheitis, epiglottitis, foreign body, peritonsillar abscess.' WHERE id = 'croup-failure-tx' AND tree_id = 'croup';
UPDATE decision_nodes SET body = E'Observe for **1-2 hours** after dexamethasone administration.\n\nMost children start feeling better within **2-3 hours** of steroid treatment. Dexamethasone has a long half-life (~36 hours) — single dose provides sustained benefit.\n\nReassess: stridor, retractions, work of breathing, ability to take fluids.' WHERE id = 'croup-mild-obs' AND tree_id = 'croup';
UPDATE decision_nodes SET body = E'**Observe minimum 2 hours after last nebulized epinephrine dose.**\n\nEpinephrine benefits are transient — symptoms may recur as effect wears off (rebound).\n\nMonitor for: return of stridor at rest, worsening retractions, tachycardia, respiratory fatigue.\n\n**Cold air exposure** (30 min outdoors at <10°C) may provide additional benefit if available — one RCT showed improvement in mild-moderate croup. [10]' WHERE id = 'croup-epi-obs' AND tree_id = 'croup';
UPDATE decision_nodes SET body = E'**Repeat nebulized epinephrine** at same dose:\n• [Racemic Epinephrine](#/drug/racemic-epinephrine) **0.5 mL of 2.25%** in 4.5 mL NS\n• OR L-epinephrine **0.5 mL/kg of 1:1000** (max 5 mL) neb\n\n**Repeated doses may prevent intubation** in many cases. [4]\n\nRestart 2-hour observation clock after each dose.\n\n**Escalation considerations:**\n• Multiple doses of epinephrine → strong indicator for admission\n• If requiring >2 doses → consider ICU level monitoring\n• **Failure to improve with dexamethasone + epinephrine** → consider alternative diagnoses (bacterial tracheitis, foreign body)' WHERE id = 'croup-repeat-epi' AND tree_id = 'croup';
UPDATE decision_nodes SET body = E'Reassess after **2 hours** from last epinephrine dose.\n\nChildren requiring multiple doses of nebulized epinephrine have a higher likelihood of needing admission.' WHERE id = 'croup-re-obs' AND tree_id = 'croup';
UPDATE decision_nodes SET body = E'**Discharge criteria:**\n• No stridor at rest for ≥2 hours after last epinephrine\n• Tolerating oral fluids\n• Comfortable, not in distress\n• Reliable caregiver with access to emergency care\n\n**Parent education:**\n• Symptoms are often **worse at night** — warn parents\n• Barking cough typically lasts 1-2 days, may continue up to 5-7 days\n• Keep child calm — agitation worsens symptoms\n• Acetaminophen/ibuprofen for fever and comfort\n• **Humidified air and cool mist lack evidence of benefit** [2][9]\n\n[Croup: When to Return to the ED](#/info/croup-return-precautions) — shareable parent handout\n\n**No additional steroid doses needed** — single dose of dexamethasone provides sustained benefit (half-life ~36 hours).' WHERE id = 'croup-discharge' AND tree_id = 'croup';
UPDATE decision_nodes SET body = E'**Admission criteria:**\n• Persistent stridor at rest despite dexamethasone + epinephrine\n• Requiring multiple doses of nebulized epinephrine\n• Significant respiratory distress\n• Unable to tolerate oral fluids\n• Young infant (<6 months) with moderate-severe croup\n• Unreliable follow-up or social concerns\n\n**Inpatient management:**\n• Continuous pulse oximetry\n• PRN nebulized epinephrine\n• Minimize agitation — keep parent at bedside\n• Reassess for alternative diagnoses if not improving: **bacterial tracheitis** (progressive toxicity, purulent secretions, radiographic findings) [4]\n• **Antibiotics only for suspected bacterial complications** — not routine for croup' WHERE id = 'croup-admit' AND tree_id = 'croup';
UPDATE decision_nodes SET body = E'**ICU admission criteria:**\n• Impending or actual respiratory failure\n• Requiring intubation\n• Severe croup unresponsive to maximal medical therapy\n\n**Intubation pearls:**\n• Use ETT **0.5-1.0 size smaller** than age-predicted\n• Oral intubation preferred\n• Have multiple smaller tube sizes available\n• ENT/anesthesia at bedside for surgical airway backup\n\n**Post-intubation:**\n• Continue dexamethasone 0.6 mg/kg q6-12h (consider for extubation facilitation)\n• Sedation to prevent self-extubation\n• Plan extubation with leak test after 24-72 hours\n\n**<3% of hospitalized croup patients require intubation** — this is rare.' WHERE id = 'croup-icu' AND tree_id = 'croup';

-- === diarrhea (24 nodes) ===
UPDATE decision_nodes SET body = E'[Acute Diarrhea Steps Summary](#/info/diarrhea-summary)\n\nEmergency evaluation of acute diarrhea — identifying serious illness and guiding treatment.\n\nDiarrhea is a change in bowel movements characterized by increased water content, volume, or frequency (>200 g/day or >3 stools/day). Most cases are self-limited, but **serious disease processes can present with diarrhea as the chief complaint**.\n\n**Definitions:**\n• **Acute** — ≤14 days\n• **Persistent** — 14-30 days\n• **Chronic** — >30 days\n\n**Classification:**\n• **Secretory** — abnormal electrolyte transport, does NOT stop with fasting (e.g., cholera)\n• **Osmotic** — non-absorbable solute, stops with fasting (e.g., sorbitol)\n• **Inflammatory** — bloody, fever, cramps (invasive bacteria, IBD)\n• **Non-inflammatory** — watery, nausea, vomiting (viral, toxin-mediated)' WHERE id = 'diarrhea-start' AND tree_id = 'diarrhea';
UPDATE decision_nodes SET body = E'**Immediate interventions:**\n• **ABCs** — secure airway if altered mental status\n• **2 large-bore IVs** — NS or LR bolus 20 mL/kg\n• **Cardiac monitor** — assess for arrhythmia from electrolyte derangement\n• **POC glucose** — hypoglycemia common in pediatric patients\n\n**Assess for sepsis:**\n• Fever + tachycardia + hypotension → septic diarrhea until proven otherwise\n• **Lactate**, **blood cultures** if sepsis suspected\n• Broad-spectrum antibiotics per sepsis protocol if indicated\n\n**Labs:** CBC, BMP (electrolytes, renal function, glucose), lactate, blood cultures, type & screen if severe anemia suspected\n\nOnce stabilized, proceed with targeted history.' WHERE id = 'diarrhea-resuscitate' AND tree_id = 'diarrhea';
UPDATE decision_nodes SET body = E'**Key history elements:**\n• **Stool character:** frequency, volume, blood, mucus, melena (patients may not recognize black stool as blood — ask specifically)\n• **Duration:** <48h likely viral; >48h raises suspicion for bacterial cause\n• **Associated symptoms:** nausea/vomiting (suggests viral), fever >38.5°C (suggests invasive bacteria), tenesmus\n• **Travel:** recent foreign travel, lake/stream exposure\n• **Diet:** raw/undercooked meat, seafood, eggs, unpasteurized milk/juice\n• **Medications:** antibiotics in past 3 months (C. difficile risk), laxatives, antacids, new medications\n• **Contacts:** ill contacts, day care, nursing home, food handlers\n• **PMH:** immunocompromised (HIV, transplant, chemo), IBD, diabetes\n\n**Red flags:**\n• Severe dehydration or hemodynamic instability\n• Bloody diarrhea or dysentery\n• Fever >38.5°C (101.3°F) with systemic illness\n• Immunocompromised patient\n• Severe abdominal pain (concern for surgical etiology)\n• Elderly with comorbidities\n• Neurologic involvement (paresthesias, weakness)' WHERE id = 'diarrhea-history' AND tree_id = 'diarrhea';
UPDATE decision_nodes SET body = E'**Differential diagnosis:**\n• **Shigella** — fever, bloody mucoid stool, tenesmus\n• **Salmonella** — fever, cramping, may be bloody\n• **Campylobacter** — fever, headache, bloody diarrhea 2-5 days after exposure\n• **E. coli O157:H7 (EHEC/STEC)** — bloody diarrhea, often afebrile, undercooked beef or unpasteurized products\n• **C. difficile** — recent antibiotic use, can be bloody\n• **IBD** — chronic/recurrent, family history\n• **Ischemic colitis** — elderly, vascular disease, severe pain\n\n[Differential Diagnosis Pitfalls](#/info/diarrhea-ddx-pitfalls)\n\n⚠️ **CRITICAL — Shiga toxin-producing E. coli (STEC):**\n• Do **NOT** give antibiotics if STEC suspected — increases risk of **hemolytic uremic syndrome (HUS)**\n• Do **NOT** give antimotility agents — delays pathogen clearance\n• Suspect STEC: bloody diarrhea + afebrile + history of undercooked beef or unpasteurized products\n\n**Mandatory workup:** stool culture, CBC with platelets (screen for HUS), BMP' WHERE id = 'diarrhea-bloody' AND tree_id = 'diarrhea';
UPDATE decision_nodes SET body = E'Temperature **>38.5°C (101.3°F)** usually indicates intestinal inflammation from **invasive bacteria** (Shigella, Salmonella, Campylobacter) or toxin-producing organisms (C. difficile, Entamoeba histolytica).\n\n**Workup:**\n• **Fecal leukocytes or fecal lactoferrin** — screens for inflammatory diarrhea\n• **Stool culture** — indicated when fever + positive fecal markers\n• **C. difficile toxin** — if antibiotic use in past 3 months\n• **CBC, BMP** — assess for leukocytosis, electrolyte derangement, renal function\n\n[Empiric Antibiotic Criteria](#/info/diarrhea-abx-criteria)\n\nFecal lactoferrin is **more sensitive** than fecal leukocytes for detecting invasive pathogens and does not require a fresh specimen.' WHERE id = 'diarrhea-febrile' AND tree_id = 'diarrhea';
UPDATE decision_nodes SET body = E'[Dehydration Assessment Guide](#/info/diarrhea-dehydration-assessment)\n\n**Adults:**\n• **Dry axilla** — supports hypovolemia diagnosis\n• **Moist mucous membranes + tongue without furrows** — argues against hypovolemia\n• Capillary refill and skin turgor have **no proven diagnostic value** in adults\n• Orthostatic vitals, BUN/Cr ratio\n\n**Children:**\n• **Acute body weight change** — best measure of dehydration\n• Mucous membrane hydration, capillary refill >2 sec, absence of tears, altered mental status — next best measures\n• Sunken anterior fontanelle in infants\n\n**IV rehydration:**\n• NS or LR bolus 20 mL/kg, repeat as needed\n• Monitor urine output as marker of volume status\n• BMP for electrolyte correction\n• Reassess after each bolus' WHERE id = 'diarrhea-dehydration' AND tree_id = 'diarrhea';
UPDATE decision_nodes SET body = E'HIV/AIDS, transplant recipients, chemotherapy, chronic steroids, and other immunocompromised patients have a **broader differential** and require **more aggressive workup**.\n\n**Additional pathogens to consider:**\n• Cryptosporidium, Microsporidium, Isospora — profuse watery diarrhea, weight loss\n• CMV — bloody diarrhea in advanced disease\n• Mycobacterium avium complex (MAC) — chronic diarrhea, advanced HIV\n• GI malignancies — lymphoma, Kaposi sarcoma\n\n**Workup:**\n• Stool culture (standard pathogens)\n• C. difficile toxin assay\n• **Ova and parasites** — indicated in this population\n• CBC, BMP, lactate\n• Consider CD4 count if HIV status unknown\n\n**Disposition:** Lower threshold for admission. Consider early GI or infectious disease consultation. If stool studies negative, endoscopy referral may be needed for definitive diagnosis.' WHERE id = 'diarrhea-immunocompromised' AND tree_id = 'diarrhea';
UPDATE decision_nodes SET body = E'Diarrhea can be a presenting feature of several **surgical emergencies**. Maintain high suspicion in patients with severe abdominal pain.\n\n[Differential Diagnosis Pitfalls](#/info/diarrhea-ddx-pitfalls)\n\n**Appendicitis:**\n• Vomiting typically **follows** pain (in gastroenteritis, vomiting **precedes** pain)\n• 1-2 loose stools (not voluminous like gastroenteritis)\n• 15% of appendices are in atypical locations\n• 27% of children initially misdiagnosed — diarrhea is a common confounding symptom\n• Serial exams improve diagnostic accuracy\n\n**Ischemic bowel:**\n• Consider in adults **>50 years** or with peripheral vascular disease\n• Severe pain out of proportion to exam\n• Voluminous diarrhea (small bowel ischemia) or bloody diarrhea (ischemic colitis)\n• Risk factors: arrhythmias, CHF, vasoconstrictors, cocaine\n• Occult blood in up to 75% of patients\n\n**Other surgical causes:** bowel obstruction, toxic megacolon, diverticulitis, intussusception (pediatric)\n\n**CT abdomen/pelvis** indicated for surgical concern. If surgical etiology identified → surgical consult.' WHERE id = 'diarrhea-surgical-ddx' AND tree_id = 'diarrhea';
UPDATE decision_nodes SET body = E'[Empiric Antibiotic Criteria](#/info/diarrhea-abx-criteria)\n\n**Selective testing — routine labs are NOT indicated for most patients:**\n\n**Fecal leukocytes / lactoferrin:** community-acquired, traveler''s, nosocomial, or diarrhea >7 days\n\n**Stool culture:** bloody stool, fever >38.5°C + positive fecal markers, immunocompromised, severe/persistent illness. Yield is low (1.5-5.6%) but identifies public health threats. Routine labs identify Shigella, Campylobacter, Salmonella.\n\n**C. difficile toxin:** antibiotic use in past 3 months, recent hospitalization, nursing home\n\n**Ova & parasites:** rarely indicated in acute diarrhea. Consider if >14 days, immunocompromised, no response to antibiotics, travel to endemic area\n\n**CBC/BMP:** severe illness, bloody diarrhea (screen for HUS — platelets), elderly, immunocompromised, significant dehydration\n\n**What is the suspected etiology?**' WHERE id = 'diarrhea-labs' AND tree_id = 'diarrhea';
UPDATE decision_nodes SET body = E'**Suspect C. difficile if:**\n• Antibiotic use in past **3 months** (especially clindamycin, fluoroquinolones, cephalosporins)\n• Recent hospitalization or nursing home residence\n• Diarrhea developing **≥3 days after hospitalization** (C. diff testing has 15-20% yield in nosocomial diarrhea vs <5% for standard stool cultures)\n\n**Testing:**\n• **C. difficile toxin assay** — preferred: NAAT (PCR) or GDH + toxin two-step algorithm\n• Toxin A/B immunoassay alone has lower sensitivity\n\n**Key management:**\n• **STOP the offending antibiotic** if possible\n• Start empiric treatment if strong clinical suspicion — stop if toxin assay returns negative\n\n**Severity classification:**\n• **Non-severe:** WBC ≤15K, Cr <1.5\n• **Severe:** WBC >15K, Cr >1.5, albumin <3\n• **Fulminant:** hypotension, ileus, megacolon → surgical consult' WHERE id = 'diarrhea-cdiff' AND tree_id = 'diarrhea';
UPDATE decision_nodes SET body = E'**Non-severe (first episode):**\n• [Vancomycin](#/drug/vancomycin/c difficile) 125 mg PO QID × 10-14 days (preferred)\n• Alternative: [Metronidazole](#/drug/metronidazole/c difficile) 500 mg PO TID × 10-14 days\n\n**Severe (WBC >15K, Cr >1.5):**\n• [Vancomycin](#/drug/vancomycin/c difficile) 125 mg PO QID × 10-14 days\n• Do NOT use metronidazole alone for severe disease\n\n**Fulminant (hypotension, ileus, megacolon):**\n• [Vancomycin](#/drug/vancomycin/c difficile) 500 mg PO/NG QID\n• PLUS [Metronidazole](#/drug/metronidazole/c difficile) 500 mg IV q8h\n• Consider rectal vancomycin enema if ileus present\n• **Surgical consult** — colectomy may be lifesaving\n\n**Disposition:** Admit severe and fulminant cases. Non-severe may be discharged with close follow-up.\n\n[Special Populations](#/node/diarrhea-special-pops)' WHERE id = 'diarrhea-cdiff-treatment' AND tree_id = 'diarrhea';
UPDATE decision_nodes SET body = E'Recent travel to endemic area (Latin America, Africa, South/Southeast Asia). Most common cause is enterotoxigenic E. coli.\n\n**Key considerations:**\n• **Southeast Asia** — >80% fluoroquinolone-resistant Campylobacter; use azithromycin instead\n• Combination therapy (antibiotic + loperamide) is most efficacious\n• Prevention counseling: carbonated/hot beverages, avoid buffets, leafy vegetables, ice' WHERE id = 'diarrhea-travelers' AND tree_id = 'diarrhea';
UPDATE decision_nodes SET body = E'**Symptomatic therapy:**\n• [Loperamide](#/drug/loperamide/traveler diarrhea) 4 mg PO initially, then 2 mg after each loose stool (max 16 mg/day)\n• [Bismuth Subsalicylate](#/drug/bismuth-subsalicylate/traveler diarrhea) 524 mg PO q30-60 min PRN (max 8 doses/day) — also helps nausea\n\nLoperamide and bismuth subsalicylate have similar efficacy, but loperamide reduces stool frequency faster. Bismuth subsalicylate has additional antiemetic properties.\n\n**Antibiotics not typically needed** for mild traveler''s diarrhea.\n\nDischarge with return precautions. [Diarrhea Discharge Instructions](#/info/diarrhea-discharge)\n\n[Special Populations](#/node/diarrhea-special-pops)' WHERE id = 'diarrhea-travelers-mild' AND tree_id = 'diarrhea';
UPDATE decision_nodes SET body = E'**Empiric antibiotics indicated:**\n• [Ciprofloxacin](#/drug/ciprofloxacin/traveler diarrhea) 500 mg PO BID × 3 days (first-line for most regions)\n• **Southeast Asia:** [Azithromycin](#/drug/azithromycin/traveler diarrhea) 1000 mg PO × 1 dose or 500 mg PO daily × 3 days (fluoroquinolone-resistant Campylobacter >80%)\n• **Children:** [TMP-SMX](#/drug/tmp-smx/traveler diarrhea)\n\n**Adjunct therapy:**\n• [Loperamide](#/drug/loperamide/traveler diarrhea) with antibiotic — combination therapy reduces diarrhea duration by 1 additional day\n• IV rehydration if unable to tolerate oral fluids\n\n**Avoid loperamide** if bloody diarrhea or high fever.\n\n[Special Populations](#/node/diarrhea-special-pops)' WHERE id = 'diarrhea-travelers-severe' AND tree_id = 'diarrhea';
UPDATE decision_nodes SET body = E'**Rehydration is the cornerstone** of diarrhea management.\n\n[Antimotility Contraindications](#/info/diarrhea-antimotility-ci)\n\nOral rehydration is preferred when tolerated — it is effective, low-cost, and an indicator of discharge readiness. Solutions should contain sodium, potassium, and glucose. Commercial ORS (Pedialyte) preferred over sports drinks (inadequate sodium replacement).\n\n**BRAT diet** (bananas, rice, applesauce, toast) has no proven advantage over resuming the patient''s normal diet.' WHERE id = 'diarrhea-treatment' AND tree_id = 'diarrhea';
UPDATE decision_nodes SET body = E'**Rehydration:**\n• Oral rehydration solution (ORS) with sodium, potassium, glucose\n• Commercial options: Pedialyte, Lytren, Rehydrolyte\n• Resume normal diet at earliest opportunity — early refeeding improves recovery\n\n**Symptomatic relief:**\n• [Loperamide](#/drug/loperamide/acute diarrhea) 4 mg PO initially, then 2 mg after each loose stool (max 16 mg/day) — preferred antimotility agent (no CNS effects, not habit-forming)\n• [Bismuth Subsalicylate](#/drug/bismuth-subsalicylate/acute diarrhea) 524 mg PO q30-60 min PRN — preferred when nausea/vomiting is prominent\n• [Ondansetron](#/drug/ondansetron/acute diarrhea) 4 mg IV or ODT for vomiting preventing oral intake\n\n[Antimotility Contraindications](#/info/diarrhea-antimotility-ci) — **AVOID** antimotility agents with bloody diarrhea, high fever, suspected inflammatory cause, or immunocompromised patients.\n\n[Diarrhea Discharge Instructions](#/info/diarrhea-discharge)\n\n[Special Populations](#/node/diarrhea-special-pops)' WHERE id = 'diarrhea-mild' AND tree_id = 'diarrhea';
UPDATE decision_nodes SET body = E'**IV rehydration:**\n• NS or LR bolus, reassess after each liter\n• Target: urine output, improved vitals, ability to tolerate oral fluids\n\n**Antiemetics:**\n• [Ondansetron](#/drug/ondansetron/acute diarrhea) 4 mg IV q4-6h PRN for vomiting preventing oral intake\n\n**Antimotility (if no contraindications):**\n• [Loperamide](#/drug/loperamide/acute diarrhea) 4 mg PO then 2 mg PRN (max 16 mg/day)\n\n**Assess for empiric antibiotic criteria:**\n• Diarrhea >48 hours (higher probability non-viral)\n• Fever >38.5°C + fecal leukocytes/lactoferrin positive or heme-positive stools\n• Acute dysentery\n\nIf meets criteria → proceed to empiric antibiotics.' WHERE id = 'diarrhea-moderate-rx' AND tree_id = 'diarrhea';
UPDATE decision_nodes SET body = E'[Empiric Antibiotic Criteria](#/info/diarrhea-abx-criteria)\n\n**Adults (fever >38.5°C + positive fecal markers, dysentery, or >48h):**\n• [Ciprofloxacin](#/drug/ciprofloxacin/acute diarrhea) 500 mg PO BID × 3-5 days\n\n**Children:**\n• [TMP-SMX](#/drug/tmp-smx/acute diarrhea) (dose by weight) × 3-5 days\n\n**Persistent diarrhea (2-4 weeks) without systemic symptoms:**\n• [Metronidazole](#/drug/metronidazole/persistent diarrhea) 250 mg PO TID × 7-10 days (covers Giardia)\n\n**Elderly considerations:** fluoroquinolones can increase theophylline and warfarin levels, and can alter phenytoin levels. Metronidazole can cause nausea/vomiting and has disulfiram-like reaction with alcohol.\n\n⚠️ **Do NOT give antibiotics if STEC (E. coli O157:H7) suspected** — increases HUS risk.\n\n[Diarrhea Discharge Instructions](#/info/diarrhea-discharge)\n\n[Special Populations](#/node/diarrhea-special-pops)' WHERE id = 'diarrhea-empiric-abx' AND tree_id = 'diarrhea';
UPDATE decision_nodes SET body = E'**Dehydration is dangerous for both mother and fetus** — aggressive rehydration is top priority.\n\n**Safest antimotility:**\n• [Loperamide](#/drug/loperamide/pregnancy) — acts peripherally (FDA Category B), safest option\n• **AVOID** diphenoxylate (CNS effects) and bismuth subsalicylate (contains salicylates)\n\n**Antibiotics:**\n• [Metronidazole](#/drug/metronidazole/pregnancy) — Category B after first trimester, can be used if benefits outweigh risks\n• **AVOID fluoroquinolones** — cartilage toxicity risk\n• **AVOID TMP-SMX** — folate antagonism, teratogenic risk (especially first trimester and near term)\n\nIf doubts about antibiotic safety, coordinate treatment with the patient''s OB/GYN.\n\nLow threshold for admission if unable to maintain oral hydration.' WHERE id = 'diarrhea-pregnant' AND tree_id = 'diarrhea';
UPDATE decision_nodes SET body = E'**Key differences from adults:**\n• **Rotavirus** is the most common cause in children\n• **ORS is preferred** over IV — evidence-based and WHO-endorsed. Use commercial ORS (Pedialyte), NOT sports drinks or plain water\n• **No antimotility agents** — not recommended in children with acute gastroenteritis\n• **No routine antiemetics** in children with acute gastroenteritis, except:\n  [Ondansetron](#/drug/ondansetron/pediatric diarrhea) 0.15 mg/kg IV/ODT (max 4 mg) — facilitates oral rehydration in vomiting children\n\n⚠️ **E. coli O157:H7 and HUS:**\n• Most common cause of acute kidney failure in children\n• Do **NOT** give antibiotics if STEC suspected — increases HUS risk\n• Monitor: platelet count, hemolytic anemia, renal function\n• Signs: pallor, bruising, petechiae, decreased urine output\n\n**Admit if:** severe dehydration, altered mental status, inability to maintain oral hydration, suspected HUS, very young (<3 months)\n\nExcessive consumption of sugary clear liquids can itself cause watery stools — ask about intake.' WHERE id = 'diarrhea-pediatric' AND tree_id = 'diarrhea';
UPDATE decision_nodes SET body = E'**Higher risk of serious etiologies:**\n• **Ischemic colitis** — consider in any elderly patient with diarrhea + abdominal pain\n• **C. difficile** — more common and more lethal in the elderly\n• **Diverticulitis** — can present with diarrhea\n• **Colonic malignancy** — occult in presentation\n• **E. coli O157:H7** — more common in elderly\n\n**Dehydration risks:** age-related disordered thirst mechanism, medications (diuretics), diabetes, limited fluid access (infirmity). Profound dehydration is common.\n\n**IV rehydration caution:** cardiovascular disease and renal dysfunction may limit rapid large-volume fluid administration.\n\n**Drug interactions with fluoroquinolones:**\n• Increases theophylline and warfarin levels\n• Can increase or decrease phenytoin levels\n• Antacids reduce fluoroquinolone absorption\n\n**Lower threshold for:** CT abdomen, admission, surgical consultation.\n\n[Diarrhea Discharge Instructions](#/info/diarrhea-discharge)' WHERE id = 'diarrhea-elderly' AND tree_id = 'diarrhea';
UPDATE decision_nodes SET body = E'[Diarrhea Discharge Instructions](#/info/diarrhea-discharge)\n\n**Discharge if:**\n• Hemodynamically stable\n• Benign abdominal examination\n• Tolerating oral fluids without vomiting\n• Adequate urine output\n• Low risk for complications\n• Reliable follow-up and understanding of return precautions\n\n**Admit or observe if:**\n• Failed ED rehydration or unable to tolerate oral fluids\n• Severe or persistent dehydration\n• Diagnostic dilemma (atypical presentation, unclear etiology)\n• Extremes of age (very young, elderly) with comorbidities\n• Immunocompromised\n• Possible surgical etiology\n• Significant electrolyte derangement\n\n**Chronic diarrhea (>30 days):** usually exceeds ED scope. Exclude serious illness, ensure stability, begin infectious workup, refer to gastroenterology.\n\n**Before discharge:** Reassess vitals, repeat abdominal exam, confirm oral tolerance, provide written discharge instructions.' WHERE id = 'diarrhea-disposition' AND tree_id = 'diarrhea';

-- === distal-radius (17 nodes) ===
UPDATE decision_nodes SET body = E'[Reduction Steps Summary](#/info/dr-summary) — quick-reference TRAMP checklist to review before reduction.\n\n**"Obtain & Maintain"** — the two questions that guide every fracture decision: [1]\n\n**1. OBTAIN — Is the current position acceptable?**\nIf yes → immobilize and follow up. If no → reduce.\n\n**2. MAINTAIN — Will the fracture shift?**\nIf stable → fiberglass OK. If unstable → plaster cast with proper molding.\n\nThis framework applies to every fracture you encounter. For distal radius, the TRAMP mnemonic provides the systematic reduction technique.\n\n[Pediatric Considerations](#/node/dr-peds) — remodeling potential, acceptable angulation by age, growth plate risks.' WHERE id = 'dr-start' AND tree_id = 'distal-radius';
UPDATE decision_nodes SET body = E'Evaluate the fracture on AP and lateral radiographs.\n\n**Acceptable position criteria:**\n• Radial height maintained\n• Radial inclination >15°\n• Volar tilt neutral or positive\n• No significant dorsal angulation\n• No intra-articular step-off >2 mm\n\n**Is the current position acceptable?**' WHERE id = 'dr-assess' AND tree_id = 'distal-radius';
UPDATE decision_nodes SET body = E'**Buckle (torus) fractures:**\n• Removable wrist splint for 3–4 weeks\n• No follow-up x-ray needed — these do not displace\n\n**Minimally displaced, stable:**\n• Short arm splint or cast\n• Fiberglass is acceptable (no molding needed for stable fractures)\n• Ensure thumb, fingers, and elbow remain FREE\n\n**Follow-up:**\n• Ortho clinic in 5–7 days for repeat films\n• Return precautions: increasing pain, numbness/tingling, inability to move fingers' WHERE id = 'dr-stable' AND tree_id = 'distal-radius';
UPDATE decision_nodes SET body = E'**Indications for operative management:**\n• Open fracture (any grade)\n• Grossly unstable / comminuted distal radius\n• Intra-articular step-off >2 mm\n• Radiocarpal subluxation\n• Associated distal radioulnar joint (DRUJ) instability\n• Failed closed reduction (2 attempts)\n\n**ED management while awaiting consult:**\n• Irrigate open wounds, apply sterile dressing\n• Reduce gross deformity if neurovascularly compromised\n• Splint in position of comfort\n• Antibiotics for open fractures (cefazolin ± gentamicin)\n• Update tetanus if needed\n• Neurovascular exam — document median nerve function' WHERE id = 'dr-surgical' AND tree_id = 'distal-radius';
UPDATE decision_nodes SET body = E'**Choose your analgesia approach.** Hematoma block is the preferred technique for most ED reductions — faster discharge (1.5 vs 4.6 hours), no NPO requirement, no monitoring team needed. [3][4][6]\n\nFor complex reductions or patient anxiety, procedural sedation remains appropriate. Regional anesthesia offers superior and longer-lasting analgesia but requires more setup time.' WHERE id = 'dr-analgesia' AND tree_id = 'distal-radius';
UPDATE decision_nodes SET body = E'[Hematoma Block Evidence](#/info/dr-hema-evidence) — comprehensive efficacy data, technique variations, and comparative studies.\n\n**TECHNIQUE:**\n1. Identify the fracture site on dorsal aspect of wrist\n2. Prep skin with chlorhexidine\n3. Insert **20-gauge needle** at dorsal fracture line\n4. **Aspirate** — dark blood confirms placement in fracture hematoma\n5. Inject **5–10 mL of 1% plain** [Lidocaine](#/drug/lidocaine/hematoma block)\n6. For combined radius + ulna fractures: second injection into ulnar hematoma\n7. Wait **5–10 minutes** for full anesthetic effect\n\n**ULTRASOUND GUIDANCE** improves accuracy and reduces pain during injection. [5][7][8]\n\n**SAFETY:** Max dose 4.5 mg/kg without epinephrine. Fracture hematoma is contiguous with marrow space — absorption is rapid, similar to IO administration. [3][5][6]' WHERE id = 'dr-hema-block' AND tree_id = 'distal-radius';
UPDATE decision_nodes SET body = E'**Procedural sedation** provides excellent analgesia and amnesia but requires more resources and time.\n\n**COMMON AGENTS:**\n• **Ketamine** 1–2 mg/kg IV — dissociative, maintains airway reflexes\n• **Propofol** 0.5–1 mg/kg IV — rapid onset/offset, no analgesia (add fentanyl)\n• **Etomidate** 0.1–0.15 mg/kg IV — hemodynamically stable\n\n**REQUIREMENTS:**\n• NPO assessment (ideally 2+ hours for clear liquids)\n• Dedicated monitoring nurse\n• Capnography, pulse oximetry, cardiac monitor\n• Resuscitation equipment at bedside\n• Longer ED stay (mean 4.6 hours vs 1.5 hours for hematoma block) [4]\n\n**BEST FOR:** Complex reductions, highly anxious patients, pediatric patients who cannot cooperate with hematoma block.' WHERE id = 'dr-proc-sed' AND tree_id = 'distal-radius';
UPDATE decision_nodes SET body = E'**BIER BLOCK (IV Regional)**\n• Double-cuff tourniquet on affected arm\n• Exsanguinate, inflate proximal cuff to 100 mmHg above SBP\n• Inject 40–50 mL 0.5% lidocaine IV into dorsal hand vein\n• Switch to distal cuff after 5 min\n• Maintain tourniquet minimum 20 min to prevent systemic toxicity\n• Comparable efficacy to hematoma block with better patient satisfaction in some studies [10]\n\n**US-GUIDED NERVE BLOCKS**\n• Median + radial nerve blocks at wrist or forearm\n• Axillary brachial plexus block for complete coverage\n• Superior analgesia and longer duration than hematoma block [12][13]\n• Higher success rate for closed reduction (94% vs 74%) [12]\n• Requires ultrasound proficiency and additional setup time [9][11]\n\n**EVIDENCE:** Cochrane review found insufficient evidence to recommend one technique over another. Choice depends on clinician skill and patient factors. [9]' WHERE id = 'dr-regional' AND tree_id = 'distal-radius';
UPDATE decision_nodes SET body = E'**TRACTION — Disimpact the fracture first.** [1]\n\nBefore you can reduce the fracture, you must recreate length by separating the fragments.\n\n**TECHNIQUE:**\n• Patient seated, arm pronated on table\n• Apply **longitudinal traction** — waterski position (lean back, steady pull)\n• Make small circles to free the distal fragment\n• Goal: recreate the length that was lost from impaction\n• Do NOT try to reduce yet — just get the fragments apart\n\n**FINGER TRAPS:** Place traps on the **thumb, index, and middle fingers** (digits 1–3) — this positions the hand in ulnar deviation during traction, which helps maintain radial length. Hang arm with 5–10 lbs of countertraction at the elbow. This frees your hands for reduction and splinting.\n\n**KEY POINT:** If you skip traction, the fragments are locked together and reduction will fail.' WHERE id = 'dr-traction' AND tree_id = 'distal-radius';
UPDATE decision_nodes SET body = E'**REDUCTION — Exaggerate, then correct.** [1]\n\nThe key insight: you must first increase the deformity to unlock the periosteum, then push the fragment back into place.\n\n**TECHNIQUE:**\n1. With traction maintained, **exaggerate the deformity** (extend the wrist further dorsally)\n2. This unlocks the dorsal periosteal hinge\n3. Now **push the distal fragment palmar** (volar) with your thumbs\n4. Simultaneously apply **ulnar deviation** to restore radial inclination\n5. You should feel a satisfying "clunk" as the fragment reduces\n\n**WHY ULNAR DEVIATION IS CRITICAL:** Ulnar deviation maintains radial length. Without it, the radius shortens relative to the ulna, losing the reduction. This is one of the most important steps — always ulnar deviate during and after reduction.\n\n**COMMON MISTAKE:** Trying to push the fragment into place without first exaggerating — the locked periosteum blocks reduction.\n\n**BOTH BONES:** If ulna is also fractured, reduce radius first (restores radial length), then assess ulna — it often reduces with the radius.' WHERE id = 'dr-reduce' AND tree_id = 'distal-radius';
UPDATE decision_nodes SET body = E'**APPLY — Plaster, not fiberglass, when molding matters.** [1]\n\nFiberglass sets too rigid too fast — you cannot mold it to maintain reduction. Save fiberglass for stable fractures that don''t need molding.\n\n**PLASTER TECHNIQUE:**\n• **10 layers** of plaster (standard thickness for adults)\n• **6-inch width** for distal radius\n• Measure length on the **uninjured side** — wrist to proximal forearm\n• Cut a **thumb hole** before applying\n• **Minimal padding** at the fracture site — padding defeats molding\n  - 2 layers of Webril only\n  - More padding = less effective mold = fracture shifts\n\n**CRITICAL CONCEPT:** The purpose of the splint is to hold the reduction. Excessive padding creates a gap between the splint and skin, allowing the fracture to move inside the splint.' WHERE id = 'dr-apply' AND tree_id = 'distal-radius';
UPDATE decision_nodes SET body = E'**MOLD — Flat hands, oval shape, don''t squeeze, don''t move.** [1][2]\n\nThis is where most reductions are lost. Improper molding lets the fracture shift back.\n\n**TECHNIQUE:**\n• Use **flat hands** (thenar eminences) — never fingertips\n• Create an **oval cross-section**, NOT a circle\n  - "Straight cast → crooked bone, crooked cast → straight bone"\n• Apply **3-point pressure**: dorsal at fracture, volar proximal and distal\n• Hold the mold — **DO NOT move your hands while plaster sets**\n• Wait for the **exothermic reaction** (heat) — plaster is setting\n• Setting time: approximately 3–5 minutes\n\n**3-POINT MOLD PRINCIPLE:**\nThe oval shape and 3-point pressure create a mechanical block that prevents the fracture from re-displacing dorsally. A round cast provides no resistance to displacement.\n\n**DO NOT SQUEEZE** — squeezing creates pressure points → skin breakdown. Mold with broad, flat pressure only.' WHERE id = 'dr-mold' AND tree_id = 'distal-radius';
UPDATE decision_nodes SET body = E'**POSITION — 10° flexion, ulnar deviation, everything else FREE.** [1]\n\n**WRIST POSITION:**\n• **10° flexion** (slight volar tilt) — counteracts dorsal displacement\n• **Ulnar deviation** — restores radial inclination\n• Hold position with thumb + index finger + middle finger\n\n**WHAT MUST BE FREE:**\n• **Elbow** — cast stops below elbow (short arm)\n• **MCP joints** — cast stops at distal palmar crease\n• **Thumb** — full ROM through thumb hole\n\n**WHY THESE THREE:**\n• Immobilizing the elbow doesn''t improve stability for distal radius\n• Blocking MCPs → finger stiffness → poor functional outcome\n• Thumb immobilization → unnecessary disability\n\n**SUGAR-TONG SPLINT:** For highly unstable fractures, a sugar-tong (elbow-to-palm with forearm loop) prevents pronation/supination and provides additional stability.' WHERE id = 'dr-position' AND tree_id = 'distal-radius';
UPDATE decision_nodes SET body = E'**Obtain post-reduction AP and lateral films.** [1]\n\n**ASSESSMENT CRITERIA:**\n• **2nd metacarpal line** should be parallel to the radial shaft on AP view\n• **Cast index** <0.80 (AP width ÷ lateral width of cast at fracture) — oval shape confirmed\n• Radial height, inclination, and volar tilt restored\n• No intra-articular step-off\n\n**"Straight cast = crooked bone. Crooked cast = straight bone."**\nIf the cast looks perfectly round on x-ray, the mold is inadequate and the fracture will re-displace.\n\n**Is the reduction acceptable?**' WHERE id = 'dr-post-xray' AND tree_id = 'distal-radius';
UPDATE decision_nodes SET body = E'**Assess what went wrong before trying again.** [1]\n\n**COMMON FAILURES:**\n• Insufficient traction — fragments still impacted\n• Did not exaggerate deformity — periosteum still locked\n• Round cast (poor mold) — no mechanical block to re-displacement\n• Too much padding — mold doesn''t transmit to bone\n• Moved hands during plaster setting — lost the mold\n\n**BEFORE RE-ATTEMPT:**\n• Remove the current cast/splint completely\n• **Top up analgesia** — additional hematoma block or supplemental sedation\n• Reassess the fracture pattern on the post-reduction films\n• Address the specific failure point\n\n**RE-ATTEMPT THE FULL TRAMP SEQUENCE:**\nDo not skip steps. Start from Traction and work through each step again.\n\n**IF 2 ATTEMPTS FAIL** → consult orthopedics for operative management. Repeated manipulation increases soft tissue swelling and complication risk.' WHERE id = 'dr-re-attempt' AND tree_id = 'distal-radius';
UPDATE decision_nodes SET body = E'**DISCHARGE INSTRUCTIONS:**\n• **Elevation** — keep hand above heart for 48 hours to minimize swelling\n• **Ice** — 20 min on / 20 min off over cast padding\n• **Finger exercises** — wiggle fingers frequently to prevent stiffness\n• **Neurovascular checks** — ensure fingers remain pink, warm, with normal sensation\n\n**RETURN IMMEDIATELY IF:**\n• Increasing pain not relieved by elevation and medication\n• Numbness, tingling, or inability to move fingers\n• Fingers turn blue, white, or cold\n• Cast feels too tight or causes pressure sores\n\n**COMPARTMENT SYNDROME WARNING:**\nAny of the above symptoms could indicate compartment syndrome — a surgical emergency.\n\n**FOLLOW-UP:**\n• **Ortho clinic in 5–7 days** for repeat films\n• 1-week x-ray checks for re-displacement (especially first 2 weeks)\n• Cast duration: typically 4–6 weeks for adults, 3–4 weeks for children\n\n[Discharge Instructions](#/info/distal-radius-discharge) — shareable patient handout' WHERE id = 'dr-dispo' AND tree_id = 'distal-radius';
UPDATE decision_nodes SET body = E'**Remodeling potential changes what counts as "acceptable."** [1]\n\nChildren''s fractures can remodel — but ONLY in the plane of joint motion. **Rotation does NOT remodel.** Any malrotation must be corrected.\n\n**ACCEPTABLE ANGULATION BY AGE:**\n• <10 years: up to 15–20° sagittal angulation may remodel\n• 10–16 years: less tolerance — aim for <10° angulation\n• Younger children tolerate more because more growth remaining\n\n**BUCKLE (TORUS) FRACTURES:**\n• Compression failure of one cortex — inherently stable\n• Removable splint for 3–4 weeks, no reduction needed\n• Evidence supports removable splint equal to casting [1]\n\n**GREENSTICK FRACTURES:**\n• Incomplete fracture — one cortex intact\n• May need reduction if significantly angulated\n• Do NOT complete the fracture — the intact cortex provides stability\n\n**GROWTH PLATE RISK:**\n• Delayed reduction increases risk of growth plate injury\n• Physeal fractures (Salter-Harris) → reduce early\n• Radial neck fractures in children: delayed reduction risks permanent growth arrest [1]\n\n**KEY DIFFERENCE:** Children tolerate more angulation but are less forgiving of delays. Reduce promptly if needed.' WHERE id = 'dr-peds' AND tree_id = 'distal-radius';

-- === echo-epss (10 nodes) ===
UPDATE decision_nodes SET body = E'**E-point septal separation (EPSS) >7 mm is a validated threshold for detecting reduced left ventricular ejection fraction (LVEF).** [1][2][3]\n\nThis measurement provides an objective, rapid assessment that complements visual estimation of cardiac function.\n\nWHAT IS EPSS?\nEPSS measures the shortest distance between the anterior mitral valve leaflet at its peak opening (E-point) and the interventricular septum during early diastole. A wider gap suggests reduced LV contractility and/or LV dilation.\n\nCLINICAL SIGNIFICANCE\n• EPSS >7 mm → suggests LVEF <50% (reduced systolic function)\n• EPSS >10 mm → indicates more severe dysfunction [2][4]\n• **100% sensitivity for severe systolic dysfunction (LVEF ≤30%) when >7 mm** [2]\n• Specificity is moderate (52%) — best when combined with other echo findings [5]\n\nIMPORTANT LIMITATIONS\n**EPSS may be inaccurate in:** aortic regurgitation, mitral stenosis, hypertrophic cardiomyopathy, and non-sinus rhythms. [3] The measurement remains valid even with abnormal septal motion, including paradoxical septal movement. [6][7]\n\n**Pediatric thresholds:** 6.0 mm for children overall, 4.9 mm for children 0–3 years old. [8]' WHERE id = 'epss-start' AND tree_id = 'echo-epss';
UPDATE decision_nodes SET body = E'PATIENT POSITIONING\nPosition the patient supine or in left lateral decubitus. Left lateral decubitus brings the heart closer to the chest wall and often improves image quality.\n\nPROBE SELECTION\nUse a phased-array cardiac transducer (2–5 MHz). Its small footprint fits between rib spaces.\n\nOBTAIN PARASTERNAL LONG-AXIS (PLAX) VIEW\n• Place the transducer in the 3rd–4th intercostal space, right next to the sternum\n• Probe marker points toward the patient''s **left hip** (standard mode)\n• Hug the sternum as you slide up and down rib spaces to find the best window\n\nOPTIMIZE THE VIEW\nClearly visualize all three key structures:\n• **Interventricular septum** — horizontal across the screen\n• **Anterior mitral valve leaflet** — opening and closing within the LV\n• **Left ventricular cavity** — posterior to the septum\n\nRemember the **3 L''s**: parasternal **L**ong axis should have the **L**eft ventricle on the **L**eft side of the screen. [3]' WHERE id = 'epss-plax' AND tree_id = 'echo-epss';
UPDATE decision_nodes SET body = E'CURSOR PLACEMENT\nWith a good PLAX view on screen, activate M-mode and position the cursor:\n\n• Place the M-mode cursor **perpendicular to the interventricular septum**\n• The cursor should pass through the **tips of the mitral valve leaflets** at the level where they open in early diastole\n• Ensure both the **septum and anterior mitral leaflet** are clearly visible on the M-mode tracing [3]\n\nOPTIMIZING THE TRACING\n• Adjust sweep speed so you can see 3–4 cardiac cycles\n• The septum should appear as a continuous bright line at the top of the M-mode display\n• The mitral valve should show its characteristic M-shaped motion pattern below the septum\n• If the tracing is unclear, return to 2D mode and readjust the cursor position' WHERE id = 'epss-mmode' AND tree_id = 'echo-epss';
UPDATE decision_nodes SET body = E'**Measure the shortest distance between the peak of the anterior mitral valve leaflet (E-point) and the interventricular septum during early diastole.** [1][2]\n\nIDENTIFYING THE E-POINT\nOn the M-mode tracing, the anterior mitral leaflet traces a characteristic pattern:\n• **E-point** — the tallest peak, representing maximal opening during early diastole\n• **A-point** — a smaller peak just before systole, from atrial contraction\n\nMeasure from the E-point peak to the nearest edge of the septum.\n\nE-WAVE & A-WAVE PHYSIOLOGY\nThe **E wave** represents early passive ventricular filling driven by the pressure gradient between the left atrium and left ventricle after mitral valve opening. This flow reflects the interplay of LA pressure, LV compliance, and the rate of ventricular relaxation. [1][2]\n\nThe **A wave** occurs later in diastole when the atrium contracts, actively propelling additional blood into the ventricle. It primarily reflects ventricular compliance and atrial contractility. [2]\n\nEPSS is measured at the peak of the E wave — it reflects both the amplitude of mitral valve excursion (influenced by filling dynamics) and left ventricular size, particularly outflow tract dilation.' WHERE id = 'epss-measure' AND tree_id = 'echo-epss';
UPDATE decision_nodes SET body = E'What is the measured EPSS value?\n\nTHRESHOLDS\n• **< 7 mm** → Normal systolic function likely\n• **7–10 mm** → Grey zone — assess for signs of fluid overload\n• **> 10 mm** → Reduced systolic function (heart failure likely)' WHERE id = 'epss-interpret' AND tree_id = 'echo-epss';
UPDATE decision_nodes SET body = E'EPSS < 7 mm suggests preserved left ventricular ejection fraction (LVEF ≥50%).\n\nThe anterior mitral leaflet reaches close to the septum during early diastole, indicating adequate ventricular filling dynamics and normal LV cavity size.\n\nCLINICAL INTEGRATION\n• Combine with visual estimation of global cardiac function across multiple views\n• Consider alternative quantitative measures if clinical suspicion for dysfunction persists: MAPSE (mitral annular plane systolic excursion) or fractional shortening [1][9][5]\n\nLIMITATIONS REMINDER\nEPSS may be inaccurate in: aortic regurgitation, mitral stenosis, HCM, and non-sinus rhythms. [3]\nPediatric thresholds: 6.0 mm (children), 4.9 mm (age 0–3 years). [8]\n\nFor a video explanation of EPSS measurement, visit [Core Ultrasound — Basic Cardiac Function](https://coreultrasound.com/basic-cardiac-function/).' WHERE id = 'epss-normal' AND tree_id = 'echo-epss';
UPDATE decision_nodes SET body = E'EPSS > 10 mm indicates significant left ventricular systolic dysfunction. [2][4]\n\n**EPSS has 100% sensitivity for detecting LVEF ≤30% when >7 mm.** [2] A measurement >10 mm strongly suggests severe reduction in ejection fraction.\n\nThe increased separation reflects poor ventricular contractility and/or significant LV dilation — the anterior mitral leaflet cannot reach the septum during early diastolic filling.\n\nCLINICAL NEXT STEPS\n• Assess for signs of fluid overload: B-lines on lung ultrasound, IVC plethora\n• Obtain additional echo views (A4C, PSAX) for visual estimation of global function\n• Consider formal echocardiography for quantitative LVEF\n• Initiate heart failure management as clinically indicated\n\nLIMITATIONS REMINDER\nEPSS may be inaccurate in: aortic regurgitation, mitral stenosis, HCM, and non-sinus rhythms. [3]\nPediatric thresholds: 6.0 mm (children), 4.9 mm (age 0–3 years). [8]\n\nFor a video explanation of EPSS measurement, visit [Core Ultrasound — Basic Cardiac Function](https://coreultrasound.com/basic-cardiac-function/).' WHERE id = 'epss-hf' AND tree_id = 'echo-epss';
UPDATE decision_nodes SET body = E'EPSS is in the grey zone (7–10 mm). **Look for additional signs of fluid overload to help determine if systolic function is truly reduced.**\n\nASSESS B-LINES (Lung Ultrasound)\n• Scan bilateral anterior chest with linear or curvilinear probe\n• B-lines are vertical hyperechoic artifacts extending from the pleural line to the bottom of the screen\n• ≥3 B-lines per intercostal space in ≥2 zones bilaterally = pulmonary edema\n\nASSESS IVC (Subcostal View)\n• Measure IVC diameter and respiratory variation\n• IVC >2.1 cm with <50% collapse on sniff = elevated RA pressure (plethoric IVC)\n• Suggests fluid overload / elevated filling pressures\n\nAre B-lines or IVC plethora present?' WHERE id = 'epss-grey' AND tree_id = 'echo-epss';
UPDATE decision_nodes SET body = E'EPSS 7–10 mm **with** signs of fluid overload (B-lines and/or IVC plethora) supports the diagnosis of reduced left ventricular systolic function.\n\nThe combination of borderline EPSS with pulmonary edema or elevated right-sided pressures increases the likelihood that LVEF is truly reduced.\n\nCLINICAL NEXT STEPS\n• Assess additional echo views (A4C, PSAX) for visual estimation of global function\n• Consider MAPSE as an additional quantitative measure [1][9]\n• Obtain formal echocardiography for quantitative LVEF\n• Initiate heart failure management as clinically indicated\n• Evaluate for underlying etiology (ischemia, valvular disease, cardiomyopathy)\n\nLIMITATIONS REMINDER\nEPSS may be inaccurate in: aortic regurgitation, mitral stenosis, HCM, and non-sinus rhythms. [3]\nPediatric thresholds: 6.0 mm (children), 4.9 mm (age 0–3 years). [8]\n\nFor a video explanation of EPSS measurement, visit [Core Ultrasound — Basic Cardiac Function](https://coreultrasound.com/basic-cardiac-function/).' WHERE id = 'epss-overload' AND tree_id = 'echo-epss';
UPDATE decision_nodes SET body = E'EPSS 7–10 mm **without** signs of fluid overload. The clinical significance is indeterminate.\n\nEPSS specificity is moderate (52%) at the >7 mm threshold [2] — false positives can occur, particularly in this borderline range.\n\nPOSSIBLE EXPLANATIONS\n• Early / compensated systolic dysfunction without volume overload\n• False positive — normal LVEF with borderline EPSS\n• Conditions that affect EPSS accuracy (AR, MS, HCM, non-sinus rhythm)\n\nCLINICAL NEXT STEPS\n• Integrate with visual estimation of global function on multiple views\n• Consider MAPSE (≥10 mm normal, <10 mm suggests reduced LVEF) [1][9]\n• Consider fractional shortening on PSAX (normal ≥25%) [5]\n• Obtain formal echocardiography if clinical suspicion for dysfunction persists\n\nLIMITATIONS REMINDER\nEPSS may be inaccurate in: aortic regurgitation, mitral stenosis, HCM, and non-sinus rhythms. [3]\nPediatric thresholds: 6.0 mm (children), 4.9 mm (age 0–3 years). [8]\n\nFor a video explanation of EPSS measurement, visit [Core Ultrasound — Basic Cardiac Function](https://coreultrasound.com/basic-cardiac-function/).' WHERE id = 'epss-indeterminate' AND tree_id = 'echo-epss';

-- === first-trimester (33 nodes) ===
UPDATE decision_nodes SET body = E'[First Trimester Emergency Steps](#/info/ft-summary) — quick reference.\n\nED approach to pregnancy-related emergencies in the **first trimester** (<14 weeks).\n\nCommon presentations:\n• **Vaginal bleeding** — miscarriage (7-27%), ectopic pregnancy (2%)\n• **Nausea/vomiting** — NVP (85%), hyperemesis gravidarum (3%)\n• **Dysuria/flank pain** — UTI, asymptomatic bacteriuria, pyelonephritis\n• **Abdominal pain** — appendicitis, ovarian torsion, ectopic\n\n**Step 1: Pregnancy test** in ALL reproductive-age women with abdominal pain or vaginal bleeding. [1]' WHERE id = 'ft-start' AND tree_id = 'first-trimester';
UPDATE decision_nodes SET body = E'Assess for hemodynamic instability:\n• Hypotension (SBP <90)\n• Tachycardia (HR >100)\n• Altered mental status\n• Signs of peritonitis\n\n**Paradoxical bradycardia** may occur with hemoperitoneum due to vagal stimulation from peritoneal blood irritation. [3]' WHERE id = 'ft-stability' AND tree_id = 'first-trimester';
UPDATE decision_nodes SET body = E'**Unstable first trimester patient = ruptured ectopic until proven otherwise.** [1]\n\n**Immediate actions:**\n• 2 large-bore IVs, aggressive fluid resuscitation\n• Type & crossmatch, activate MTP if needed\n• **Bedside FAST exam** — free intraperitoneal fluid?\n• **Bedside pelvic ultrasound** — IUP present?\n\n**If free fluid + no IUP → ruptured ectopic:**\n• O-negative blood transfusion\n• **Emergent OB consult for surgical intervention**\n• Do NOT delay for beta-hCG or formal imaging\n\n94% of all ectopic pregnancy-related deaths are from hemorrhagic shock due to rupture. [2]\n\nRupture can occur at **very low beta-hCG levels**. Beta-hCG <1500 mIU/mL carries 2× higher risk of ectopic. [4]' WHERE id = 'ft-unstable-ectopic' AND tree_id = 'first-trimester';
UPDATE decision_nodes SET body = E'Determine the primary presentation to guide workup.\n\nAll stable patients need:\n• Urine pregnancy test (if not done)\n• Focused obstetric history — [gravida/parity (TPAL)](#/info/ft-ob-history), prior ectopic, assisted reproductive technology\n• Focused physical exam including pelvic if indicated' WHERE id = 'ft-stable-branch' AND tree_id = 'first-trimester';
UPDATE decision_nodes SET body = E'**Bedside or formal transvaginal ultrasound** + quantitative beta-hCG.\n\nEmergency physicians have **99.96% negative predictive value** for ectopic when IUP identified on bedside US. [5]\n\n[Ectopic Pregnancy Sites & Risk Factors](#/info/ft-ectopic-risk)\n\n**Risk factors:** prior ectopic, PID/STI history, salpingitis, IUD in situ, smoking (>1 pack/day OR 4), assisted reproductive technology.\n\nNearly **half of patients** with ectopic will have NO risk factors. [1]' WHERE id = 'ft-us-eval' AND tree_id = 'first-trimester';
UPDATE decision_nodes SET body = E'Intrauterine pregnancy confirmed on ultrasound.\n\nIn the **general population**, this essentially **rules out ectopic** (heterotopic risk: 1 in 4,000-30,000).\n\n**Exception — Assisted Reproductive Technology (ART):** Heterotopic pregnancy risk is **1 in 100**. Maintain suspicion if ART patient with IUP + concerning symptoms. [7]\n\nIf the patient has **vaginal bleeding with confirmed IUP**, evaluate for miscarriage spectrum.' WHERE id = 'ft-iup-confirmed' AND tree_id = 'first-trimester';
UPDATE decision_nodes SET body = E'No IUP visualized. Beta-hCG below the **discriminatory zone**.\n\n**Discriminatory zone:** ACOG recommends conservatively ≥3500 mIU/mL (transvaginal US). Below this, a normal IUP may simply be too early to visualize. [8]\n\n**Serial beta-hCG monitoring:**\n• Normal viable IUP: beta-hCG rises **≥53% in 48 hours** [9]\n• Slower rise or plateau: concerning for ectopic or nonviable IUP\n• Declining levels: may indicate completed miscarriage\n\n**CRITICAL:** One-third of patients eventually diagnosed with ectopic had a beta-hCG rise of ≥53% at 48h, and 20% had decline mimicking miscarriage. [10]\n\n**Trends CANNOT reliably exclude ectopic.** Continue serial monitoring until definitive diagnosis.' WHERE id = 'ft-pul' AND tree_id = 'first-trimester';
UPDATE decision_nodes SET body = E'Beta-hCG **≥3500 mIU/mL** with no IUP visualized.\n\nThis strongly suggests a **nonviable pregnancy** — either:\n• Nonviable IUP (missed miscarriage, complete miscarriage)\n• Ectopic pregnancy\n\n**Does not definitively diagnose ectopic.** OB consultation recommended for further evaluation and management.\n\nPatient should have close follow-up with serial beta-hCG and ultrasound until diagnosis is established.' WHERE id = 'ft-no-iup-high' AND tree_id = 'first-trimester';
UPDATE decision_nodes SET body = E'Confirmed or highly suspected ectopic pregnancy.\n\n**All management in consultation with OB.**\n\nDetermine if patient is a candidate for medical vs surgical management.' WHERE id = 'ft-ectopic-confirmed' AND tree_id = 'first-trimester';
UPDATE decision_nodes SET body = E'[Methotrexate](#/drug/methotrexate/ectopic pregnancy) — single-dose IM regimen in consultation with OB.\n\n**Candidates (all must apply):**\n• Hemodynamically stable\n• No fetal cardiac activity (FCA has OR 9.1 for failure) [12]\n• Beta-hCG <5000 mIU/mL (>5000 has OR 5.45 for failure) [11]\n• Reliable for follow-up\n• No contraindications to methotrexate\n\n**Absolute contraindications to methotrexate:**\n• Immunodeficiency\n• Cytopenia (anemia, leukopenia, thrombocytopenia)\n• Active pulmonary disease\n• Active peptic ulcer disease\n• Hepatic or renal dysfunction\n• Breastfeeding [13]\n\n**Follow-up:** Serial beta-hCG at day 4 and day 7 post-injection. Expect decline. If inadequate decline, repeat dose or surgical intervention.' WHERE id = 'ft-ectopic-medical' AND tree_id = 'first-trimester';
UPDATE decision_nodes SET body = E'**Emergent OB consult for surgical intervention.**\n\n**Indications:**\n• Hemodynamic instability / ruptured ectopic\n• Contraindications to methotrexate\n• Beta-hCG >5000 mIU/mL\n• Fetal cardiac activity present\n• Failed medical management\n• Unreliable for follow-up\n\n**Procedures (OB to determine):**\n• **Salpingostomy** — removes ectopic, preserves tube (consider if contralateral tube damaged)\n• **Salpingectomy** — removes entire tube with ectopic (preferred in most cases)\n\nFor ruptured ectopic: **emergent laparotomy**. Do not delay for additional workup.' WHERE id = 'ft-ectopic-surgical' AND tree_id = 'first-trimester';
UPDATE decision_nodes SET body = E'Classify based on **cervical os status** and **ultrasound findings**.\n\n[Miscarriage Types & Findings](#/info/ft-miscarriage-types)\n\nMiscarriage rates: 9-17% (age 20-30), 20% (age 35), 40% (age 40). Approximately half are due to fetal chromosomal abnormalities. [14]\n\n**If fever + uterine tenderness → suspect septic abortion** — emergent OB consult, broad-spectrum IV antibiotics, surgical evacuation.' WHERE id = 'ft-miscarriage-type' AND tree_id = 'first-trimester';
UPDATE decision_nodes SET body = E'Vaginal bleeding with a **viable IUP** (closed cervical os, fetal cardiac activity detected).\n\n**Prognosis:** If fetal cardiac activity is present, only **3.4%** progress to miscarriage. However, heavy bleeding may increase this to 11-18%. [15]\n\nSpotting alone has no significant increase in miscarriage risk (OR 1.1). Heavy bleeding + pain increases risk (OR 3.0). [15]\n\n**Management:**\n• Reassurance — most will have normal pregnancy\n• No evidence supports bed rest\n• Strict return precautions\n• Close OB follow-up\n\n**NOTE:** 2-fold increased risk of subsequent adverse outcomes (preterm birth, low birth weight) — ensure OB is aware. [16]' WHERE id = 'ft-threatened' AND tree_id = 'first-trimester';
UPDATE decision_nodes SET body = E'All products of conception have passed. Uterus is empty on ultrasound. Cervical os is closed.\n\n**Management:**\n• Confirm with ultrasound — empty uterus, closed os\n• No further ED intervention needed\n• Serial beta-hCG should trend to zero\n• OB follow-up for confirmation of completed miscarriage\n• Emotional support and grief resources\n\n[Managing Communication Around Pregnancy Loss](#/info/ft-miscarriage-communication)' WHERE id = 'ft-complete' AND tree_id = 'first-trimester';
UPDATE decision_nodes SET body = E'**OB consultation** for definitive management plan.\n\nOptions for the stable patient (no clear superiority among them): [17]\n\n**If visible products in cervix:** Remove at bedside with ring forceps. Consider sending to pathology (especially in recurrent miscarriage).\n\n**Surgical management is MANDATORY** for patients with significant hemorrhage or hemodynamic instability.' WHERE id = 'ft-nonviable-mgmt' AND tree_id = 'first-trimester';
UPDATE decision_nodes SET body = E'Allow natural passage of products of conception.\n\n**Success rate:** 50-80% will have complete miscarriage within **7-10 days**.\n\nHigher success in incomplete miscarriage (already-open os) vs missed miscarriage.\n\nUp to **40%** of patients initially managed expectantly or medically may ultimately require unplanned surgical management. [19]\n\n**Counsel patient:**\n• Expect cramping and bleeding (may be heavy)\n• Return to ED if soaking >1 pad/hour for 2+ hours, fever, or lightheadedness\n• OB follow-up within 1 week\n\n[Miscarriage Discharge Instructions](#/info/ft-miscarriage-discharge)' WHERE id = 'ft-expectant' AND tree_id = 'first-trimester';
UPDATE decision_nodes SET body = E'[Misoprostol](#/drug/misoprostol/miscarriage) **800 mcg intravaginally** — single dose.\n\n**Efficacy:** 91% effective within 7 days. [18]\n\nHigh patient satisfaction rates when compared to surgical management.\n\nUp to 40% may require unplanned admission or surgical management. [19]\n\n**Contraindications:**\n• Hemodynamic instability (needs surgical evacuation)\n• Septic abortion\n• Confirmed ectopic pregnancy\n\n**Counsel patient:** Expect significant cramping and bleeding. Return precautions for heavy bleeding, fever, or worsening pain.\n\n[Miscarriage Discharge Instructions](#/info/ft-miscarriage-discharge)' WHERE id = 'ft-medical-miscarriage' AND tree_id = 'first-trimester';
UPDATE decision_nodes SET body = E'**Dilation & Curettage (D&C)** — most effective option.\n\n**Indications:**\n• Hemodynamic instability or significant hemorrhage (MANDATORY)\n• Patient preference\n• Failed medical or expectant management\n• Septic abortion\n\n**Advantages:**\n• Lowest rates of incomplete miscarriage, bleeding, and need for transfusion [17]\n• Definitive and rapid\n\nArranged through OB consultation — typically same-day or next-day procedure.\n\nConsider sending products to pathology for analysis, especially in recurrent miscarriage.' WHERE id = 'ft-surgical-miscarriage' AND tree_id = 'first-trimester';
UPDATE decision_nodes SET body = E'**Intrauterine infection** in the setting of miscarriage or therapeutic abortion.\n\n**Presentation:** fever, uterine tenderness, purulent cervical discharge.\n\n**EMERGENT management:**\n• Large-bore IV access, fluid resuscitation\n• Blood cultures\n• Broad-spectrum IV antibiotics (gentamicin + clindamycin + ampicillin)\n• **Emergent OB consult for surgical evacuation**\n• May progress rapidly to sepsis/septic shock\n\nDo not delay surgical evacuation for antibiotic therapy to take effect.' WHERE id = 'ft-septic' AND tree_id = 'first-trimester';
UPDATE decision_nodes SET body = E'**Check Rh status** in all patients with first trimester vaginal bleeding or miscarriage.\n\nACOG 2017: Whether to administer anti-D immune globulin in threatened miscarriage **at or before 12 weeks is controversial** — no evidence-based recommendation can be made. [20]\n\n**Reasonable approach:**\n• **Minimal bleeding, early first trimester:** May withhold\n• **Heavy bleeding or near 12 weeks:** Consider administration\n• **Discuss with your hospital OB department** for institutional policy\n\n**If indicated:**\n• [Rh(D) Immune Globulin](#/drug/rh-immune-globulin/first trimester) 50 mcg IM within 72 hours\n• If 50 mcg unavailable, 300 mcg dose can be substituted\n\n**Only for Rh(D)-negative AND unsensitized patients.**' WHERE id = 'ft-rh-rhogam' AND tree_id = 'first-trimester';
UPDATE decision_nodes SET body = E'**Nausea and vomiting of pregnancy (NVP)** affects 85% of pregnant women. **Hyperemesis gravidarum** (3%) is the most severe form.\n\nNVP is a **diagnosis of exclusion** — rule out other causes first.\n\nNVP is actually **protective** against pregnancy loss (nausea HR 0.44; nausea + vomiting HR 0.20). [21]\n\n[NVP Stepwise Treatment Pathway](#/info/ft-nvp-pathway)\n\n**Assess:** Can the patient tolerate oral medications?' WHERE id = 'ft-nvp-assess' AND tree_id = 'first-trimester';
UPDATE decision_nodes SET body = E'**First-line (ACOG Level A):** [22]\n• [Pyridoxine (B6)](#/drug/pyridoxine/nvp) 10-25 mg PO TID\n• OR [Pyridoxine](#/drug/pyridoxine/nvp) + [Doxylamine](#/drug/doxylamine/nvp) 12.5 mg PO TID\n\n**Non-pharmacologic adjuncts:**\n• **Ginger capsules** 250 mg PO QID\n• **P6 acupressure** wristband (reduced nausea, vomiting, ketonuria in RCT) [23]\n• Convert prenatal vitamin to **folic acid only** (reduces nausea trigger)\n\nPyridoxine + doxylamine is **superior** to pyridoxine alone. [22]\n\nDid first-line therapy improve symptoms?' WHERE id = 'ft-nvp-oral' AND tree_id = 'first-trimester';
UPDATE decision_nodes SET body = E'Add one of the following to pyridoxine ± doxylamine:\n\n• [Dimenhydrinate](#/drug/dimenhydrinate/nvp) 50 mg PO QID (max 200 mg/day if also taking doxylamine)\n• [Diphenhydramine](#/drug/diphenhydramine/nvp) 50 mg PO QID\n• [Prochlorperazine](#/drug/prochlorperazine/nvp) 25 mg PR q12h\n• [Promethazine](#/drug/promethazine/nvp) 12.5 mg PO or PR q6h\n\nNo high-quality evidence supports one specific agent over another. [24]\n\nDid second-line therapy improve symptoms?' WHERE id = 'ft-nvp-oral-step2' AND tree_id = 'first-trimester';
UPDATE decision_nodes SET body = E'**IV fluid resuscitation:**\n• **D5NS** preferred over NS (slightly decreased nausea at 8-16h) [25]\n• Consider adding [Thiamine](#/drug/thiamine/hyperemesis) 100 mg IV if protracted vomiting (prevents Wernicke encephalopathy before glucose administration) [22]\n\n**Lab workup:** BMP (electrolytes, renal function), LFTs, urinalysis (ketonuria)\n\n**IV antiemetics — choose one:**\n• [Metoclopramide](#/drug/metoclopramide/nvp) 10 mg IV q8h — reasonable first choice, no fetal malformation risk\n• [Ondansetron](#/drug/ondansetron/nvp) 8 mg IV over 15 min q12h — effective but possible small risk of fetal cardiac abnormalities [26]\n• [Dimenhydrinate](#/drug/dimenhydrinate/nvp iv) 50 mg IV in 50 mL NS over 20 min q6h\n• [Promethazine](#/drug/promethazine/nvp iv) 12.5 mg IV q6h\n\n**Ondansetron:** Exhaust other options first given possible fetal cardiac risk. [26]\n\nDid IV therapy improve symptoms?' WHERE id = 'ft-nvp-iv' AND tree_id = 'first-trimester';
UPDATE decision_nodes SET body = E'**Hyperemesis gravidarum** — loss of ≥5% prepregnancy body weight with persistent nausea, vomiting, and ketonuria.\n\n**OB consultation and admission for:**\n• Continued IV rehydration (D5NS at 125 mL/hr)\n• Electrolyte monitoring and repletion\n• [Thiamine](#/drug/thiamine/hyperemesis) 100 mg IV daily (prevent Wernicke encephalopathy)\n• Parenteral antiemetic regimen\n• Nutritional assessment\n\nOne quarter of women with severe NVP have considered pregnancy termination due to symptoms. [21]' WHERE id = 'ft-hg-admit' AND tree_id = 'first-trimester';
UPDATE decision_nodes SET body = E'First trimester patients can present with **nonobstetric conditions** that require modified diagnostic and treatment approaches.\n\n[Imaging Safety in Pregnancy](#/info/ft-imaging-safety)\n[Antibiotic Safety in Pregnancy](#/info/ft-abx-safety)' WHERE id = 'ft-nonob-branch' AND tree_id = 'first-trimester';
UPDATE decision_nodes SET body = E'**In pregnancy, asymptomatic bacteriuria MUST be treated** if discovered. Untreated asymptomatic bacteriuria has a 2.4% risk of progression to pyelonephritis (vs 0.6% with treatment). [27]\n\n**Send urine culture** — negative urinalysis does not reliably exclude bacteriuria.\n\n**First-line antibiotics (7-day course):**\n• [Amoxicillin](#/drug/amoxicillin/uti pregnancy) 875 mg PO BID\n• [Cephalexin](#/drug/cephalexin/uti pregnancy) 500 mg PO q6h\n• [Nitrofurantoin](#/drug/nitrofurantoin/uti pregnancy) 100 mg PO BID — likely safe, but ACOG recommends use in first trimester only "when no other suitable alternatives are available" [28]\n\n[Antibiotic Safety in Pregnancy](#/info/ft-abx-safety)\n\nLocal antibiotic resistance patterns should guide empiric therapy.' WHERE id = 'ft-uti-eval' AND tree_id = 'first-trimester';
UPDATE decision_nodes SET body = E'**Admit ALL pregnant patients with pyelonephritis** for initial IV antibiotics. Insufficient evidence for outpatient management. [29]\n\n**Treatment:**\n• [Ceftriaxone](#/drug/ceftriaxone/pyelonephritis pregnancy) 1 g IV daily\n• Continue IV until afebrile 48 hours\n• Transition to oral antibiotics (e.g., [Cephalexin](#/drug/cephalexin/uti pregnancy)) guided by culture sensitivities\n\nBilateral mild hydronephrosis is **normal** in pregnancy (from hormonal changes + uterine compression). Do not over-interpret this finding.\n\nPregnant patients with pyelonephritis have **increased rates of sepsis and septic shock** compared to nonpregnant patients. [1]' WHERE id = 'ft-pyelo' AND tree_id = 'first-trimester';
UPDATE decision_nodes SET body = E'Most common surgical problem in pregnancy, though pregnant women are actually **less likely** to have appendicitis than age-matched nonpregnant women. [30]\n\n**Despite traditional teaching, RLQ pain is the most common location** at all gestational ages. [31]\n\nPeritonitis is more common in pregnant patients with appendicitis (OR 1.3). Peritonitis → 4× higher rate of preterm birth. [32]\n\n**Imaging algorithm:**\n1. **Ultrasound first** — but visualization rate as low as 7%, sensitivity only 18% [33]\n2. **MRI without contrast** — 94% sensitivity, 97% specificity. First trimester MRI is safe (no fetal risk to age 4). [34, 35]\n3. **CT abdomen/pelvis** — if US indeterminate and MRI unavailable. Single study does NOT exceed threshold for fetal harm. Discuss risks/benefits with patient. [36]\n\n**AVOID gadolinium** — associated with stillbirth, neonatal death, and rheumatologic conditions. [35]\n\n[Imaging Safety in Pregnancy](#/info/ft-imaging-safety)\n\n**Treatment: surgical.** No data support antibiotics-only strategy in pregnancy. All patients need surgical consultation. [1]' WHERE id = 'ft-appendicitis' AND tree_id = 'first-trimester';
UPDATE decision_nodes SET body = E'**48-hour follow-up** for repeat beta-hCG and ultrasound.\n\n**Discharge criteria:**\n• Hemodynamically stable\n• Normal vital signs\n• No US evidence of ruptured ectopic\n• Reliable for follow-up\n\n**Strict return precautions:**\n• Severe or worsening abdominal pain\n• Heavy vaginal bleeding (soaking >1 pad/hour)\n• Lightheadedness, dizziness, or syncope\n• Fever\n• Shoulder pain (referred from diaphragmatic irritation)\n\nContinue serial monitoring until definitive diagnosis established (IUP confirmed, ectopic diagnosed, or beta-hCG reaches zero confirming completed miscarriage). [1]' WHERE id = 'ft-dispo-pul' AND tree_id = 'first-trimester';
UPDATE decision_nodes SET body = E'[Miscarriage Discharge Instructions](#/info/ft-miscarriage-discharge) — shareable patient handout\n\n**Provide:**\n• Clear explanation of diagnosis in compassionate, culturally sensitive manner [37]\n• Prescription for chosen management (misoprostol if medical, or expectant instructions)\n• Pain management: ibuprofen 600 mg PO q6h PRN\n• Grief counseling resources and pregnancy-loss support groups [37]\n\n**OB follow-up** within 1-2 weeks.\n\n**Return precautions:**\n• Soaking >1 pad/hour for 2+ consecutive hours\n• Fever >100.4°F (38°C)\n• Foul-smelling discharge\n• Lightheadedness or syncope\n• Persistent heavy bleeding beyond 2 weeks\n\nGrief takes different forms — give permission to grieve in their own way. [37]' WHERE id = 'ft-dispo-miscarriage' AND tree_id = 'first-trimester';
UPDATE decision_nodes SET body = E'**Discharge criteria:**\n• Tolerating oral intake\n• Normal vital signs\n• Electrolytes corrected (if checked)\n• Able to keep down oral medications\n\n**Prescriptions:**\n• [Pyridoxine](#/drug/pyridoxine/nvp) 25 mg PO TID ± [Doxylamine](#/drug/doxylamine/nvp) 12.5 mg PO TID\n• Consider generic pyridoxine + doxylamine instead of brand combination (significantly cheaper)\n• Second-line agent if needed\n\n**Counsel:**\n• Small, frequent meals\n• Avoid triggers (strong smells, fatty/spicy foods)\n• Ginger (250 mg capsules QID) and P6 acupressure wristband as adjuncts\n• OB follow-up within 1 week\n\n**Return if:** unable to keep down fluids for >12 hours, persistent vomiting, lightheadedness, dark urine.' WHERE id = 'ft-dispo-nvp' AND tree_id = 'first-trimester';
UPDATE decision_nodes SET body = E'**Admit if:**\n• Hemodynamic instability\n• Ruptured ectopic (OR)\n• Pyelonephritis (IV antibiotics)\n• Appendicitis (surgical)\n• Hyperemesis gravidarum refractory to ED treatment\n• Septic abortion\n\n**Discharge if:**\n• Hemodynamically stable\n• Diagnosis established or safe plan for outpatient follow-up\n• Able to tolerate oral intake and medications\n• Reliable for follow-up (especially PUL patients — 48h recheck)\n• Adequate pain control\n\n**ALL patients:** OB follow-up arranged. Clear return precautions documented.' WHERE id = 'ft-dispo-general' AND tree_id = 'first-trimester';

-- === hiv (34 nodes) ===
UPDATE decision_nodes SET body = E'[HIV ED Management Steps Summary](#/info/hiv-steps-summary) — quick reference.\n\nHIV is now a manageable chronic disease with HAART, but ~14% of HIV-infected persons remain unaware of their status, driving continued transmission. [1] Approximately 80% of new transmissions are from persons not yet diagnosed or not in regular care.\n\nThe ED plays a critical role in:\n• Identifying undiagnosed HIV infection\n• Managing complications of chronic HIV and its treatment\n• Initiating [PEP](#/tree/pep) for potential exposures\n• Referring candidates for PrEP\n\n**Key first step:** Determine the patient''s HIV disease status — this drives the entire differential diagnosis.' WHERE id = 'hiv-start' AND tree_id = 'hiv';
UPDATE decision_nodes SET body = E'**Ask the patient:**\n• Most recent CD4 count and viral load (or at least if VL is "undetectable")\n• Current antiretroviral medications and compliance\n• Prior opportunistic infections\n• Recent travel or sick contacts\n\nPatients unaware of their CD4/VL or not engaged in care should be considered at **higher risk** for OIs and complications of untreated infection. [4]\n\nCD4 counts and viral load can be ordered from the ED but results will typically not be available for real-time decision-making. An **absolute lymphocyte count <950 cells/mcL** may suggest CD4 <200, though guidelines do not advocate this as a reliable estimate. [5, 6]' WHERE id = 'hiv-status-assess' AND tree_id = 'hiv';
UPDATE decision_nodes SET body = E'[HIV Testing & Screening Guide](#/info/hiv-testing-guide) — universal vs risk-based approach.\n\n**CDC (2006):** Routine opt-out HIV screening for ages 13-64 in healthcare settings where undiagnosed prevalence ≥0.1%. [3]\n**USPSTF (Grade A):** Routine screening ages 15-65. [7]\n**ACEP:** Endorsed ED HIV testing since 2007. [8]\n\n**High-risk patients who should NOT be missed:**\n• Sexually active MSM\n• Persons who inject drugs and their sex partners\n• Persons who exchange sex for money or drugs\n• Sex partners of HIV-infected persons\n• Patients with new STI diagnosis\n\n**Testing technology:**\n• **Fourth-generation (preferred):** Detects HIV antibody + p24 antigen — can identify infection as early as **2 weeks** post-exposure [9]\n• Rapid point-of-care tests available (fingerstick slightly less accurate than lab-based)\n• If acute infection suspected and 4th-gen test negative → **must send HIV viral load**\n\nA 2018 study of >200,000 ED patients showed 0.4% new-diagnosis yield with nontargeted 4th-gen screening, of which 14.5% were acute HIV. [9]' WHERE id = 'hiv-screening' AND tree_id = 'hiv';
UPDATE decision_nodes SET body = E'[Acute Seroconversion Features](#/info/hiv-seroconversion-features) — clinical presentation guide.\n\nAfter HIV exposure, local viral replication occurs over several days before entering the bloodstream with high viremia. **75-90% of patients** develop an acute illness during seroconversion. [1]\n\n**Classic presentation:**\n• Fever, headache, malaise\n• Sore throat (**without exudate**)\n• Lymphadenopathy (generalized)\n• GI symptoms (nausea, diarrhea)\n\n**More distinctive features:**\n• Genital or mucocutaneous ulcers\n• Nondescript **macular rash** (face, trunk, upper extremities) — mimics viral exanthem\n• **Notably absent:** respiratory or pulmonary symptoms\n\nCD4 count may drop acutely during seroconversion, rarely causing OIs (e.g., thrush). CD4 typically rebounds once the body gains some viral control.\n\nThe syndrome lasts **weeks** and patients frequently seek ED evaluation.' WHERE id = 'hiv-seroconversion' AND tree_id = 'hiv';
UPDATE decision_nodes SET body = E'**Diagnosis of acute seroconversion is challenging:**\n\n• Third-generation (antibody-only) tests may miss early infection — **no longer recommended as first-line**\n• **Fourth-generation tests** (antibody + p24 antigen) can often identify infection as early as **2 weeks** post-exposure — preferred initial test [9]\n• Early infection can still be missed within 2 weeks of exposure\n\n**Critical rule:** When acute infection is suspected and 4th-gen test is NEGATIVE → **order HIV viral load.** [9]\n\n**Why diagnosis matters:**\n• Patients with acute infection have **extremely high viral loads** and are more infectious than at any other stage\n• Identification allows prompt referral and rapid ART initiation\n• Undetectable = untransmittable (U=U) — the PARTNER 2 study showed zero transmissions when HIV+ partner had undetectable VL [10, 11]\n\n**Window periods:**\n• 4th-gen test: ~2 weeks\n• 3rd-gen antibody test: ~3-4 weeks\n• Viral load: ~10 days (earliest detection)' WHERE id = 'hiv-seroconversion-testing' AND tree_id = 'hiv';
UPDATE decision_nodes SET body = E'**Confirmed or highly suspected new HIV infection:**\n\n**Immediate actions:**\n• Baseline labs: CBC, BMP, hepatic function, CD4 count, viral load\n• Screen for co-infections: hepatitis B, hepatitis C, syphilis (RPR/VDRL), other STIs\n• Pregnancy test if applicable\n\n**Rapid ART initiation:**\nCurrent HHS and IAS-USA guidelines recommend **same-day initiation** of ART for newly diagnosed patients — reduces time to viral suppression and improves linkage to care. [12, 13]\n\nMost initial regimens use an **INSTI + 2 NRTIs:**\n• [Biktarvy](#/drug/biktarvy/hiv treatment) (BIC/FTC/TAF) — preferred single-tablet regimen\n• [TDF/FTC](#/drug/tdf-ftc/hiv prep) + [Dolutegravir](#/drug/dolutegravir/hiv pep)\n\n**ED role:**\n• Urgent referral to HIV specialist for same-day or next-day appointment\n• Ensure baseline labs are drawn\n• Counsel on transmission risk and safe practices\n• Document for linkage-to-care programs\n\n**If the patient has acute seroconversion illness,** treat symptoms supportively while expediting referral.' WHERE id = 'hiv-new-diagnosis' AND tree_id = 'hiv';
UPDATE decision_nodes SET body = E'Patients with **well-controlled HIV** (CD4 >200, undetectable VL, treatment-adherent) are living longer and now present with **typical diseases of aging**, adverse medication effects, and chronic inflammatory state complications rather than OIs. [14]\n\nTreat these patients similarly to immunocompetent individuals, with attention to:\n• Higher baseline cardiovascular risk\n• Chronic inflammatory state → hypercoagulability\n• Medication side effects and interactions\n\nWhat is the primary complaint?' WHERE id = 'hiv-well-controlled' AND tree_id = 'hiv';
UPDATE decision_nodes SET body = E'**Well-controlled HIV patients** develop **traditional pulmonary infections** of immunocompetent patients. **Streptococcus pneumoniae** is the most common cause of bacterial pneumonia — treatment does not differ from non-HIV patients. [15, 16]\n\n**Disposition** can mirror practice for non-HIV patients, as well-controlled patients have similar pneumonia mortality. CURB-65 can be applied, though one small study found higher mortality with scores ≥2 AND CD4 <200. [17]\n\n**COPD** is an increasing concern:\n• HIV patients smoke at **2× the rate** of the general population [18]\n• Lung injury from prior OIs and drug effects contribute\n• Chronic HIV may be an independent risk factor [19]\n• Treatment is the same as for non-HIV patients\n\n**Venous thromboembolism / PE:**\n• Chronic inflammatory state → **hypercoagulability** → higher VTE rates [20, 21]\n• Consider PE with pleuritic chest pain, dyspnea — even if COPD is known\n• PERC criteria may not be validated for HIV patients (HIV status not reported in original study)\n\n**Key pitfall:** Do not anchor on COPD for an HIV patient with pleuritic chest pain — consider PE.' WHERE id = 'hiv-respiratory' AND tree_id = 'hiv';
UPDATE decision_nodes SET body = E'HIV patients have **increased cardiovascular risk** from multiple factors: traditional risk factors, chronic inflammatory state, and medication effects (metabolic syndrome, abacavir MI association). [22, 23]\n\n**Acute coronary syndromes:**\n• HIV and some treatments are associated with CAD **absent traditional risk factors**\n• Abacavir has been associated with MI in retrospective studies (not yet confirmed prospectively) [24, 25]\n• Do NOT dismiss ACS in younger HIV patients — age alone does not rule it out\n\n**Heart failure:**\n• Prevalence 7.2% in HIV vs 4.4% in controls (P <.0001) [26]\n• Hazard ratio 3.2 for developing HF compared to non-HIV patients [27]\n• Only slightly lower rates even in patients on ARVs\n\n**Venous thromboembolism:**\n• 2.6 per 1000 patient-years [28]\n• Risk factors: CD4 <200, VL >100,000, current/recent OIs [29]\n• Chronic inflammatory state is the primary driver\n\n**Management:** Standard evidence-based protocols. Be aware of **drug interactions** between ARVs and anticoagulants, statins, and antiarrhythmics — especially with PI-based regimens.' WHERE id = 'hiv-cardiovascular' AND tree_id = 'hiv';
UPDATE decision_nodes SET body = E'**Guide evaluation by CD4 count.** Even well-controlled HIV carries slightly higher cerebrovascular risk.\n\n**Stroke:**\n• Risk ratio **2.56** (95% CI 1.43-4.61) compared to non-HIV [30]\n• Multifactorial: inflammatory state, atherosclerosis, smoking, metabolic medication effects\n• Follow standard evidence-based stroke algorithms\n\n**HIV-associated neurocognitive disorder (HAND):**\n• Most frequently identified neurologic disorder in HIV\n• Subacute cognitive deficits, central motor abnormalities, behavioral changes\n• Does NOT meet criteria for dementia\n• Rates decrease with longer periods of undetectable virus [31]\n\n**CNS OIs** (toxo, crypto, PML) are rare with well-controlled disease but increase dramatically with CD4 <200 → see [Immunocompromised pathway](#/node/hiv-cns-oi)\n\n**Imaging considerations:**\n• Immunocompetent HIV patient with headache probably does not need CT\n• But if CD4 is decreasing → CNS OIs and malignancy risk increases → neuroimaging indicated\n• CT may require **contrast** to identify infections or lymphoma\n• MRI provides better identification of smaller lesions and leptomeningeal enhancement\n• LP required if meningitis suspected' WHERE id = 'hiv-neuro' AND tree_id = 'hiv';
UPDATE decision_nodes SET body = E'**Diarrhea** is one of the most common HIV presentations in the ED. Up to **60% of patients on treatment** report an episode in the prior month. [32]\n\n**In well-controlled patients, OIs are rarely the cause.** More common etiologies:\n• **Medication side effect** — leading diagnosis for isolated diarrhea [33]\n• HIV enteropathy\n• Same pathogens that affect non-HIV individuals\n\n**Critical exception: C. difficile** — more common in HIV than non-HIV patients. Careful history for recent antibiotics or hospitalizations. [34]\n\n**Hepatobiliary disease:**\n• **61% of HIV patients are co-infected with HCV** in a large US analysis [35]\n• 10% co-infected with HBV [36]\n• Nearly all ARVs have hepatotoxicity potential, worsened by viral hepatitis co-infection\n• ED visit is an opportunity to **screen for HCV** in HIV patients not previously tested\n\n**Atazanavir** (PI) inhibits UDP-glucuronosyltransferase → **indirect hyperbilirubinemia and jaundice** — benign, resolves when drug is stopped.\n\n**Key pitfall:** Do not assume diarrhea is always a medication side effect — exclude C. difficile and assess for red flags.' WHERE id = 'hiv-gi' AND tree_id = 'hiv';
UPDATE decision_nodes SET body = E'Renal disease can be caused by HIV infection itself AND nephrotoxic medications.\n\n**Tenofovir disoproxil fumarate (TDF) nephrotoxicity:**\n• Can cause **Fanconi syndrome** — polyuria, polydipsia, dehydration [37]\n• Labs: elevated creatinine, reduced GFR, acidemia, hypochloremia, hypokalemia, hypophosphatemia\n• UA: glucosuria, proteinuria\n• Higher risk in patients with pre-existing renal impairment\n• **TAF (tenofovir alafenamide)** has reduced risk — better renal biomarkers out to 144 weeks [38]\n• Withhold TDF and other nephrotoxins (e.g., ibuprofen) while resuscitating\n\n**PI-associated nephrolithiasis (CRITICAL for ED):**\n• [Atazanavir](#/drug/atazanavir/nephrolithiasis) and indinavir cause kidney stones\n• PIs have poor solubility + significant urinary excretion → stone formation\n• **Stones are RADIOLUCENT** if composed purely of drug metabolites [39, 40]\n• May NOT be visible on standard noncontrast CT\n• Look for **secondary signs**: hydroureter, perinephric stranding\n• If ongoing symptoms → urology consult for ureteroscopy\n• Discuss with HIV provider regarding medication adjustment\n\n**AKI treatment** is the same as for non-HIV patients.' WHERE id = 'hiv-renal' AND tree_id = 'hiv';
UPDATE decision_nodes SET body = E'[HIV System-Based Complications](#/info/hiv-system-complications) — comprehensive reference.\n\n**Hematologic:**\n• Cytopenias of all cell lines common — bone marrow suppression in uncontrolled HIV\n• Medication-induced anemia often macrocytic (diagnosis of exclusion) [28]\n• Higher VTE rates (2.6/1000 patient-years)\n• Evaluate for thrombotic thrombocytopenic purpura (TTP) if hemolytic anemia + thrombocytopenia [41]\n\n**Endocrine & Metabolic:**\n• Metabolic syndrome: dyslipidemia, insulin resistance, truncal obesity (HIV-associated lipodystrophy) [42, 43]\n• Thyrotoxicosis/Graves disease with immune reconstitution (IRIS) — 8-33 months after starting HAART [44]\n• Glucocorticoid deficiency from adrenal involvement in AIDS — consider in hypotensive AIDS patients\n• Diabetes: both ARVs (especially PIs) and chronic inflammation increase risk [45]\n\n**Musculoskeletal:**\n• Lower bone mineral density → increased **fracture risk** [46, 47]\n• Higher rates of **avascular necrosis** — HIV and ARVs both implicated\n• As CD4 drops: spinal infections, osteomyelitis, discitis, atypical organisms (TB, NTM) [48]\n\n**Psychiatric:**\n• Depression, anxiety, substance use disorders are highly prevalent [49]\n• **Demoralization syndrome** — similar to depression but without anhedonia; does NOT respond to antidepressants\n• New-onset mania → evaluate for organic etiology (especially in untreated disease)\n• Screen all HIV patients for suicidal/homicidal ideation\n\n**Dermatologic:**\n• Drug-related skin reactions common → medication noncompliance [50]\n• Folliculitis (MRSA most common pathogen), HSV, HPV warts, seborrheic dermatitis, molluscum\n• Disseminated VZV in poorly controlled HIV — can cross dermatomes, may be superinfected' WHERE id = 'hiv-other-systems' AND tree_id = 'hiv';
UPDATE decision_nodes SET body = E'**Weakness is one of the most challenging presentations** in HIV patients.\n\nCommon causes of weakness in non-HIV patients are also common in HIV:\n• **Sepsis** — from any source\n• **Metabolic:** Hypoglycemia, electrolyte derangements (K+, Ca2+, Na+)\n• **Carbon monoxide poisoning** (in winter months)\n• **Anemia** — medication-induced or HIV-related\n\n**HIV-specific considerations:**\n• **OIs** (if CD4 <200 or unknown) — PJP, TB, disseminated MAC\n• **Medication adverse effects** — lactic acidosis (rare with current NRTIs), Fanconi syndrome (TDF)\n• **Adrenal insufficiency** — consider in AIDS patients with hypotension\n• **Malignancy** — lymphoma, Kaposi sarcoma\n\n**Workup:**\n• CBC, BMP (glucose, K+, Ca2+, Na+), hepatic function, lactate, VBG\n• If CD4 unknown or <200: expand workup (cultures, CXR, CT as indicated)\n• Consider serum lactic acid if anion gap metabolic acidosis or severe illness\n• CD4 and viral load (results not available for ED decisions but guide outpatient management)\n\n**HIV patients receive ~4.5 lab tests per ED visit** compared to 3.5 for non-HIV patients. [4]' WHERE id = 'hiv-weakness' AND tree_id = 'hiv';
UPDATE decision_nodes SET body = E'Patient has **CD4 <200, detectable viral load, not in care, or unknown status.** These patients are at risk for opportunistic infections AND chronic disease complications.\n\n**AIDS** is defined by CD4 <200 cells/mcL OR development of certain OIs or cancers.\n\n**After acute illness, untreated HIV has ~8-10 years of clinical latency** before AIDS develops. Many remain asymptomatic but have lymphadenopathy. Chronic untreated infection causes a persistent inflammatory state predisposing to CAD, VTE, and COPD. [1]\n\nWhat is the primary concern?' WHERE id = 'hiv-immunocompromised' AND tree_id = 'hiv';
UPDATE decision_nodes SET body = E'**Pneumocystis jirovecii pneumonia (PJP):**\n• Classic: indolent, **nonproductive cough** + exertional dyspnea\n• CXR: perihilar or **"batwing" infiltrate** (see image below)\n• **LDH typically elevated** — a normal LDH helps rule OUT PJP [51]\n• LDH is not specific (elevated in lymphoma, TB, toxoplasmosis)\n• Prophylaxis: [TMP-SMX](#/drug/tmp-smx/pjp prophylaxis) when CD4 <200\n\n**Tuberculosis:**\n• HIV patients at increased risk for both novel infection and reactivation\n• Risk increases with poorly controlled infection\n• In the US, most common in persons who inject drugs\n• Consider in any HIV patient with cough, fever, weight loss, night sweats\n\n**With disease progression and advanced immunosuppression:**\n• At risk for drug-resistant and atypical organisms\n• Consider expanding antibiotic coverage\n• Consult infectious disease\n\n**Treatment for common pneumonias** (Strep. pneumoniae) is the same as for non-HIV patients. [15, 16]' WHERE id = 'hiv-pulm-oi' AND tree_id = 'hiv';
UPDATE decision_nodes SET body = E'CNS OIs typically do **not appear until CD4 <200.** Rates have decreased significantly with treatment adherence.\n\n**Toxoplasmosis:**\n• Ring-enhancing mass lesion(s) on contrast CT or MRI\n• Fever, headache, focal neurologic deficits, seizures\n• Most common CNS mass lesion in AIDS\n\n**Cryptococcal meningitis:**\n• Subacute headache, fever, meningismus\n• May have only headache with subtle findings\n• LP with opening pressure (often elevated), CSF cryptococcal antigen, India ink\n\n**Progressive multifocal leukoencephalopathy (PML):**\n• JC virus — progressive white matter lesions\n• Subacute cognitive decline, focal deficits without fever\n• No effective antiviral — treatment is immune reconstitution with ART\n\n**CNS lymphoma:**\n• Ring-enhancing lesion (can mimic toxoplasmosis)\n• Often periventricular\n\n**Imaging considerations:**\n• **Nonenhanced CT may miss lesions** — contrast required\n• **MRI is superior** for smaller lesions and leptomeningeal enhancement\n• LP required for suspected meningitis/encephalitis\n\n**Key pitfall:** Do not accept a normal nonenhanced CT in an immunocompromised patient with neurologic symptoms — get contrast or MRI.' WHERE id = 'hiv-cns-oi' AND tree_id = 'hiv';
UPDATE decision_nodes SET body = E'As CD4 drops, GI OI risk increases significantly.\n\n**C. difficile** — more common in HIV vs non-HIV patients regardless of CD4 count. Careful history: recent antibiotics, hospitalizations. [34]\n\n**With progressive immunosuppression (CD4 <100-200):**\n• **Cryptosporidium** — watery diarrhea, can be chronic/severe\n• **Cytomegalovirus (CMV)** — bloody diarrhea, colitis, can cause perforation\n• **Microsporidiosis** — chronic watery diarrhea\n• **Mycobacterium avium complex (MAC)** — fever, weight loss, diarrhea, hepatosplenomegaly (usually CD4 <50)\n\n**Stool studies** guided by disease stage:\n• All patients: C. difficile toxin, bacterial cultures, ova/parasites\n• Immunosuppressed: add AFB stool culture, Cryptosporidium antigen, microsporidium stain, CMV evaluation\n\n**Key point:** Initiation of ART to restore GI immune function will help eradicate many of these OIs. Link patients to HIV care.\n\n**Hepatobiliary OIs:**\n• Acalculous cholecystitis (CMV, Cryptosporidium)\n• MAC hepatitis\n• Peliosis hepatis (Bartonella)' WHERE id = 'hiv-gi-oi' AND tree_id = 'hiv';
UPDATE decision_nodes SET body = E'**Constitutional symptoms:**\n• Fever, weight loss, night sweats → evaluate for disseminated MAC, TB, lymphoma\n• Pancytopenia from bone marrow suppression\n\n**Dermatologic:**\n• **Kaposi sarcoma** — purple-red nodular lesions (HHV-8 associated)\n• Disseminated VZV — can cross dermatomes, may be superinfected\n• Severe molluscum contagiosum, extensive seborrheic dermatitis\n• Oral hairy leukoplakia (EBV — cannot be scraped off, unlike thrush)\n\n**Ocular:**\n• **CMV retinitis** (CD4 <50) — "pizza pie" fundoscopy, painless vision loss\n• Refer urgently to ophthalmology\n\n**Oropharyngeal:**\n• Oral candidiasis (thrush) — suggests CD4 <200\n• Oral hairy leukoplakia\n• Aphthous ulcers\n\n**When to strongly consider AIDS:**\n• CD4 <200 (by definition) or CD4 unknown\n• Any OI or AIDS-defining cancer\n• Recurrent bacterial pneumonia\n• Cervical cancer, lymphoma\n\n**All immunocompromised patients need:**\n• Comprehensive physical exam including oral mucosa and skin\n• Low threshold for imaging\n• Infectious disease consultation' WHERE id = 'hiv-other-oi' AND tree_id = 'hiv';
UPDATE decision_nodes SET body = E'**Low threshold for admission** in immunocompromised HIV patients.\n\n**Admit if:**\n• Suspected or confirmed OI requiring inpatient treatment (PJP, cryptococcal meningitis, toxoplasmosis, CMV)\n• Hemodynamic instability, sepsis\n• CNS symptoms with abnormal imaging or LP\n• Inability to tolerate oral medications or nutrition\n• Social barriers to outpatient follow-up\n\n**If discharging:**\n• Urgent follow-up with HIV specialist or infectious disease (within 24-72 hours)\n• Ensure patient has access to medications\n• Emphasize linkage to care — this is a critical opportunity\n• Start or resume OI prophylaxis if indicated ([TMP-SMX](#/drug/tmp-smx/pjp prophylaxis) for CD4 <200)\n\n**Do NOT stop HAART** for GI side effects or most complaints — viral resistance develops with inconsistent compliance. Very few scenarios warrant stopping: **Stevens-Johnson syndrome** and **nevirapine-associated hepatic failure** are clear indications. [1]\n\n**Involve the patient''s HIV provider** or ID consultant in all decisions to modify or stop ART.' WHERE id = 'hiv-immunocompromised-disposition' AND tree_id = 'hiv';
UPDATE decision_nodes SET body = E'[ARV Drug Classes & Side Effects](#/info/hiv-arv-classes) — comprehensive reference table.\n\nMost current regimens use an **INSTI + 2 NRTIs** (e.g., Biktarvy). INSTI-based regimens are preferred for tolerability, reduced pill burden, and faster viral suppression. [12, 13]\n\nWhich drug class or concern?' WHERE id = 'hiv-med-overview' AND tree_id = 'hiv';
UPDATE decision_nodes SET body = E'NRTIs/NtRTIs inhibit reverse transcription of HIV RNA into DNA. Current drugs are relatively well tolerated. [12]\n\n**Tenofovir disoproxil fumarate (TDF):**\n• **Fanconi syndrome** — polyuria, polydipsia, dehydration, elevated creatinine [37]\n• Labs: acidemia, hypokalemia, hypophosphatemia, glucosuria, proteinuria\n• Bone density loss and fractures\n• **TAF** (tenofovir alafenamide) has reduced renal and bone toxicity [38]\n\n**Abacavir:**\n• **Hypersensitivity reaction** in 3-5% — fever, rash, GI/respiratory symptoms, usually within first 6 weeks [52]\n• Associated with **HLA-B*5701 allele** — screening is mandatory before starting\n• If HLA-B*5701 positive → abacavir is **contraindicated**\n• **NEVER rechallenge** after hypersensitivity — can be fatal\n• Retrospective association with **myocardial infarction** (not confirmed prospectively) [24, 25]\n\n**Class effects (rare with current drugs):**\n• GI upset, nausea, headache, insomnia\n• Lactic acidosis — extremely rare with current regimens\n• Transaminitis — rare\n\n**For PrEP:** Both TDF/FTC and TAF/FTC are FDA-approved. TAF/FTC is NOT approved for use in heterosexual women (not studied). [53, 54]' WHERE id = 'hiv-nrti-effects' AND tree_id = 'hiv';
UPDATE decision_nodes SET body = E'NNRTIs directly bind and inactivate HIV reverse transcriptase. Examples: efavirenz, rilpivirine, doravirine, nevirapine, etravirine.\n\n**Efavirenz — neuropsychiatric effects:**\n• Vivid dreams, nightmares, insomnia, confusion (often resolve after first weeks) [55]\n• **Severe cases:** psychosis, suicidal ideation, attempted/completed suicide\n• **Immediate discontinuation** if severe psychosis or suicidality\n• Often avoided in patients with psychiatric history\n• Rilpivirine: may cause insomnia/depression but lower risk than efavirenz [13]\n\n**Doravirine (newest NNRTI):**\n• Fewer CNS adverse events than efavirenz [56, 57]\n• Favorable lipid profile\n• Most commonly used in treatment-experienced patients with limited options\n\n**Skin reactions (all NNRTIs):**\n• Rash, GI upset, headache, dizziness — common\n• Infrequently: **Stevens-Johnson syndrome, toxic epidermal necrolysis, erythema multiforme** (more common with nevirapine)\n\n**Nevirapine — hepatotoxicity:**\n• FDA black box warning (2000)\n• Most frequent in first 6 weeks\n• Higher risk: chronic hepatitis, female CD4 >250, male CD4 >400 [12, 13]\n• Can cause liver failure' WHERE id = 'hiv-nnrti-effects' AND tree_id = 'hiv';
UPDATE decision_nodes SET body = E'PIs prevent cleavage of essential polyproteins needed for mature HIV virion production. Most common today: **atazanavir** and **darunavir**, used with a booster (low-dose ritonavir or cobicistat). [13]\n\n**Common side effects:** Nausea, diarrhea, abdominal discomfort.\n\n**Metabolic effects:**\n• Lipodystrophy (central fat accumulation, peripheral wasting)\n• Dyslipidemia, hypertriglyceridemia\n• Type 2 diabetes (less common with lower-dose ritonavir boosting)\n• Rarely: pancreatitis from hypertriglyceridemia\n\n**[Atazanavir](#/drug/atazanavir/hiv jaundice):**\n• Inhibits UDP-glucuronosyltransferase → **indirect hyperbilirubinemia and jaundice** — benign, resolves on discontinuation\n• **RADIOLUCENT kidney stones** — PIs have poor solubility and significant urinary excretion [39, 40]\n• Stones may NOT be seen on noncontrast CT — look for hydroureter, perinephric stranding\n• Requires **acidic environment** for absorption → PPIs and H2 blockers may interfere\n\n**Drug interactions (CRITICAL):**\n• PIs (especially boosted with ritonavir/cobicistat) inhibit **CYP3A4** → major interactions with anticoagulants, statins, corticosteroids, antiarrhythmics, antiepileptics, antidepressants [13]\n• Much higher interaction risk than INSTI or NNRTI regimens\n• See [Drug Interactions](#/node/hiv-drug-interactions)' WHERE id = 'hiv-pi-effects' AND tree_id = 'hiv';
UPDATE decision_nodes SET body = E'**Integrase strand transfer inhibitors (INSTIs):** Block incorporation of viral DNA into host cell DNA. First-line for most patients. [12, 13]\n\nExamples: [Biktarvy](#/drug/biktarvy/hiv treatment) (bictegravir), [Dolutegravir](#/drug/dolutegravir/hiv pep), elvitegravir/cobicistat, raltegravir.\n\n**Generally very well tolerated** — rare discontinuations in clinical trials.\n• ~90% of patients attain and maintain undetectable VL through 96 weeks [58]\n• Raltegravir has the lowest drug interaction risk\n• Elvitegravir requires cobicistat booster → higher drug interaction risk and GI intolerance\n\n**Dolutegravir pregnancy concern:**\n• Initial Botswana data showed 4 neural tube defects in dolutegravir-exposed pregnancies [59]\n• Subsequent studies: risk exists but is lower than initially feared\n• **Review guidelines before using dolutegravir for PEP in women of childbearing age**\n\n**Entry inhibitors (rarely used):**\n• **Enfuvirtide** — injection site nodules; largely replaced by INSTIs\n• **Maraviroc** — CCR5 blocker; rare hepatotoxicity, hypotension with renal impairment\n• **Ibalizumab** — monoclonal antibody; hypersensitivity risk during/after infusion\n• Reserved for treatment-experienced patients with limited options' WHERE id = 'hiv-insti-effects' AND tree_id = 'hiv';
UPDATE decision_nodes SET body = E'**CRITICAL:** Several NRTIs/NtRTIs have dual activity against HIV AND hepatitis B:\n• **Tenofovir alafenamide (TAF)**\n• **Tenofovir disoproxil fumarate (TDF)**\n• **Emtricitabine (FTC)**\n• **Lamivudine (3TC)**\n\n**If a patient co-infected with HBV stops any of these medications**, there is risk of **acute hepatitis B flare** — fatalities have been reported. [1, 36]\n\n~10% of HIV patients are co-infected with HBV. [36]\n\n**ED presentation:**\n• Patient recently stopped or ran out of ARV medication\n• Elevated transaminases, jaundice, RUQ pain\n• May progress to fulminant hepatic failure\n\n**Management:**\n• Supportive care\n• **Consult infectious disease** for treatment options and reinitiation of therapy\n• Evaluate for other etiologies of hepatitis in parallel\n• Do NOT delay specialist consultation\n\n**When to stop HAART (very few scenarios):**\n• Stevens-Johnson syndrome\n• Nevirapine-associated hepatic failure\n• All other decisions to stop → involve HIV provider' WHERE id = 'hiv-hbv-caution' AND tree_id = 'hiv';
UPDATE decision_nodes SET body = E'**PI-based regimens** (especially boosted with ritonavir or cobicistat) carry the highest risk of drug interactions through **CYP3A4 inhibition**. [13]\n\n**High-risk combinations in the ED:**\n• **Anticoagulants** — warfarin, DOACs: altered metabolism\n• **Statins** — lovastatin and simvastatin contraindicated with PIs; use atorvastatin/rosuvastatin with dose adjustment\n• **Corticosteroids** — fluticasone + ritonavir → iatrogenic Cushing syndrome\n• **Antiarrhythmics** — amiodarone, flecainide, lidocaine: levels may be dangerously altered\n• **Antiepileptics** — carbamazepine, phenytoin: bidirectional interactions\n• **Antimalarials, antidepressants** — various interactions\n\n**INSTI-based regimens** have fewer interactions but:\n• Dolutegravir/bictegravir: chelation with polyvalent cations (antacids, Ca2+, Fe2+)\n• Dolutegravir increases metformin levels\n\n**Atazanavir absorption** requires acidic environment — PPIs and H2 blockers interfere.\n\n**Before prescribing any new medication** to an HIV patient on PIs:\n• Use an HIV drug interaction checker\n• When in doubt, consult pharmacy or infectious disease\n\n**Key ED takeaway:** Always check drug interactions when prescribing to HIV patients, especially those on PI-based or cobicistat-boosted regimens.' WHERE id = 'hiv-drug-interactions' AND tree_id = 'hiv';
UPDATE decision_nodes SET body = E'The ED plays a vital role in preventing new HIV infections through PEP and PrEP awareness. [1, 60]\n\nWhich prevention scenario?' WHERE id = 'hiv-prevention' AND tree_id = 'hiv';
UPDATE decision_nodes SET body = E'**PEP is most effective when given ASAP** — ideally within 2 hours of exposure.\n\n**NOT recommended when care is sought >72 hours after exposure.** [60]\n\n**Indications:** Sexual exposure, needlestick/percutaneous, mucous membrane exposure, sexual assault.\n\n**Preferred regimens (28 days):**\n• [Biktarvy](#/drug/biktarvy/hiv pep) 1 tablet daily — preferred single-tablet regimen\n• [TDF/FTC](#/drug/tdf-ftc/hiv pep) + [Dolutegravir](#/drug/dolutegravir/hiv pep) — alternative\n• [TDF/FTC](#/drug/tdf-ftc/hiv pep) + [Darunavir](#/drug/darunavir/hiv pep)/[Ritonavir](#/drug/ritonavir/hiv pep) — second alternative\n\n**Baseline testing:** HIV test on exposed patient.\n\n**Adherence is critical:** One study showed <60% follow-up rates and <25% completed full 28-day course. [61] Emphasize adherence and arrange follow-up.\n\n**For the complete PEP decision pathway** including exposure risk assessment, special populations, and follow-up: [Post Exposure Prophylaxis Consult](#/tree/pep)\n\nRisk of transmission depends on type of exposure and viral load of source. Undetectable viral load = virtually zero transmission risk (PARTNER 2 study). [10]' WHERE id = 'hiv-pep-overview' AND tree_id = 'hiv';
UPDATE decision_nodes SET body = E'**PrEP is highly effective:** PROUD trial showed **86% relative risk reduction** in HIV acquisition. IPREX and DISCOVER studies showed >90% reduction with daily adherence. [53, 54, 62]\n\n**FDA-approved PrEP regimens:**\n• [TDF/FTC](#/drug/tdf-ftc/hiv prep) (Truvada®) — approved for all genders\n• TAF/FTC (Descovy®) — approved for MSM and transgender women only (women not studied) [54]\n\n**PrEP follow-up protocol:**\n• Daily medication, follow-up every 3 months\n• HIV testing at each visit\n• STI symptom assessment, side effect evaluation\n• Renal function at 3 months, then every 6 months [53]\n\n**Who to refer from the ED:**\n• MSM (especially with recent STI diagnosis) [63, 64]\n• Persons who inject drugs and their sex partners\n• Persons exchanging sex for money or drugs\n• Sex partners of HIV-infected persons with detectable VL\n• Any patient requesting PrEP information\n\n**ED role:** Educate, provide referral to PrEP provider. Do NOT start PrEP from the ED without baseline HIV testing and renal function.' WHERE id = 'hiv-prep-referral' AND tree_id = 'hiv';
UPDATE decision_nodes SET body = E'**Admission criteria:**\n• Suspected or confirmed OI requiring inpatient treatment\n• Hemodynamic instability, sepsis, respiratory failure\n• CNS symptoms with concerning imaging or LP findings\n• New diagnosis with acute seroconversion illness and complications\n• Inability to tolerate oral medications\n• Social barriers to safe discharge and follow-up\n\n**Orders:**\n• Continue home HAART regimen (do NOT hold unless directed by ID)\n• Infectious disease consultation for OI management\n• CD4 count and viral load if not recently available\n• Screen for co-infections (HBV, HCV) if not previously documented\n• Medication reconciliation — alert pharmacy to ARV drug interactions\n\n**If patient has fallen out of care:**\n• Social work consultation for linkage to HIV services\n• This hospitalization is an opportunity to re-engage the patient in treatment' WHERE id = 'hiv-admit' AND tree_id = 'hiv';
UPDATE decision_nodes SET body = E'**Discharge criteria:**\n• Stable vital signs, able to tolerate PO\n• No suspected OI requiring inpatient treatment\n• Well-controlled HIV with manageable complaint\n• Reliable follow-up available\n\n**Discharge instructions:**\n• Continue all HIV medications as prescribed — **do NOT stop HAART**\n• Follow up with HIV provider within 1-2 weeks (or sooner per complaint)\n• Return for worsening symptoms, new fever, inability to take medications\n\n**Linkage to care opportunities:**\n• If not engaged in HIV care → provide contact information for local HIV clinic\n• If PEP started → arrange follow-up in 3-7 days for adherence check\n• If PrEP candidate identified → refer to PrEP provider\n• If newly diagnosed → urgent HIV specialist referral (same day if possible)\n• If untested → offer HIV testing before discharge or provide referral\n\n**The ED visit is a critical touchpoint** — 80% of new transmissions come from those not diagnosed or not in care. Identifying and linking these patients is one of the highest-impact interventions the ED can provide. [1]\n\n[Discharge Instructions](#/info/hiv-ed-discharge) — shareable patient handout' WHERE id = 'hiv-discharge' AND tree_id = 'hiv';

-- === ich (17 nodes) ===
UPDATE decision_nodes SET body = E'[ICH Steps Summary](#/info/ich-summary) — time-critical hemorrhage management.\n\nSpontaneous ICH accounts for 10–15% of all strokes with ~40% 30-day mortality. Early hemostatic therapy, BP control, and neurosurgical consultation are the cornerstones of acute management.\n\n**Immediate actions:**\n• Non-contrast CT head — confirm diagnosis, estimate hematoma volume\n• Establish IV access ×2\n• Activate stroke/neurosurgery team\n• NPO (potential surgical candidate)\n\n**Do NOT delay anticoagulant reversal while awaiting labs** — empiric reversal should be given immediately if clinical suspicion of anticoagulant use is high.' WHERE id = 'ich-start' AND tree_id = 'ich';
UPDATE decision_nodes SET body = E'**Initial labs:**\n• CBC, BMP, Mg, Phos\n• INR, PTT, fibrinogen\n• Anti-Xa level if on oral Xa inhibitors (apixaban, rivaroxaban)\n• Toxicology screen (if clinically warranted)\n• Type & screen\n• ABG/VBG if intubated\n\n**Hematoma volume (ABC/2):**\nA × B × C ÷ 2 (cm) = volume in mL\n• A = largest diameter on axial CT\n• B = perpendicular diameter on same slice\n• C = number of slices with hemorrhage × slice thickness\n• <30 mL = relatively favorable prognosis\n• >30 mL = moderate-to-severe\n\n[CT Markers of Expansion](#/info/ich-ct-markers) — swirl sign, black hole sign, spot sign\n\n**CT Angiography:** Obtain for nearly all patients unless classic hypertensive location in an older patient. **Mandatory** if:\n• Lobar ICH in patient <70 years\n• Deep/posterior fossa ICH in patient <45 years\n• Deep ICH in patient 45–70 without hypertension history\n\n**Serial CT:** Repeat at ~6h and 24h for stable patients. More frequent if neuro decline or sedated.' WHERE id = 'ich-labs' AND tree_id = 'ich';
UPDATE decision_nodes SET body = E'**Determine anticoagulant/antiplatelet status immediately.**\n\nDo NOT wait for lab results before initiating reversal — empiric reversal should begin as soon as the agent is identified.\n\n[Causes of ICH](#/info/ich-causes) — hypertensive, CAA, vascular malformation, coagulopathy' WHERE id = 'ich-anticoag' AND tree_id = 'ich';
UPDATE decision_nodes SET body = E'**Goal: INR <1.4 as rapidly as possible.**\n\n**First-line: [4-Factor PCC](#/drug/pcc-4factor/warfarin ich)**\n• 25–50 IU/kg IV based on INR and weight\n• Onset: 10–15 minutes\n• Superior to FFP — faster correction, less volume\n\n**PLUS [Vitamin K](#/drug/vitamin-k/warfarin ich)**\n• 10 mg IV slow push (over 15–30 min)\n• Prevents INR rebound after PCC wears off (6–8h)\n• IV route preferred — oral takes 12–24h\n\n**FFP** (15 mL/kg) only if PCC unavailable — slower, volume overload risk\n\n**Monitoring:**\n• Recheck INR 15–30 min post-PCC\n• If INR still >1.4 → repeat PCC dose\n• Recheck INR at 6h (Vitamin K sustains correction)' WHERE id = 'ich-warfarin-rev' AND tree_id = 'ich';
UPDATE decision_nodes SET body = E'**First-line: [Idarucizumab](#/drug/idarucizumab/dabigatran ich) (Praxbind)**\n• 5 g IV as two consecutive 2.5 g bolus doses\n• Onset: immediate — complete reversal within minutes\n• Specific monoclonal antibody fragment for dabigatran\n\n**If idarucizumab unavailable:**\n• [4-Factor PCC](#/drug/pcc-4factor/doac ich) 50 IU/kg IV\n• OR activated PCC (FEIBA) 50 IU/kg IV\n\n**Adjuncts:**\n• Hemodialysis can remove dabigatran (60% reduction in 2–3h) — consider if idarucizumab unavailable and severe bleeding\n• Activated charcoal 50 g if ingestion within 2h (intubated patients only)\n\n**Note:** Dabigatran is the only DOAC with a specific reversal agent.' WHERE id = 'ich-dabi-rev' AND tree_id = 'ich';
UPDATE decision_nodes SET body = E'**Applies to: apixaban, rivaroxaban, edoxaban**\n\n**Option 1: [4-Factor PCC](#/drug/pcc-4factor/doac ich)**\n• 50 IU/kg IV\n• Most widely available option\n• Onset: 15–30 minutes\n\n**Option 2: Andexanet alfa (Andexxa)**\n• Specific Xa inhibitor reversal agent\n• Dosing depends on agent and time since last dose\n• Note: recently withdrawn from US market due to thrombotic concerns — availability varies\n\n**If last dose within 2h (intubated patient):**\n• Activated charcoal 50 g via OG/NG tube\n\n**Monitoring:**\n• Anti-Xa levels if available (not required before treatment)\n• Repeat CT at 6h to assess for expansion\n• Watch for thrombotic complications post-reversal' WHERE id = 'ich-xa-rev' AND tree_id = 'ich';
UPDATE decision_nodes SET body = E'**Unfractionated Heparin (UFH):**\n• [Protamine](#/drug/protamine/heparin reversal) 1 mg per 100 units UFH given in prior 2–3h\n• Max single dose: 50 mg\n• Onset: 5 minutes — complete reversal\n• Check PTT 15 min after administration\n\n**LMWH (enoxaparin):**\n• [Protamine](#/drug/protamine/lmwh reversal) — partial reversal only (~60%)\n• If enoxaparin given within 8h: Protamine 1 mg per 1 mg enoxaparin\n• If 8–12h: Protamine 0.5 mg per 1 mg enoxaparin\n• If >12h: likely no benefit\n\n**Thrombolysis-associated ICH:**\n• Cryoprecipitate 10 units (to replenish fibrinogen)\n• [Tranexamic acid](#/drug/tranexamic-acid/ich hemostasis) 1 g IV\n• Target fibrinogen >200 mg/dL\n• Platelets if count <100,000' WHERE id = 'ich-heparin-rev' AND tree_id = 'ich';
UPDATE decision_nodes SET body = E'**Not on anticoagulation — consider adjunct measures:**\n\n**Tranexamic acid (TXA):**\n• [TXA](#/drug/tranexamic-acid/ich hemostasis) 1 g IV over 10 min (within 3h of onset)\n• Significant reduction in hematoma expansion (OR 0.82)\n• Did NOT improve mortality or functional outcomes in TICH-2\n• May be considered — TICH-3 trial underway\n\n**Antiplatelet agents:**\n• Platelet transfusion is **NOT recommended** (PATCH trial — worse outcomes)\n• DDAVP 0.3 mcg/kg IV may be considered (limited evidence, DASH pilot)\n\n**Thrombocytopenia:**\n• Target platelets >100,000 if possible\n• Transfuse platelets if count <100,000\n\n**Coagulation factors:**\n• Check fibrinogen — supplement with cryoprecipitate if <200 mg/dL\n• Correct any identified coagulopathy' WHERE id = 'ich-coag-adj' AND tree_id = 'ich';
UPDATE decision_nodes SET body = E'**Treat pain and anxiety FIRST** — hypertension may be secondary. Proper analgesia/sedation (especially in intubated patients) can significantly improve BP.\n\n**AHA/ASA 2022 BP Targets:**\n• SBP 150–220 → target **130–150 mmHg** (reasonable)\n• SBP >220 → target **140–180 mmHg** (less evidence)\n• **Avoid SBP <130** — potentially harmful\n• **Avoid drops >70 mmHg** in first hour\n\n**Timing:** Maximum benefit when started immediately (hematoma expansion risk highest in first 3h). Transition to oral agents after >24h if stable.\n\n**Preferred IV agents:**\n• [Clevidipine](#/drug/clevidipine/ich blood pressure) — smoothest titration (t½ ~1 min)\n• [Nicardipine](#/drug/nicardipine/ich blood pressure) — more widely available, less expensive\n• [Labetalol](#/drug/labetalol/ich blood pressure) — bolus dosing option\n\n**Avoid:** Nitroprusside, nitroglycerin, hydralazine — may increase ICP.' WHERE id = 'ich-bp' AND tree_id = 'ich';
UPDATE decision_nodes SET body = E'Hematoma location determines surgical approach and prognosis.\n\n**Supratentorial (most common):**\n• Basal ganglia/external capsule (60–65%)\n• Thalamus (15–20%)\n• Lobar (cortical)\n\n**Infratentorial:**\n• Cerebellar (5–10%) — unique urgency\n• Pontine (5%) — poor prognosis regardless\n\n**Intraventricular extension** occurs in >40% and worsens prognosis.' WHERE id = 'ich-location' AND tree_id = 'ich';
UPDATE decision_nodes SET body = E'**Evidence for surgical evacuation is limited:**\n\n**STITCH-I Trial** (1,033 patients): No benefit from early surgery overall. Possible trend toward benefit for hematomas within 1 cm of cortical surface and lobar hemorrhage with GCS 9–12.\n\n**STITCH-II Trial** (601 patients): Focused on predicted surgical benefit subgroup — still no significant difference vs conservative management.\n\n**Possible indications for craniotomy:**\n• Large hematoma with significant midline shift\n• Elevated ICP refractory to medical management\n• Hemorrhage secondary to resectable lesion (AVM, tumor)\n• Lobar location, no IVH extension, very early presentation\n\n**Emerging:** Minimally invasive surgery (MISTIE III) — may be more promising than traditional craniotomy.\n\n**Decompressive hemicraniectomy:** Consider for massive edema with impending herniation when other options exhausted.\n\nConsult neurosurgery for all supratentorial ICH — even if medical management planned initially.' WHERE id = 'ich-supra-surg' AND tree_id = 'ich';
UPDATE decision_nodes SET body = E'**The cerebellum is unique — patients may deteriorate rapidly (12–24h).**\n\nRisks of cerebellar hemorrhage:\n• Direct brainstem compression → catastrophic damage\n• 4th ventricle compression → obstructive hydrocephalus\n• Upward transtentorial herniation\n\n**Paradox:** Cerebellar ICH patients tend to have better prognosis than other ICH types IF timely surgical intervention is performed.\n\n**AHA/ASA 2022 — Immediate surgical evacuation if:**\n• Hematoma volume **>15 mL**\n• Neurological deterioration\n• Brainstem compression\n• Hydrocephalus\n\n**Important:** Ventriculostomy (EVD) alone without posterior fossa decompression is **NOT recommended** — increases risk of upward transtentorial herniation.\n\nEVD pressure may not accurately reflect posterior fossa pressure.\n\nConsult neurosurgery **immediately** — this is a time-critical surgical emergency.' WHERE id = 'ich-cerebellar-surg' AND tree_id = 'ich';
UPDATE decision_nodes SET body = E'**IVH occurs in >40% of ICH patients and worsens prognosis.**\n\nComplications:\n• Hydrocephalus and elevated ICP\n• Central (neurogenic) fever\n\n**External Ventricular Drain (EVD):**\n• **Indicated** for hydrocephalus contributing to reduced consciousness\n• Ideal candidate: initially well, then develops hydrocephalus with neuroworsening\n• **Caveat:** EVD increases survival but may not increase rate of good neurologic outcome\n\n**Intraventricular tPA (CLEAR III Trial):**\n• 500 patients randomized to intraventricular tPA vs saline via EVD\n• Improved survival but did NOT increase good functional outcomes\n• May be considered when: predominantly IVH without large parenchymal hematoma, and hydrocephalus might resolve with clot dissolution\n\nConsult neurosurgery for EVD placement. Monitor ICP continuously.' WHERE id = 'ich-ivh-evd' AND tree_id = 'ich';
UPDATE decision_nodes SET body = E'**Incidence:** ~10% convulsive seizures; subclinical seizure rate is substantially higher.\n\n**Risk factors:**\n• Cortical involvement (lobar hemorrhages)\n• Coexisting subarachnoid or subdural hemorrhage\n• Rebleeding\n\n**Continuous EEG monitoring indications:**\n• Impaired consciousness disproportionate to CT findings\n• Unexplained fluctuations in mental status\n• Any witnessed seizure or clinical signs of seizure\n\n**Treatment:**\n• **Seizure prophylaxis is NOT recommended** — prior evidence showed no benefit with phenytoin, and phenytoin has numerous side effects\n• **Treat witnessed seizure, EEG seizure, or nonconvulsive status epilepticus:**\n  – [Levetiracetam](#/drug/levetiracetam/ich seizure) 20 mg/kg IV (max 3000 mg) — preferred first-line\n  – Avoid phenytoin (may worsen outcomes in ICH)' WHERE id = 'ich-seizures' AND tree_id = 'ich';
UPDATE decision_nodes SET body = E'**Intracranial Pressure:**\n• ICP elevation from mass effect, perihematomal edema, and/or obstructive hydrocephalus\n• **Edema peaks at ~5–6 days** — anticipate delayed neurological deterioration\n• Boluses of hypertonic saline or hypertonic bicarbonate for acute ICP crisis (bridge to EVD or surgery)\n• Routine hypertonic saline not supported by evidence\n\n**Sodium:**\n• Avoid hyponatremia or rapid decreases in sodium — worsens cerebral edema\n• Target Na >135 mEq/L\n\n**Fever:**\n• Treat aggressively with acetaminophen — also provides analgesic benefit\n• **Neurogenic fever** may occur, especially with IVH extension — diagnosis of exclusion\n• Work up infection first (blood/urine cultures, CXR)\n• For refractory neurogenic fever: bromocriptine\n• INTREPID trial: automated surface cooling does NOT improve outcomes — do not use enforced normothermia devices routinely' WHERE id = 'ich-icp-fever' AND tree_id = 'ich';
UPDATE decision_nodes SET body = E'**AHA/ASA 2022 recommendations:**\n\n**Immediately:**\n• Intermittent pneumatic compression (IPC) — start on admission\n\n**After 24–48 hours:**\n• If ICH has demonstrated stability on serial imaging:\n  – Low-dose [UFH](#/drug/ufh/dvt prophylaxis) 5000 units SQ q8–12h\n  – OR [Enoxaparin](#/drug/enoxaparin/dvt prophylaxis) 40 mg SQ daily\n  – Starting chemical DVT prophylaxis is reasonable\n\n**Caution:**\n• Patients with underlying coagulopathy or imaging evidence of ongoing hemorrhage expansion may require individualized approach\n• Weigh bleeding risk vs thromboembolism risk (ICH patients are immobilized, high VTE risk)\n\nHigh-risk for DVT: immobilization, weakness/paralysis, older age, obesity.' WHERE id = 'ich-dvt' AND tree_id = 'ich';
UPDATE decision_nodes SET body = E'**All ICH patients → ICU admission** for continuous neuro monitoring and BP management.\n\n**Ongoing care:**\n• Neuro checks q1h minimum (more frequent during acute phase)\n• Serial CT: 6h, 24h, and with any neuro decline\n• ICP monitoring if EVD placed\n• Transition IV antihypertensives to PO after >24h if stable\n• DVT prophylaxis per protocol\n• Early rehabilitation consultation\n• Goals of care discussion with family — especially for severe ICH\n\n**Prognostication:**\n• [ICH Score](#/calculator/ich-score) — 30-day mortality prediction (0–6 points)\n• [FUNC Score](#/calculator/func-score) — 90-day functional independence (0–11 points)\n• [Prognostication Details & Limitations](#/info/ich-prognostication)\n\n**Overall prognosis:**\n• 30-day mortality: ~40%\n• 1-year survival: ~50%\n• Functional independence at 1 year: ~20%\n\n**[Cerebral Amyloid Angiopathy](#/info/ich-caa)** — if lobar ICH in elderly, normotensive patient\n\nRestart anticoagulation decisions should be individualized (typically deferred ≥4 weeks, and avoided entirely in CAA).' WHERE id = 'ich-disposition' AND tree_id = 'ich';

-- === meningitis (28 nodes) ===
UPDATE decision_nodes SET body = E'[Meningitis/Encephalitis Steps Summary](#/info/mening-steps-summary) — quick reference.\n\nInfectious meningitis and encephalitis are life-threatening conditions requiring **time-critical empiric treatment**. Untreated bacterial meningitis approaches **100% mortality**; even with therapy, mortality is **14–25%**. [1,3,5]\n\nHerpes simplex encephalitis mortality was **70%** prior to antiviral therapy; now **~9%** with treatment. [7]\n\n• **Meningitis** = inflammation of meninges and subarachnoid space\n• **Encephalitis** = inflammation of brain parenchyma itself\n• Focal neurological deficits indicate brain tissue involvement (encephalitis) [8]\n\n**Key principle:** Empiric antimicrobials must be given **within 1 hour** of suspicion — do NOT delay for imaging or LP. [1,19]' WHERE id = 'mening-start' AND tree_id = 'meningitis';
UPDATE decision_nodes SET body = E'The classic triad of **fever, neck stiffness, and altered mental status** is present in only **44–66%** of bacterial meningitis cases. [3,5]\n\nHowever, when **headache** is added as a 4th symptom:\n• At least **2 of 4** symptoms are present in **95%** of cases [5]\n• At least **1 of 4** is present in **99–100%** of cases [5]\n\n**Stated differently:** Absence of ALL 4 symptoms (headache, fever, neck stiffness, altered mental status) effectively **rules out** meningitis/encephalitis. [9]\n\n**Individual symptom frequencies in ABM:**\n• Headache: 84–87%\n• Fever: 78%\n• Neck stiffness: 73–83%\n• Altered mental status (GCS <14): 79–80% [5]\n\n**Risk factors to elicit:** Immunocompromise (HIV, transplant, immunosuppressants), recent neurosurgery, CSF leaks, basilar skull fracture, recent otitis/sinusitis, herpes history, travel/geographic exposure, animal/insect contact, vaccination status. [9,22,25]' WHERE id = 'mening-clinical' AND tree_id = 'meningitis';
UPDATE decision_nodes SET body = E'**Kernig and Brudzinski signs:**\n• Sensitivity: only **2%** (essentially useless for ruling out) [13]\n• Specificity: **97–98%** (useful when positive, but rarely positive) [13]\n\n**Jolt accentuation of headache:**\n• Originally reported sensitivity 65–97%, but subsequent studies show only **21% sensitivity**, 82% specificity [13]\n• Inadequate to confirm or refute diagnosis\n\n**Key exam findings suggesting specific etiologies:**\n• Petechial rash (palms/soles) → *N. meningitidis* (also other bacterial causes) [9]\n• Dermatomal vesicular rash → VZV meningitis/encephalitis [6]\n• Swollen parotid glands (unvaccinated) → mumps [6]\n\n**Findings suggesting encephalitis (brain parenchyma involvement):**\n• Motor weakness / hemiparesis\n• Aphasia\n• Personality changes, hallucinations, psychosis\n• Dysautonomia\n• Seizures [8]' WHERE id = 'mening-exam' AND tree_id = 'meningitis';
UPDATE decision_nodes SET body = E'Focal deficits (hemiparesis, aphasia, personality changes, seizures) indicate **brain parenchyma involvement** and the presence of **encephalitis** rather than isolated meningitis. [8]\n\nThis distinction guides both the diagnostic workup (MRI utility) and empiric treatment (acyclovir).' WHERE id = 'mening-focal-deficits' AND tree_id = 'meningitis';
UPDATE decision_nodes SET body = E'**Immediately start empiric treatment:**\n• [Acyclovir](#/drug/acyclovir/encephalitis) 10 mg/kg IV q8h (HSV-1 most common endemic cause) [7]\n• PLUS empiric bacterial meningitis coverage (see next steps) [1]\n\n**CT is indicated** in all patients with focal deficits (mass lesion must be excluded before LP). [12,18]\n\n**MRI** is superior to CT for detecting encephalitis and can distinguish subtypes (e.g., HSV → temporal lobe involvement), but should not delay treatment. [8]\n\nHerpes simplex encephalitis mortality: **70% untreated → 9% with acyclovir**. [7,15]' WHERE id = 'mening-encephalitis-pathway' AND tree_id = 'meningitis';
UPDATE decision_nodes SET body = E'[CT Before LP Criteria](#/info/mening-ct-criteria) — international guideline comparison.\n\nCT is NOT needed before LP in most patients. CT is insensitive for meningitis/encephalitis. [12]\n\nHerniation after LP is rare: only **0.1%** deteriorated within 1 hour, and **91%** who deteriorated had a prior normal CT. [18]\n\n**CT IS indicated before LP if ANY of the following:** [12,15]' WHERE id = 'mening-ct-decision' AND tree_id = 'meningitis';
UPDATE decision_nodes SET body = E'**CRITICAL:** Start empiric antibiotics and [Dexamethasone](#/drug/dexamethasone/meningitis) BEFORE CT imaging. Do NOT delay treatment for any diagnostic test. [1,19,20]\n\nDelayed antibiotics correlate with disease progression and **increased mortality**. [19,20]\n\nAfter CT:\n• If no mass lesion or contraindication → proceed to LP\n• If mass lesion found → neurosurgical consultation; continue empiric treatment\n\n**Blood cultures** should be drawn before antibiotics when possible (66% yield in ABM). [5]' WHERE id = 'mening-abx-then-ct' AND tree_id = 'meningitis';
UPDATE decision_nodes SET body = E'No indications for CT before LP — proceed directly.\n\n**Start empiric antibiotics within 1 hour** of suspicion, ideally immediately after LP. [1]\n\nIf LP will be delayed for any reason, start antibiotics **first** — never wait. Antibiotics before LP reduce culture sensitivity but PCR remains reliable for days. [11,12]\n\n**Blood cultures** should be drawn before antibiotics (66% yield in ABM). [5]' WHERE id = 'mening-lp-direct' AND tree_id = 'meningitis';
UPDATE decision_nodes SET body = E'[CSF Interpretation Guide](#/info/mening-csf-guide) — reference for interpreting results.\n\n**Position:** Lateral decubitus if opening pressure measurement desired.\n\n**Collect 4 tubes (up to 15 mL safely):** [14,23]\n• **Tube 1:** WBC and RBC count\n• **Tube 2:** Protein, glucose, lactate, PCR\n• **Tube 3:** Gram stain, cultures, antigen tests, additional PCR\n• **Tube 4:** WBC and RBC count (compare to Tube 1 for traumatic tap)\n\n**Larger volumes increase sensitivity** of diagnostic tests. CSF is produced at 22 mL/hr. [14]\n\n**Traumatic tap?** Use the [CSF Traumatic Tap Correction](#/calculator/csf-correction) calculator to determine predicted WBC from RBC contamination.\n\n**Opening pressure:**\n• Normal: <20 cm H₂O\n• Elevated in bacterial meningitis; >40 cm H₂O in 39% of ABM cases [5,14]' WHERE id = 'mening-lp-technique' AND tree_id = 'meningitis';
UPDATE decision_nodes SET body = E'[Empiric Antimicrobial Table](#/info/mening-abx-table) — full regimens by risk category.\n\n**Antibiotics within 1 HOUR of suspicion.** [1]\n\nA retrospective study of 269 ABM episodes over 25 years demonstrated that delayed antibiotics correlated with **disease progression and increased mortality**. [19]\n\nAnother study of 119 ABM patients showed an **incremental association** between longer delays to antimicrobials and mortality. [20]\n\n**For ALL suspected bacterial meningitis:**\n• [Dexamethasone](#/drug/dexamethasone/meningitis) 0.15 mg/kg IV q6h × 2–4 days — give WITH or up to 15–20 min BEFORE first antibiotic dose [1,21]\n• Add [Acyclovir](#/drug/acyclovir/encephalitis) 10 mg/kg IV q8h if ANY encephalitis features [7]' WHERE id = 'mening-empiric-timing' AND tree_id = 'meningitis';
UPDATE decision_nodes SET body = E'**Targets:** *S. pneumoniae* (most common), *N. meningitidis* [2]\n\n**Regimen:**\n• [Ceftriaxone](#/drug/ceftriaxone/adult meningitis) 2g IV q12h (higher dose for CNS penetration) [1,24]\n• [Vancomycin](#/drug/vancomycin/meningitis) 15–20 mg/kg IV q8–12h (for cephalosporin-resistant pneumococci) [1,24]\n• [Dexamethasone](#/drug/dexamethasone/meningitis) 0.15 mg/kg IV q6h × 2–4 days [1,21]\n\n**Alternative:** [Meropenem](#/drug/meropenem/meningitis) 2g IV q8h if cephalosporin allergy or concern for multidrug-resistant organisms. [25]\n\n**Add [Acyclovir](#/drug/acyclovir/encephalitis)** 10 mg/kg IV q8h if ANY encephalitis features. [7]' WHERE id = 'mening-tx-standard' AND tree_id = 'meningitis';
UPDATE decision_nodes SET body = E'**Age ≥50, pregnant, or immunocompromised** patients are at increased risk for *L. monocytogenes* meningitis (mortality **17–30%**). [1,24]\n\nPregnant women are **10–20× more likely** to contract listerial infections. Infection during pregnancy is often devastating for the fetus. [24]\n\n**Regimen:**\n• [Ceftriaxone](#/drug/ceftriaxone/adult meningitis) 2g IV q12h [1]\n• [Vancomycin](#/drug/vancomycin/meningitis) 15–20 mg/kg IV q8–12h [1]\n• [Ampicillin](#/drug/ampicillin/adult meningitis) 2g IV q4h (Listeria coverage) [1,24]\n• [Dexamethasone](#/drug/dexamethasone/meningitis) 0.15 mg/kg IV q6h × 2–4 days [21]\n\n**Note:** [Meropenem](#/drug/meropenem/meningitis) has activity against *L. monocytogenes* — if used, ampicillin may be omitted. [1]\n\n**Add [Acyclovir](#/drug/acyclovir/encephalitis)** if encephalitis features present. [7]' WHERE id = 'mening-tx-expanded' AND tree_id = 'meningitis';
UPDATE decision_nodes SET body = E'**Risk factors:** Neurosurgical procedures, shunts/drains, CSF leaks, basilar skull fractures. [25]\n\n**Common pathogens:** Gram-negative bacilli (*P. aeruginosa*, *A. baumannii*), gram-positive skin flora (*Staphylococcus* spp including MRSA). Mortality: **16–41%**. [25]\n\n**Regimen:**\n• [Vancomycin](#/drug/vancomycin/meningitis) 15–20 mg/kg IV q8–12h (MRSA coverage) [25]\n• [Meropenem](#/drug/meropenem/meningitis) 2g IV q8h (broad gram-negative + Pseudomonas coverage) [25]\n• OR [Cefepime](#/drug/cefepime/adult meningitis) 2g IV q8h as alternative to meropenem [25]\n\n**CSF lactate** is particularly useful for diagnosis — postoperative inflammation alters conventional markers but does NOT affect lactate. [25]\n\nConsider Infectious Disease consultation for second-/third-line agents (linezolid). [25]' WHERE id = 'mening-tx-nosocomial' AND tree_id = 'meningitis';
UPDATE decision_nodes SET body = E'**Cryptococcal meningitis** is the 2nd highest cause of mortality in HIV/AIDS patients. *C. neoformans* causes ~1 million cases/year in HIV/AIDS, with ~600,000 annual deaths. [17]\n\nTypically subacute: weeks of evolving headache, neck stiffness, malaise.\n\n**Serum cryptococcal antigen (CrAg):** 99.7% sensitive, 94.1% specific — send immediately. [17]\n\n**Empiric antifungal regimen (after ID consultation):**\n• [Amphotericin B liposomal](#/drug/amphotericin-b/cryptococcal meningitis) 3–4 mg/kg/day IV [22]\n• [Flucytosine](#/drug/flucytosine/cryptococcal meningitis) 25 mg/kg PO q6h [22]\n• Induction × 1 week, then [Fluconazole](#/drug/fluconazole/cryptococcal meningitis) 400–800 mg/day [22]\n\n**ALSO give empiric bacterial coverage** (Ceftriaxone + Vancomycin + Ampicillin) until CSF results available. [1]\n\n**⚠️ Do NOT give corticosteroids** — associated with worsened outcomes in cryptococcal meningitis. [1,21]' WHERE id = 'mening-tx-crypto' AND tree_id = 'meningitis';
UPDATE decision_nodes SET body = E'No blood test can substitute for CSF analysis. Useful adjuncts:\n\n**Blood cultures:** Up to **66% yield** in ABM — collect before antibiotics. [5]\n\n**Serum procalcitonin (PCT):** Most discriminating biomarker for bacterial vs viral meningitis. [10,16]\n• PCT >0.25–0.5 ng/mL: **90–95% sensitivity, 98–100% specificity** for ABM [16]\n• More sensitive than any CSF marker for this purpose\n• Limited by availability in many EDs\n\n**C-reactive protein (CRP):**\n• CRP >37 mg/L: 85% sensitivity, 84% specificity for bacterial vs viral [10]\n• Reduced utility in elderly/immunocompromised\n\n**Serum cryptococcal antigen:** 99.7% sensitive for cryptococcal meningitis in immunocompromised patients. [17]\n\n**CBC:** Average WBC 17,500 in ABM vs 11,096 in viral — poor discriminatory value. [10]' WHERE id = 'mening-blood-tests' AND tree_id = 'meningitis';
UPDATE decision_nodes SET body = E'[CSF Interpretation Guide](#/info/mening-csf-guide) — detailed reference with normal values and patterns.\n\nCompare CSF results to expected patterns. **Note:** 6% of culture-proven ABM cases lack elevated WBC, and 10% have lymphocyte-predominant differentials. Early bacterial meningitis may mimic viral patterns. [1,14]' WHERE id = 'mening-csf-pattern' AND tree_id = 'meningitis';
UPDATE decision_nodes SET body = E'**Continue empiric antibiotics.** Await Gram stain, culture, and PCR for pathogen identification.\n\n**CSF Gram stain:** 60–99% sensitivity, 97–100% specificity. Sensitivity reduced after antibiotics. Negative Gram stain does NOT exclude bacterial meningitis. [5,14]\n\n**CSF culture:** Definitive diagnosis + antibiotic sensitivities. Sensitivity reduced **>30%** if LP performed >4 hours after antibiotics. *N. meningitidis* cultures may sterilize within 2 hours of antibiotics. [14]\n\n**CSF PCR:** Detects bacterial DNA even days after antibiotics — 87–100% sensitivity, 98–100% specificity. [12]\n\n**CSF lactate >35.1 mg/dL:** 93% sensitivity, 97% specificity for bacterial meningitis (when obtained before antibiotics). Particularly useful in healthcare-associated infections. [11]\n\n[Corticosteroid Guide](#/info/mening-steroid-guide) — continue dexamethasone for pneumococcal meningitis; discontinue if *Listeria* or *Cryptococcus* identified. [21]' WHERE id = 'mening-bacterial-mgmt' AND tree_id = 'meningitis';
UPDATE decision_nodes SET body = E'Viral meningitis is generally self-limited with lower morbidity than bacterial. However, viral **encephalitis** (especially HSV-1) has high mortality without treatment. [6,7]\n\n**Most common causes:** Non-polio enteroviruses (23–61%), HSV-2, arthropod-borne viruses. [6]\n\nAssess for encephalitis features:' WHERE id = 'mening-viral-branch' AND tree_id = 'meningitis';
UPDATE decision_nodes SET body = E'**HSV-1 is the most common endemic cause** of viral encephalitis in the Western world. [7]\n\n**[Acyclovir](#/drug/acyclovir/encephalitis) 10 mg/kg IV q8h** — continue for all suspected encephalitis. [7]\n• In the landmark RCT (208 patients): acyclovir reduced mortality from **70% to 28%** [7]\n• Contemporary mortality with acyclovir + ICU care: **~9%** [15]\n\n**If HSV-1 PCR negative but high clinical suspicion:**\n• Continue acyclovir — false-negative PCR is possible in the first **72 hours** [7]\n• Repeat PCR at **3–7 days** [7]\n\n**MRI findings:** Temporal lobe involvement is characteristic of HSV encephalitis. [8]\n\n**VZV encephalitis:** More common in immunocompromised patients. Continue acyclovir if VZV identified. [6]\n\n**⚠️ Corticosteroids** are NOT indicated for viral encephalitis (unlike bacterial meningitis). Consider if autoimmune encephalitis suspected (relapse weeks after initial infection — consult neurology). [1]' WHERE id = 'mening-encephalitis-tx' AND tree_id = 'meningitis';
UPDATE decision_nodes SET body = E'Viral meningitis is generally **self-limited** with lower mortality and fewer long-term complications than bacterial causes. [6]\n\n**Management:**\n• Supportive care: IV fluids, antiemetics, analgesics\n• No directed antiviral therapy has proven to affect outcomes for most viral causes [6]\n\n**Important caveats:**\n• Early bacterial meningitis may mimic viral patterns — 25% of *L. monocytogenes* cases have normal or near-normal CSF [1]\n• If ANY diagnostic uncertainty, continue empiric antibiotics and admit [14]\n• Patients with severe symptoms (refractory headache, persistent vomiting) may still require admission even with viral etiology\n\n**Disposition:** Some low-risk patients may be appropriate for discharge. See disposition criteria. [23]' WHERE id = 'mening-viral-mgmt' AND tree_id = 'meningitis';
UPDATE decision_nodes SET body = E'Fungal meningitis is primarily a disease of **immunocompromised** populations. Most cases present **subacutely** with weeks of evolving symptoms. [8]\n\n**Most common cause:** *Cryptococcus neoformans* (~1 million cases/year in HIV/AIDS). [17]\n\nOther causes: *Histoplasma*, *Coccidioides*, *Candida* species.\n\n**Treatment (requires ID consultation):**\n• **Induction (1 week):** [Amphotericin B liposomal](#/drug/amphotericin-b/cryptococcal meningitis) 3–4 mg/kg/day IV + [Flucytosine](#/drug/flucytosine/cryptococcal meningitis) 25 mg/kg PO q6h [22]\n• **Consolidation:** [Fluconazole](#/drug/fluconazole/cryptococcal meningitis) 400–800 mg/day PO [22]\n• This regimen showed lowest mortality in a Cochrane review of 13 studies (2426 participants) [22]\n\n**⚠️ Do NOT give corticosteroids** — dexamethasone is associated with **worsened outcomes** in cryptococcal and listerial meningitis. Discontinue immediately if either pathogen identified. [1,21]' WHERE id = 'mening-fungal-mgmt' AND tree_id = 'meningitis';
UPDATE decision_nodes SET body = E'**When in doubt, treat as bacterial meningitis.**\n\n**Key pitfalls with equivocal CSF:**\n• **6%** of culture-proven ABM cases have NO elevated WBC count [1,14]\n• **10%** of ABM cases have lymphocyte-predominant (not neutrophil) differentials [1,14]\n• **25%** of *L. monocytogenes* cases have normal or near-normal CSF findings [1]\n• Early in disease course, bacterial patterns may be incomplete\n• Prior antibiotic administration alters CSF findings\n\n**Management:**\n• Continue full empiric antibiotic regimen\n• Continue [Dexamethasone](#/drug/dexamethasone/meningitis) pending pathogen identification [21]\n• Admit for monitoring and repeat assessment\n• Await cultures, PCR, and repeat CSF if needed\n\n**CSF lactate >35.1 mg/dL** favors bacterial cause (93% sensitivity, 97% specificity pre-antibiotics). [11]\n**Serum PCT >0.25–0.5 ng/mL** strongly favors bacterial etiology (90–95% sensitivity). [16]' WHERE id = 'mening-equivocal' AND tree_id = 'meningitis';
UPDATE decision_nodes SET body = E'[Corticosteroid Guide](#/info/mening-steroid-guide) — detailed evidence and dosing.\n\n**[Dexamethasone](#/drug/dexamethasone/meningitis) 0.15 mg/kg IV q6h × 2–4 days** [1,21]\n\nGive WITH or up to **15–20 minutes BEFORE** first antibiotic dose. [1]\n\n**Evidence (Cochrane 2015, 25 studies, 4121 patients):**\n• Overall ABM: nonsignificant mortality reduction (17.8% vs 19.9%) [21]\n• **Pneumococcal meningitis in high-income countries:** significant mortality reduction [21]\n• **TB meningitis:** corticosteroids reduced mortality by ~25% at 18 months [21]\n\n**⚠️ STOP corticosteroids if pathogen is NOT *S. pneumoniae* or *M. tuberculosis*:**\n• *L. monocytogenes:* nonsignificant trend toward **worse outcomes** with corticosteroids [21]\n• *C. neoformans:* corticosteroids associated with **worsened outcomes** [1]\n\n[Postexposure Prophylaxis Guide](#/info/mening-pep-guide) — regimens for contacts of *N. meningitidis* and *H. influenzae*.' WHERE id = 'mening-steroids' AND tree_id = 'meningitis';
UPDATE decision_nodes SET body = E'[Disposition Criteria](#/info/mening-dispo-criteria) — discharge vs ward vs ICU criteria.\n\nMost patients with meningitis and encephalitis will be admitted. Determine appropriate level of care: [1,23]' WHERE id = 'mening-dispo' AND tree_id = 'meningitis';
UPDATE decision_nodes SET body = E'**Discharge criteria (extrapolated from pediatric data, use clinical judgment):** [23]\n• Nontoxic clinical appearance\n• Normal serum WBC count\n• Mild CSF pleocytosis only\n• Negative CSF Gram stain\n• Adequate symptom control (headache, nausea, vomiting)\n• Reliable support system and follow-up capability\n\n**Return precautions — discuss thoroughly:**\n• Worsening headache\n• Vomiting\n• Confusion or behavioral changes\n• Seizures\n• Fever >38.5°C\n• Neck stiffness worsening\n\n**Follow-up:** Primary care within **3 days** for reassessment. [23]\n\n[Discharge Instructions](#/info/meningitis-discharge) — shareable patient handout' WHERE id = 'mening-discharge' AND tree_id = 'meningitis';
UPDATE decision_nodes SET body = E'**Indications:**\n• Alert enough to maintain airway\n• Stable vital signs\n• Not receiving titratable medications\n• Does not require close neurological monitoring\n\n**Ward management:**\n• Continue IV antibiotics pending CSF analysis results\n• Tailor antimicrobial therapy once causative agent identified\n• Continue dexamethasone if bacterial meningitis suspected (discontinue if not *S. pneumoniae* or TB) [1,21]\n• Patients with viral meningitis who have severe symptoms (refractory headache, persistent vomiting) should be admitted for symptom management\n• Serial neurological assessments' WHERE id = 'mening-ward' AND tree_id = 'meningitis';
UPDATE decision_nodes SET body = E'**Indications:**\n• GCS score ≤8 — consider advanced airway management [8]\n• Hemodynamic instability requiring vasopressors\n• Seizure activity or focal neurological deficits\n• All cases of **severe encephalitis**\n• Rapidly declining level of consciousness\n\n**ICU capabilities required:**\n• Continuous electroencephalographic (EEG) monitoring\n• Intracranial pressure (ICP) monitoring capability\n• Frequent neurological reassessment\n• Advanced airway management\n• Titratable IV medications\n\n**⚠️ Osmotic agents and therapeutic hypothermia** are NOT recommended — studies stopped early due to concerns for increased mortality in treatment groups. [1]' WHERE id = 'mening-icu' AND tree_id = 'meningitis';

-- === neonatal-resus (27 nodes) ===
UPDATE decision_nodes SET body = E'[Algorithm — Quick Reference](#/node/nrp-algorithm-ref)\n[Setup and Tools — Quick Reference](#/node/nrp-setup-ref)\n[NRP Steps Summary](#/info/nrp-summary) — quick-reference checklist for neonatal resuscitation.\n\n**Neonatal resuscitation** follows a systematic, stepwise approach from initial assessment through advanced interventions.\n\n**Key statistics:** [1]\n• ~90% of newborns transition without intervention beyond warmth, drying, and stimulation\n• ~10% need early support (PPV, supplemental O2)\n• <1% need extensive resuscitation (CPR + medications)\n\n**Modules:**\n• Module 1: Preparation & Initial Assessment — team, equipment, cord management, initial evaluation\n• Module 2: Initial Steps — Golden 30 Seconds (warm, dry, position, stimulate, clear)\n• Module 3: Positive Pressure Ventilation — PPV technique, corrective steps, advanced airway\n• Module 4: Chest Compressions — CPR technique, intubation\n• Module 5: Medications & Vascular Access — epinephrine, UVC, volume resuscitation\n• Module 6: Post-Resuscitation — APGAR, normothermia, NICU transfer\n\n**Cross-links:**\n• [Precipitous Delivery](#/tree/precip-delivery) — ED delivery management\n• [Shoulder Dystocia](#/tree/shoulder-dystocia) — if turtle sign during delivery' WHERE id = 'nrp-start' AND tree_id = 'neonatal-resus';
UPDATE decision_nodes SET body = E'TEAM BRIEFING\n• Assign roles before delivery: **team leader**, airway manager, compressor, medication nurse, timekeeper/recorder\n• NRP pre-brief questions: gestational age, number of babies, risk factors (meconium, preeclampsia, prematurity), cord management plan\n• Communicate: **"vigorous" vs "non-vigorous"** dictates cord strategy\n\nEQUIPMENT CHECKLIST\n• **Radiant warmer** — turn ON now (prewarming)\n• **T-piece resuscitator** (preferred 2025) or self-inflating bag with manometer\n• **Pulse oximeter** — right hand/wrist (preductal)\n• **Cardiac monitor** — 3-lead ECG (most accurate HR)\n• **Suction** — bulb syringe + wall suction with 10F/12F catheter\n• **Intubation** — laryngoscope (Miller 0/00), ETT (2.5–4.0), stylet, tape\n• **UVC kit** — umbilical catheter (3.5F/5F), umbilical tape, sterile instruments\n• **Medications** — epinephrine 1:10,000, normal saline, D10W\n\n**Document:** cord clamping time, APGARs, time to ventilation [1][2]' WHERE id = 'nrp-preparation' AND tree_id = 'neonatal-resus';
UPDATE decision_nodes SET body = E'DELAYED CORD CLAMPING (DCC) — 2025 GUIDELINES [1][5]\n\n**Vigorous term/late preterm:**\n• DCC **30–60 seconds** recommended\n• Improves placental transfusion, iron stores, and hemoglobin\n\n**Non-vigorous ≥35 weeks:**\n• **Intact cord milking (ICM)** may be reasonable (compared to immediate clamping)\n• Milk cord toward baby 3–4 times over 2 seconds\n\n**Preterm 28–34 weeks:**\n• ICM when DCC isn''t possible\n\n**<28 weeks:**\n• ICM is **NOT recommended** — risk of intraventricular hemorrhage\n\n**Clamp immediately if:**\n• Baby needs resuscitation and can''t wait\n• Placental abruption, cord avulsion, or other emergency\n\n**Communicate cord management plan to the team before delivery.** [5]' WHERE id = 'nrp-cord-mgmt' AND tree_id = 'neonatal-resus';
UPDATE decision_nodes SET body = E'PRETERM ASSESSMENT [1][2]\n\n**Viability assessment:**\n• Dating most accurate in 1st trimester (±3–5 days)\n• Later dating accuracy: ±1–2 weeks\n• U/S: BPD + femur length for estimation\n\n**Preterm-specific needs:**\n• **Plastic wrap <32 weeks** — cover body (not face) to prevent heat loss\n• **Higher starting FiO2** — 21–30% for ≥35 wk, 21–30% for <35 wk (titrate to SpO2 targets)\n• **Temperature is critical** — hypothermia worsens all outcomes\n• **Surfactant** may be needed if <32 wk (NICU decision)\n\n**Gestational age estimation if unknown:**\n• Weight: ~500g at 23–24 wk, ~1000g at 28 wk, ~1500g at 32 wk, ~2500g at 37 wk\n• Sole creases, ear cartilage, breast tissue for Ballard score (post-resuscitation)\n\n**Both hypothermia AND hyperthermia worsen outcomes.** Target normothermia (36.5–37.5°C) for all infants. [1]' WHERE id = 'nrp-preterm' AND tree_id = 'neonatal-resus';
UPDATE decision_nodes SET body = E'INITIAL EVALUATION — The 3 Questions [1][2][3]\n\nAssess immediately at birth:\n\n**1. Term gestation?** (≥37 weeks)\n**2. Breathing or crying?**\n**3. Good muscle tone?** (flexed, active)' WHERE id = 'nrp-initial-eval' AND tree_id = 'neonatal-resus';
UPDATE decision_nodes SET body = E'VIGOROUS NEWBORN\n\n• **Skin-to-skin** contact with mother\n• **Delayed cord clamping** 30–60 seconds\n• **Dry** the baby with warm towels\n• **Maintain normothermia** (36.5–37.5°C)\n• **APGAR scoring** at 1 and 5 minutes\n\nContinue monitoring for transition. If at any point the baby develops apnea, labored breathing, or HR <100 → proceed to initial steps.' WHERE id = 'nrp-routine' AND tree_id = 'neonatal-resus';
UPDATE decision_nodes SET body = E'INITIAL STEPS — Complete within 30 seconds [1][2][3]\n\n**W — WARM**\n• Radiant heater ON — **NO blankets on top** (blocks radiant heat)\n• Plastic wrap for <32 weeks\n\n**D — DRY**\n• Vigorously dry with warm towels\n• Remove wet towels — replace with dry\n\n**P — POSITION**\n• **Sniffing position** — slight neck extension to open airway\n• Shoulder roll if needed for neutral alignment\n\n**S — STIMULATE**\n• **Flick the soles of the feet**\n• **Rub the back** — up and down along the spine\n• Primary apnea always responds to stimulation\n\n**C — CLEAR AIRWAY (PRN)**\n• Suction **mouth then nose** ("M before N")\n• Avoid vigorous or deep suctioning — causes bradycardia via vagal stimulation\n• Only suction if secretions are obstructing the airway' WHERE id = 'nrp-initial-steps' AND tree_id = 'neonatal-resus';
UPDATE decision_nodes SET body = E'MECONIUM MANAGEMENT (2025 Update) [1][6]\n\n**Vigorous baby + meconium:**\n• Proceed with normal initial steps\n• No special suctioning needed\n\n**Non-vigorous baby + meconium:**\n• **Do NOT delay PPV for suctioning** (2025 guideline change)\n• Begin PPV as indicated — ventilation is the priority\n• ET suctioning **only if airway is obstructed** (visible thick meconium blocking airway)\n\n**Meconium aspirator** is no longer routinely recommended — it delays time to PPV without proven benefit. [1][6]\n\n**Key teaching point:** "Primary apnea responds to stimulation. **Secondary apnea does NOT** — it requires PPV." [2]' WHERE id = 'nrp-meconium' AND tree_id = 'neonatal-resus';
UPDATE decision_nodes SET body = E'30-SECOND REASSESSMENT [1][2]\n\nAfter initial steps, evaluate:\n• **Breathing** — spontaneous, regular respirations?\n• **Heart rate** — auscultate or palpate umbilical stump (6 sec × 10)\n• **Tone** — flexed and active?\n• **Color** — improving?' WHERE id = 'nrp-golden30-eval' AND tree_id = 'neonatal-resus';
UPDATE decision_nodes SET body = E'SUPPLEMENTAL O2 / CPAP [1][2]\n\n**Pulse oximetry** — apply to **right hand/wrist** (preductal)\n• Do NOT use left hand or feet (postductal — lower readings are normal)\n\n**SpO2 targets by minute of life:** [1]\n• 1 min: 60–65%\n• 2 min: 65–70%\n• 3 min: 70–75%\n• 4 min: 75–80%\n• 5 min: 80–85%\n• 10 min: 85–95%\n\n**Labored breathing with adequate HR:**\n• Start **CPAP 5–6 cmH2O** via mask\n• Supplement O2 to meet SpO2 targets\n• Avoid hyperoxia — titrate FiO2 down as saturations improve\n\n**If worsening or HR drops <100 → proceed to PPV**\n\nContinue monitoring. Most babies with labored breathing improve with CPAP alone.' WHERE id = 'nrp-breathing-support' AND tree_id = 'neonatal-resus';
UPDATE decision_nodes SET body = E'PPV — The Most Important Intervention in NRP [1][2][3]\n\n**T-piece resuscitator preferred** (2025) — provides consistent PIP and PEEP. Self-inflating bag acceptable if T-piece unavailable. [1]\n\n**TECHNIQUE:**\n• **C-E grip** — C fingers seal mask, E fingers lift jaw\n• **Mask seal** — covers mouth and nose, not eyes\n• **Sniffing position** — slight neck extension\n• **PIP** 20–25 cmH2O (avoid barotrauma)\n• **Rate** 40–60/min ("squeeze—release—release")\n• **FiO2** start at 21% for ≥35 weeks; 21–30% for <35 weeks\n• **Confirm chest rise** and bilateral breath sounds\n\n**SpO2 TARGETS by minute:** [1]\n• 1 min: 60–65% → 2 min: 65–70% → 3 min: 70–75%\n• 4 min: 75–80% → 5 min: 80–85% → 10 min: 85–95%\n• Monitor on right hand/wrist (preductal)\n• **Avoid hyperoxia** — titrate FiO2 to targets\n\n**Ventilation is the single most important intervention.** Most neonatal bradycardia is caused by inadequate ventilation. [2]' WHERE id = 'nrp-ppv' AND tree_id = 'neonatal-resus';
UPDATE decision_nodes SET body = E'PREDUCTAL SpO2 TARGETS [1][2]\n\nMonitor on **right hand/wrist** (preductal — above the ductus arteriosus).\n\n**Target SpO2 by minute of life:**\n• 1 min: 60–65%\n• 2 min: 65–70%\n• 3 min: 70–75%\n• 4 min: 75–80%\n• 5 min: 80–85%\n• 10 min: 85–95%\n\n**Why preductal?** The right hand receives blood from the aorta BEFORE the ductus arteriosus. Left hand and feet receive mixed blood — lower SpO2 is expected and doesn''t indicate poor oxygenation.\n\n**Titrate FiO2:**\n• Below target → increase FiO2 by 10–20%\n• Above target → decrease FiO2 by 10–20%\n• **Avoid hyperoxia** — especially in premature infants (retinopathy risk)\n\n**Cardiac monitor** (3-lead ECG) provides the most accurate HR — more reliable than pulse oximetry waveform during resuscitation. [1]' WHERE id = 'nrp-spo2-targets' AND tree_id = 'neonatal-resus';
UPDATE decision_nodes SET body = E'PPV REASSESSMENT — after 30 seconds of effective PPV [1][2]\n\n**Check heart rate:**\n• Auscultate, palpate umbilical stump, or cardiac monitor\n• 6-second count × 10 for quick assessment' WHERE id = 'nrp-ppv-eval' AND tree_id = 'neonatal-resus';
UPDATE decision_nodes SET body = E'MR SOPA — Corrective Steps for Ineffective Ventilation [1][2]\n\nIf HR is not improving with PPV, systematically troubleshoot:\n\n**M — Mask adjust**\n• Reapply mask — ensure tight seal, no air leak\n• Reposition C-E grip\n\n**R — Reposition**\n• Sniffing position — slight neck extension\n• Shoulder roll for alignment\n\n**S — Suction**\n• Suction mouth then nose\n• Clear any secretions obstructing airway\n\n**O — Open mouth**\n• Open baby''s mouth slightly\n• Jaw thrust if needed\n\n**P — Pressure increase**\n• Increase PIP by 5 cmH2O increments\n• Up to 30–40 cmH2O if needed for chest rise\n\n**A — Alternative airway**\n• Consider ETT intubation or LMA (supraglottic airway)\n• LMA may be used for ≥34 weeks, >2 kg (2025 update) [1]\n\nIf still no improvement after corrective steps → proceed to advanced airway.' WHERE id = 'nrp-corrective' AND tree_id = 'neonatal-resus';
UPDATE decision_nodes SET body = E'ADVANCED AIRWAY — ETT or LMA [1][2]\n\n**ETT Intubation:**\n• Use **cardiac monitor** to confirm HR before and after\n• **Attempt limit:** 30 seconds per attempt — ventilate between attempts\n• Confirm placement: chest rise, bilateral breath sounds, CO2 detector\n• Secure tube — neonatal ETTs are extremely easy to dislodge\n\n**LMA / Supraglottic Airway (2025 update):**\n• May use as **initial interface** for ≥34 weeks, >2 kg [1]\n• Faster to place than ETT\n• Cannot suction through LMA — switch to ETT if tracheal suctioning needed\n\n**When to intubate:**\n• Failed PPV despite corrective steps\n• Need for chest compressions (intubation required before CPR)\n• Prolonged PPV anticipated\n• Tracheal suctioning for airway obstruction\n• Special circumstances: CDH (congenital diaphragmatic hernia)\n\nSee ETT sizing reference →' WHERE id = 'nrp-advanced-airway' AND tree_id = 'neonatal-resus';
UPDATE decision_nodes SET body = E'NEONATAL ETT SIZING [1][2]\n\n**ETT size = Gestational Age (weeks) / 10**\n\n**Sizing table:**\n• 23–24 weeks → ETT **2.5**\n• 25–28 weeks → ETT **3.0**\n• 29–34 weeks → ETT **3.5**\n• ≥35 weeks → ETT **3.5–4.0**\n\n**Laryngoscope blade:**\n• **Miller 0** — most neonates\n• **Miller 00** — extreme preterm (<28 weeks)\n\n**ETT depth at lip:**\n• **6 + weight (kg) = cm at lip**\n• Example: 3 kg baby → 6 + 3 = 9 cm at lip\n\n**Securing tips:**\n• Hold tube to roof of mouth during securing\n• Neonatal ETTs are **extremely easy to dislodge** — secure firmly\n• Confirm with CO2 detector + bilateral breath sounds\n• Recheck position after every patient movement' WHERE id = 'nrp-ett-sizing' AND tree_id = 'neonatal-resus';
UPDATE decision_nodes SET body = E'CRITICAL DECISION POINT [1][2]\n\nAfter ensuring effective ventilation (confirmed chest rise, corrective steps applied):\n\n**Is the heart rate still <60 bpm?**\n\nHR <60 despite effective PPV indicates the need for chest compressions.' WHERE id = 'nrp-hr60-check' AND tree_id = 'neonatal-resus';
UPDATE decision_nodes SET body = E'NEONATAL CPR [1][2][3]\n\n**MUST secure airway first** — intubate or place LMA before starting compressions.\n\n**Technique — 2-thumb encircling:**\n• Both thumbs on **lower third of sternum**, just below the nipple line\n• Wrap fingers around the chest\n• Compress **1/3 of anteroposterior diameter**\n\n**Compression-to-ventilation ratio: 3:1**\n• "One—two—three—breathe" (120 events/min = 90 compressions + 30 breaths)\n• This is DIFFERENT from pediatric/adult CPR (15:2 or 30:2)\n\n**During CPR:**\n• Increase to **100% FiO2**\n• Establish vascular access: **UVC preferred** (fastest), IO as alternative\n• Prepare epinephrine\n\n**Goal: HR >60 bpm**\n• Reassess every 60 seconds\n• Once HR >60 → stop compressions, continue PPV\n• If HR remains <60 after 60 seconds of CPR → epinephrine [1][2]' WHERE id = 'nrp-cpr' AND tree_id = 'neonatal-resus';
UPDATE decision_nodes SET body = E'CPR REASSESSMENT — after 60 seconds [1][2]\n\nPause compressions briefly to assess heart rate.\n\n**Is HR ≥60 bpm?**' WHERE id = 'nrp-cpr-eval' AND tree_id = 'neonatal-resus';
UPDATE decision_nodes SET body = E'EPINEPHRINE — Neonatal Resuscitation [1][2][3]\n\n[Epinephrine](#/drug/epinephrine/neonatal resuscitation)\n\n**IV/IO (preferred):**\n• **0.01–0.03 mg/kg** of 1:10,000 (= 0.1–0.3 mL/kg)\n• Repeat every **3–5 minutes** as needed\n\n**ET (if no IV/IO access):**\n• **0.05–0.1 mg/kg** of 1:10,000 (= 0.5–1 mL/kg)\n• Higher dose needed via ET — absorption is unpredictable\n• Switch to IV/IO route as soon as access established\n\n**IV/IO is ALWAYS preferred over ET.** Establish UVC access as quickly as possible.\n\n**Preparation:**\n• Use **1:10,000 concentration** (0.1 mg/mL)\n• Pre-draw doses in labeled syringes\n• Flush with 1–3 mL NS after IV administration\n\n**Continue CPR between doses.** Do not stop compressions to give epinephrine. [1][2]' WHERE id = 'nrp-epinephrine' AND tree_id = 'neonatal-resus';
UPDATE decision_nodes SET body = E'UVC PROCEDURE [1][2]\n\n**Umbilical cord anatomy:**\n• **2 arteries** — thick-walled, small lumen (at top of cross-section)\n• **1 vein** — thin-walled, large lumen (at bottom of cross-section)\n• **Catheterize the VEIN** — larger, easier to cannulate\n\n**Catheter size:**\n• **5 French** — term\n• **3.5 French** — preterm\n\n**Procedure:**\n1. Tie **umbilical tape** at base of stump — gentle tie to control bleeding\n2. Cut cord 1–2 cm above skin\n3. Identify the single large-lumen vein\n4. **Prime catheter** with NS\n5. Insert gently — **only 2–4 cm** until blood aspirates freely\n6. Do NOT advance further — risk of hepatic injury\n\n**IO access** is an acceptable alternative if UVC cannot be placed quickly.\n\n**Once access is established:** give IV epinephrine (preferred over ET route). [1][2]' WHERE id = 'nrp-uvc' AND tree_id = 'neonatal-resus';
UPDATE decision_nodes SET body = E'PERSISTENT HR <60 AFTER EPINEPHRINE [1][2]\n\nIf the heart rate remains <60 after epinephrine and ongoing CPR, consider reversible causes:\n\n• **Hypovolemia** — maternal hemorrhage, placental abruption, cord avulsion\n• **Pneumothorax** — especially after vigorous PPV\n• **Equipment failure** — ETT displacement, monitor malfunction\n• **Prolonged resuscitation** — >20 minutes without response' WHERE id = 'nrp-persistent' AND tree_id = 'neonatal-resus';
UPDATE decision_nodes SET body = E'VOLUME & GLUCOSE RESUSCITATION [1][2]\n\n**Hypovolemia — clinical signs:**\n• Pallor despite adequate oxygenation\n• Weak pulses\n• Poor response to resuscitation\n• Known maternal hemorrhage or placental abruption\n\n**Normal saline:**\n• **10 mL/kg** IV/IO — infuse over 5–10 minutes\n• May repeat if needed\n\n**O-negative pRBCs:**\n• **10 mL/kg** — for acute blood loss (abruption, cord avulsion)\n• Uncrossmatched O-negative\n\n**D10W (10% Dextrose):**\n• **2 mL/kg** IV — for hypoglycemia (glucose <40 mg/dL)\n• Neonates have limited glycogen stores — check glucose early\n\n**Naloxone:**\n• **No longer routinely recommended** in neonatal resuscitation\n• PPV is the treatment for respiratory depression, regardless of cause [1]\n\nReassess after volume — if HR improving → continue PPV → post-resuscitation care.' WHERE id = 'nrp-volume' AND tree_id = 'neonatal-resus';
UPDATE decision_nodes SET body = E'WHEN TO CONSIDER STOPPING [1][4]\n\n**No detectable heart rate after 20 minutes of comprehensive resuscitation** (effective ventilation, chest compressions, epinephrine, volume) may be an appropriate time to discuss discontinuation.\n\n**Factors to consider:**\n• Gestational age and estimated viability\n• Duration of no detectable HR\n• Presence of any reversible causes\n• Parental wishes (if known)\n• Local institutional guidelines\n\n**Team and family discussion:**\n• Involve the family if possible\n• Communicate clearly and compassionately\n• Support the team — neonatal resuscitation discontinuation is emotionally difficult\n\n**Document everything:**\n• Time of birth, APGAR scores\n• All interventions and timing\n• Time of decision to discontinue\n• Who was present and involved in decision' WHERE id = 'nrp-discontinuation' AND tree_id = 'neonatal-resus';
UPDATE decision_nodes SET body = E'POST-RESUSCITATION MONITORING [1][2]\n\n**APGAR scoring:**\n• Assess at **1, 5, and 10 minutes** after birth\n• Appearance, Pulse, Grimace, Activity, Respiration\n\n**Normothermia:**\n• Target **36.5–37.5°C** — monitor continuously\n• Both hypothermia AND hyperthermia worsen outcomes\n• **Therapeutic hypothermia** criteria: ≥36 weeks, moderate-severe HIE, initiated within 6 hours under NICU conditions — NOT during active resuscitation [1]\n\n**Glucose monitoring:**\n• Check within 30–60 minutes of stabilization\n• Treat if <40 mg/dL: D10W 2 mL/kg IV\n\n**NICU transfer:**\n• Any neonate requiring PPV or more should be evaluated by NICU\n• Communicate resuscitation details during handoff\n• Document: all interventions, timing, cord clamping time, APGARs\n\n**Family communication:**\n• Update parents on baby''s condition and plan\n• Allow skin-to-skin when stable\n\n**Team debrief:**\n• Review what went well and what could improve\n• Address emotional impact on team members [1][2]' WHERE id = 'nrp-postresus' AND tree_id = 'neonatal-resus';
UPDATE decision_nodes SET body = E'Neonatal resuscitation algorithm overview — systematic stepwise approach from birth through compressions and epinephrine.\n\nReference: emergencymedicinecases.com' WHERE id = 'nrp-algorithm-ref' AND tree_id = 'neonatal-resus';
UPDATE decision_nodes SET body = E'Neonatal resuscitation equipment sizing and setup reference — term vs preterm numbers, UVC anatomy, and monitoring placement.\n\nReference: Dr. Andrew Kitlowski MD, EM Simulation Cases' WHERE id = 'nrp-setup-ref' AND tree_id = 'neonatal-resus';

-- === neurosyphilis (10 nodes) ===
UPDATE decision_nodes SET body = E'Neurosyphilis should be considered in any patient with confirmed syphilis who has neurological symptoms or signs.\n\nThe diagnosis requires a combination of clinical, serologic, and CSF findings.\n\n**Key presentations:**\n• Visual changes, hearing loss\n• Cognitive impairment, psychiatric symptoms\n• Cranial nerve deficits, meningismus\n• Stroke-like symptoms\n• Tabes dorsalis (late)\n• General paresis (late)' WHERE id = 'ns-start' AND tree_id = 'neurosyphilis';
UPDATE decision_nodes SET body = E'CSF analysis is indicated for patients with syphilis and neurological symptoms.\n\n**Order:**\n• CSF-VDRL (highly specific, low sensitivity)\n• CSF FTA-ABS (more sensitive, less specific)\n• CSF cell count with differential\n• CSF protein\n• CSF glucose\n\n**Interpretation aids:**\n• CSF-VDRL reactive → diagnostic\n• CSF pleocytosis (>5 WBC/µL) → supportive\n• Elevated CSF protein → supportive\n• CSF FTA-ABS negative → helps rule out' WHERE id = 'ns-csf-eval' AND tree_id = 'neurosyphilis';
UPDATE decision_nodes SET body = E'A reactive CSF-VDRL is **diagnostic** of neurosyphilis.\n\n**First-line treatment:**\nAqueous crystalline penicillin G **18–24 million units/day** IV\n• 3–4 million units IV q4h, OR\n• Continuous infusion\n• Duration: **10–14 days**\n\n**Alternative (if IV not feasible):**\nProcaine penicillin 2.4 million units IM daily\nPLUS probenecid 500 mg PO QID\n× 10–14 days\n\n**PCN allergy:**\nDesensitization preferred. If not possible:\nCeftriaxone 2g IV/IM daily × 10–14 days (limited data)\n\n**Follow-up:**\n• Repeat CSF at 6 months\n• CSF pleocytosis should normalize first\n• Re-treat if CSF not improved at 6 months' WHERE id = 'ns-confirmed' AND tree_id = 'neurosyphilis';
UPDATE decision_nodes SET body = E'CSF-VDRL negative but CSF pleocytosis (>5 WBC/µL) or elevated protein with neurological symptoms → **treat as neurosyphilis**.\n\n**Treatment** (same as confirmed):\nAqueous crystalline penicillin G **18–24 million units/day** IV\n• 3–4 million units IV q4h × 10–14 days\n\n**Follow-up:**\n• Repeat CSF at 6 months\n• If CSF not improving, re-treat' WHERE id = 'ns-probable' AND tree_id = 'neurosyphilis';
UPDATE decision_nodes SET body = E'Normal CSF with non-reactive CSF-VDRL makes neurosyphilis unlikely.\n\n**Consider alternative diagnoses** for neurological symptoms.\n\n**Treat underlying syphilis stage:**\n• Early (primary/secondary/early latent): Benzathine PCN G 2.4M units IM × 1\n• Late latent: Benzathine PCN G 2.4M units IM weekly × 3 weeks\n\n**Re-evaluate** if symptoms progress or new neuro symptoms develop.' WHERE id = 'ns-unlikely' AND tree_id = 'neurosyphilis';
UPDATE decision_nodes SET body = E'Ocular and otosyphilis can occur at **any stage** of syphilis and require treatment as neurosyphilis **regardless of CSF findings**.\n\n**Ocular manifestations:**\n• Uveitis (most common), optic neuritis\n• Retinitis, papillitis\n• Vision loss\n\n**Otic manifestations:**\n• Sensorineural hearing loss\n• Tinnitus, vertigo\n\n**Treatment:**\nAqueous crystalline penicillin G **18–24 million units/day** IV\n• 3–4 million units IV q4h × 10–14 days\n\n**Consults:**\n• Ophthalmology (ocular involvement)\n• ENT/Audiology (otic involvement)\n• Infectious Disease\n\nCSF examination is recommended but treatment should NOT be delayed.' WHERE id = 'ns-ocular-otic' AND tree_id = 'neurosyphilis';
UPDATE decision_nodes SET body = E'Routine CSF examination is **NOT recommended** for asymptomatic late latent syphilis.\n\n**Exceptions — CSF exam IS indicated if:**\n• Treatment failure (titer not declining)\n• HIV co-infection with late latent syphilis\n• Neurological signs develop\n• Tertiary syphilis (aortitis, gumma)' WHERE id = 'ns-asymptomatic' AND tree_id = 'neurosyphilis';
UPDATE decision_nodes SET body = E'**First-line:**\nBenzathine penicillin G 2.4 million units IM weekly × 3 weeks\n(Total: 7.2 million units)\n\n**PCN allergy:**\nDesensitization preferred.\nAlternative: Doxycycline 100 mg PO BID × 28 days\n\n**Follow-up:**\n• Quantitative nontreponemal titers at 6, 12, and 24 months\n• 4-fold decline expected\n• If titers do not decline → evaluate for treatment failure, consider CSF exam' WHERE id = 'ns-latent-treatment' AND tree_id = 'neurosyphilis';

-- === nstemi (17 nodes) ===
UPDATE decision_nodes SET body = E'Establish diagnosis: [troponin rise](#/info/nstemi-troponin-sensitivity) AND at least one of ischemic symptoms, new ST depression/T-wave inversion, or wall motion abnormality.\n\n**Immediate actions:**\n• [Aspirin](#/drug/aspirin) 162–325 mg chewed\n• [Nitroglycerin](#/drug/nitroglycerin) 0.4 mg SL q5min × 3 — rule out RV infarction first\n• Morphine ONLY for refractory pain (may increase mortality)\n• Supplemental O₂ only if SpO₂ <90%\n• 12-lead ECG within 10 minutes\n• Serial troponins q3–6h' WHERE id = 'nstemi-start' AND tree_id = 'nstemi';
UPDATE decision_nodes SET body = E'Choose ONE anticoagulation strategy:\n• [Enoxaparin](#/drug/enoxaparin) 1 mg/kg SC q12h — preferred for most patients\n• [UFH](#/drug/ufh) 60 units/kg bolus (max 4,000), 12 units/kg/hr (max 1,000) — preferred if CrCl <30 or PCI within 24h\n• [Fondaparinux](#/drug/fondaparinux) 2.5 mg SC daily — preferred for conservative strategy (lowest bleeding risk per OASIS-5)\n\nDo NOT switch between anticoagulants (increases bleeding risk).' WHERE id = 'nstemi-initial-anticoag' AND tree_id = 'nstemi';
UPDATE decision_nodes SET body = E'Assess for features requiring emergent catheterization (<2 hours):\n• Hemodynamic instability (cardiogenic shock)\n• Refractory/recurrent chest pain despite medical therapy\n• Sustained ventricular arrhythmias (VT/VF)\n• Acute mitral regurgitation or VSD\n• Signs of heart failure (new pulmonary edema)' WHERE id = 'nstemi-risk-stratify' AND tree_id = 'nstemi';
UPDATE decision_nodes SET body = E'**Immediate PCI indicated.**\n• Activate cath lab\n• [UFH](#/drug/ufh) preferred anticoagulation (can titrate in cath lab)\n• If on fondaparinux: supplement with UFH 60 units/kg IV bolus (catheter thrombosis risk)\n• P2Y12 inhibitor loading: [Ticagrelor](#/drug/ticagrelor) 180 mg OR [Prasugrel](#/drug/prasugrel) 60 mg (if no prior stroke/TIA)\n• Consider [Metoprolol](#/drug/metoprolol) if HR >100 and no contraindications\n• Bedside [Echo (POCUS)](#/info/nstemi-pocus) for wall motion, EF, mechanical complications' WHERE id = 'nstemi-emergent' AND tree_id = 'nstemi';
UPDATE decision_nodes SET body = E'Low TIMI risk. Conservative management appropriate.\nSee [Conservative Management Details](#/info/nstemi-conservative)\n\nMedical therapy:\n• Continue anticoagulation (fondaparinux preferred — lowest bleeding)\n• [Metoprolol](#/drug/metoprolol) — target HR <70\n• [Nitroglycerin](#/drug/nitroglycerin) PRN chest pain\n• [Atorvastatin](#/drug/atorvastatin) 80 mg PO (start immediately)\n• Clopidogrel 300 mg loading if no P2Y12 yet (ticagrelor also acceptable)\n\nStress test before discharge.' WHERE id = 'nstemi-conservative' AND tree_id = 'nstemi';
UPDATE decision_nodes SET body = E'TIMI ≥4 (high risk). Cardiac catheterization within 24 hours.\n\n**Pre-PCI preparation:**\n• P2Y12 loading: [Ticagrelor](#/drug/ticagrelor) 180 mg preferred (PLATO: NNT 54 for CV death/MI/stroke)\n• Alternative: [Clopidogrel](#/drug/clopidogrel/acs) 600 mg if ticagrelor not available or on OAC\n• Continue anticoagulation (do NOT switch agents)\n• NPO (anticipate catheterization)\n• [Metoprolol](#/drug/metoprolol) — target HR <70 if tolerated\n• [Atorvastatin](#/drug/atorvastatin) 80 mg PO' WHERE id = 'nstemi-early-invasive' AND tree_id = 'nstemi';
UPDATE decision_nodes SET body = E'TIMI 3 (intermediate risk) or failed conservative strategy.\n\nCardiac catheterization within 25–72 hours.\n• Allows stabilization with medical therapy\n• Same pre-PCI preparation as early invasive\n• P2Y12 loading: [Ticagrelor](#/drug/ticagrelor) 180 mg OR [Clopidogrel](#/drug/clopidogrel/acs) 300–600 mg\n• If deferring P2Y12 until anatomy known: acceptable strategy per guidelines\n• Continue beta-blocker, statin, anticoagulation' WHERE id = 'nstemi-delayed-invasive' AND tree_id = 'nstemi';
UPDATE decision_nodes SET body = E'Select P2Y12 inhibitor for 12-month DAPT.\nSee [P2Y12 Selection Guide](#/info/nstemi-antiplatelet-cx)\n\n**Preferred:** [Ticagrelor](#/drug/ticagrelor) 90 mg BID\n• PLATO trial: reduced CV death/MI/stroke vs clopidogrel (NNT 54)\n• Aspirin ≤100 mg/day required\n\n**High ischemic risk (diabetes, stent thrombosis):** [Prasugrel](#/drug/prasugrel) 10 mg daily\n• TRITON-TIMI 38: more potent, but more bleeding\n• CONTRAINDICATED if prior stroke/TIA\n• Avoid if age ≥75 or weight <60 kg\n\n**High bleeding risk or on OAC:** [Clopidogrel](#/drug/clopidogrel/acs) 75 mg daily\n• Preferred for triple therapy (OAC + DAPT)\n• Least bleeding risk of the three' WHERE id = 'nstemi-post-pci' AND tree_id = 'nstemi';
UPDATE decision_nodes SET body = E'Coronary anatomy indicates CABG (e.g., left main, multivessel disease with diabetes).\n\n**P2Y12 hold times before surgery:**\n• [Ticagrelor](#/drug/ticagrelor): hold ≥3 days (minimum), ideally 5 days\n• [Clopidogrel](#/drug/clopidogrel/acs): hold ≥5 days\n• [Prasugrel](#/drug/prasugrel): hold ≥7 days\n\nContinue aspirin. Restart P2Y12 inhibitor 24–48h post-CABG.\nRefer cardiac surgery.' WHERE id = 'nstemi-cabg' AND tree_id = 'nstemi';
UPDATE decision_nodes SET body = E'Standard DAPT: 12 months post-PCI\n• Aspirin 81 mg + P2Y12 inhibitor daily\n\n**De-escalation options after 1–3 months if high bleeding risk:**\n• Switch from ticagrelor/prasugrel to clopidogrel (HOST-REDUCE trial)\n• Aspirin monotherapy after 1–3 months of DAPT (TWILIGHT trial)\n\n**Extended DAPT beyond 12 months:**\n• Consider if high ischemic risk (prior MI, diabetes, multivessel disease)\n• Ticagrelor 60 mg BID (PEGASUS-TIMI 54)\n\nIs this a MINOCA presentation?' WHERE id = 'nstemi-dapt-duration' AND tree_id = 'nstemi';
UPDATE decision_nodes SET body = E'Myocardial infarction with non-obstructive coronary arteries (≤50% stenosis on angiography). Present in 5–10% of MI patients.\n\nSee [MINOCA Workup & Management](#/info/nstemi-minoca)\n\n**Etiologies:**\n• Coronary spasm (most common)\n• Plaque disruption/erosion\n• Spontaneous coronary artery dissection (SCAD)\n• Takotsubo cardiomyopathy\n• Myocarditis\n\n**KEY:** Standard ACS regimens may be HARMFUL depending on etiology.\n• Coronary spasm: beta-blockers may worsen; use CCBs and nitrates\n• SCAD: anticoagulation may extend dissection; conservative preferred\n• Takotsubo: avoid catecholamines; supportive care\n• Myocarditis: avoid NSAIDs; treat underlying cause\n\nCardiac MRI recommended for all MINOCA patients.' WHERE id = 'nstemi-minoca' AND tree_id = 'nstemi';
UPDATE decision_nodes SET body = E'**The 5 pillars of post-ACS pharmacotherapy:**\n\n1. **DAPT:** Aspirin 81 mg + P2Y12 inhibitor × 12 months\n2. **Statin:** [Atorvastatin](#/drug/atorvastatin) 80 mg (or rosuvastatin 20–40 mg) — target LDL <70\n3. **Beta-blocker:** [Metoprolol](#/drug/metoprolol) succinate — continue if EF <40% or hypertension; may discontinue after 1 year if EF preserved\n4. **ACE inhibitor/ARB:** Start within 24h if EF ≤40%, hypertension, or diabetes. Consider for all post-ACS patients.\n5. **Aldosterone antagonist:** Add if EF ≤40% + HF symptoms or diabetes (EPHESUS trial)\n\nAlso: PPI if DAPT (GI prophylaxis — use pantoprazole, NOT omeprazole with clopidogrel)' WHERE id = 'nstemi-discharge' AND tree_id = 'nstemi';
UPDATE decision_nodes SET body = E'**Targets:**\n• BP <130/80 mmHg\n• LDL <70 mg/dL (consider <55 if very high risk)\n• HbA1c <7% (individualized)\n• BMI <25 (or waist <102 cm M, <88 cm F)\n• Smoking cessation — NNT 12 for mortality reduction\n\n**Cardiac rehabilitation:**\n• Class I recommendation (36 sessions over 12 weeks)\n• 25% relative reduction in cardiovascular mortality\n• Improves functional capacity, quality of life, depression\n\nDid the patient have atrial fibrillation detected?' WHERE id = 'nstemi-risk-factors' AND tree_id = 'nstemi';
UPDATE decision_nodes SET body = E'Patient requires both anticoagulation (AF) and DAPT (stent).\n\n**Triple therapy (OAC + aspirin + P2Y12) for SHORTEST possible duration:**\n• 1 week (if high bleeding risk) to 1 month maximum\n• Then dual therapy: OAC + [Clopidogrel](#/drug/clopidogrel/acs) 75 mg daily (preferred P2Y12 for triple/dual)\n• At 12 months: OAC alone (discontinue P2Y12)\n\n**Preferred DOAC:** Rivaroxaban 15 mg daily (PIONEER AF-PCI) or Apixaban 5 mg BID (AUGUSTUS)\n• Avoid warfarin if possible (more bleeding than DOAC-based regimens)\n• Avoid prasugrel in triple therapy (excess bleeding)\n• Avoid ticagrelor in triple therapy (limited data)' WHERE id = 'nstemi-triple-therapy' AND tree_id = 'nstemi';
UPDATE decision_nodes SET body = E'EF ≤40% post-MI = high-risk. Initiate guideline-directed medical therapy (GDMT):\n\n**Core GDMT (start before discharge):**\n• ACE inhibitor or ARB (or ARNI if stable) — SAVE, VALIANT trials\n• Beta-blocker ([Metoprolol](#/drug/metoprolol) succinate or carvedilol) — CAPRICORN trial\n• Aldosterone antagonist (eplerenone 25–50 mg or spironolactone) if EF ≤40% + HF symptoms or diabetes — EPHESUS trial\n• SGLT2 inhibitor (empagliflozin or dapagliflozin) — EMPEROR-Reduced, DAPA-HF\n\n**Reassess EF at 3 months.** If persistent EF ≤35%: evaluate for ICD (40 days post-MI minimum).\n\nContinue DAPT + statin as planned.' WHERE id = 'nstemi-hf-management' AND tree_id = 'nstemi';
UPDATE decision_nodes SET body = E'**Post-discharge follow-up:**\n• Cardiology: 1–2 weeks\n• PCP: 2–4 weeks\n• Cardiac rehab: referral before discharge (36 sessions)\n• Stress test at 4–6 weeks if not revascularized\n• Echo at 3 months if EF <50% at presentation\n• Lab work: lipid panel at 4–12 weeks (LDL target <70)\n\n**DAPT adherence counseling:**\n• Do NOT stop P2Y12 without cardiology guidance\n• Stent thrombosis risk highest in first 30 days\n• If surgery needed: consult cardiology for P2Y12 bridging plan\n• Carry medication list; inform all providers of stent placement\n\n**Red flags — return to ED:**\n• Chest pain lasting >15 minutes not relieved by nitroglycerin\n• Shortness of breath at rest or worsening\n• Syncope or near-syncope\n• Sustained palpitations' WHERE id = 'nstemi-followup' AND tree_id = 'nstemi';

-- === pe-treatment (14 nodes) ===
UPDATE decision_nodes SET body = E'Confirmed or high-probability acute pulmonary embolism. Risk stratification guides treatment.\n\nAssess **hemodynamic status** first:\n• SBP, heart rate, signs of shock\n• Bedside echo for RV strain\n• Troponin and BNP\n\nUse [PESI](#/calculator/pesi) or [sPESI](#/calculator/spesi) to risk-stratify normotensive patients.' WHERE id = 'pe-start' AND tree_id = 'pe-treatment';
UPDATE decision_nodes SET body = E'Sustained hypotension (SBP <90 mmHg or drop ≥40 mmHg for >15 min), cardiogenic shock, or cardiac arrest.\n\n**Mortality >15%** without immediate treatment.\n\n**ICD-10:** I26.02 (saddle embolus with acute cor pulmonale), I26.09, I26.90' WHERE id = 'pe-massive' AND tree_id = 'pe-treatment';
UPDATE decision_nodes SET body = E'**1. Anticoagulation** — start immediately:\n• [UFH](#/drug/ufh/pe) 80 units/kg bolus → 18 units/kg/hr infusion\n• Preferred over LMWH if thrombolysis anticipated\n\n**2. Systemic thrombolysis** (if no contraindications):\n• [Alteplase](#/drug/alteplase/pulmonary) 100 mg IV over 2 hours\n• OR accelerated regimen: 0.6 mg/kg (max 50 mg) over 15 min in cardiac arrest\n\n**3. If thrombolysis contraindicated:**\n• Catheter-directed therapy (CDT)\n• Surgical embolectomy\n• Consider ECMO as bridge in refractory shock\n\n**Volume resuscitation:** Cautious — >500 mL can worsen RV failure. Use vasopressors (norepinephrine preferred) for hemodynamic support.' WHERE id = 'pe-massive-tx' AND tree_id = 'pe-treatment';
UPDATE decision_nodes SET body = E'Normotensive but with evidence of RV strain or myocardial injury.\n\nAssess for **both**:\n• **RV dysfunction** — echo (RV/LV ratio >0.9, McConnell sign, TAPSE <16mm) or CT (RV/LV ≥0.9)\n• **Elevated biomarkers** — troponin AND/OR BNP/NT-proBNP' WHERE id = 'pe-submassive' AND tree_id = 'pe-treatment';
UPDATE decision_nodes SET body = E'**Anticoagulation** — start immediately:\n• [Enoxaparin](#/drug/enoxaparin/pe) 1 mg/kg SC q12h, OR\n• [UFH](#/drug/ufh/pe) if considering escalation to thrombolysis, OR\n• [Fondaparinux](#/drug/fondaparinux/pe) 5–10 mg SC daily (weight-based)\n\n**ICU monitoring recommended.** Watch closely for clinical deterioration.\n\n**Rescue thrombolysis** if hemodynamic decompensation:\n• [Alteplase](#/drug/alteplase/pulmonary) 100 mg IV over 2h\n• Half-dose alteplase (50 mg) may reduce bleeding risk — emerging evidence\n\n**Consider catheter-directed therapy** if thrombolysis contraindicated but patient deteriorating.' WHERE id = 'pe-submassive-high' AND tree_id = 'pe-treatment';
UPDATE decision_nodes SET body = E'Either RV dysfunction OR elevated biomarkers, but **not both**.\n\n**Anticoagulation alone** — thrombolysis not indicated:\n• [Enoxaparin](#/drug/enoxaparin/pe) 1 mg/kg SC q12h, OR\n• [UFH](#/drug/ufh/pe) if CrCl <30 or concern for rapid escalation\n\n**Hospital admission** for monitoring (typically step-down unit).\n\nReassess if clinical deterioration → escalate to intermediate-high risk pathway.' WHERE id = 'pe-submassive-low' AND tree_id = 'pe-treatment';
UPDATE decision_nodes SET body = E'No RV dysfunction on imaging, normal cardiac biomarkers, no hypotension.\n\n**PESI Class I–II** or **sPESI = 0**.\n\nUse [PESI](#/calculator/pesi) or [sPESI](#/calculator/spesi) to confirm low-risk classification.' WHERE id = 'pe-low-risk' AND tree_id = 'pe-treatment';
UPDATE decision_nodes SET body = E'Assess for **outpatient management** (Hestia criteria or institutional protocol):\n\n• Hemodynamically stable\n• No need for supplemental O₂\n• No active bleeding or high bleeding risk\n• No severe renal impairment (CrCl >30)\n• No severe pain requiring IV analgesics\n• Good social support and reliable follow-up\n• Able to take oral medications\n• No pregnancy' WHERE id = 'pe-outpatient-check' AND tree_id = 'pe-treatment';
UPDATE decision_nodes SET body = E'**DOACs preferred** (no parenteral bridge needed):\n• [Apixaban](#/drug/apixaban/pe) 10 mg BID × 7 days → 5 mg BID\n• [Rivaroxaban](#/drug/rivaroxaban/pe) 15 mg BID × 21 days → 20 mg daily with food\n\n**Follow-up:** Within 3–7 days with primary care or hematology.\n\n**Patient education:**\n• Return for worsening dyspnea, chest pain, hemoptysis, syncope\n• Adherence to anticoagulation is critical\n• Minimum 3 months of therapy; reassess for extended treatment' WHERE id = 'pe-outpatient-tx' AND tree_id = 'pe-treatment';
UPDATE decision_nodes SET body = E'Admit for **24–48h observation** with initiation of anticoagulation.\n\nStart oral DOAC therapy:\n• [Apixaban](#/drug/apixaban/pe) 10 mg BID × 7 days → 5 mg BID, OR\n• [Rivaroxaban](#/drug/rivaroxaban/pe) 15 mg BID × 21 days → 20 mg daily\n\nTransition to outpatient when clinically stable and oral intake confirmed.' WHERE id = 'pe-inpatient-low' AND tree_id = 'pe-treatment';
UPDATE decision_nodes SET body = E'Choice depends on renal function, bleeding risk, patient preference, and cost.\n\n**Key decision points:**\n• CrCl <30 mL/min → UFH preferred\n• Cancer-associated VTE → DOAC (apixaban/rivaroxaban) or LMWH\n• Pregnancy → LMWH only (DOACs contraindicated)\n• HIT → argatroban or fondaparinux' WHERE id = 'pe-anticoag-selection' AND tree_id = 'pe-treatment';
UPDATE decision_nodes SET body = E'**Single-drug approach (no parenteral lead-in):**\n• [Apixaban](#/drug/apixaban/pe) 10 mg BID × 7 days → 5 mg BID\n• [Rivaroxaban](#/drug/rivaroxaban/pe) 15 mg BID × 21 days → 20 mg daily (with food)\n\n**Parenteral lead-in required (5–10 days LMWH/UFH first):**\n• [Edoxaban](#/drug/edoxaban/pe) 60 mg daily (30 mg if CrCl 15–50, weight ≤60 kg, or P-gp inhibitor)\n• [Dabigatran](#/drug/dabigatran/pe) 150 mg BID\n\n**Duration:** Minimum 3 months. Extended treatment for unprovoked PE, recurrent VTE, or persistent risk factors.' WHERE id = 'pe-doac' AND tree_id = 'pe-treatment';
UPDATE decision_nodes SET body = E'• [Enoxaparin](#/drug/enoxaparin/pe) 1 mg/kg SC q12h (or 1.5 mg/kg daily)\n• Start warfarin on day 1 — overlap until INR 2.0–3.0 for ≥24 hours\n• Discontinue LMWH after INR therapeutic × 2 consecutive days\n• Target INR: 2.0–3.0\n\n**Duration:** Minimum 3 months. Extended for unprovoked or recurrent VTE.\n\n**Monitoring:** INR weekly until stable, then monthly.' WHERE id = 'pe-lmwh-warfarin' AND tree_id = 'pe-treatment';
UPDATE decision_nodes SET body = E'**CrCl <30 mL/min:**\n• [UFH](#/drug/ufh/pe) preferred — renally independent clearance\n• Adjust LMWH dose for CrCl 15–30 (enoxaparin 1 mg/kg SC daily)\n• Apixaban may be used cautiously (least renal elimination of DOACs)\n\n**Severe hepatic disease (Child-Pugh C):**\n• UFH preferred\n• DOACs contraindicated in severe hepatic impairment\n\n**HIT (heparin-induced thrombocytopenia):**\n• Discontinue ALL heparin products immediately\n• [Fondaparinux](#/drug/fondaparinux/pe) or argatroban as alternatives\n• Bridge to warfarin only after platelet recovery (>150k)' WHERE id = 'pe-renal-hepatic' AND tree_id = 'pe-treatment';

-- === peds-fever (37 nodes) ===
UPDATE decision_nodes SET body = E'**Fever Without a Source (FWS):** T ≥38°C (100.4°F) rectally in an infant 0–6 months with no identifiable source on history and physical exam.\n\nREFERENCES\n• [HSV Workup Criteria](#/info/pf-hsv-criteria)\n• [UTI Risk Factors](#/info/pf-uti-risk)\n• [Ceftriaxone Contraindications](#/info/pf-ceftriaxone-ci)\n• [Antimicrobial Dosing](#/info/pf-abx-dosing)\n\nSelect the patient’s age:' WHERE id = 'pf-start' AND tree_id = 'peds-fever';
UPDATE decision_nodes SET body = E'Patient meets one or more exclusion criteria for the FWS pathway.\n\nEXCLUSION CRITERIA\n• Preterm (<37 weeks gestational age)\n• Immunocompromised\n• Indwelling devices (VP shunt, central line)\n• Known immune deficiency\n• Recent hospitalization (within 7 days)\n• Current antibiotics or recent (<48h)\n\nOFF-PATHWAY TRIGGERS\n• Focal bacterial infection identified (cellulitis, abscess, pneumonia, osteomyelitis)\n• Hypothermia (<36°C / 96.8°F)\n• Bronchiolitis with clear viral syndrome\n• Clinically ill-appearing (not toxic, but not well)' WHERE id = 'pf-off-pathway' AND tree_id = 'peds-fever';
UPDATE decision_nodes SET body = E'Ill-appearing infant requires full sepsis workup and empiric antibiotics regardless of age.\n\nFULL SEPSIS WORKUP\n• CBC with differential\n• Blood culture\n• CMP\n• UA + urine culture (catheterized)\n• Lumbar puncture: CSF cell count, glucose, protein, Gram stain, culture, meningitis/encephalitis PCR panel\n• Consider: CRP, Procalcitonin, stool culture (if diarrhea)\n• Consider: [HSV workup](#/info/pf-hsv-criteria) if <21 days or risk factors\n\nEMPIRIC ANTIBIOTICS BY AGE\n• **0–7 days:** [Ampicillin](#/drug/ampicillin) + [Gentamicin](#/drug/gentamicin)\n• **8–28 days:** [Ceftriaxone](#/drug/ceftriaxone/pediatric fever) (or [Cefepime](#/drug/cefepime) if [CI](#/info/pf-ceftriaxone-ci)) + [Ampicillin](#/drug/ampicillin)\n• **29–60 days:** [Ceftriaxone](#/drug/ceftriaxone/pediatric fever) + [Vancomycin](#/drug/vancomycin)\n• **>60 days:** [Ceftriaxone](#/drug/ceftriaxone/pediatric fever) + [Vancomycin](#/drug/vancomycin)\n\nSee [Antimicrobial Dosing Reference](#/info/pf-abx-dosing) for weight-based doses.' WHERE id = 'pf-toxic' AND tree_id = 'peds-fever';
UPDATE decision_nodes SET body = E'Does the infant have any of the following off-pathway triggers?\n\n• Focal bacterial infection (cellulitis, abscess, pneumonia, osteomyelitis)\n• Hypothermia (<36°C / 96.8°F)\n• Bronchiolitis with clear viral syndrome\n• Clinically ill-appearing' WHERE id = 'pf-neo-screen' AND tree_id = 'peds-fever';
UPDATE decision_nodes SET body = E'**All 0–21 day neonates require full sepsis workup including LP.**\n\nLABS TO ORDER\n• CBC with differential\n• Blood culture\n• CMP\n• UA (catheterized) — if positive, send urine culture\n• Lumbar puncture:\n  – CSF cell count with differential\n  – CSF glucose, protein\n  – CSF Gram stain\n  – CSF culture\n  – Meningitis/encephalitis PCR panel\n  – Hold tube #4 (for HSV PCR if needed)\n\nOPTIONAL\n• CRP, Procalcitonin\n• Stool culture (if diarrhea present)' WHERE id = 'pf-neo-labs' AND tree_id = 'peds-fever';
UPDATE decision_nodes SET body = E'Does the infant have [HSV risk factors or clinical features](#/info/pf-hsv-criteria)?\n\n• Skin vesicles (mouth, scalp, trunk)\n• Seizures\n• Lethargy, poor feeding\n• Hepatosplenomegaly\n• Thrombocytopenia or transaminitis\n• CSF pleocytosis\n• Maternal HSV history' WHERE id = 'pf-neo-hsv' AND tree_id = 'peds-fever';
UPDATE decision_nodes SET body = E'**Add [Acyclovir](#/drug/acyclovir) 20 mg/kg IV q8h**\n\nHSV TESTING TO ORDER\n• HSV PCR — blood (plasma)\n• HSV PCR — CSF (from held tube #4)\n• Surface cultures: conjunctiva, throat, nasopharynx, rectum\n• Vesicle fluid: viral culture + PCR (if lesions present)\n• AST, ALT (hepatic involvement screen)\n\nDURATION\n• Minimum 5 doses or until HSV PCR results negative\n• If PCR not resulted after 5 doses → contact Infectious Disease\n• Ensure adequate hydration (crystalline nephropathy risk)' WHERE id = 'pf-neo-hsv-rx' AND tree_id = 'peds-fever';
UPDATE decision_nodes SET body = E'Select the neonate’s age to determine the appropriate empiric regimen.\n\nSee [Antimicrobial Dosing Reference](#/info/pf-abx-dosing) for complete dosing table.' WHERE id = 'pf-neo-age' AND tree_id = 'peds-fever';
UPDATE decision_nodes SET body = E'Review CSF results from the lumbar puncture.\n\n**ABNORMAL CSF (0–28 days):**\n• WBC >15 cells/mm³\n• Positive Gram stain\n• Traumatic tap or uninterpretable\n\nNote: Traumatic taps are common in neonates. If bloody, use correction ratio or treat as if abnormal.' WHERE id = 'pf-neo-csf' AND tree_id = 'peds-fever';
UPDATE decision_nodes SET body = E'**Escalate to meningitic dosing based on age:**\n\n**0–7 DAYS**\n• [Ampicillin](#/drug/ampicillin) 100 mg/kg IV q8h (meningitic dose)\n• Add [Cefepime](#/drug/cefepime) 50 mg/kg IV q12h\n• Discontinue [Gentamicin](#/drug/gentamicin)\n• Consider [Acyclovir](#/drug/acyclovir) if not already started\n\n**8–21 DAYS**\n• [Ceftriaxone](#/drug/ceftriaxone/pediatric meningitis) 50 mg/kg IV q12h (meningitic dose)\n• Add [Ampicillin](#/drug/ampicillin) 75 mg/kg IV q6h (meningitic dose)\n• Consider [Acyclovir](#/drug/acyclovir) if not already started\n\nSee [Antimicrobial Dosing Reference](#/info/pf-abx-dosing) for complete dosing.' WHERE id = 'pf-neo-mening' AND tree_id = 'peds-fever';
UPDATE decision_nodes SET body = E'**ALL 0–21 day neonates are admitted** regardless of clinical appearance or lab results.\n\nINPATIENT MANAGEMENT\n• Continue empiric antibiotics pending culture results\n• Blood cultures: finalized at 24–36 hours\n• CSF cultures: finalized at 48–72 hours\n\nIF PATHOGEN IDENTIFIED\n• Narrow antibiotics to targeted therapy\n• Duration based on organism and site\n\nIF NO PATHOGEN AT 24–36 HOURS + WELL-APPEARING\n• Discontinue antimicrobials\n• Observe for clinical stability\n• Manage supportively for duration of illness' WHERE id = 'pf-neo-admit' AND tree_id = 'peds-fever';
UPDATE decision_nodes SET body = E'Does the infant have any of the following off-pathway triggers?\n\n• Focal bacterial infection identified\n• Hypothermia (<36°C / 96.8°F)\n• Bronchiolitis with clear viral syndrome\n• Clinically ill-appearing' WHERE id = 'pf-22-screen' AND tree_id = 'peds-fever';
UPDATE decision_nodes SET body = E'LABS TO ORDER\n• CBC with differential\n• Blood culture\n• CMP\n• **Procalcitonin (PCT)**\n• UA (catheterized) — if positive, send urine culture\n\nOPTIONAL\n• CRP\n• Stool culture (if diarrhea present)\n\nLP is not automatically required for this age group — it depends on inflammatory marker results and shared decision-making.' WHERE id = 'pf-22-labs' AND tree_id = 'peds-fever';
UPDATE decision_nodes SET body = E'Are ANY of the following inflammatory markers abnormal?\n\n**ABNORMAL CRITERIA:**\n• Temperature >38.5°C (101.3°F)\n• Procalcitonin >0.5 ng/mL\n• CRP >2.0 mg/dL\n• ANC >4,000 cells/mm³\n\nAny single abnormal marker → higher risk.\nAll normal → lower risk but still requires evaluation.' WHERE id = 'pf-22-im' AND tree_id = 'peds-fever';
UPDATE decision_nodes SET body = E'Lumbar puncture is recommended if inflammatory markers are abnormal. For normal markers, LP is a shared decision with the family.\n\n**ABNORMAL CSF (22–28 days):**\n• WBC >15 cells/mm³\n• Positive Gram stain' WHERE id = 'pf-22-lp' AND tree_id = 'peds-fever';
UPDATE decision_nodes SET body = E'**MENINGITIS DOSING (22–28 DAYS)**\n• [Ceftriaxone](#/drug/ceftriaxone/pediatric meningitis) 50 mg/kg IV q12h (meningitic dose)\n• Add [Ampicillin](#/drug/ampicillin) 75 mg/kg IV q6h (meningitic dose)\n• Consider [Acyclovir](#/drug/acyclovir) 20 mg/kg IV q8h if HSV risk factors\n\nSee [Antimicrobial Dosing Reference](#/info/pf-abx-dosing) for complete dosing.' WHERE id = 'pf-22-mening' AND tree_id = 'peds-fever';
UPDATE decision_nodes SET body = E'Review the [urinalysis results](#/info/pf-ua-interpret).\n\n**Positive UA:** Leukocyte esterase, nitrites, >5 WBC/hpf, or bacteria on Gram stain.\n\nIf UA positive, ensure catheterized urine culture was sent.' WHERE id = 'pf-22-ua' AND tree_id = 'peds-fever';
UPDATE decision_nodes SET body = E'**ANTIBIOTIC TREATMENT**\n• [Cefazolin](#/drug/cefazolin) 17 mg/kg IV q8h (without bacteremia)\n• [Cefazolin](#/drug/cefazolin) 33 mg/kg IV q8h (with concurrent bacteremia)\n• Step-down to [Cephalexin](#/drug/cephalexin) 17 mg/kg PO TID when tolerating PO\n• Total duration: 10 days (IV + PO combined)\n\nADMIT for IV antibiotics and monitoring.' WHERE id = 'pf-22-uti' AND tree_id = 'peds-fever';
UPDATE decision_nodes SET body = E'Normal CSF and negative UA. Disposition depends on inflammatory marker status and shared decision-making with the family.\n\n**IF ABNORMAL INFLAMMATORY MARKERS:**\nHigher risk — admission preferred. If family elects home observation:\n• [Ceftriaxone](#/drug/ceftriaxone/pediatric fever) 50 mg/kg IM/IV x1 before discharge\n• Mandatory follow-up in 24 hours\n\n**IF NORMAL INFLAMMATORY MARKERS:**\nLower risk — home observation is reasonable.\n• Antibiotics optional (prefer off antibiotics)\n• Follow-up in 24 hours' WHERE id = 'pf-22-sdm' AND tree_id = 'peds-fever';
UPDATE decision_nodes SET body = E'**IF DISCHARGED HOME**\n• Review [Discharge Criteria](#/info/pf-discharge) — all must be met\n• Consider [Ceftriaxone](#/drug/ceftriaxone/pediatric fever) 50 mg/kg IM/IV x1 if inflammatory markers abnormal\n• Mandatory PCP or ED follow-up within 24 hours\n• Provide [Return Precautions](#/info/pf-discharge)\n• Culture callback: blood culture results at 24–36h\n\n**IF ADMITTED**\n• Continue observation\n• If abnormal inflammatory markers: may give [Ceftriaxone](#/drug/ceftriaxone/pediatric fever) 50 mg/kg IV q24h\n• If normal inflammatory markers: prefer off antibiotics, discuss close observation\n• Culture results at 24–36h determine next steps\n\n**IF LP NOT PERFORMED**\n• Abnormal inflammatory markers: recommend admission, prefer off antibiotics but may give Ceftriaxone\n• Normal inflammatory markers: home observation reasonable with 24h follow-up' WHERE id = 'pf-22-dispo' AND tree_id = 'peds-fever';
UPDATE decision_nodes SET body = E'Does the infant have any of the following off-pathway triggers?\n\n• Focal bacterial infection identified\n• Hypothermia (<36°C / 96.8°F)\n• Bronchiolitis with clear viral syndrome\n• Clinically ill-appearing' WHERE id = 'pf-60-screen' AND tree_id = 'peds-fever';
UPDATE decision_nodes SET body = E'LABS TO ORDER\n• CBC with differential\n• Blood culture\n• CMP\n• **Procalcitonin (PCT)**\n• UA (catheterized) — if positive, send urine culture\n\nOPTIONAL\n• CRP\n• Stool culture (if diarrhea present)\n\nLP is determined by inflammatory marker results.' WHERE id = 'pf-60-labs' AND tree_id = 'peds-fever';
UPDATE decision_nodes SET body = E'Are ANY of the following inflammatory markers abnormal?\n\n**ABNORMAL CRITERIA:**\n• Temperature >38.5°C (101.3°F)\n• Procalcitonin >0.5 ng/mL\n• CRP >2.0 mg/dL\n• ANC >4,000 cells/mm³\n\nAny single abnormal marker → higher risk → LP recommended.\nAll normal → lower risk → no LP needed.' WHERE id = 'pf-60-im' AND tree_id = 'peds-fever';
UPDATE decision_nodes SET body = E'Lumbar puncture recommended for elevated inflammatory markers.\n\n**ABNORMAL CSF (29–60 days):**\n• WBC >9 cells/mm³ (lower threshold than 0–28 days)\n• Positive Gram stain' WHERE id = 'pf-60-lp' AND tree_id = 'peds-fever';
UPDATE decision_nodes SET body = E'**MENINGITIS DOSING (29–60 DAYS)**\n• [Ceftriaxone](#/drug/ceftriaxone/pediatric meningitis) 50 mg/kg IV q12h (meningitic dose)\n• Add [Vancomycin](#/drug/vancomycin) 15 mg/kg IV q6h\n• Consider [Acyclovir](#/drug/acyclovir) 20 mg/kg IV q8h if HSV risk factors\n\nNote: [Vancomycin](#/drug/vancomycin) added (instead of [Ampicillin](#/drug/ampicillin)) to cover MRSA and resistant GBS/pneumococcus in this age group.\n\nSee [Antimicrobial Dosing Reference](#/info/pf-abx-dosing) for complete dosing.' WHERE id = 'pf-60-mening' AND tree_id = 'peds-fever';
UPDATE decision_nodes SET body = E'Review the [urinalysis results](#/info/pf-ua-interpret).\n\n**Positive UA:** Leukocyte esterase, nitrites, >5 WBC/hpf, or bacteria on Gram stain.\n\nIf UA positive, ensure catheterized urine culture was sent.' WHERE id = 'pf-60-ua' AND tree_id = 'peds-fever';
UPDATE decision_nodes SET body = E'**ANTIBIOTIC TREATMENT**\n• [Cefazolin](#/drug/cefazolin) 17 mg/kg IV q8h (without bacteremia)\n• [Cefazolin](#/drug/cefazolin) 33 mg/kg IV q8h (with concurrent bacteremia)\n• Step-down to [Cephalexin](#/drug/cephalexin) 17 mg/kg PO TID when tolerating PO\n• Total duration: 10 days (IV + PO combined)\n\nADMIT for IV antibiotics and monitoring.' WHERE id = 'pf-60-uti' AND tree_id = 'peds-fever';
UPDATE decision_nodes SET body = E'Abnormal inflammatory markers but normal CSF and negative UA.\n\n• [Ceftriaxone](#/drug/ceftriaxone/pediatric fever) 50 mg/kg IM/IV x1 recommended\n• Home observation with mandatory 24-hour follow-up\n• OR admit for observation' WHERE id = 'pf-60-sdm' AND tree_id = 'peds-fever';
UPDATE decision_nodes SET body = E'**IF DISCHARGED HOME**\n• Review [Discharge Criteria](#/info/pf-discharge) — all must be met\n• [Ceftriaxone](#/drug/ceftriaxone/pediatric fever) 50 mg/kg IM/IV x1 before discharge\n• Mandatory PCP or ED follow-up within 24 hours\n• Provide [Return Precautions](#/info/pf-discharge)\n• Culture callback: blood culture results at 24–36h\n\n**IF ADMITTED**\n• [Ceftriaxone](#/drug/ceftriaxone/pediatric fever) 50 mg/kg IV q24h\n• Monitor for clinical deterioration\n• Culture results at 24–36h determine next steps' WHERE id = 'pf-60-dispo' AND tree_id = 'peds-fever';
UPDATE decision_nodes SET body = E'All inflammatory markers normal → low risk for serious bacterial infection. No LP needed.\n\n**UA POSITIVE?**\n• If UA positive: [Cephalexin](#/drug/cephalexin) 17 mg/kg PO TID x 10 days + home\n• Ensure catheterized urine culture was sent\n\n**UA NEGATIVE?**\n• No antibiotics needed\n• Home observation with follow-up\n\n**DISCHARGE REQUIREMENTS**\n• Review [Discharge Criteria](#/info/pf-discharge)\n• PCP or ED follow-up within 24 hours\n• Provide [Return Precautions](#/info/pf-discharge)\n• Culture callback: blood culture results at 24–36h' WHERE id = 'pf-60-low' AND tree_id = 'peds-fever';
UPDATE decision_nodes SET body = E'**Temperature threshold: ≥39°C (102.2°F) or <36°C**\n\nAssess the infant for source of fever:' WHERE id = 'pf-6m-screen' AND tree_id = 'peds-fever';
UPDATE decision_nodes SET body = E'Identifiable bacterial source found on exam. Manage per condition-specific guidelines.\n\nCOMMON FOCAL INFECTIONS\n• Urinary tract infection → UA + culture, antibiotics per UTI guidelines\n• Pneumonia → CXR, antibiotics per CAP guidelines\n• Cellulitis/abscess → I&D if fluctuant, antibiotics based on severity\n• Acute otitis media → antibiotics per AOM guidelines\n• Osteomyelitis/septic arthritis → urgent orthopedic and ID consult\n\n**RED FLAG:** Prolonged fever >5 days without clear source → consider Kawasaki disease or MIS-C.' WHERE id = 'pf-6m-focal' AND tree_id = 'peds-fever';
UPDATE decision_nodes SET body = E'Defined viral syndrome identified. Supportive care for the viral illness.\n\nHowever, **still screen for UTI** — UTI can coexist with viral infections in this age group.\n\nObtain UA. See [UTI Risk Factors](#/info/pf-uti-risk) for screening criteria.' WHERE id = 'pf-6m-viral' AND tree_id = 'peds-fever';
UPDATE decision_nodes SET body = E'**Fever Without an Apparent Source (FWAS)**\n\nLABS TO ORDER\n• CBC with differential\n• Blood culture\n• UA (catheterized if [risk factors](#/info/pf-uti-risk) present)\n• Procalcitonin\n\nOPTIONAL: CMP, CRP, stool culture (if diarrhea)\n\nAssess PCV (pneumococcal conjugate vaccine) status and [UTI risk](#/info/pf-uti-risk):' WHERE id = 'pf-6m-workup' AND tree_id = 'peds-fever';
UPDATE decision_nodes SET body = E'Infant has <2 PCV doses → higher risk for invasive pneumococcal disease.\n\n**ADDITIONAL ASSESSMENT**\n• If WBC >15,000 or <5,000 cells/mm³: obtain blood culture + consider empiric [Ceftriaxone](#/drug/ceftriaxone/pediatric fever) 50 mg/kg IM/IV x1\n• If WBC 5,000–15,000: lower risk, observe\n\n**DISPOSITION**\n• If given Ceftriaxone: mandatory 24-hour follow-up\n• Review [Discharge Criteria](#/info/pf-discharge)\n• Provide [Return Precautions](#/info/pf-discharge)\n• Culture callback at 24–36h' WHERE id = 'pf-6m-pcv' AND tree_id = 'peds-fever';
UPDATE decision_nodes SET body = E'**TREATMENT OPTIONS BY CLINICAL STATUS**\n\nWELL-APPEARING + TOLERATING PO\n• [Cephalexin](#/drug/cephalexin) 17 mg/kg PO TID x 10 days\n• OR [Ceftriaxone](#/drug/ceftriaxone/pediatric fever) 50 mg/kg IM/IV x1, then oral step-down\n\nILL-APPEARING OR NOT TOLERATING PO\n• [Cefazolin](#/drug/cefazolin) 17 mg/kg IV q8h\n• Step-down to [Cephalexin](#/drug/cephalexin) 17 mg/kg PO TID when tolerating PO\n• If bacteremia: [Cefazolin](#/drug/cefazolin) 33 mg/kg IV q8h\n\nTotal duration: 10 days (IV + PO combined)\n\nENSURE: Catheterized urine culture sent. Follow up culture results.' WHERE id = 'pf-6m-uti' AND tree_id = 'peds-fever';
UPDATE decision_nodes SET body = E'**ED DISCHARGE CRITERIA** (all must be met)\n• Well-appearing on exam\n• Tolerating oral liquids\n• Reliable caregiver with transportation\n• PCP or ED follow-up within 24 hours confirmed\n• Caregiver comfortable with home observation\n• Review [full Discharge Criteria](#/info/pf-discharge)\n\n**IF CRITERIA NOT MET → ADMIT**\n\n**FOLLOW-UP**\n• PCP or ED in 24 hours\n• Culture callback: blood culture results at 24–36h\n• Provide [Return Precautions](#/info/pf-discharge)' WHERE id = 'pf-6m-dispo' AND tree_id = 'peds-fever';

-- === pep (15 nodes) ===
UPDATE decision_nodes SET body = E'[Patient Info Sheet: PEP](#/info/pep-patient-info) — printable summary of transmission risk, treatment effectiveness, and side effects.\n\nWhat type of HIV exposure occurred?' WHERE id = 'pep-start' AND tree_id = 'pep';
UPDATE decision_nodes SET body = E'Was the exposure to a substantial-risk body fluid?\n\nSUBSTANTIAL RISK\n• Blood\n• Semen / vaginal secretions\n• Rectal secretions\n• Breast milk\n• Any visibly bloody body fluid\n\nNEGLIGIBLE RISK\n• Urine, saliva, sweat, tears (without visible blood)' WHERE id = 'pep-fluid' AND tree_id = 'pep';
UPDATE decision_nodes SET body = E'Has it been ≤72 hours since the exposure?\n\nPEP must be initiated as soon as possible. Efficacy decreases with delay and is not recommended after 72 hours.' WHERE id = 'pep-timing' AND tree_id = 'pep';
UPDATE decision_nodes SET body = E'What is the source person’s HIV status?\n\nIf source is known HIV+ on ART with sustained undetectable viral load (<200 copies/mL), transmission risk is negligible (U=U). PEP may still be offered per patient preference.' WHERE id = 'pep-source' AND tree_id = 'pep';
UPDATE decision_nodes SET body = E'**Do not delay PEP for test results.** Start medications now; adjust later based on labs.\n\nBASELINE LABS\n• HIV Ag/Ab combo (4th gen)\n• Hepatitis B [surface Ag](#/info/hbv-serology), [surface Ab](#/info/hbv-serology), [core Ab](#/info/hbv-serology)\n• Hepatitis C Ab\n• BMP (creatinine for renal dosing)\n• CBC\n• Pregnancy test (if applicable)\n• STI screening (GC/CT, syphilis RPR)\n\nFor occupational exposures, also test the source patient for HIV, HBV, and HCV.' WHERE id = 'pep-workup' AND tree_id = 'pep';
UPDATE decision_nodes SET body = E'PEP is safe and recommended in pregnancy. Use the same preferred regimen.\n\n• [Biktarvy](#/drug/biktarvy) (BIC/FTC/TAF) — preferred single-tablet regimen, extensive safety data in pregnancy\n• Alternative: [TDF/FTC](#/drug/tdf-ftc) + [Dolutegravir](#/drug/dolutegravir)\n• Avoid efavirenz-based regimens\n• OB/HIV specialist consultation recommended' WHERE id = 'pep-pregnancy' AND tree_id = 'pep';
UPDATE decision_nodes SET body = E'Dose adjustment required for CrCl <50 mL/min.\n\n• Use TAF-based regimen (TAF is preferred over TDF in renal impairment)\n• [Biktarvy](#/drug/biktarvy) — do not use if CrCl <30\n• If CrCl <30: consult ID/pharmacy for alternative regimen\n• Avoid TDF if CrCl <60 (nephrotoxic)' WHERE id = 'pep-renal' AND tree_id = 'pep';
UPDATE decision_nodes SET body = E'**PREFERRED REGIMEN**\n[Biktarvy](#/drug/biktarvy) (bictegravir/emtricitabine/TAF) — 1 tablet PO daily x 28 days\n\n**ALTERNATIVE REGIMEN**\n[TDF/FTC](#/drug/tdf-ftc) (Truvada) 1 tablet PO daily + [Dolutegravir](#/drug/dolutegravir) (Tivicay) 50 mg PO daily x 28 days\n\n**SECOND ALTERNATIVE**\n[TDF/FTC](#/drug/tdf-ftc) + [Darunavir](#/drug/darunavir) 800 mg PO daily + [Ritonavir](#/drug/ritonavir) 100 mg PO daily x 28 days\n\nPrescribe full 28-day course from the ED. Do not dispense starter packs — patients may not follow up for refills.' WHERE id = 'pep-regimen' AND tree_id = 'pep';
UPDATE decision_nodes SET body = E'HIV TESTING SCHEDULE\n• Baseline: HIV Ag/Ab (4th gen) at initial visit\n• 4–6 weeks: Repeat HIV test\n• 3 months: Repeat HIV test (final if 4th gen used)\n\nMEDICATION FOLLOW-UP\n• 2-week visit: Assess adherence, side effects, renal function\n• Complete full 28 days — early discontinuation reduces efficacy\n\nHEPATITIS B & C FOLLOW-UP\n• Review baseline Hepatitis B [surface Ag](#/info/hbv-serology), [surface Ab](#/info/hbv-serology), [core Ab](#/info/hbv-serology) results\n• If susceptible (all negative): start HBV vaccine series; give HBIG if source HBV+\n• HCV: Baseline + 6-month HCV Ab; if seroconversion, early DAA treatment cures >95%\n\nOCCUPATIONAL EXPOSURES\n• Report to occupational health / employee health\n\nPrEP TRANSITION\n• For patients with ongoing HIV risk, transition to PrEP after completing PEP and confirming HIV-negative status\n• No gap needed between PEP and PrEP' WHERE id = 'pep-followup' AND tree_id = 'pep';

-- === pneumothorax (14 nodes) ===
UPDATE decision_nodes SET body = E'Point-of-care ultrasound (POCUS) is highly sensitive and specific for pneumothorax detection, especially in supine trauma patients. Can detect as little as **20-50 mL of air**.\n\n**Indications:**\n• Chest trauma\n• Sudden dyspnea\n• Pleuritic chest pain\n• Decreased breath sounds\n• Subcutaneous emphysema\n• Post-procedure evaluation' WHERE id = 'pneumothorax-start' AND tree_id = 'pneumothorax';
UPDATE decision_nodes SET body = E'**Probe:** High-frequency linear probe\n\n**Position:** Scan anterior chest at **2nd-4th intercostal spaces**, mid-clavicular line\n\n**Steps:**\n1. Compare bilateral lung sliding\n2. Use **M-mode** to confirm findings\n3. Look for lung point if no sliding\n\n**Tip:** In trauma, this is part of the **eFAST** exam. Supine position — air rises anteriorly.' WHERE id = 'pocus-technique' AND tree_id = 'pneumothorax';
UPDATE decision_nodes SET body = E'Assess for **lung sliding** — the shimmering movement of the visceral pleura against the parietal pleura during respiration.\n\nAlso look for:\n• **Comet tail artifacts** (B-lines)\n• **Seashore sign** on M-mode (normal)\n• **Barcode/stratosphere sign** on M-mode (abnormal)' WHERE id = 'lung-sliding-assessment' AND tree_id = 'pneumothorax';
UPDATE decision_nodes SET body = E'**Lung sliding, comet tails, and B-lines exclude pneumothorax** at the scanned locations.\n\n**Negative predictive value >99%**\n\nIf clinical suspicion persists despite normal POCUS:\n• Scan additional rib spaces\n• Consider CT chest\n• Repeat imaging if symptoms change' WHERE id = 'normal-findings' AND tree_id = 'pneumothorax';
UPDATE decision_nodes SET body = E'Absent lung sliding with **stratosphere sign** on M-mode (barcode sign) suggests pneumothorax.\n\n**Important:** Absent sliding alone is not diagnostic — can also be seen in:\n• Mainstem intubation\n• Pleural adhesions\n• Apnea\n• Severe ARDS\n\nCheck **multiple rib spaces** and look for the **lung point**.' WHERE id = 'stratosphere-sign' AND tree_id = 'pneumothorax';
UPDATE decision_nodes SET body = E'The **lung point** is **pathognomonic** for pneumothorax — where lung sliding appears and disappears with respiration at the border of the collapsed lung.\n\n**Specificity: 100%**\n\nSlide the probe laterally from the area of absent sliding until you see intermittent sliding.' WHERE id = 'lung-point' AND tree_id = 'pneumothorax';
UPDATE decision_nodes SET body = E'**POCUS confirmed pneumothorax** (lung point = 100% specificity).\n\n**Size estimation by lung point location:**\n• Anterior chest only → **Small**\n• Extends to mid-axillary line → **Moderate**\n• Extends posteriorly → **Large**' WHERE id = 'confirmed-ptx' AND tree_id = 'pneumothorax';
UPDATE decision_nodes SET body = E'If absent lung sliding throughout the **entire hemithorax** without a lung point, suspect **massive pneumothorax** with complete lung collapse.\n\n**Confirm with CXR** — assess for mediastinal shift.\n\nIf hemodynamically unstable → treat as tension pneumothorax.' WHERE id = 'no-lung-point' AND tree_id = 'pneumothorax';
UPDATE decision_nodes SET body = E'**Assess for tension pneumothorax:**\n• Hypotension\n• Tracheal deviation\n• Distended neck veins\n• Severe respiratory distress\n\n**DO NOT wait for imaging if tension suspected.**' WHERE id = 'tension-assessment' AND tree_id = 'pneumothorax';
UPDATE decision_nodes SET body = E'**Needle decompression STAT:**\n• **14-gauge angiocath**\n• **2nd ICS, mid-clavicular line**\n• OR **4th-5th ICS, anterior axillary line**\n\n**Follow with chest tube placement.**\n\nSee [Chest Tube / Pneumothorax Management](#/tree/chest-tube) for tube thoracostomy procedure.' WHERE id = 'needle-decompression' AND tree_id = 'pneumothorax';
UPDATE decision_nodes SET body = E'Obtain **CXR or CT** to assess pneumothorax size.\n\nPOCUS lung point location provides initial size estimate.' WHERE id = 'stable-ptx-management' AND tree_id = 'pneumothorax';
UPDATE decision_nodes SET body = E'**Observation with high-flow O2** (if not COPD):\n• Repeat imaging in **6 hours**\n• Admit for observation\n• Supplemental O2 increases reabsorption rate (~2%/day → ~4%/day)\n\n**Discharge criteria:**\n• Stable or improving on repeat imaging\n• No respiratory distress\n• Reliable follow-up available' WHERE id = 'small-ptx' AND tree_id = 'pneumothorax';
UPDATE decision_nodes SET body = E'**Chest tube placement** indicated.\n\nSimple aspiration may be considered for **primary spontaneous pneumothorax** in select patients.\n\nSee [Chest Tube / Pneumothorax Management](#/tree/chest-tube) for:\n• Tube thoracostomy procedure\n• Insertion technique\n• Post-placement management' WHERE id = 'large-ptx' AND tree_id = 'pneumothorax';
UPDATE decision_nodes SET body = E'In trauma, pneumothorax evaluation is part of the **eFAST exam**.\n\n**Key points:**\n• Supine position — air rises **anteriorly**\n• Up to **50% of pneumothoraces** are occult on initial CXR but visible on CT\n• POCUS detects occult PTX missed on supine CXR\n\n**Occult PTX management:**\n• Observation appropriate for small, stable occult PTX\n• Consider chest tube if **positive pressure ventilation** planned or PTX enlarging' WHERE id = 'trauma-efast' AND tree_id = 'pneumothorax';

-- === potassium (24 nodes) ===
UPDATE decision_nodes SET body = E'[Potassium Disorders Steps Summary](#/info/k-summary) — stepwise management of hyperkalemia and hypokalemia.\n\nWhat is the serum potassium level?\n\nConfirm result with clinical context. Consider repeating if unexpected.' WHERE id = 'k-start' AND tree_id = 'potassium';
UPDATE decision_nodes SET body = E'**Rule out pseudohyperkalemia before treating:**\n\n• In vitro hemolysis (most common artifact) — repeat lab\n• Severe polycythemia (platelets >1M or WBC >50K) — use heparinized tube or POC\n• Prolonged tourniquet application or fist clenching\n• Delayed sample processing\n\n**Point-of-care testing** is generally accurate but cannot detect hemolysis.\n\nIf lab reports severe hyperkalemia but ECG is normal → consider pseudohyperkalemia and repeat the lab.' WHERE id = 'k-pseudo' AND tree_id = 'potassium';
UPDATE decision_nodes SET body = E'The **first response** to a lab report of hyperkalemia should be to look at telemetry and obtain an ECG.\n\n[Hyperkalemia ECG Findings](#/info/k-hyper-ecg-info) — progression by K+ level\n\n**If ECG shows hyperkalemia features** → confirms diagnosis, treat as severe.\n\n**If severe lab value but normal ECG** → consider pseudohyperkalemia, repeat lab.\n\nMost patients with hyperkalemia are **asymptomatic**, even with severe elevations.' WHERE id = 'k-hyper-ecg' AND tree_id = 'potassium';
UPDATE decision_nodes SET body = E'Classify severity based on potassium level, ECG changes, chronicity, and ongoing K+ release.\n\n**Severe hyperkalemia (KDIGO):**\n• K+ ≥ 6.5 mEq/L with ECG changes\n• K+ ≥ 6.0 mEq/L with rapid rise or ongoing release (TLS, rhabdo)\n\n**Chronic hyperkalemia** (e.g., dialysis patients) is better tolerated than acute.\n\n**Most dangerous ECG findings:** Bradycardia (RR 12.3), QRS widening (RR 4.7), junctional rhythm (RR 7.5).' WHERE id = 'k-hyper-severity' AND tree_id = 'potassium';
UPDATE decision_nodes SET body = E'**[1] Treat definable causes:**\n• Discontinue offending medications and nephrotoxins\n• Establish euvolemia with adequate perfusion\n• Consider renal diet with limited K+ intake\n\n**[2] Gentle kaliuresis:**\n• [Furosemide](#/drug/furosemide) 40-80 mg IV — may be sufficient as sole diuretic\n• Replace urine volume with Lactated Ringers to maintain even fluid balance\n\nIf single diuretic fails → escalate to aggressive kaliuresis strategy.' WHERE id = 'k-hyper-mod' AND tree_id = 'potassium';
UPDATE decision_nodes SET body = E'**Start ALL temporizing measures simultaneously.**\n\nThese shift K+ into cells and stabilize the myocardium. They are **temporizing only** — K+ will return to baseline in 2-4 hours without definitive elimination therapy.\n\n**Three interventions:**\n1. IV Calcium → membrane stabilization\n2. Insulin + Dextrose → intracellular K+ shift\n3. Beta-2 agonist → intracellular K+ shift\n\n**Do NOT provide temporizing measures without definitive therapy.** This will temporarily improve the K+ but hyperkalemia will inevitably recur.' WHERE id = 'k-hyper-step1' AND tree_id = 'potassium';
UPDATE decision_nodes SET body = E'**Indications:** ECG changes (especially bradycardia, QRS widening, conduction delays). Controversial for isolated peaked T-waves.\n\n**Dosing:**\n• Peripheral access: [Calcium Gluconate](#/drug/calcium-gluconate) **3 grams IV over 10 minutes**\n• Central access: [Calcium Chloride](#/drug/calcium-chloride) **1 gram IV over 10 minutes**\n\n**Duration:** 30-60 minutes only — may need to repeat 1-2 times.\n\nRapid IV calcium may cause flushing, nausea, abdominal discomfort.\n\n**Hyperkalemia is generally more dangerous than hypercalcemia** — err on the side of treating. Avoid pushing ionized calcium >3 mM.' WHERE id = 'k-hyper-calcium' AND tree_id = 'potassium';
UPDATE decision_nodes SET body = E'**[Regular Insulin](#/drug/regular-insulin) 5 units IV bolus** (must be IV, NOT subcutaneous).\n\n**Dextrose co-administration:**\n• Glucose < 250 mg/dL → **D50W 2 ampules** (100 mL total) OR **D10W 500 mL over 4 hours** (preferred — less rebound hypoglycemia)\n• Glucose 180-250 → half-dose dextrose (25g)\n• Glucose > 250 → no dextrose needed\n\n**Monitor fingerstick glucose q1h for 4-6 hours.** If glucose < 70 → give additional dextrose.\n\n**Effect:** Onset 15-30 min. K+ reduction: 0.5-1.2 mEq/L. Duration: ~4 hours — plan for redosing or definitive therapy.' WHERE id = 'k-hyper-insulin' AND tree_id = 'potassium';
UPDATE decision_nodes SET body = E'**Preferred:** [Terbutaline](#/drug/terbutaline) **0.5 mg SQ** — single injection, logistically superior.\n\n**Alternative:** [Albuterol](#/drug/albuterol-neb) **10-20 mg nebulized** (4-8 standard nebs back-to-back). Nearly always underdosed in practice — a single 2.5 mg neb is inadequate.\n\n**If hypotensive/bradycardic:** [Epinephrine](#/drug/epinephrine) infusion — treats both hyperkalemia AND hemodynamic instability simultaneously.\n\n**Effect:** Onset 5-30 min. K+ reduction: 0.5-1 mEq/L. Duration: 2-4 hours. Efficacy ~50% lower in ESRD.' WHERE id = 'k-hyper-beta2' AND tree_id = 'potassium';
UPDATE decision_nodes SET body = E'Assess volume status and serum bicarbonate to guide fluid choice.\n\n**Do NOT use normal saline** — high chloride content worsens hyperkalemia.\n\nIsotonic bicarbonate is the **preferred resuscitative fluid** for hyperkalemic patients with metabolic acidosis.' WHERE id = 'k-hyper-step2' AND tree_id = 'potassium';
UPDATE decision_nodes SET body = E'**Preparation:** 3 ampules NaHCO₃ in 1 liter D5W = **150 mM isotonic bicarbonate solution**.\n\n**Dosing:** 500-1000 mL/hour if severely hypovolemic. Target serum bicarb 24-28 mEq/L.\n\n**Isotonic bicarb lowers K+ three ways:**\n1. Dilution\n2. Shifting K+ into muscle cells\n3. Alkalosis promotes renal K+ excretion\n\n**Common mistake:** Giving isotonic bicarb at 100-150 mL/hr alongside another crystalloid. This prevents achieving the full benefit — use isotonic bicarb AS the resuscitative fluid.\n\n**AVOID hypertonic bicarbonate** (ampules alone) — proven ineffective in multiple RCTs. Osmotic shifts counteract the K-lowering effect.\n\nOnce bicarb > 24 and still hypovolemic → switch to LR for remaining volume.' WHERE id = 'k-hyper-bicarb' AND tree_id = 'potassium';
UPDATE decision_nodes SET body = E'Scale diuretic intensity to severity of hyperkalemia and renal function.\n\n**Normal renal function:**\n• [Furosemide](#/drug/furosemide) 60-160 mg IV alone may suffice\n\n**Moderate-severe renal dysfunction ("nephron bomb"):**\n• [Furosemide](#/drug/furosemide) 160-250 mg IV (or [Bumetanide](#/drug/bumetanide) 4-5 mg IV)\n• + [Chlorothiazide](#/drug/chlorothiazide) 500-1000 mg IV (or [Metolazone](#/drug/metolazone) 5-10 mg PO)\n• +/- [Acetazolamide](#/drug/acetazolamide) 250-1000 mg IV/PO\n• +/- [Fludrocortisone](#/drug/fludrocortisone) 0.2 mg PO (esp. patients on ACEi/ARB, tacrolimus)\n\n**Replace urine losses** with crystalloid:\n• Bicarb < 22 → isotonic bicarbonate\n• Bicarb ≥ 22 → Lactated Ringers\n\nIn life-threatening hyperK, **err on the side of excessive diuretic**. Large-volume diuresis is easily corrected with crystalloid.' WHERE id = 'k-hyper-step3' AND tree_id = 'potassium';
UPDATE decision_nodes SET body = E'Monitor urine output. If the patient produces urine, check potassium content.\n\nIf making urine but K+ not falling → consider adding [Fludrocortisone](#/drug/fludrocortisone) 0.2 mg PO.\n\nCheck electrolytes (including Mg) frequently and replete as needed.' WHERE id = 'k-hyper-step3-response' AND tree_id = 'potassium';
UPDATE decision_nodes SET body = E'[Lokelma (SZC)](#/drug/sodium-zirconium-cyclosilicate) **10 grams PO q8h**\n\nOnly **mildly effective** (~0.2 mM reduction at 4 hours, ~0.4 mM at 24 hours). Should NOT be relied upon as sole treatment.\n\nMay help **avoid or delay dialysis** in borderline cases.\n\n**Avoid Kayexalate** — antiquated, probably ineffective for acute hyperK, and can cause **colonic necrosis**.\n\nPatiromer is less effective than SZC (~0.23 mM at 7 hours). Only use if SZC unavailable.' WHERE id = 'k-hyper-step4' AND tree_id = 'potassium';
UPDATE decision_nodes SET body = E'**Indications for emergent dialysis:**\n1. Chronic hemodialysis patient (kaliuresis is futile)\n2. Failure of all other measures (anuric despite diuretic bomb, not a candidate for large-volume isotonic bicarb)\n\n**Do NOT delay dialysis** while hoping potassium binders will work.\n\nFor chronic HD patients, 5 grams of SZC daily on non-dialysis days may help reduce intradialytic hyperkalemia.' WHERE id = 'k-hyper-step5' AND tree_id = 'potassium';
UPDATE decision_nodes SET body = E'**Ongoing monitoring during acute hyperkalemia treatment.**\n\nRecheck K+ every 1-2 hours. Repeat ECG with any clinical change.\n\nInsulin K+ shift lasts ~4 hours — plan for redosing or definitive elimination.\n\nMonitor glucose q1h for 4-6 hours post-insulin. Check Mg, Ca, phosphorus frequently.\n\nReplace urine losses with appropriate crystalloid. Address underlying cause simultaneously.' WHERE id = 'k-hyper-monitor' AND tree_id = 'potassium';
UPDATE decision_nodes SET body = E'Check ECG for arrhythmia risk. [Hypokalemia ECG Findings](#/info/k-hypo-ecg-info)\n\nAssess for life-threatening features:\n• Arrhythmia (VT, TdP, new AF)\n• Respiratory failure\n• Paralysis or severe weakness' WHERE id = 'k-hypo-assess' AND tree_id = 'potassium';
UPDATE decision_nodes SET body = E'[Potassium Chloride IV](#/drug/potassium-chloride-iv) **5-10 mEq over 15-30 minutes** with continuous cardiac monitoring.\n\nRepeat until hemodynamically stable, ECG changes resolve, and K+ > 3 mEq/L. Then:\n• 20-40 mEq IV at up to 10 mEq/hr (peripheral)\n• Up to 20 mEq/hr (central line + cardiac monitoring)\n\n**Use glucose-free fluids** — glucose stimulates insulin and worsens intracellular K+ shift.\n\n**Always check and correct magnesium** — up to 50% of hypokalemic patients have concurrent hypoMg, which makes K+ repletion refractory.\n\nIf Mg < 2.0 → [Magnesium Sulfate](#/drug/magnesium-sulfate/hypomagnesemia) 2g IV over 1 hour.' WHERE id = 'k-hypo-severe' AND tree_id = 'potassium';
UPDATE decision_nodes SET body = E'[Potassium Chloride Oral](#/drug/potassium-chloride-oral) **20-40 mEq PO**\n\nEach 20 mEq raises serum K+ ~0.2 mEq/L. KCl is the **preferred salt** (most causes of hypoK involve concurrent chloride losses).\n\nRecheck K+ in 2-4 hours.\n\n**Target K+ ≥ 4.0 mEq/L** — especially in heart failure and arrhythmia-prone patients.\n\n**Dietary potassium alone is INSUFFICIENT** — food K+ is coupled with phosphate, not chloride, and ineffective for replacing chloride-associated losses.\n\n**Always check magnesium** — hypoMg causes refractory hypokalemia via ROMK channel dysfunction.' WHERE id = 'k-hypo-mild' AND tree_id = 'potassium';
UPDATE decision_nodes SET body = E'**Common causes:**\n• Diuretics (thiazides > loops — 0.6 vs 0.3 mEq/L decrease)\n• GI losses (vomiting, diarrhea, NG suction)\n• Refeeding syndrome\n• DKA treatment (insulin shifts K+ intracellularly)\n• Alkalosis\n\n**Workup:**\n• BMP, Mg, Phos\n• Urine K+ and Cl-\n• If urine K+ > 30 mEq/day → renal losses\n• If urine K+ < 25 mEq/day → extrarenal losses\n\n**Key:** Identify and treat the underlying cause in ALL patients.' WHERE id = 'k-hypo-workup' AND tree_id = 'potassium';
UPDATE decision_nodes SET body = E'**Chronic K+ replacement and prevention strategy.**\n\nOral KCl 50-75 mEq/day for chronic replacement.\n\nFor diuretic-induced hypokalemia: low-salt diet, consider K-sparing diuretic, ACEi/ARB, or beta-blocker addition.\n\nLoop diuretics cause less hypoK than thiazides. Correct hypomagnesemia. Target K+ ≥ 4.0 mEq/L in heart failure patients.' WHERE id = 'k-hypo-chronic' AND tree_id = 'potassium';
UPDATE decision_nodes SET body = E'**Hypokalemic Periodic Paralysis (HypoPP)**\n\nEpisodic flaccid paralysis, **proximal > distal**, with normal-to-decreased reflexes. Lasting minutes to days with spontaneous recovery.\n\n**Triggers:** Rest after strenuous exercise, carbohydrate-rich evening meals (morning attacks), stress, cold, high sodium intake, corticosteroids, alcohol\n\n**KEY DISTINCTION:** Hypokalemia in HypoPP is **transcellular redistribution, NOT true body K+ depletion**. This fundamentally changes treatment.\n\n**Genetics:** CACNA1 (calcium channel) or SCN4A (sodium channel) mutations.' WHERE id = 'k-hypopp-assess' AND tree_id = 'potassium';
UPDATE decision_nodes SET body = E'**CRITICAL: This is NOT true K+ depletion — aggressive replacement causes dangerous rebound hyperkalemia.**\n\n[Potassium Chloride Oral](#/drug/potassium-chloride-oral) **1 mEq/kg oral** (~60 mEq for 60 kg patient)\n• Use **immediate-release or liquid** formulation ONLY\n• **AVOID slow-release** KCl — too slow and unpredictable\n• If no improvement in 30 min → 0.3 mEq/kg additional dose\n• Monitor K+ every 30 minutes\n\n**For severe attacks requiring IV:**\n• Max rate 0.3 mEq/kg/hr with continuous cardiac monitoring\n\n**AVOID:**\n• Glucose-containing fluids (worsens intracellular shift)\n• Corticosteroids (known trigger)\n• Aggressive IV KCl (rebound hyperkalemia)\n\n**Resolution of weakness may lag behind K+ normalization.**' WHERE id = 'k-hypopp-acute' AND tree_id = 'potassium';
UPDATE decision_nodes SET body = E'**Long-term prevention of hypokalemic periodic paralysis attacks.**\n\nTrigger avoidance: low sodium, low carbohydrate diet, avoid steroids/cold/stress/alcohol.\n\nDaily oral KCl 10-20 mEq TID (especially nocturnal dose for morning attacks).\n\nAcetazolamide is first-line pharmacologic prevention. If intolerant: K-sparing diuretics (triamterene, spironolactone, eplerenone).\n\nGenetic counseling: CACNA1 or SCN4A testing for family planning.' WHERE id = 'k-hypopp-prevent' AND tree_id = 'potassium';

-- === precip-delivery (21 nodes) ===
UPDATE decision_nodes SET body = E'[Delivery Steps Summary](#/info/precip-delivery-summary) — quick-reference checklist to review immediately before delivery.\n\n**Precipitous delivery** occurs when labor and delivery happen rapidly — often before planned arrival at a delivery unit. ~3% of all US deliveries. [4]\n\n**Page OB and Pediatrics immediately.** Do not delay — even if delivery seems far off.\n\nThis consult provides a stepwise approach to assessing and managing an ED precipitous delivery:\n\n• Module 1: Initial Assessment — history, exam, and decision to deliver\n• Module 2: Preparation — team, equipment, positioning\n• Module 3: Stage 1 — Labor coaching and crowning\n• Module 4: Stage 2 — Head delivery, nuchal cord, shoulders, cord clamping, neonatal assessment\n• Module 5: Stage 3 — Placenta delivery, oxytocin, laceration assessment, postpartum monitoring' WHERE id = 'precip-start' AND tree_id = 'precip-delivery';
UPDATE decision_nodes SET body = E'OB HISTORY — RAPID ASSESSMENT\n• Gestational age / due date\n• Gravida / Para (G_P_)\n• Singleton vs multiples\n• Pregnancy complications (preeclampsia, GDM, placenta previa)\n• Contraction timing — onset, frequency, duration\n• Fluid leakage or bleeding (ROM, bloody show)\n\nSIGNS OF IMMINENT DELIVERY\n• **Crowning** — fetal head visible at introitus\n• **Perineal bulging** — stretching of perineum from descending head\n• **Irresistible urge to push** — involuntary bearing down\n• **Bloody show** — mucous plug passage\n• **Rupture of membranes** — gush of clear/blood-tinged fluid\n• **Anal sphincter relaxation** — suggests very low station\n\n**"Never trust a multip."** Multiparous patients can progress from 4 cm to delivery in minutes. [1][2][6]' WHERE id = 'precip-history' AND tree_id = 'precip-delivery';
UPDATE decision_nodes SET body = E'CERVICAL EXAM\n\n**Effacement** — thinning of the cervix, measured 0–100%. At 100% effacement the cervix is paper-thin.\n\n**Dilation** — opening of the cervical os, measured 0–10 cm. At 10 cm the cervix is fully dilated and ready for delivery.\n\n**Station** — position of the fetal presenting part relative to the ischial spines:\n• **-5 to -1** — presenting part is above the ischial spines (floating to engaged)\n• **0** — presenting part is at the level of the ischial spines (engaged)\n• **+1 to +5** — presenting part is below the ischial spines (descending to crowning)\n\nStation +3 to +5 with full dilation = imminent delivery. [1][2]' WHERE id = 'precip-exam' AND tree_id = 'precip-delivery';
UPDATE decision_nodes SET body = E'Is delivery imminent?\n\nDelivery is imminent if:\n• Crowning or fully dilated (10 cm)\n• Active pushing with visible presenting part\n• No time for safe transfer\n\nIf the patient can be safely transferred to L&D or a facility with OB capabilities, transfer is preferred. [7]' WHERE id = 'precip-imminent' AND tree_id = 'precip-delivery';
UPDATE decision_nodes SET body = E'EMTALA CONSIDERATIONS\n\n**Active labor is an emergency medical condition under EMTALA.** [7]\n\nA woman in active labor must be stabilized before transfer. If delivery is imminent, the hospital must deliver the baby regardless of OB availability.\n\nTRANSFER GUIDELINES\n• Ensure receiving facility has OB capabilities and has accepted the patient\n• **Antenatal transfer is always preferred over neonatal transfer** — a pregnant patient in a vehicle is safer than a newborn in an ambulance [3]\n• Document medical necessity for transfer\n• Send all records and lab results with the patient\n• Continuous fetal monitoring during transport if available' WHERE id = 'precip-transfer' AND tree_id = 'precip-delivery';
UPDATE decision_nodes SET body = E'CALL FOR HELP\n\n**Page OB and Pediatrics STAT** — even if you''ve already called, confirm they are en route.\n\nTEAM ASSIGNMENTS\nMinimum 4 people:\n• **You** — delivering provider (at the perineum)\n• **Nurse 1** — assigned to mom (vitals, meds, documentation)\n• **Nurse 2** — assigned to baby (warming, stimulation, APGAR)\n• **Provider 2** — assigned to baby ([Neonatal Resuscitation](#/tree/neonatal-resus) if needed)\n\nEQUIPMENT — NEONATAL\n• Neonatal warmer — **turn on now** (prewarming)\n• [Neonatal Resuscitation](#/tree/neonatal-resus) equipment (bag-valve-mask, suction, O2)\n• Pulse oximetry for newborn\n\nIf you are alone, prepare what you can and call for backup. [1][3]' WHERE id = 'precip-callhelp' AND tree_id = 'precip-delivery';
UPDATE decision_nodes SET body = E'DELIVERY EQUIPMENT\n• Sterile gloves (two pairs)\n• Sterile scissors or scalpel (for cord cutting)\n• Umbilical cord clamps x2 (Kelly clamps work if cord clamps unavailable)\n• Bulb suction\n• Clean towels and warm blankets for baby\n• Chux pads / absorbent pads under the patient\n\nCONFIRM VERTEX PRESENTATION\nIf time permits, perform a **bedside ultrasound** to confirm vertex (head-down) presentation.\n**If NOT vertex → see Breech Delivery consult** (future)\n\nPERINEAL PREPARATION\n• Clean the perineum with antiseptic if time permits\n• Drape the patient\n• Position in dorsal lithotomy (feet in stirrups if available, or knees bent and supported) [1][2]' WHERE id = 'precip-equipment' AND tree_id = 'precip-delivery';
UPDATE decision_nodes SET body = E'PRE-DELIVERY CHECKLIST\n\n✓ OB and Peds paged\n✓ Team assigned (mom nurse, baby nurse, baby provider)\n✓ Neonatal warmer ON and prewarming\n✓ Delivery equipment at bedside\n✓ Patient positioned and draped\n✓ Vertex presentation confirmed (if time for U/S)\n\nYou are ready to deliver. The next modules walk through each stage of labor and delivery step by step. [1][2][3]' WHERE id = 'precip-ready' AND tree_id = 'precip-delivery';
UPDATE decision_nodes SET body = E'THREE STAGES OF LABOR\n\n**Stage 1 — Cervical Dilation**\n• Latent phase: irregular contractions, 0–5 cm dilation\n• Active phase: strong regular contractions, nulliparous ~1.2 cm/hr, multiparous ~1.5 cm/hr\n• Transition: 8–10 cm, intense contractions, nausea/shaking common\n\n**Stage 2 — Delivery of the Baby**\nFrom full dilation to delivery. Active pushing: 1–2 hours (nulliparous), often shorter for multiparous.\n\n**Stage 3 — Delivery of the Placenta**\nFrom baby delivery to placenta delivery. Usually 5–15 minutes. Up to 30 minutes is normal.\n\n**"Never trust a multip."** Multiparous patients can progress through all stages much faster than expected. [1][2][6]' WHERE id = 'precip-stage1' AND tree_id = 'precip-delivery';
UPDATE decision_nodes SET body = E'COACHING THE PATIENT\n\n**During contractions:**\n• Take a deep breath at the start of each contraction\n• Bear down and push for **10 seconds x 3** per contraction\n• Rest between contractions — use this time for encouragement\n\n**When the head is crowning:**\n• Tell the patient to **STOP pushing**\n• Breathe through contractions — pant or blow\n• This allows controlled, slow delivery of the head and reduces perineal tearing\n\n**Reassure throughout.** Many patients having precipitous deliveries in the ED are terrified. Calm, clear communication makes a difference.\n\nYou are their doctor. They need to hear: "You''re doing great. We''re going to deliver this baby safely." [1][3][6]' WHERE id = 'precip-coaching' AND tree_id = 'precip-delivery';
UPDATE decision_nodes SET body = E'DELIVERING THE HEAD\n\n**Perineal support technique:**\n• Place one hand on the perineum with a towel — apply gentle **upward pressure** on the fetal chin through the perineum\n• Other hand on the fetal occiput — apply gentle **counter-pressure** to control the speed of delivery\n• Goal: **slow, controlled delivery** of the head to minimize perineal tearing\n\n**Key points:**\n• Let the uterus do the work — do NOT pull on the head\n• Between contractions, maintain gentle pressure to prevent rapid expulsion\n• The head will naturally extend as it delivers over the perineum\n\n**Routine suctioning of the nose and mouth is NO LONGER recommended** (NRP 8th edition). Only suction if the airway is visibly obstructed. [5]\n\nOnce the head is delivered, proceed immediately to check for nuchal cord. [1][2]' WHERE id = 'precip-head' AND tree_id = 'precip-delivery';
UPDATE decision_nodes SET body = E'NUCHAL CORD CHECK\n\nImmediately after the head delivers, **sweep your finger around the baby''s neck** feeling for the umbilical cord.\n\nNuchal cord occurs in 20–30% of deliveries and is usually manageable. [1][2]' WHERE id = 'precip-nuchal' AND tree_id = 'precip-delivery';
UPDATE decision_nodes SET body = E'TIGHT NUCHAL CORD — CLAMP AND CUT\n\nIf the cord is too tight to slip over the baby''s head:\n\n1. Apply **two clamps** on the cord close together\n2. **Cut between** the clamps with sterile scissors\n3. Unwrap the cord from the neck\n4. **Deliver the baby promptly** — the cord is now cut and the baby has no placental circulation\n\nThis is time-sensitive. Once the cord is cut, the baby must be delivered and assessed quickly. [1][2]' WHERE id = 'precip-nuchal-cut' AND tree_id = 'precip-delivery';
UPDATE decision_nodes SET body = E'SHOULDER DELIVERY\n\n**Anterior shoulder (top):**\n• Apply gentle **DOWNWARD traction** on the head (toward the floor)\n• Guide the anterior shoulder under the pubic symphysis\n• The shoulder should slip out — do NOT force\n\n**Posterior shoulder (bottom):**\n• Then apply gentle **UPWARD traction** (toward the ceiling)\n• Deliver the posterior shoulder\n\n**CRITICAL SAFETY POINTS:**\n• Apply traction in the **long axis of the fetal neck** — pulling at an angle risks brachial plexus injury\n• Use steady, gentle traction — never jerk or twist\n• The body will follow the shoulders\n\n**If the head delivers but retracts against the perineum ("turtle sign") → [Shoulder Dystocia](#/tree/shoulder-dystocia).** This is an obstetric emergency requiring specific maneuvers (McRoberts, suprapubic pressure). **See [Shoulder Dystocia](#/tree/shoulder-dystocia) consult.** [1][2][3]' WHERE id = 'precip-shoulders' AND tree_id = 'precip-delivery';
UPDATE decision_nodes SET body = E'CORD CLAMPING AND CUTTING\n\n**DO NOT DROP THE BABY.** The baby is wet and slippery.\n\n1. Place the baby directly on mom''s abdomen — **skin-to-skin contact**\n2. Dry the baby vigorously with a warm towel\n3. Clamp the cord in **two places**, approximately **3 cm apart**, with the first clamp ~3 cm from the baby''s abdomen\n4. **Cut between the two clamps** with sterile scissors\n\nDELAYED CORD CLAMPING\nCurrent NRP guidelines recommend delayed cord clamping (30–60 seconds) in vigorous term newborns. If the baby requires resuscitation, clamp and cut immediately. [5]\n\nNON-STERILE ENVIRONMENT\nIf delivery occurred without sterile instruments, clean the cord stump with antiseptic to prevent omphalitis (cord infection). [1][2]' WHERE id = 'precip-cord' AND tree_id = 'precip-delivery';
UPDATE decision_nodes SET body = E'IMMEDIATE NEONATAL ASSESSMENT\n\n**Dry and stimulate** the baby with warm towels. Most babies will cry and become pink within the first minute.\n\nAPGAR SCORING\nAssess at **1 minute and 5 minutes** after delivery:\n• Appearance (color)\n• Pulse (heart rate)\n• Grimace (reflex irritability)\n• Activity (muscle tone)\n• Respiration (breathing effort)\n\nNEONATAL TRANSITION STATISTICS [5]\n• **~90%** of newborns transition without any intervention beyond warmth, drying, and stimulation\n• **~10%** will need additional support (positive pressure ventilation, supplemental O2)\n• **<1%** will need chest compressions\n\n**If the baby is not breathing or heart rate is <100 bpm → initiate NRP ([Neonatal Resuscitation](#/tree/neonatal-resus) Program).** [5]\n\nEnsure the baby stays warm — hypothermia is a significant risk in ED deliveries. [1][5]' WHERE id = 'precip-baby' AND tree_id = 'precip-delivery';
UPDATE decision_nodes SET body = E'STAGE 3 — PLACENTAL DELIVERY\n\nThe placenta typically delivers **5–15 minutes** after the baby. Up to 30 minutes is normal.\n\nSIGNS OF PLACENTAL SEPARATION\n• **Cord lengthening** — the cord appears to get longer as the placenta detaches\n• **Gush of blood** — normal separation bleeding\n• **Uterine fundus rises** — becomes firm and globular\n\nDELIVERY TECHNIQUE\n• Apply **gentle, steady traction** on the cord with one hand\n• Other hand on the uterine fundus — **guard against uterine inversion** by applying counter-pressure\n• May ask the patient to push gently\n\n**NEVER force the placenta.** Aggressive traction risks uterine inversion — a life-threatening emergency. If the placenta does not deliver within 30 minutes, this is a **retained placenta** requiring manual removal by OB. [1][2][8]' WHERE id = 'precip-placenta' AND tree_id = 'precip-delivery';
UPDATE decision_nodes SET body = E'PLACENTAL EXAMINATION\n\nAfter delivery, inspect the placenta carefully:\n\n**COMPLETENESS**\n• All cotyledons (lobes) present — the maternal surface should look like a complete jigsaw puzzle\n• Check edges for torn vessels (suggests retained succenturiate lobe)\n• **Retained placental fragments → postpartum hemorrhage risk** [8]\n\n**CORD VESSELS**\n• Normal: **2 arteries + 1 vein** (3-vessel cord)\n• Single umbilical artery (2-vessel cord) occurs in ~1% of births — associated with renal and cardiac anomalies\n• Normal cord length: 35–70 cm\n\n**SAVE THE PLACENTA** — OB and pathology will want to examine it. Place in a basin or bag. [1][2]' WHERE id = 'precip-placenta-exam' AND tree_id = 'precip-delivery';
UPDATE decision_nodes SET body = E'OXYTOCIN — POSTPARTUM UTEROTONIC\n\n[Oxytocin](#/drug/oxytocin/precipitous delivery) 20 units in 1L NS (or LR) at 250 mL/hr.\n\n**Do NOT give IV push** — can cause profound hypotension. [8]\n\n**Timing:** Start after the placenta is delivered. Do not wait to assess bleeding — **empiric oxytocin decreases postpartum hemorrhage risk.** [8]\n\nBIMANUAL UTERINE MASSAGE\n• Place one hand on the uterine fundus abdominally\n• Massage firmly until the uterus contracts and feels firm ("boggy" uterus = atony = hemorrhage risk)\n• Continue massage intermittently until uterine tone is maintained\n\n**Uterine atony is the #1 cause of postpartum hemorrhage.** Oxytocin + massage addresses this directly. [8]' WHERE id = 'precip-oxytocin' AND tree_id = 'precip-delivery';
UPDATE decision_nodes SET body = E'LACERATION ASSESSMENT\n\nExamine the vaginal canal and perineum for tears:\n\n**CLASSIFICATION**\n• 1st degree — perineal skin/vaginal mucosa only\n• 2nd degree — extends into perineal muscles\n• 3rd degree — involves the anal sphincter\n• 4th degree — extends through the rectal mucosa\n\n**MANAGEMENT**\n• If you are comfortable → repair 1st and 2nd degree tears in the ED\n• 3rd and 4th degree tears → **defer to OB** (specialist repair required)\n• If deferring any repair → **pack the vaginal canal** with gauze to tamponade bleeding\n\nMONITOR FOR POSTPARTUM HEMORRHAGE\n• **PPH = blood loss >1000 mL** or signs of hypovolemia [8]\n• Monitor for 1 hour after placental delivery\n• Assess uterine tone, vaginal bleeding, vital signs every 15 minutes\n\n**If significant hemorrhage → see Postpartum Hemorrhage consult** (future). [1][8]' WHERE id = 'precip-lacerations' AND tree_id = 'precip-delivery';
UPDATE decision_nodes SET body = E'Delivery complete.\n\n**Congratulate the mother.**\n\nPOSTDELIVERY CHECKLIST\n✓ Uterus firm (not boggy)\n✓ Bleeding controlled\n✓ Vaginal/perineal lacerations assessed and addressed\n✓ Baby assessed — APGAR at 1 and 5 minutes documented\n✓ Placenta examined and saved for pathology\n✓ Oxytocin infusing\n✓ Skin-to-skin contact maintained\n\nMONITORING\n• Monitor mom for **1 hour post-placenta delivery**: uterine tone, vaginal bleeding, vital signs q15 min\n• Monitor baby: temperature, respiratory status, feeding\n• Document all times: delivery, placenta, APGAR scores, medications\n\nDISPOSITION\n• Admit to OB service for postpartum care\n• Neonatal assessment by pediatrics\n• If delivered at facility without OB: arrange transfer to appropriate facility after stabilization [7]' WHERE id = 'precip-complete' AND tree_id = 'precip-delivery';

-- === priapism (44 nodes) ===
UPDATE decision_nodes SET body = E'Priapism = prolonged erection lasting > 4 hours, unrelated to sexual stimulation.\n\nTwo types:\n• Ischemic (low-flow) — EMERGENCY. Most common. Veno-occlusive.\n• Non-ischemic (high-flow) — NOT an emergency. Arterial. Usually post-trauma.\n\nHistory to obtain:\n• Duration of erection\n• Pain level\n• Trauma history (straddle injury, perineal blunt trauma)\n• PDE5 inhibitor or intracavernosal injection (ICI) use\n• Sickle cell disease\n• Medications (antipsychotics, trazodone, anticoagulants)' WHERE id = 'priapism-start' AND tree_id = 'priapism';
UPDATE decision_nodes SET body = E'ISCHEMIC (Low-Flow)\n• Painful, fully rigid\n• No trauma history\n• Dark blood on aspiration\n• Compartment syndrome of the penis\n• UROLOGIC EMERGENCY\n\nNON-ISCHEMIC (High-Flow)\n• Painless or mild discomfort\n• Partially erect (not fully rigid)\n• Trauma history (straddle injury, kick, fall)\n• Bright red blood on aspiration\n• Arterial fistula → unregulated inflow\n• NOT an emergency\n\nIf unsure, corporal blood gas or Color Doppler ultrasound can help differentiate.' WHERE id = 'priapism-differential' AND tree_id = 'priapism';
UPDATE decision_nodes SET body = E'Aspirate blood from corpus cavernosum and send for blood gas.\n\nBLOOD COLOR\n• Dark, deoxygenated = ischemic\n• Bright red, oxygenated = non-ischemic\n\nISCHEMIC PATTERN\n• pO₂ < 30 mmHg\n• pCO₂ > 60 mmHg\n• pH < 7.25\n\nNON-ISCHEMIC PATTERN\n• pO₂ > 90 mmHg\n• pCO₂ < 40 mmHg\n• pH 7.35–7.45\n\nNote: Exact cutoffs are not standardized across studies, but the pattern of hypoxia + hypercarbia + acidosis reliably identifies ischemic priapism.\n\nColor Doppler ultrasound is a complementary noninvasive option if available.' WHERE id = 'priapism-bloodgas' AND tree_id = 'priapism';
UPDATE decision_nodes SET body = E'NOT a urologic emergency.\n\n• Usually from perineal trauma → arterial fistula\n• Partially tumescent, painless\n• 62% resolve spontaneously\n• No aspiration or phenylephrine needed\n• ED risk much lower than ischemic type' WHERE id = 'priapism-nonischemic-info' AND tree_id = 'priapism';
UPDATE decision_nodes SET body = E'Non-ischemic priapism is not an emergency.\n\n• Most cases resolve on their own\n• If persistent: selective arterial embolization (85–100% success)\n• Requires interventional radiology referral\n• Erectile function preserved in 80–100% of cases' WHERE id = 'priapism-nonischemic-result' AND tree_id = 'priapism';
UPDATE decision_nodes SET body = E'UROLOGIC EMERGENCY.\n\n• Ischemic priapism = compartment syndrome of the penis\n• Smooth muscle necrosis begins at 4–6 hours\n• Delayed treatment > 24 hours → 30–70% erectile dysfunction\n• Time-sensitive: proceed to assess duration and etiology now' WHERE id = 'priapism-ischemic-confirm' AND tree_id = 'priapism';
UPDATE decision_nodes SET body = E'Does this patient have sickle cell disease (SCD)?\n\n• ~40% of males with SCD experience priapism\n• SCD priapism has specific initial management steps' WHERE id = 'priapism-sickle-check' AND tree_id = 'priapism';
UPDATE decision_nodes SET body = E'How long has the erection been present?\n\n• < 4 hours: supportive measures may help\n• ≥ 4 hours: requires emergent procedural intervention' WHERE id = 'priapism-scd-duration' AND tree_id = 'priapism';
UPDATE decision_nodes SET body = E'Try supportive measures first:\n\n• IV hydration (NS bolus)\n• Analgesia (ketorolac, opioids PRN)\n• Warm shower or warm packs\n• Supplemental O₂\n\n⚠️ Do NOT use RBC transfusion to treat priapism in SCD patients.\n\nMonitor for resolution. If no improvement, proceed to aspiration.' WHERE id = 'priapism-scd-supportive' AND tree_id = 'priapism';
UPDATE decision_nodes SET body = E'Priapism resolved with supportive care.\n\n• Hematology follow-up for recurrence prevention\n• Options: hydroxyurea, GnRH agonists, PDE5i prophylaxis\n\n[Return Precautions](#/info/priapism-return-precautions)' WHERE id = 'priapism-scd-resolved' AND tree_id = 'priapism';
UPDATE decision_nodes SET body = E'SCD priapism ≥ 4 hours requires the same procedural treatment as non-SCD ischemic priapism.\n\n• Continue IV hydration and analgesia\n• Hematology consult for crisis management\n• Do NOT use RBC transfusion to treat priapism\n• Proceed to penile block for anesthesia' WHERE id = 'priapism-scd-emergent' AND tree_id = 'priapism';
UPDATE decision_nodes SET body = E'Post-intracavernosal injection priapism.\n\nConservative measures (try briefly, < 30–60 min):\n• Ice packs\n• Attempt ejaculation\n• Exercise (walking, climbing stairs)\n\n⚠️ Do NOT let conservative measures delay treatment.\nIf fully rigid and painful, proceed directly to phenylephrine.' WHERE id = 'priapism-post-ici' AND tree_id = 'priapism';
UPDATE decision_nodes SET body = E'Prolonged erection resolved with conservative measures.\n\n• Observe 30–60 min to confirm sustained resolution\n• Adjust ICI dose on follow-up with urology\n\n[Return Precautions](#/info/priapism-return-precautions)' WHERE id = 'priapism-post-ici-resolved' AND tree_id = 'priapism';
UPDATE decision_nodes SET body = E'Duration > 36–48 hours:\n\n• Smooth muscle necrosis likely advanced\n• Aspiration + phenylephrine less likely to succeed\n• Still attempt aspiration + phenylephrine first\n• If unsuccessful: immediate surgical consultation\n• AUA/SMSNA recommends early penile prosthesis over delayed placement\n\nProceed to penile block.' WHERE id = 'priapism-prolonged' AND tree_id = 'priapism';
UPDATE decision_nodes SET body = E'Adequate anesthesia is essential before aspiration.\n\nDorsal penile nerve block provides excellent analgesia for corporal aspiration and irrigation.\n\nAgent: 1% lidocaine WITHOUT epinephrine\n• The penis is supplied by end-arteries\n• NEVER use epinephrine — risk of ischemic necrosis\n\nDose: ~10 mL total (5 mL per side)' WHERE id = 'priapism-penile-block-intro' AND tree_id = 'priapism';
UPDATE decision_nodes SET body = E'PROCEDURE\n\n1. Clean the base of the penis with antiseptic\n2. Identify the **10 o''clock** and **2 o''clock** positions at the penile base\n3. Insert a **27-gauge needle** at the **10 o''clock** position\n4. Advance under Buck''s fascia (feel a slight pop)\n5. Aspirate to ensure you''re not in a vessel\n6. Inject 5 mL of 1% lidocaine (no epi)\n7. Repeat at the **2 o''clock** position with 5 mL\n\n**You must pop through Buck''s fascia to anesthetize the nerve.**\n\nTotal: 10 mL of 1% lidocaine without epinephrine\n\n⚠️ Avoid the 12 o''clock midline (dorsal vein and deep dorsal artery)' WHERE id = 'priapism-penile-block-technique' AND tree_id = 'priapism';
UPDATE decision_nodes SET body = E'• Wait 5–10 minutes for full anesthetic effect\n• Test with pinprick on penile shaft\n• If inadequate, supplement with additional local at injection sites\n\nWhen adequate anesthesia confirmed, proceed to corporal aspiration.' WHERE id = 'priapism-penile-block-complete' AND tree_id = 'priapism';
UPDATE decision_nodes SET body = E'EQUIPMENT\n• 18–21 gauge butterfly needle or angiocath\n• Three-way stopcock\n• 20–60 mL syringe (for aspiration)\n• 10–20 mL syringe with normal saline (for irrigation)\n• Sterile prep and drape\n\nINJECTION SITE\n• Lateral aspect of proximal penile shaft\n• 2 o''clock or 10 o''clock position\n• AVOID 12 o''clock (dorsal neurovascular bundle)\n• AVOID 6 o''clock (urethra)\n\nSingle-side entry is sufficient — the two corpora communicate via the intercavernosal septum.' WHERE id = 'priapism-aspiration-intro' AND tree_id = 'priapism';
UPDATE decision_nodes SET body = E'PROCEDURE\n\n1. Insert needle at 2 or 10 o''clock into corpus cavernosum\n2. Aspirate dark, deoxygenated blood\n3. Continue aspirating until blood turns bright red\n   (bright red = fresh arterial inflow restored)\n4. Typically 20–30 mL per aspiration cycle\n\nTIP: Can send initial aspirate for blood gas if type not yet confirmed.\n\nIRRIGATION\n5. After aspiration, irrigate with 20–30 mL normal saline\n6. Re-aspirate\n7. Repeat aspiration–irrigation cycles until aspirate is bright red\n\nIrrigation clears clotted blood and metabolic waste, improving resolution rates.' WHERE id = 'priapism-aspiration-technique' AND tree_id = 'priapism';
UPDATE decision_nodes SET body = E'Did aspiration and irrigation produce detumescence?\n\n• Aspiration + irrigation alone: ~36% success rate\n• If not resolved, proceed to phenylephrine injection' WHERE id = 'priapism-aspiration-response' AND tree_id = 'priapism';
UPDATE decision_nodes SET body = E'Priapism resolved with aspiration and irrigation.\n\n• Observe 30–60 min to confirm sustained resolution\n• Urology follow-up in 1–2 days\n\n[Return Precautions](#/info/priapism-return-precautions)' WHERE id = 'priapism-aspiration-success' AND tree_id = 'priapism';
UPDATE decision_nodes SET body = E'Phenylephrine = first-line sympathomimetic (AUA/SMSNA 2022).\n\nWhy phenylephrine?\n• Pure alpha-1 agonist → no intrinsic inotropy, no increase in heart rate\n• Causes smooth muscle contraction → venous outflow\n• 74% success rate (vs 25% terbutaline)\n• Combined with aspiration: 70–100% success\n\nOnset: 1 minute | Duration: 10–20 minutes\n\nTap for mixing instructions:\n• [Phenylephrine](#/drug/phenylephrine) — first-line\n• [Epinephrine](#/drug/epinephrine) — alternative if no phenylephrine' WHERE id = 'priapism-phenylephrine-intro' AND tree_id = 'priapism';
UPDATE decision_nodes SET body = E'⚠️ The corpora cavernosa communicate freely — only ONE side needs to be injected.\n\nPHENYLEPHRINE (first-line)\n• 200 mcg (2 mL of 100 mcg/mL solution) per dose\n• Inject into corpus cavernosum\n• Every 5 minutes\n• Up to 5 doses TOTAL (= 1 mg max)\n\nEPINEPHRINE (alternative — if phenylephrine unavailable)\n• 20 mcg (2 mL of 10 mcg/mL solution) per dose\n• Inject into corpus cavernosum\n• Every 5 minutes\n• Up to 5 doses TOTAL (= 100 mcg max)\n\nMONITORING\n• Check BP and HR every 5 min between injections\n• HOLD if SBP > 160 or HR > 110\n• Contraindicated: uncontrolled HTN, MAO inhibitor use\n\nPEDIATRIC / SCD: use lower dose (100 mcg phenylephrine per injection)' WHERE id = 'priapism-phenylephrine-dose' AND tree_id = 'priapism';
UPDATE decision_nodes SET body = E'TECHNIQUE\n\n1. Inject 2 mL phenylephrine (200 mcg) through the same needle used for aspiration\n2. Wait 5 minutes\n3. Re-aspirate to remove additional stagnant blood\n4. Assess for detumescence\n5. If still rigid, repeat injection (up to 5 doses total)\n\nRemember: Corpora cavernosa communicate freely.\nOnly one side needs injection. 5 doses = 5 doses TOTAL, not per side.\n\nAlternating approach:\n• Aspirate → Inject phenylephrine → Wait 5 min → Aspirate again → Reassess\n• Continue cycling up to 5 doses' WHERE id = 'priapism-phenylephrine-inject' AND tree_id = 'priapism';
UPDATE decision_nodes SET body = E'After phenylephrine injection(s), has detumescence occurred?\n\n• May require up to 5 doses (every 5 min)\n• Combined aspiration + phenylephrine: 70–100% success' WHERE id = 'priapism-phenylephrine-response' AND tree_id = 'priapism';
UPDATE decision_nodes SET body = E'Priapism resolved with aspiration + phenylephrine.\n\n[Return Precautions](#/info/priapism-return-precautions)' WHERE id = 'priapism-phenylephrine-success' AND tree_id = 'priapism';
UPDATE decision_nodes SET body = E'Failed aspiration, irrigation, and phenylephrine (1 hour max).\n\n• This is refractory ischemic priapism\n• Requires surgical intervention\n• Duration of priapism determines surgical approach\n• Urgent urology consultation required' WHERE id = 'priapism-refractory' AND tree_id = 'priapism';
UPDATE decision_nodes SET body = E'Shunting creates a pathway for blood to drain from the corpora cavernosa.\n\nTwo categories:\n• DISTAL shunts — preferred first (less invasive, lower morbidity)\n• PROXIMAL shunts — if distal fails (more invasive, higher complication rate)\n\nDistal shunts connect corpus cavernosum to glans penis.\nProximal shunts connect to corpus spongiosum or saphenous vein.\n\nUrology consultation required for all shunting procedures.' WHERE id = 'priapism-shunting-info' AND tree_id = 'priapism';
UPDATE decision_nodes SET body = E'WINTER (percutaneous)\n• Tru-Cut biopsy needle through glans into distal corpora\n\nEBBEHOJ (percutaneous)\n• No. 11 scalpel blade through glans into corpora\n\nAL-GHORAB (open)\n• Open excision of distal tunica albuginea through glans incision\n\nT-SHUNT (variation)\n• No. 10 blade with 90-degree rotation\n\nAll create a fistula at the glans for blood to drain into the corpus spongiosum.' WHERE id = 'priapism-distal-shunt' AND tree_id = 'priapism';
UPDATE decision_nodes SET body = E'QUACKELS\n• Corporospongiosal shunt at penoscrotal junction\n\nGRAYHACK\n• Saphenous vein-to-corpus cavernosum anastomosis\n\n⚠️ More invasive, higher complication rate.\nUsed only when distal shunts fail.' WHERE id = 'priapism-proximal-shunt' AND tree_id = 'priapism';
UPDATE decision_nodes SET body = E'Priapism resolved with surgical shunting.\n\n• Post-op monitoring per urology\n• ED risk depends on duration of priapism before resolution\n• Consider PDE5i trial at 4–6 weeks for erectile rehabilitation\n\n[Return Precautions](#/info/priapism-return-precautions)' WHERE id = 'priapism-shunt-success' AND tree_id = 'priapism';
UPDATE decision_nodes SET body = E'Shunting has failed to produce detumescence.\n\nOptions:\n• If distal shunt attempted → may try proximal shunt\n• If both failed, or duration > 48hr with necrotic tissue:\n  → Immediate penile prosthesis recommended (AUA/SMSNA 2022)\n\nEarly prosthesis (within days) has better outcomes than delayed placement:\n• Easier implantation\n• Less penile fibrosis\n• Better length preservation\n• Patient satisfaction 60–100%' WHERE id = 'priapism-shunt-fail' AND tree_id = 'priapism';
UPDATE decision_nodes SET body = E'Duration > 36–48 hours with failed medical management:\n\n• Smooth muscle necrosis likely advanced\n• AUA/SMSNA 2022: consider immediate penile prosthesis\n• Still attempt aspiration + phenylephrine first if not yet done\n• If unsuccessful, do not delay surgical consultation\n\nEarly prosthesis placement (within days) has better outcomes:\n• Easier implantation before fibrosis develops\n• Better penile length preservation\n• Patient satisfaction 60–100%' WHERE id = 'priapism-prosthesis-consider' AND tree_id = 'priapism';
UPDATE decision_nodes SET body = E'Detumescence achieved despite prolonged duration.\n\n• High risk of erectile dysfunction (30–70% at > 24hr duration)\n• Urology follow-up within 48 hours\n• Early erectile rehabilitation counseling\n• PDE5i trial at 4–6 weeks\n\n[Return Precautions](#/info/priapism-return-precautions)' WHERE id = 'priapism-prolonged-resolved' AND tree_id = 'priapism';
UPDATE decision_nodes SET body = E'Immediate prosthesis implantation for refractory prolonged ischemic priapism.\n\nAUA/SMSNA 2022: early placement preferred over delayed.\n\nBenefits:\n• Prevents penile shortening from fibrosis\n• Restores erectile function\n• Avoids difficult delayed implantation in scarred tissue\n• Patient satisfaction 60–100%' WHERE id = 'priapism-prosthesis-result' AND tree_id = 'priapism';

-- === psych-assessment (19 nodes) ===
UPDATE decision_nodes SET body = E'A **comprehensive psychiatric assessment** follows a structured format including both historical information and a systematic **Mental Status Examination (MSE)**.\n\nThe MSE is a structured way to assess and document a patient''s current cognitive, behavioral, and emotional functioning. Unlike the MMSE (cognitive screening), the MSE offers a **broader view** of the patient''s psychological state during a specific encounter.\n\n**10 Components of the MSE:**\n1. Appearance\n2. Behavior\n3. Speech & Language\n4. Mood (subjective)\n5. Affect (objective)\n6. Thought Process\n7. Thought Content & Perception\n8. Suicidal / Homicidal Risk\n9. Cognition\n10. Insight & Judgment\n\n**Documentation for CPT 90792 must include:**\n• Complete medical and psychiatric history\n• Mental status examination findings\n• Initial diagnosis\n• Evaluation of capacity to respond to treatment\n• Initial treatment plan' WHERE id = 'psych-start' AND tree_id = 'psych-assessment';
UPDATE decision_nodes SET body = E'**Presenting Complaint:**\n• Chief complaint in patient''s own words\n• Onset, duration, and course of current symptoms\n• Precipitating events or stressors\n\n**Psychiatric History:**\n• Previous psychiatric diagnoses\n• Prior hospitalizations (voluntary vs. involuntary)\n• Previous treatments and response\n• History of self-harm or suicide attempts\n\n**Medication History:**\n• Current psychotropic medications (dose, duration, adherence)\n• Previous medication trials and why discontinued\n• Over-the-counter and herbal supplements\n\n**Substance Use:**\n• Alcohol — type, quantity, frequency, last use\n• Illicit drugs — type, route, frequency, last use\n• Tobacco/nicotine, caffeine\n• History of withdrawal symptoms or DTs\n\n**Medical History:**\n• Relevant medical conditions (thyroid, neurologic, metabolic)\n• Recent head trauma or seizures\n• Current medical medications\n\n**Family Psychiatric History:**\n• Psychiatric diagnoses in first-degree relatives\n• Family history of suicide or substance use\n\n**Social History:**\n• Living situation, employment, relationships\n• Support system, legal issues\n\n**Collateral Sources:**\n• Family members, EMS, pharmacy records, prior ED visits\n• Document who provided information and relationship to patient' WHERE id = 'psych-history' AND tree_id = 'psych-assessment';
UPDATE decision_nodes SET body = E'**Appearance** refers to how the patient presents physically. These observations offer insight into level of functioning, mood, and potential psychiatric symptoms.\n\n**Hygiene & Grooming:**\n• Clean, neat, shaven\n• Body odor, disheveled, unkempt, malodorous\n\n**Dress:**\n• Appropriate, casual, neat, business, fashionable\n• Bizarre, inappropriate, dirty, stained, ragged, layered\n\n**Posture:**\n• Relaxed, rigid, slumped, tense\n\n**Facial Expressions:**\n• Calm, sad, anxious, angry, perplexed, masked, grimacing, tearful\n\n**Apparent Age:**\n• Younger than / older than / consistent with stated age\n\n**Body Habitus:**\n• Normal, underweight, overweight, obese, cachectic\n\n**Distinguishing Features:**\n• Tattoos, piercings, scars, visible injuries, track marks\n\n**Makeup/Adornment:**\n• Appropriate, garish, bizarre, none\n\n**Assessment Prompts:**\n• "How do you usually get ready for the day?"\n• "Have you noticed any changes in your daily routines or energy levels?"\n\n**Example:** "Patient appears older than stated age. Disheveled, with stained clothing and poor hygiene. Avoids eye contact and sits with a slouched posture."' WHERE id = 'psych-appearance' AND tree_id = 'psych-assessment';
UPDATE decision_nodes SET body = E'**Behavior** refers to how the patient moves, responds, and engages during the encounter.\n\n**Eye Contact:**\n• Good, fleeting, intense, avoidant, staring, none\n\n**Cooperativeness / Attitude:**\n• Friendly, cooperative, open, relaxed, candid\n• Guarded, evasive, hostile, withdrawn, suspicious\n• Passive, sullen, manipulative, demanding, overly friendly\n\n**Psychomotor Activity:**\n• Normal, restless, tense, agitated\n• Decreased activity, psychomotor retardation, catatonic\n\n**Movement Disorders:**\n• Tremor, tics, twitches, stereotypies\n• Tardive dyskinesia (lip smacking, tongue writhing, grimacing)\n• Akathisia, dystonia, posturing\n\n**Body Language / Gestures:**\n• Open, closed, defensive, threatening\n• Appropriate gesturing, mannerisms\n\n**Gait:**\n• Steady, unsteady, shuffling, limping, uses assistive device\n\n**Level of Arousal:**\n• Alert, drowsy, somnolent, obtunded, comatose\n\n**Rapport / Engagement:**\n• Engaged, cooperative, distant, superficial, disinhibited\n\n**Assessment Prompts:**\n• "How are you feeling about today''s visit?"\n• "Have you noticed any changes in your movement or body sensations lately?"\n\n**Example:** "Patient sits rigidly, avoids eye contact, and displays frequent lip smacking. Motor activity is tense but controlled. Guarded attitude throughout the session."' WHERE id = 'psych-behavior' AND tree_id = 'psych-assessment';
UPDATE decision_nodes SET body = E'**Speech patterns** offer insight into cognitive and emotional state. Disruptions may indicate mood disorders, anxiety, thought disorganization, or neurocognitive impairment.\n\n**Rate:**\n• Normal (~100-150 words/minute)\n• Rapid / pressured (→ mania, anxiety)\n• Slow / hesitant (→ depression, sedation)\n• Delayed onset\n\n**Rhythm:**\n• Normal prosody, articulate\n• Monotone, stuttering, dysarthric, slurred\n\n**Volume:**\n• Normal, loud, soft, whispered, mute\n\n**Content / Quantity:**\n• Normal, fluent, verbose / loquacious\n• Impoverished / poverty of speech (→ depression, negative symptoms)\n• Spontaneous vs. only responsive to questions\n\n**Tone:**\n• Normal, anxious, angry, whiny, flat, tremulous\n\n**Fluency:**\n• Fluent, non-fluent, word-finding difficulty\n\n**Articulation:**\n• Clear, slurred (→ intoxication, neurologic), mumbling\n\n**Latency:**\n• Normal response time\n• Increased latency (→ depression, thought blocking, sedation)\n\n**Assessment Prompts:**\n• "Has anyone mentioned changes in the way you speak lately?"\n• "Do you feel like it''s harder to find words or express yourself?"\n\n**Example:** "Speech is slow in rate, low in volume, with increased latency. Normal articulation. Poverty of speech noted."' WHERE id = 'psych-speech' AND tree_id = 'psych-assessment';
UPDATE decision_nodes SET body = E'**Mood** is the patient''s **self-reported** emotional state — what they TELL you they feel. It represents a **sustained emotion** present over a prolonged period that can alter their perception of the world.\n\n**Ask the patient:**\n• "How is your mood today?"\n• "How have you been feeling over the past few days?"\n• "Would you say your emotions have been steady or up and down?"\n• "Have you felt sad or discouraged?"\n• "Have you been feeling anxious or worried?"\n• "On a scale of 1-10, how would you rate your mood?"\n\n**Document in patient''s own words** (in quotes).\n\n**Common Descriptors:**\n• Euthymic (normal)\n• Depressed, sad, hopeless, empty\n• Irritable, angry\n• Anxious, fearful, worried\n• Euphoric, elevated, expansive\n• Apathetic, flat\n• Labile (rapidly changing)\n\n**Key Distinction:**\n• **Mood** = what the patient TELLS you (subjective, sustained)\n• **Affect** = what you OBSERVE (objective, moment-to-moment)\n\n**Example:** "Patient describes mood as ''I just feel empty inside.''"' WHERE id = 'psych-mood' AND tree_id = 'psych-assessment';
UPDATE decision_nodes SET body = E'**Affect** is the clinician''s **objective observation** of the patient''s emotional expression — what you SEE. It is an observable emotion expressed in the moment, fluctuating during the encounter.\n\n**Intensity:**\n• Normal\n• Flat (no emotional expression → schizophrenia, severe depression)\n• Blunted (minimal expression)\n• Exaggerated\n\n**Quality:**\n• Sad, agitated, euphoric, anxious, angry, fearful, indifferent\n\n**Fluctuation / Stability:**\n• Stable\n• Labile — rapidly shifting, easily altered between states (→ mania, TBI, pseudobulbar affect)\n\n**Range:**\n• Broad / full (normal variation)\n• Restricted / constricted (reduced variation)\n• Flat (absent expression)\n• Expansive\n\n**Congruence:**\n• Mood-congruent (affect matches stated mood)\n• Mood-incongruent (laughing while describing sadness → psychosis)\n\n**Appropriateness:**\n• Appropriate to content of discussion\n• Inappropriate (affect mismatches topic)\n\n**Assessment Prompts:**\n• "How have you been feeling over the past few days?"\n• "Would you say your emotions have been steady or up and down lately?"\n\n**Example:** "Affect is restricted in range, blunted in intensity, mood-congruent, and appropriate to content."' WHERE id = 'psych-affect' AND tree_id = 'psych-assessment';
UPDATE decision_nodes SET body = E'**Thought process** describes the *form and flow* of thinking — HOW the patient thinks. Assess the amount, speed, and the way thoughts are linked together.\n\n**Stream of Thought** (amount and speed):\n• **Goal-directed / linear** — thoughts connect logically (normal)\n• **Rapid** — increased speed but still coherent\n• **Impoverished** — slow thinking, few spontaneous ideas\n• **Thought blocking** — abrupt interruption mid-sentence (→ schizophrenia)\n• **Distractible** — easily pulled off-topic by stimuli\n\n**Form of Thought** (how thoughts are linked):\n• **Circumstantial** — reaches the point via excessive detail\n• **Tangential** — wanders off topic, never reaches the point\n• **Loose associations** — unrelated ideas shift without logic\n• **Flight of ideas** — rapid shifting between loosely connected topics (→ mania)\n• **Perseveration** — repetitive return to same idea\n• **Clang associations** — connections based on sound, not meaning\n• **Word salad** — incoherent, random words without structure\n• **Neologisms** — made-up words\n• **Illogical** — conclusions don''t follow from premises\n• **Incoherent** — incomprehensible speech\n\n**Assessment Prompts:**\n• "Do you find it easy to focus or follow through on your thoughts?"\n\n**Example:** "Thought process is tangential with loose associations. Patient unable to maintain goal-directed conversation."' WHERE id = 'psych-thought-process' AND tree_id = 'psych-assessment';
UPDATE decision_nodes SET body = E'**THOUGHT CONTENT** — WHAT the patient is thinking about.\n\n**Content of Thought:**\n• **Delusions** (fixed false beliefs):\n  — Paranoid / persecutory — being watched, followed, harmed\n  — Grandiose — inflated self-importance or abilities\n  — Somatic — false beliefs about body\n  — Referential — events/media directed at them\n  — Erotomanic — belief someone is in love with them\n  — Nihilistic — belief that self/world doesn''t exist\n  — Religious — divine mission or possession\n• **Obsessions** — intrusive, unwanted thoughts\n• **Compulsions** — repetitive behaviors to reduce anxiety\n• **Phobias** — specific fears\n• **Ruminations** — repetitive worried thoughts\n• **Overvalued ideas** — strongly held but not delusional\n\n**Possession of Thought:**\n• Thought broadcasting — belief thoughts are transmitted to others\n• Thought insertion — belief thoughts are placed by external force\n• Thought withdrawal — belief thoughts are being removed\n\n**PERCEPTION** — sensory experiences.\n\n**PERCEPTIONS Mnemonic:**\n• **P**erception disturbances?\n• **E**ncephalitis considered?\n• **R**eflex hallucinations?\n• **C**oncentration affected?\n• **E**xperiences — derealization, depersonalization?\n• **P**seudohallucinations (insight preserved)?\n• **T**actile, auditory, visual, gustatory, olfactory hallucinations?\n• **I**pseity disturbance (disturbed sense of self)?\n• **O**rganic states?\n• **N**egative symptoms?\n• **S**ensory impairment?\n\n**Command hallucinations:** Ask specifically, document content.\n\n**Screening Questions:**\n• "Do you see or hear things that others don''t?"\n• "Do you ever feel like things aren''t real?"\n• "Do you have thoughts that feel intrusive or hard to stop?"\n\n**Note:** SI/HI is assessed in the Safety module.\n\n**Example:** "Patient reports auditory hallucinations (non-command voices commenting on actions). Denies visual hallucinations. Endorses paranoid ideation that coworkers are monitoring him."' WHERE id = 'psych-thought-content' AND tree_id = 'psych-assessment';
UPDATE decision_nodes SET body = E'**Cognitive assessment** determines how well the patient processes information, recalls memories, and maintains awareness.\n\n**Alertness:**\n• Alert, lethargic, obtunded, stuporous, comatose\n\n**Orientation** (document as A&Ox3 or A&Ox4):\n• Person — "What is your name?"\n• Place — "Where are you right now?"\n• Time — "What year/month/day is it?"\n• Situation — "Why are you here today?"\n\n**Clouding of Consciousness:**\n• Drowsiness, memory impairment, impaired concentration\n• Subtle fluctuations in awareness (→ delirium)\n\n**Attention & Concentration:**\n• Serial 7s (100, 93, 86, 79, 72...)\n• Spell "WORLD" backward\n• Days of the week backward\n• Digit span forward/backward\n\n**Memory:**\n• **Immediate** — repeat 3 words (apple, table, penny)\n• **Short-term** — recall those 3 words after 5 minutes\n• **Long-term** — biographical facts (birthday, address)\n\n**Visuospatial Functioning:**\n• Clock drawing test (draw clock showing 11:10)\n• Copy intersecting pentagons or 3D cube\n\n**Abstract Reasoning:**\n• Similarities — "How are an apple and orange alike?"\n• Proverb interpretation — "A stitch in time saves nine"\n\n**Language:**\n• Naming — point to common objects\n• Comprehension — follow multi-step commands\n• Repetition — "No ifs, ands, or buts"\n\n**Formal Screening:** Consider MMSE (cutoff 24/30) or MoCA (cutoff 26/30) if cognitive impairment suspected.\n\n**Cultural Considerations:** Language barriers, education level, and cultural norms may affect performance. Use interpreter services. Adjust expectations for literacy and background. General knowledge varies by culture/ethnicity.\n\n**Reversible causes to consider:** hypothyroidism, B12 deficiency, infections, medications (beta-blockers, steroids, anticholinergics), substance use.\n\n**Assessment Prompts:**\n• "Can you tell me where we are and what today''s date is?"\n• "I''ll say 3 words — can you repeat them back to me?"\n\n**Example:** "Alert and oriented x4. Attention fair, distracted during serial 7s. Recalls 2/3 words at 5 minutes. Insight and judgment limited."' WHERE id = 'psych-cognition' AND tree_id = 'psych-assessment';
UPDATE decision_nodes SET body = E'**Suicidal Ideation — ask directly:**\n• "Do you feel that life is not worth living?"\n• "Have you had thoughts of hurting yourself?"\n• "Have you thought about killing yourself?"\n• "Do you have a plan? Do you have the means?"\n• "Have you ever attempted suicide before?"\n\nConsider using the **Columbia Suicide Severity Rating Scale (C-SSRS)** for structured screening.\n\n**Homicidal Ideation — ask directly:**\n• "Have you had thoughts of hurting anyone else?"\n• "Is there anyone you feel angry enough to harm?"\n• "Do you have a plan or access to weapons?"\n\n**Risk Factors for Suicide:**\n• Previous attempts (strongest predictor)\n• Access to lethal means — **ask specifically about firearms**\n• Recent losses, social isolation\n• Substance use, chronic pain\n• Male sex, older age, psychiatric diagnosis\n• Recent ED visits, recent discharge from psychiatric facility\n\n**Protective Factors:**\n• Social support, children at home\n• Future orientation, religious beliefs\n• Therapeutic alliance, treatment engagement\n\n**Descriptors:** Not suicidal, passive ideation, active ideation with/without plan, intent reported, homicidal intent reported.' WHERE id = 'psych-safety' AND tree_id = 'psych-assessment';
UPDATE decision_nodes SET body = E'**Passive SI** — patient expresses desire to be dead or not alive but denies active plan or intent.\n\n**Further Assessment:**\n• Frequency and duration of thoughts\n• Any preparatory behaviors (giving away possessions, writing notes)\n• Access to means — **ask specifically about firearms**\n• Substance use (acutely increases risk)\n• Recent changes in behavior or functioning\n\n**Safety Planning (Stanley-Brown Model):**\n1. Warning signs that a crisis is developing\n2. Internal coping strategies\n3. People and social settings that provide distraction\n4. People to contact for help\n5. Professionals and agencies to contact\n6. Making the environment safe (lethal means counseling)\n\n**Disposition Considerations:**\n• Means restriction counseling (document specifically)\n• Outpatient psychiatric follow-up within 48-72 hours\n• Crisis resources: **988 Suicide & Crisis Lifeline**\n• Consider social work consult\n• Discharge may be appropriate if patient is **not intoxicated, has support system, agrees to safety plan, and can contract for safety**\n\n**Document:** risk factors, protective factors, safety plan, and clinical reasoning for disposition.' WHERE id = 'psych-si-passive' AND tree_id = 'psych-assessment';
UPDATE decision_nodes SET body = E'**Active SI with plan or intent requires immediate intervention.**\n\n**Immediate Actions:**\n• 1:1 sitter / continuous observation\n• Remove all potential means (sharps, cords, medications)\n• Place patient in safe environment (ligature-resistant room)\n• Voluntary vs. involuntary hold based on jurisdiction\n\n**Consult Psychiatry for:**\n• Risk assessment and safety planning\n• Medication evaluation\n• Inpatient admission recommendation\n• Voluntary vs. involuntary commitment determination\n\n**Labs to Consider:**\n• Urine drug screen, blood alcohol\n• TSH, CBC, BMP (rule out medical contributors)\n• Acetaminophen/salicylate levels if ingestion suspected\n\n**Documentation Must Include:**\n• Specific ideation content (in patient''s own words)\n• Presence/absence of plan and means\n• Risk factors and protective factors\n• Disposition rationale\n• Who was consulted\n\n**Example:** "Patient endorses SI with plan to overdose on home medications. Has access to stockpiled pills. Prior attempt 6 months ago. 1:1 sitter placed. Psychiatry consulted."' WHERE id = 'psych-si-active' AND tree_id = 'psych-assessment';
UPDATE decision_nodes SET body = E'**Homicidal ideation requires immediate safety measures and may trigger duty to warn/protect obligations.**\n\n**Immediate Actions:**\n• Ensure staff safety — do not interview alone\n• Security at bedside if agitated or threatening\n• Search for weapons per hospital protocol\n• 1:1 observation\n\n**Assessment:**\n• Specificity of target (identified vs. generalized)\n• Specificity of plan\n• Access to weapons\n• History of violence\n• Substance intoxication\n\n**Duty to Warn / Tarasoff Obligations:**\n• Varies by state — know your jurisdiction\n• Generally required when there is an **identifiable target** and **credible threat**\n• Document notification of intended victim and/or law enforcement\n\n**Consult Psychiatry** for risk assessment and disposition.\n\n**Document:** specific threats made, targets identified, actions taken, and parties notified.' WHERE id = 'psych-hi' AND tree_id = 'psych-assessment';
UPDATE decision_nodes SET body = E'**Insight** — the extent to which the patient recognizes and appraises their experiences.\n\n**Levels of Insight:**\n• **Good / Complete** — acknowledges illness, understands need for treatment, willing to engage\n• **Fair / Partial** — acknowledges some symptoms but minimizes severity or attributes to wrong cause\n• **Poor / Limited** — denies illness, blames external factors, resistant to treatment\n• **Absent / None** — no recognition of illness whatsoever\n\n**Key Questions:**\n• Do they have insight into their symptoms and diagnosis?\n• What is their judgment on the problem?\n• Are they willing to work with healthcare professionals?\n• Are they AWARE of potential treatments?\n• Are they ACCEPTING that the problem may be a result of mental illness?\n\n**Judgment** — patient''s decision-making capacity.\n\n**Judgment Levels:** Good, fair, poor, impaired, inflated.\n\n**Assessment Methods:**\n• "What would you do if you found a stamped, addressed letter on the ground?"\n• "What would you do if you smelled smoke in a crowded theater?"\n• Evaluate recent decisions and their consequences\n• Assess understanding of treatment recommendations\n• Assess problem-solving ability\n\n**Capacity** (4 criteria):\n1. Express a consistent choice\n2. Understand the relevant information\n3. Appreciate how it applies to their situation\n4. Rationally manipulate the information\n\n**Clinical Judgment & Risk Assessment:**\nSynthesize all MSE findings into an overall risk formulation. Consider whether the patient is a danger to self, danger to others, or gravely disabled.\n\n**Example:** "Insight is poor — patient denies any mental health concerns despite florid psychotic symptoms. Judgment impaired as evidenced by inability to plan for basic safety needs."' WHERE id = 'psych-insight' AND tree_id = 'psych-assessment';
UPDATE decision_nodes SET body = E'**Consider labs to rule out medical contributors to psychiatric symptoms:**\n\n**Routine:**\n• CBC — infection, anemia\n• BMP — electrolytes, glucose, renal function\n• TSH — hypothyroidism / hyperthyroidism\n• Urinalysis — UTI (especially elderly with altered mental status)\n\n**As Clinically Indicated:**\n• Urine drug screen — substance-induced symptoms\n• Blood alcohol level\n• B12 and folate — deficiency causes cognitive/mood changes\n• LFTs — hepatic encephalopathy\n• HIV testing\n• RPR/VDRL — neurosyphilis\n• Lyme titer (endemic areas)\n• Ammonia level\n• Acetaminophen and salicylate levels (if overdose suspected)\n\n**Imaging:**\n• CT head — first psychotic break, focal neuro findings, trauma, elderly new-onset symptoms\n\n**Abnormal findings should prompt medical workup before attributing symptoms to primary psychiatric illness.**\n\n**Environmental Assessment:**\nWhen conducting MSE in the patient''s home or residential setting, physical surroundings offer clues about cognitive functioning, reality testing, and self-care capacity (hoarding, safety hazards, food availability).' WHERE id = 'psych-labs' AND tree_id = 'psych-assessment';
UPDATE decision_nodes SET body = E'**Determine appropriate level of care based on the complete assessment.**\n\n**Your documentation must include:**\n1. Complete medical and psychiatric history\n2. Mental status examination findings (all 10 components)\n3. Initial diagnosis\n4. Evaluation of capacity to respond to treatment\n5. Initial treatment plan\n\n**Use objective and descriptive language.** Avoid vague terms like "seems sad." Instead: "Patient avoided eye contact, sat hunched over, spoke in a low tone."\n\n**Include direct quotes** when describing mood, thought content, or delusions.\n\n**Clearly document any safety concerns** — be specific about what was reported, how risk was assessed, and what actions were taken.\n\n**Consider cultural context** — behavior and communication are influenced by cultural background. What appears to be restricted affect or guardedness may be culturally appropriate.' WHERE id = 'psych-disposition' AND tree_id = 'psych-assessment';
UPDATE decision_nodes SET body = E'**Discharge Criteria Met:**\n• No active suicidal or homicidal ideation\n• Patient is not acutely intoxicated\n• Adequate support system identified\n• Patient agrees to safety plan\n• Outpatient follow-up arranged\n\n**Discharge Plan:**\n• Safety plan completed and reviewed with patient\n• Means restriction counseling documented\n• Crisis resources provided (**988 Suicide & Crisis Lifeline**)\n• Outpatient psychiatry appointment within 48-72 hours\n• Medication reconciliation if applicable\n• Return precautions reviewed\n\n**Return to ED if:**\n• Worsening suicidal or homicidal thoughts\n• Inability to maintain safety\n• New or worsening psychotic symptoms\n• Medication side effects or adverse reactions' WHERE id = 'psych-discharge' AND tree_id = 'psych-assessment';
UPDATE decision_nodes SET body = E'**Admission Criteria:**\n• Active suicidal or homicidal ideation with plan/intent\n• Acute psychosis requiring stabilization\n• Inability to care for self (gravely disabled)\n• Failed outpatient management\n• Need for medication adjustment requiring monitoring\n• Substance withdrawal requiring medical management\n\n**Voluntary Admission:**\n• Patient consents to treatment\n• Document capacity to consent\n• Patient retains right to request discharge\n\n**Involuntary Hold:**\n• Criteria vary by state (typically: danger to self, danger to others, gravely disabled)\n• Document specific behaviors and statements supporting criteria\n• Know your state''s hold duration and process\n• Physician certification required\n\n**Orders:**\n• Admit to psychiatric unit\n• 1:1 or Q15 safety checks as indicated\n• Medications as recommended by psychiatry\n• Diet, activity level\n• Labs if not already obtained\n\n**Document:** clinical reasoning for admission, voluntary vs. involuntary status, patient''s statements supporting criteria.' WHERE id = 'psych-admit' AND tree_id = 'psych-assessment';

-- === rabies (30 nodes) ===
UPDATE decision_nodes SET body = E'[Rabies Steps Summary](#/info/rabies-summary) — quick-reference for both clinical rabies workup and post-exposure prophylaxis.\n\nRabies is nearly **100% fatal once symptomatic**. Post-exposure prophylaxis is highly effective if given promptly — no confirmed PEP failures when administered correctly.\n\nSelect your clinical scenario below.' WHERE id = 'rabies-start' AND tree_id = 'rabies';
UPDATE decision_nodes SET body = E'**Rabies is frequently missed at initial presentation.** The diagnosis requires high clinical suspicion.\n\n**Key clues:**\n• Acute neuropsychiatric illness + travel to rabies-endemic area\n• **Pain, paresthesia, or pruritus at a prior bite site** — relatively specific for rabies\n• History of animal exposure **weeks to months** prior (incubation typically several weeks to months)\n• Patients may not recall or report animal exposures\n\n[Rabies Differential Diagnosis](#/info/rabies-ddx) — distinguishing rabies from HSV encephalitis, tetanus, GBS, and autoimmune encephalitis.\n\n**Infection control:** Standard + contact precautions. Careful handling of saliva, respiratory secretions, CSF. Rabies is **nationally notifiable**.' WHERE id = 'rabies-clinical' AND tree_id = 'rabies';
UPDATE decision_nodes SET body = E'Approximately **80% develop furious (encephalitic) rabies** and **20% develop paralytic rabies**. These forms are clinically distinct.\n\nBat rabies variants can present atypically.' WHERE id = 'rabies-form' AND tree_id = 'rabies';
UPDATE decision_nodes SET body = E'**Characteristic features:**\n• **Hydrophobia** — pharyngeal/laryngeal spasms triggered by attempts to swallow water or even the sight/sound of water\n• **Aerophobia** — similar spasms triggered by air blown on the face\n• **Fluctuating consciousness** with periods of agitation alternating with lucidity\n• **Inspiratory spasms** involving contraction of inspiratory muscles\n• **Hypersalivation** with difficulty swallowing\n• **Autonomic dysfunction** — tachycardia, hypertension, hyperthermia\n• Anxiety, hyperexcitability, and delirium\n\n**Average survival: 5-6 days** from symptom onset without intensive care.\n\n**Key differentiators from mimics:**\n• HSV encephalitis — lacks hydrophobia/aerophobia, temporal lobe MRI findings\n• Tetanus — continuous rigidity between spasms (absent in rabies), normal consciousness\n• Autoimmune encephalitis (anti-NMDAR) — prominent seizures (85%), responds to immunotherapy' WHERE id = 'rabies-furious' AND tree_id = 'rabies';
UPDATE decision_nodes SET body = E'**Characteristic features:**\n• **Ascending flaccid paralysis** beginning in the bitten extremity — closely mimics Guillain-Barré syndrome\n• **Preserved consciousness** until preterminal phase (key distinguishing feature from GBS)\n• Lower motor neuron weakness without hyperexcitability of furious rabies\n• Progression to coma, myoedema, bladder incontinence\n\n**Average survival: ~11 days** (longer than furious form).\n\n**Distinguishing from GBS:**\n• Pain/paresthesias at bite site (rabies) vs distal paresthesias (GBS)\n• CSF: minimal pleocytosis (rabies) vs albuminocytologic dissociation (GBS)\n• Fever and rapid autonomic dysfunction (rabies) vs progression over 12h-28d (GBS)\n• Exposure history weeks to months prior\n\n**Note:** Paralytic rabies has **lower diagnostic sensitivity** across all specimen types compared to furious rabies.' WHERE id = 'rabies-paralytic' AND tree_id = 'rabies';
UPDATE decision_nodes SET body = E'**Bat rabies variants** can present with atypical features:\n• Focal brainstem signs\n• Myoclonus\n• Hemichorea\n• Horner''s syndrome\n\n**Rare presentations mimicking:**\n• Transverse myelitis\n• Neuromyelitis optica\n• Tetanus with locked jaw\n\n**Diagnostic challenge:** These presentations may not trigger clinical suspicion for rabies. Always consider rabies in the differential of acute, unexplained neuropsychiatric illness — especially with any possible animal exposure history or travel to endemic areas.' WHERE id = 'rabies-atypical' AND tree_id = 'rabies';
UPDATE decision_nodes SET body = E'**Immediately consult local public health laboratory or CDC** — rabies diagnostic testing is not available at most hospital or reference laboratories.\n\n[Diagnostic Specimens & Interpretation](#/info/rabies-dx-guide) — complete 4-specimen protocol with sensitivities and timing.\n\n**No single test is sufficient for antemortem diagnosis.** Four specimen types should be collected:\n\n**1. Saliva** — RT-PCR for viral RNA (≥3 serial samples for >98% sensitivity)\n**2. Nuchal skin biopsy** — DFA for rabies antigen in cutaneous nerves (~100% sensitivity when adequate tissue)\n**3. CSF** — antibody testing (diagnostic in unvaccinated patients; ~100% sensitivity after day 12)\n**4. Serum** — antibody testing\n\n**Combined sensitivity is 100%** when all 4 specimen types are tested.\n\n**Timing:** Early illness (week 1) → prioritize saliva RT-PCR + nuchal biopsy. Later illness (>7-12 days) → antibody testing has higher yield.\n\n**Caveat:** Prior IVIG administration can cause false-positive serology.' WHERE id = 'rabies-dx-workup' AND tree_id = 'rabies';
UPDATE decision_nodes SET body = E'Once clinical symptoms develop, **no effective therapy exists** and rabies is nearly uniformly fatal.\n\nOf ~10 documented rabies survivors, **most had received partial PEP before symptom onset**, and nearly all had permanent neurological deficits.' WHERE id = 'rabies-mgmt' AND tree_id = 'rabies';
UPDATE decision_nodes SET body = E'**Recommended for most patients with clinical rabies.**\n\n• Liberal use of **sedatives and analgesics** for comfort\n• Symptom management: antispasmodics for pharyngeal spasms, anxiolytics for agitation\n• Family counseling regarding prognosis\n• Avoid unnecessary invasive procedures\n\n**Infection control:**\n• Standard + contact precautions throughout\n• Careful handling of all secretions (saliva, respiratory, CSF)\n• Rapid risk assessment of all exposed personnel in coordination with public health\n• Report to local/state health department — **rabies is nationally notifiable**\n\n**2024 Kentucky/Ohio case:** Inconsistent adherence to standard precautions resulted in **52 of 60 healthcare workers requiring PEP** due to saliva exposure.' WHERE id = 'rabies-palliative' AND tree_id = 'rabies';
UPDATE decision_nodes SET body = E'**The Milwaukee Protocol has failed in at least 26 subsequent cases** and is now considered ineffective. The original protocol included therapeutic coma with burst suppression, but this is **no longer recommended**.\n\n**Modified approach (current):**\n• Ketamine and midazolam for sedation and dysautonomia\n• Nimodipine (with caution — hypotension risk)\n• ICU supportive care\n• Standard + contact infection control precautions\n\n**Factors that may favor aggressive therapy** (outcomes still poor):\n• Prior partial PEP before symptom onset\n• Young age, previously healthy, immunocompetent\n• Mild neurological disease at therapy initiation\n• New World bat rabies variant (vs canine variant)\n• Early detection of neutralizing antibodies in serum/CSF\n\n**ID and neurology consultation recommended.**' WHERE id = 'rabies-aggressive' AND tree_id = 'rabies';
UPDATE decision_nodes SET body = E'Classify the exposure using WHO categories.\n\n**Category I — No exposure:** Touching, feeding, licks on intact skin\n**Category II — Minor:** Nibbling uncovered skin, minor scratches/abrasions without bleeding\n**Category III — Severe:** Transdermal bites/scratches, mucous membrane contamination, broken skin + saliva, **any direct bat contact**' WHERE id = 'rabies-contact' AND tree_id = 'rabies';
UPDATE decision_nodes SET body = E'Skin was not broken and no mucous membrane contamination occurred. This is **not a rabies exposure**.\n\n**Wound care:** Wash affected area with soap and water as a general hygiene measure.\n\nUpdate tetanus prophylaxis if not current.' WHERE id = 'rabies-cat1' AND tree_id = 'rabies';
UPDATE decision_nodes SET body = E'What animal was involved? Species determines risk level and whether observation is an option.\n\n[Rabies Risk by Animal Type](#/info/rabies-animal-risk) — detailed reference table.' WHERE id = 'rabies-animal-type' AND tree_id = 'rabies';
UPDATE decision_nodes SET body = E'What animal caused the severe exposure?\n\nCategory III exposures require **RIG + vaccine** unless the animal can be confirmed rabies-negative.\n\n[Rabies Risk by Animal Type](#/info/rabies-animal-risk) — detailed reference.' WHERE id = 'rabies-animal-type-severe' AND tree_id = 'rabies';
UPDATE decision_nodes SET body = E'**Healthy dogs, cats, and ferrets can be observed for 10 days.**\n\nIf animal is:\n• **Available and healthy** — begin wound care, **hold PEP** pending observation. If animal develops signs of rabies or dies → begin PEP immediately.\n• **Unavailable, stray, or wild-acting** — begin PEP now (vaccine only for Category II)\n• **Dead or euthanized** — send head for testing. Begin PEP pending results; discontinue if negative.\n\n**Observation applies ONLY to dogs, cats, and ferrets.** No reliable observation period exists for wildlife.' WHERE id = 'rabies-observe' AND tree_id = 'rabies';
UPDATE decision_nodes SET body = E'**Healthy dogs, cats, and ferrets can be observed for 10 days.**\n\nFor Category III exposures:\n• **Animal available and healthy** — **Start RIG + vaccine immediately.** If animal remains healthy at day 10, may discontinue vaccine series.\n• **Animal unavailable, stray, or wild-acting** — complete full RIG + vaccine series\n• **Dead or euthanized** — send head for testing. Start PEP pending results; discontinue if negative.\n\n**Do NOT delay RIG for Category III exposures.** RIG must be given with the first vaccine dose and **cannot be given after day 7** of the vaccine series.' WHERE id = 'rabies-observe-severe' AND tree_id = 'rabies';
UPDATE decision_nodes SET body = E'**Bats require a lower threshold for PEP due to small, unnoticed bites.**\n\nPEP IS indicated if bat was found in room with:\n• Sleeping person\n• Unattended child\n• Intoxicated or cognitively impaired person\n• Person who cannot reliably exclude bite/scratch\n\nPEP is NOT indicated ONLY if patient can **definitively confirm** no bite, scratch, or mucous membrane exposure occurred.\n\n**Bat bites can be virtually invisible** — fang marks may not be visible to the naked eye.\n\n**All bat exposures should be treated as Category III** (RIG + vaccine) unless definitively excluded.' WHERE id = 'rabies-bat' AND tree_id = 'rabies';
UPDATE decision_nodes SET body = E'Raccoons, skunks, foxes, and coyotes are **high-risk rabies reservoir species** in the US.\n\n• If animal captured/killed → send for testing. Start vaccine pending results.\n• If animal escaped → assume rabid, begin **vaccine series** (no RIG for Category II).\n\n**Wild animal behavior note:** A "friendly" or diurnal raccoon/skunk should raise suspicion for rabies.' WHERE id = 'rabies-wildlife-cat2' AND tree_id = 'rabies';
UPDATE decision_nodes SET body = E'Raccoons, skunks, foxes, and coyotes are **high-risk rabies reservoir species** in the US.\n\n**Immediate PEP (RIG + vaccine) is indicated for all Category III wildlife exposures.**\n\n• If captured/killed → send for testing. Start full PEP pending results; discontinue only if testing confirms negative.\n• If escaped → complete full PEP course.\n\nConsult local public health for animal disposition and testing.' WHERE id = 'rabies-wildlife-cat3' AND tree_id = 'rabies';
UPDATE decision_nodes SET body = E'Small rodents (mice, rats, squirrels, hamsters, gerbils, guinea pigs, chipmunks) and rabbits are **almost never found to be infected with rabies** and have not been known to transmit rabies to humans.\n\n**Exceptions requiring public health consultation:**\n• **Woodchucks (groundhogs)** — higher risk among rodents\n• Unusual behavior in the animal\n• Local public health advisory\n\n**Wound care:** Wash with soap and water ≥15 minutes. Update tetanus if needed.' WHERE id = 'rabies-rodent' AND tree_id = 'rabies';
UPDATE decision_nodes SET body = E'**Wound care is the single most effective rabies prevention measure** — reduces risk by up to 90% in animal studies.\n\n**Immediate wound care:**\n1. **Wash wound with soap and water for at least 15 minutes** — vigorous flushing\n2. Irrigate with **povidone-iodine** (Betadine) or virucidal agent if available\n3. Do NOT apply caustic agents (bleach, acid)\n\n**Suturing guidance:**\n• **Delay primary closure if possible** — leaving wounds open reduces infection risk\n• If suturing required for cosmetic/hemostatic reasons: **infiltrate RIG into wound bed first**, then suture loosely\n• Approximate wound edges rather than tight closure\n\n**Tetanus:** Update tetanus prophylaxis per standard wound guidelines if not current.' WHERE id = 'rabies-wound' AND tree_id = 'rabies';
UPDATE decision_nodes SET body = E'Has the patient **previously completed** a full rabies vaccine series (pre-exposure or post-exposure)?\n\nPreviously vaccinated patients need a **shorter protocol** (2 doses, no RIG) unless immunocompromised.' WHERE id = 'rabies-pep-decision' AND tree_id = 'rabies';
UPDATE decision_nodes SET body = E'Is the patient immunocompromised?\n\n**Immunocompromising conditions include:**\n• HIV/AIDS\n• Active chemotherapy or radiation\n• Chronic corticosteroid use (>2 mg/kg or >20 mg/day prednisone for >14 days)\n• Solid organ or stem cell transplant\n• Primary immunodeficiency\n• Anti-CD20 therapy (rituximab) within 6 months' WHERE id = 'rabies-immune-check' AND tree_id = 'rabies';
UPDATE decision_nodes SET body = E'Previously vaccinated patients have an **anamnestic immune response** — they need only 2 vaccine doses and **no RIG**.\n\nHowever, immunocompromised patients may not mount an adequate anamnestic response.' WHERE id = 'rabies-prevax-immune' AND tree_id = 'rabies';
UPDATE decision_nodes SET body = E'**RABIES IMMUNE GLOBULIN (RIG)**\n• [Rabies Immune Globulin (HRIG)](#/drug/rabies-rig/rabies pep) **20 IU/kg**\n• **Infiltrate as much as anatomically feasible into and around the wound(s)**\n• Inject remainder IM at a site **distant from the vaccine injection site**\n• Give with the first vaccine dose ONLY — **do NOT give RIG after day 7** of the vaccine series\n• Do NOT exceed 20 IU/kg (may interfere with active antibody production)\n\n**RABIES VACCINE**\n• [Rabies Vaccine (HDCV or PCECV)](#/drug/rabies-vaccine/rabies pep unvaccinated) **1.0 mL IM** deltoid (adults) or anterolateral thigh (children)\n• **4-dose series: Days 0, 3, 7, 14**\n• Day 0 = today (give vaccine at a different site than RIG)\n\n**PREGNANCY** is NOT a contraindication to rabies PEP.' WHERE id = 'rabies-full-pep' AND tree_id = 'rabies';
UPDATE decision_nodes SET body = E'**Immunocompromised patients require a modified protocol:**\n\n**RIG** — Give **even if previously vaccinated:**\n• [Rabies Immune Globulin (HRIG)](#/drug/rabies-rig/rabies pep) **20 IU/kg** — infiltrate wound, remainder IM distant from vaccine\n\n**VACCINE — 5-dose series:**\n• [Rabies Vaccine (HDCV or PCECV)](#/drug/rabies-vaccine/rabies pep immunocompromised) **1.0 mL IM**\n• **Days 0, 3, 7, 14, and 28** (additional day 28 dose)\n\n**POST-VACCINATION SEROLOGY:**\n• Check rabies virus neutralizing antibody (RVNA) titer **7-14 days after last dose**\n• Adequate response: ≥0.5 IU/mL\n• If inadequate: administer additional vaccine dose and recheck\n\n**ID/infectious disease consultation recommended** for all immunocompromised patients.' WHERE id = 'rabies-immunocomp-pep' AND tree_id = 'rabies';
UPDATE decision_nodes SET body = E'**No RIG needed** — previously vaccinated, immunocompetent patients already have memory B cells.\n\n**VACCINE — 2-dose series:**\n• [Rabies Vaccine (HDCV or PCECV)](#/drug/rabies-vaccine/rabies pep previously vaccinated) **1.0 mL IM** deltoid (adults) or anterolateral thigh (children)\n• **Days 0 and 3** only\n\n**Applies to patients who have received:**\n• Prior complete PEP series\n• Pre-exposure prophylaxis (2- or 3-dose series)\n• Prior series with documented adequate antibody titer' WHERE id = 'rabies-prevax-regimen' AND tree_id = 'rabies';
UPDATE decision_nodes SET body = E'**UNVACCINATED, IMMUNOCOMPETENT — 4 doses:**\nDay 0 (today) | Day 3 | Day 7 | Day 14\n+ RIG on Day 0 only\n\n**UNVACCINATED, IMMUNOCOMPROMISED — 5 doses:**\nDay 0 (today) | Day 3 | Day 7 | Day 14 | Day 28\n+ RIG on Day 0 (even if previously vaccinated)\n+ Post-series serology\n\n**PREVIOUSLY VACCINATED, IMMUNOCOMPETENT — 2 doses:**\nDay 0 (today) | Day 3\nNo RIG needed\n\n**Administration site:**\n• Adults: **deltoid muscle** (NEVER gluteal — poor immunogenicity)\n• Children: anterolateral thigh acceptable\n• Vaccine and RIG must be given at **different anatomic sites**\n\n[Rabies PEP — Patient Information](#/info/rabies-patient-info) — shareable vaccination schedule and return instructions.' WHERE id = 'rabies-schedule' AND tree_id = 'rabies';
UPDATE decision_nodes SET body = E'**FOLLOW-UP VACCINATION VISITS:**\n• Schedule vaccine doses per protocol above\n• Doses can be given at PCP, urgent care, public health department, or ED\n• **Do not restart the series if a dose is delayed** — resume where left off\n\n**ANIMAL OBSERVATION (dogs/cats/ferrets only):**\n• If 10-day observation in progress → contact animal control/public health for updates\n• Animal develops rabies signs or dies → ensure PEP is completed\n• Animal healthy at day 10 → may discontinue vaccine series\n\n**MONITORING:**\n• Watch wound for signs of infection\n• Vaccine side effects: injection site pain (up to 74%), headache, nausea — generally mild\n• Rare: immune complex-like reaction (urticaria, arthralgias) with booster doses of HDCV\n\n**PUBLIC HEALTH:**\n• Report animal bite to local animal control/health department\n• Ensure animal disposition plan is in place' WHERE id = 'rabies-followup' AND tree_id = 'rabies';

-- === sah (25 nodes) ===
UPDATE decision_nodes SET body = E'[SAH Steps Summary](#/info/sah-summary) — quick reference.\n\nSpontaneous SAH (sSAH) results from extravasation of blood into the CSF. **85% are caused by aneurysm rupture.** 10% are nonaneurysmal perimesencephalic hemorrhage (better prognosis).\n\n• Incidence: ~10 per 100,000/year in the US\n• Mortality: ~40% at 1 week; 10-15% die prehospital\n• Misdiagnosis rate: up to 5% on initial ED visit\n• Delayed or missed diagnosis → significantly worse outcomes\n\n**Risk factors:** Hypertension, smoking, heavy alcohol use, cocaine, family history of aSAH, polycystic kidney disease, connective tissue disorders, female sex.' WHERE id = 'sah-start' AND tree_id = 'sah';
UPDATE decision_nodes SET body = E'**Classic:** Sudden-onset severe headache ("worst headache of my life") peaking within seconds — **thunderclap headache**. Neither sensitive nor specific for SAH.\n\n• 10-16% of thunderclap headaches are SAH\n• 70% present with headache alone, no focal symptoms\n• **Normal neurologic exam in 75%** of aSAH patients\n• Transient LOC in ~25%\n• Vomiting in ~70%; neck stiffness in ~60%\n• Seizures or cranial nerve palsies suggest serious pathology\n\n**Atypical presentations:**\n• Isolated neck/back pain (8% have no headache)\n• General malaise without typical headache\n• Sentinel/warning headache (10-43%) days to weeks before major SAH — **10x higher rebleeding risk**\n\n**Key pearl:** No headache features reliably distinguish SAH from benign causes. Pain responding to analgesics does NOT exclude SAH.' WHERE id = 'sah-presentation' AND tree_id = 'sah';
UPDATE decision_nodes SET body = E'For patients with **acute nontraumatic headache** reaching maximal intensity within 1 hour and a **normal neurologic examination**, apply the Ottawa SAH Rule.\n\n**Further workup required if ANY present:**\n• Age ≥40 years\n• Neck pain or stiffness\n• Witnessed loss of consciousness\n• Onset during exertion\n• Thunderclap headache (peaks within 1 minute)\n• Limited neck flexion on examination\n\nSensitivity **100%** (validation studies). Specificity 27.5%.\n\n2019 ACEP Clinical Policy supports using this rule to identify patients who may not require imaging.' WHERE id = 'sah-ottawa' AND tree_id = 'sah';
UPDATE decision_nodes SET body = E'Patient meets **no Ottawa SAH Rule criteria** (age <40, no neck pain/stiffness, no LOC, no exertional onset, no thunderclap, normal neck flexion).\n\n2019 ACEP Clinical Policy supports that these patients may not require imaging for SAH.\n\n**However**, if clinical suspicion remains high based on overall presentation, proceeding with CT is still appropriate. The rule is designed to identify the lowest-risk cohort, not to replace clinical judgment.\n\n**Discharge instructions:**\n• Return immediately for worsening headache, new neurologic symptoms, or altered consciousness\n• Follow up with primary care within 1-2 weeks' WHERE id = 'sah-low-risk' AND tree_id = 'sah';
UPDATE decision_nodes SET body = E'The initial test for suspected sSAH is **noncontrast head CT**. CT sensitivity is time-dependent — blood is degraded and diluted by CSF circulation over time.\n\n**CT sensitivity by timing:**\n• Within 6 hours: **98.7%** (meta-analysis of 8,907 patients)\n• Day 0: 92-100%\n• Day 1: 86%\n• Day 2: 76%\n• Day 5: 58%\n\n**Conditions for highest sensitivity (≤6h):**\n• Third-generation or newer scanner\n• Interpreted by attending radiologist\n• Normal neurologic examination\n• Normal hematocrit (anemia may make blood isodense with CSF)\n\n**Key pearl:** A negative CT does not rule out SAH, especially with later presentations.' WHERE id = 'sah-ct' AND tree_id = 'sah';
UPDATE decision_nodes SET body = E'Interpret the noncontrast head CT result in the context of **time from symptom onset.**\n\n**CT positive:** Hyperdensity in the basal cisterns (typical aneurysmal pattern) or cerebral convexities (consider traumatic or convexal SAH).\n\n**CT negative ≤6h:** In a prospective study of 3,132 patients, CT within 6 hours had 100% sensitivity. A meta-analysis reports 98.7% sensitivity with appropriate conditions.\n\n**CT negative >6h:** Sensitivity decreases progressively — additional testing is needed.' WHERE id = 'sah-ct-result' AND tree_id = 'sah';
UPDATE decision_nodes SET body = E'A negative CT within 6 hours of symptom onset has very high sensitivity for SAH, **but may not be 100%** depending on scanner generation and interpretation.\n\n**ACEP 2019 Level B recommendation:** In patients presenting within 6 hours with a negative CT on a third-generation or newer scanner read by an attending radiologist, a normal neurologic exam, and no anemia, sSAH may be ruled out without LP.\n\n**Consider proceeding to LP if:**\n• High clinical suspicion despite negative CT\n• Uncertain scanner generation\n• CT read by non-radiologist\n• Patient has anemia (Hct <30%)\n• Symptom onset time uncertain' WHERE id = 'sah-early-neg' AND tree_id = 'sah';
UPDATE decision_nodes SET body = E'[LP Interpretation Guide](#/info/sah-lp-guide) — detailed reference.\n\nFor patients with negative CT and ongoing suspicion for SAH, LP is the next diagnostic step.\n\n**Technique:**\n• Patient in lateral recumbent position\n• Measure **opening pressure** (elevated >20 cm H₂O in 60% of sSAH)\n• Collect **4 serial tubes** of CSF\n• Send last tube for cell count AND xanthochromia\n\n**Key considerations:**\n• Traumatic tap occurs in 10-15% of patients\n• Xanthochromia takes up to 12 hours to develop\n• If LP performed <12h after onset, accept either RBCs or xanthochromia as positive\n• Finding normal CSF at any time point excludes SAH\n\n**Opening pressure clues:** Elevated → SAH, cerebral venous thrombosis, or idiopathic intracranial hypertension. Decreased → spontaneous intracranial hypotension.' WHERE id = 'sah-lp' AND tree_id = 'sah';
UPDATE decision_nodes SET body = E'**Assess the CSF results:**\n\n**Positive for SAH:**\n• Xanthochromia (yellow color from hemoglobin breakdown) — highly suggestive, unlikely with traumatic tap\n• Persistent RBCs constant across all 4 tubes (usually in thousands)\n\n**Equivocal:**\n• Partial clearing of RBCs (e.g., 3,000 in tube 1, 400 in tube 4) — may be traumatic tap OR SAH\n• >10,000 RBCs in final tube = 6x more likely SAH\n\n**Negative:**\n• Zero RBCs in final tube = traumatic tap\n• Normal CSF (no RBCs, no xanthochromia) = SAH excluded\n\n**Visual xanthochromia:** Centrifuge last tube, compare against water on white background. Sensitivity 93%, specificity 95%, NPV 99%.' WHERE id = 'sah-lp-results' AND tree_id = 'sah';
UPDATE decision_nodes SET body = E'With partial clearing of RBCs, the distinction between traumatic tap and true SAH can be difficult.\n\n**Obtain CTA** to evaluate for aneurysm. CTA sensitivity for aneurysms is **97-99%** compared to digital subtraction angiography.\n\n**Key findings:**\n• Patients with bloody CSF and negative cerebrovascular imaging are at low risk for subsequent SAH\n• CTA may identify incidental aneurysms (2% of population) — require neurosurgical consultation\n• Aneurysm detection decreases for aneurysms <4 mm\n\n**Consult neurosurgery** for shared decision-making regarding further workup or observation.' WHERE id = 'sah-equivocal' AND tree_id = 'sah';
UPDATE decision_nodes SET body = E'SAH has been excluded by the diagnostic workup.\n\n**Negative CT + negative LP** = SAH confidently ruled out, supported by multiple prospective studies with long-term follow-up (no subsequent SAH over 3+ years).\n\n**Negative CT within 6h** (with appropriate conditions) = SAH ruled out per ACEP 2019 Level B recommendation.\n\n**Consider alternative diagnoses:**\n• Migraine or other primary headache syndrome\n• Cerebral venous sinus thrombosis\n• Idiopathic intracranial hypertension\n• Spontaneous intracranial hypotension\n• Meningitis\n• Reversible cerebral vasoconstriction syndrome (RCVS)\n\n**Discharge safely** with outpatient follow-up and return precautions for worsening symptoms.' WHERE id = 'sah-negative-workup' AND tree_id = 'sah';
UPDATE decision_nodes SET body = E'**Subarachnoid hemorrhage is confirmed.** Immediately:\n\n• **Obtain neurosurgical consultation** — arrange definitive therapy\n• **Order CTA** (if not already done) to identify the aneurysm\n• Begin ED management and monitoring\n\n**CT hemorrhage patterns:**\n• **Basal cisterns** — typical aneurysmal SAH\n• **Cerebral convexities** — traumatic SAH, or convexal SAH (RCVS if <60y, cerebral amyloid angiopathy if >60y)\n• **Perimesencephalic** — blood around midbrain with normal angiogram; 10% of sSAH, excellent prognosis (98% survive without deficits)\n\n**Aneurysm locations** (85% of sSAH):\n• 70% in anterior communicating, posterior communicating, or middle cerebral arteries\n• Remainder in posterior circulation' WHERE id = 'sah-confirmed' AND tree_id = 'sah';
UPDATE decision_nodes SET body = E'**Grade severity** to guide management and predict outcomes.\n\n**Hunt & Hess Scale** — most widely used clinically:\n• Grade 1: Asymptomatic or mild headache\n• Grade 2: Severe headache, stiff neck, no focal deficits\n• Grade 3: Drowsy, mild focal deficit\n• Grade 4: Stupor, moderate-severe hemiparesis\n• Grade 5: Coma, decerebrate posturing\n\nHigher grade = higher mortality. Grades 4-5 historically 70-90% mortality, improved with modern care.\n\n**Modified Fisher Scale** — predicts vasospasm risk from CT:\n• Grade 0-1: Low vasospasm risk\n• Grade 2-3: Moderate-high risk\n• Grade 4: Thick SAH with IVH → highest vasospasm risk' WHERE id = 'sah-grading' AND tree_id = 'sah';
UPDATE decision_nodes SET body = E'**Cerebral vasospasm** is a delayed complication developing **days to 2 weeks** post-SAH, with peak incidence at **7-10 days**.\n\n**Risk prediction (Modified Fisher Scale):**\n• Thick clot and intraventricular hemorrhage → highest risk\n• Thin SAH without IVH → lowest risk\n\n**Vasospasm may be:**\n• **Asymptomatic** — detected only on imaging\n• **Symptomatic** — delayed neurologic deterioration causing significant morbidity\n\n**Key management implications:**\n• All confirmed SAH patients should receive [Nimodipine](#/drug/nimodipine/vasospasm prevention) for vasospasm prevention\n• High-grade Fisher patients need closer monitoring and earlier neurosurgical intervention\n• The VASOGRADE scale (combines WFNS + Modified Fisher) further stratifies risk as green/yellow/red' WHERE id = 'sah-vasospasm-risk' AND tree_id = 'sah';
UPDATE decision_nodes SET body = E'**Prioritize:** Airway management, hemodynamic monitoring, supportive care, and prevention of complications.\n\n**General measures:**\n• **Bed rest** with head of bed at 30° (facilitates venous drainage)\n• **NPO** until surgical/endovascular treatment plan is decided\n• **Continuous cardiac monitoring** — ECG changes in 50-100% of patients\n• **Serial neurologic examinations** — monitor for deterioration\n• **Adequate analgesia** — [Acetaminophen](#/drug/acetaminophen/headache) 1 g PO/IV q6h. Avoid NSAIDs (platelet dysfunction). Use opioids cautiously (interfere with neuro exam).\n• **Antiemetics** as needed for comfort\n\n**Outcomes are best** when care is provided by multidisciplinary teams at specialized high-volume centers (OR 0.77 for in-hospital mortality).' WHERE id = 'sah-initial-mgmt' AND tree_id = 'sah';
UPDATE decision_nodes SET body = E'**Target: SBP <160 mmHg** until aneurysm is secured (AHA/ASA 2012).\n\nHigher pressures may increase rebleeding risk, but aggressive lowering may compromise cerebral perfusion.\n\n**Titratable IV agents:**\n• [Labetalol](#/drug/labetalol/sah blood pressure) — 10-20 mg IV bolus over 1-2 min. Repeat or start infusion 2-8 mg/min. Max 300 mg/24h.\n• [Nicardipine](#/drug/nicardipine/sah blood pressure) — 5 mg/hr IV, titrate by 2.5 mg/hr q5-15 min. Max 15 mg/hr.\n• [Clevidipine](#/drug/clevidipine/sah blood pressure) — 1-2 mg/hr IV, double q90 sec to target. Ultra-short t½ (~1 min).\n\n**Avoid nitroprusside** — increases intracranial pressure and risk of toxicity with prolonged infusion.\n\n**Arterial line** recommended for continuous BP monitoring if extended ED stay anticipated.' WHERE id = 'sah-bp-control' AND tree_id = 'sah';
UPDATE decision_nodes SET body = E'[Nimodipine](#/drug/nimodipine/vasospasm prevention) is the **only proven pharmacologic intervention** to reduce morbidity from vasospasm-related ischemia.\n\n**Dosing:** 60 mg PO every 4 hours × 21 days\n• If unable to swallow: crush and administer via nasogastric tube\n• **No evidence for IV nimodipine** — oral route only\n• Give to hemodynamically stable patients\n• Part of comprehensive stroke center measures\n\n**Evidence:** Cochrane review of 16 trials — risk ratio 0.67 (95% CI 0.55-0.81) for secondary ischemia. Landmark RCT (554 patients) established the standard regimen.\n\n**Not effective for vasospasm prevention:**\n• IV magnesium sulfate\n• Statins (no benefit in recent large RCTs despite early promise)\n\n**Note:** Can be initiated in the ED but does not necessarily need to start before transfer. Discuss with specialist team.' WHERE id = 'sah-vasospasm-prev' AND tree_id = 'sah';
UPDATE decision_nodes SET body = E'Up to **20% of patients** have a seizure during or soon after aSAH. Seizures can cause rebleeding from an unsecured aneurysm.\n\n**Key points:**\n• **No RCTs** on prophylactic antiepileptic drugs (AEDs) in SAH\n• **Phenytoin should be avoided** — associated with worse outcomes, functional decline, and cognitive disability\n• If prophylaxis is used, prefer a **short course (<3 days)** — same benefit as longer courses without cumulative adverse effects\n\n**If prophylaxis is initiated:**\n• [Levetiracetam](#/drug/levetiracetam/sah seizure) 500 mg PO/IV BID — preferred due to better side-effect profile\n• No hepatic metabolism, no drug interactions, no cardiac effects\n\n**Reasonable to defer AED initiation** to the inpatient management service in patients who have not already seized. Use in accordance with local institutional protocols.' WHERE id = 'sah-seizure-mgmt' AND tree_id = 'sah';
UPDATE decision_nodes SET body = E'Rebleeding is **one of the most devastating complications** after aSAH, with the highest mortality of any complication.\n\n• Cumulative incidence: **8-23%** in first 72 hours\n• **50-90% of episodes occur within first 6 hours** after primary bleed\n• Clinical signs: acute/worsening headache, decreased consciousness, loss of brainstem reflexes, posturing, respiratory arrest, seizures\n\n**Risk factors for rebleeding:**\n• High-grade SAH (Hunt & Hess 4-5)\n• Larger aneurysms\n• Prolonged time to surgery\n• Sentinel/warning bleeds\n• Catheter angiography\n\n**Prevention strategies:**\n• **Early definitive repair** — primary strategy (within 72 hours)\n• **Blood pressure control** — SBP <160 mmHg\n• **Antifibrinolytics** — short courses may reduce rebleeding; discuss with neurosurgical team before initiating\n\n**Rapid diagnosis + early repair** remains the optimal approach.' WHERE id = 'sah-rebleed-prev' AND tree_id = 'sah';
UPDATE decision_nodes SET body = E'[SAH ECG Changes](#/info/sah-ecg-changes) — detailed reference.\n\nCardiac abnormalities are **common** following acute sSAH due to catecholamine surge and autonomic stimulation.\n\n**ECG changes (50-100% of patients):**\n• Nonspecific ST-segment and T-wave changes\n• Prolonged QRS, U waves, prolonged QT interval\n• ST elevations mimicking MI — coronary angiography typically normal\n• Serious arrhythmias in <5% (associated with worse outcomes)\n\n**Troponin:** Elevated in 20-40% of acute cases. Indicates cardiopulmonary complications and worse outcomes.\n\n**Neurogenic stunned myocardium (Takotsubo):**\n• Acutely depressed EF (can be as low as 20%)\n• Apical akinesis/ballooning with normal coronary arteries\n• Transient — most recover over several weeks\n• May present with pulmonary edema and ACS symptoms\n\n**Management:** SAH is a **contraindication to thrombolytics and anticoagulants**. Focus on the primary neurologic insult while supporting cardiac dysfunction.' WHERE id = 'sah-cardiac-comp' AND tree_id = 'sah';
UPDATE decision_nodes SET body = E'**Vascular imaging:** Cerebral angiography (DSA) is the gold standard for preoperative planning. CTA has 97-99% sensitivity. Angiography may be negative in 10-20% (perimesencephalic hemorrhage, vasospasm, thrombosed aneurysm).\n\n**Two approaches to aneurysm repair:**\n\n**Endovascular coiling:**\n• ISAT trial (2,143 patients) — improved outcomes vs clipping\n• Slightly higher rebleeding risk\n• Increasing use as first-line approach\n\n**Microvascular clipping:**\n• Higher seizure risk\n• May be necessary for certain aneurysm anatomies\n\n**Timing:** Early treatment within 72 hours is the common approach.\n\nThe choice depends on **aneurysm anatomy, clinician expertise, and patient factors** — best made by a multidisciplinary team.' WHERE id = 'sah-definitive' AND tree_id = 'sah';
UPDATE decision_nodes SET body = E'**Pregnant/Postpartum Women:**\n• Pregnancy and postpartum are hypercoagulable states\n• Also consider: ischemic stroke, cerebral venous thrombosis, RCVS, pre-eclampsia, PRES\n• Management principles are the same\n\n**Anticoagulated Patients:**\n• Reverse therapeutic anticoagulation in the acute setting\n• **Do NOT reverse antiplatelet agents** unless neurosurgical procedure is planned — transfusion without benefit increases mortality\n\n**Perimesencephalic Hemorrhage:**\n• 10% of sSAH; blood confined around midbrain on CT\n• Normal angiogram required (DSA is test of choice)\n• **Excellent prognosis** — 98% survive without deficits\n• Fewer complications than aSAH\n\n**Acute Clinical Deterioration:**\n• Repeat CT immediately to identify cause\n• Possible causes: rebleeding, cerebral infarction, acute hydrocephalus, subdural extension\n• These declines are potentially treatable — early identification is key' WHERE id = 'sah-special-pop' AND tree_id = 'sah';
UPDATE decision_nodes SET body = E'All patients with confirmed SAH require **ICU admission**, preferably a neurointensive care unit, for continuous monitoring until definitive aneurysm repair.\n\n**Better outcomes at high-volume centers** — meta-analysis of 36,000+ patients: reduction in mortality (OR 0.77, 95% CI 0.60-0.97).\n\n**Transfer considerations:**\n• Average 5.2 hours from diagnosis to arrival at neurosurgical center\n• 90% arrive without significant GCS deterioration\n• Air transport is safe and effective\n• Prearranged interfacility agreements facilitate efficient transfer' WHERE id = 'sah-dispo' AND tree_id = 'sah';
UPDATE decision_nodes SET body = E'**Arrange emergent transfer** to a center with:\n• Neurosurgical ICU\n• Both surgical (clipping) and endovascular (coiling) capabilities\n• Multidisciplinary neurovascular team\n\n**Pre-transfer management:**\n• Secure airway if GCS ≤8\n• Continuous cardiac monitoring and BP management (SBP <160)\n• Start [Nimodipine](#/drug/nimodipine/vasospasm prevention) 60 mg PO q4h if hemodynamically stable\n• Communicate Hunt & Hess grade, Fisher grade, and CT findings to receiving team\n• NPO for potential procedural intervention\n• Bring all imaging on disc or ensure electronic transfer\n\n**Transfer is generally safe** — 90% of patients arrive without significant clinical deterioration.' WHERE id = 'sah-transfer' AND tree_id = 'sah';
UPDATE decision_nodes SET body = E'**Admit to neurointensive care unit** for:\n• Continuous hemodynamic and neuro monitoring\n• Definitive aneurysm repair (within 72 hours)\n• Vasospasm surveillance (peak risk days 7-10)\n• Management of secondary complications\n\n**Ongoing ED management until bed available:**\n• BP target SBP <160 with titratable IV agents\n• [Nimodipine](#/drug/nimodipine/vasospasm prevention) 60 mg PO q4h\n• Serial neuro checks q1h\n• NPO status maintained\n• Adequate analgesia and antiemetics\n• Watch for clinical deterioration — repeat CT immediately if decline\n\n**Prognosis:** In-hospital mortality >30% even at high-volume centers. Aggressive approaches may still be warranted in severe cases (Hunt & Hess 4-5) given improved modern outcomes.' WHERE id = 'sah-icu' AND tree_id = 'sah';

-- === shoulder-dystocia (11 nodes) ===
UPDATE decision_nodes SET body = E'[Shoulder Dystocia Steps Summary](#/info/sd-summary) — quick-reference escalation checklist to review before delivery.\n\n**Shoulder dystocia occurs when the baby''s anterior shoulder becomes impacted behind the mother''s pubic symphysis after delivery of the fetal head.** The remainder of the baby does not follow the head as it usually does during vaginal delivery.\n\nKEY FACTS\n• Cannot be predicted with any degree of accuracy [1]\n• Cannot be prevented by any specific strategies or maneuvers [1]\n• Occurs in approximately 1.5% of vaginal deliveries [9]\n\nTWO SIGNS OF SHOULDER DYSTOCIA\n**1. Failure to deliver** — The baby''s body does not emerge with standard traction and maternal pushing after delivery of the fetal head.\n\n**2. The "Turtle Sign"** — The fetal head suddenly retracts back against the mother''s perineum after emerging from the vagina. The baby''s cheeks bulge out, resembling a turtle pulling its head back into its shell. This retraction is caused by the anterior shoulder catching on the posterior surface of the maternal pubic bone.' WHERE id = 'sd-start' AND tree_id = 'shoulder-dystocia';
UPDATE decision_nodes SET body = E'**As soon as shoulder dystocia is recognized, the delivering clinician must act immediately and calmly.**\n\nIMMEDIATE ACTIONS\n• **Announce** "shoulder dystocia" clearly to the room\n• **Call for help** — request a second obstetrician if available\n• **Call pediatrics/NICU** — for neonatal evaluation and potential resuscitation\n• **Call anesthesia** — in case procedural intervention is needed\n• **Request extra personnel** — nurses, additional hands\n• **Designate a timekeeper** — call out elapsed time every 30 seconds\n• **Designate a note taker** — record timing of events and maneuvers attempted\n\nTIME WINDOW\n**You have approximately 4–5 minutes** to deliver a previously well-oxygenated term infant before the risk of hypoxic brain injury becomes significant. [2][3]\n\n• Wood (1973): fetal pH drops ~0.04 units per minute during shoulder dystocia [4]\n• Leung (2011): pH drop ~0.01 units per minute; 4–5 min before ischemic neuropathy risk [2]\n• This time frame depends on the oxygenation and acidosis status of the fetus prior to onset\n\nDO NOT PANIC\nBy restraining panic, keeping a cool head, and employing a previously thought-out set of maneuvers, almost all shoulder dystocias can be resolved with excellent results. [1]' WHERE id = 'sd-initial' AND tree_id = 'shoulder-dystocia';
UPDATE decision_nodes SET body = E'Unless a baby falls out of the mother, some traction is always applied to the infant''s head during delivery. This is standard of care practiced by obstetricians across the United States and described in major obstetrical textbooks (Williams Obstetrics, Stanford Handbook). [1]\n\nAXIAL TRACTION\nPer ACOG (2014): because the infant''s position within the pelvis is at some angle relative to the horizontal plane, **axial traction is generally applied in the direction below the horizontal plane** (downward axial traction). This is distinguished from downward lateral traction or lateral bending. [1]\n\nON "EXCESSIVE FORCE"\nSome investigators (Allen 1991, Gonik) have attempted to quantify "excessive force" using piezoelectric fingertip sensors. There is no universally accepted threshold. [12]\n\nWhen all maneuvers have been exhausted and the only options are maximal extraction effort, hypoxic neurologic damage, or fetal death — **the risk of brachial plexus or other injury must be accepted** to save the baby''s life. [1]' WHERE id = 'sd-traction' AND tree_id = 'shoulder-dystocia';
UPDATE decision_nodes SET body = E'**McRoberts maneuver and suprapubic pressure should be implemented rapidly and simultaneously as the first intervention.** Together they resolve 50–60% of all shoulder dystocias. [5][6]\n\nMcROBERTS MANEUVER\nNamed for William A. McRoberts, Jr. (University of Texas at Houston).\n• **Sharply flex the mother''s legs upon her abdomen** (hyperflexion of hips)\n• This rotates the symphysis pubis cephalad and straightens the sacrum\n• Does NOT change actual pelvic dimensions — changes the angle of inclination between symphysis and sacral promontory [7]\n• Significantly reduces required fetal extractive forces and brachial plexus stretching [8]\n• McRoberts alone resolves 39–42% of shoulder dystocias [5][6]\n\nSUPRAPUBIC PRESSURE\n• An assistant makes a fist and places it just above the maternal pubic bone\n• Push the fetal anterior shoulder to one side (toward the oblique diameter)\n• Shoulder dystocias are frequently caused by shoulders entering the pelvis in direct AP orientation instead of the more physiologic oblique diameter\n• Pushing the shoulder to an oblique position often frees it\n\nCOMPLICATIONS (RARE)\n• Symphyseal separation\n• Transient femoral neuropathy from overly aggressive hyperflexion' WHERE id = 'sd-mcroberts' AND tree_id = 'shoulder-dystocia';
UPDATE decision_nodes SET body = E'McRoberts maneuver + suprapubic pressure have been applied.\n\n**Did the shoulder dystocia resolve?**\n\nExpected success rate: 50–60% with both maneuvers combined. [5][6]' WHERE id = 'sd-first-check' AND tree_id = 'shoulder-dystocia';
UPDATE decision_nodes SET body = E'**Rotational maneuvers use progressive corkscrew rotation of the posterior shoulder to release the impacted anterior shoulder.**\n\nWOOD''S SCREW MANEUVER (1943)\n• Apply pressure on the **anterior surface of the posterior shoulder**\n• Progressively rotate the posterior shoulder 180° in a corkscrew fashion\n• This rotates the baby''s shoulder girdle, freeing the anterior shoulder from behind the symphysis\n\nRUBIN''S MANEUVER (Variation)\n• Apply pressure on the **posterior surface of the posterior shoulder**\n• This has the advantage of **flexing the shoulders across the chest**, decreasing the bisacromial diameter\n• The reduced shoulder width makes passage through the pelvis easier\n\nBOTH DIRECTIONS\nTry clockwise and counter-clockwise rotation — one direction may succeed where the other fails.\n\nGurewitsch & Allen (2005) suggest rotational maneuvers may place **less stretch on the brachial plexus** than McRoberts or suprapubic pressure. [10]' WHERE id = 'sd-rotational' AND tree_id = 'shoulder-dystocia';
UPDATE decision_nodes SET body = E'**If rotational maneuvers fail, attempt delivery of the posterior arm.** Hoffman (2011) found this maneuver had the highest rate of successful delivery compared to all other maneuvers. [9]\n\nTECHNIQUE\n• Insert hand behind the posterior shoulder of the fetus\n• Locate the posterior arm\n• **Sweep the arm across the fetal chest** and deliver it\n• With the posterior arm delivered, rotate the baby to dislodge the anterior shoulder\n• Complete delivery\n\nRISKS\n• Humeral fracture: 12.4% in Gherman''s 1998 series (11 of 89 cases) [11]\n• Almost all humeral fractures heal quickly without permanent damage\n• A small price to pay for delivery in a life-threatening situation\n\nEVIDENCE COMPARISON\n• Leung (2011): Rotational methods vs posterior arm — similar success rates, but rotational methods may have less fetal injury (4.4% vs 21%) [2]\n• Hoffman (2011): Posterior arm had highest success rate with no difference in injury rates [9]\n• Spain (2015): No individual maneuver associated with morbidity after adjusting for duration/severity — "use the maneuver most likely to result in successful delivery" [13]' WHERE id = 'sd-posterior-arm' AND tree_id = 'shoulder-dystocia';
UPDATE decision_nodes SET body = E'Rotational maneuvers and/or posterior arm delivery have been attempted.\n\n**Did the shoulder dystocia resolve?**\n\nMcFarland (1996) found that McRoberts + suprapubic + Wood''s screw + posterior arm delivery were sufficient to resolve **all** remaining cases in his series. [6]' WHERE id = 'sd-second-check' AND tree_id = 'shoulder-dystocia';
UPDATE decision_nodes SET body = E'**If all standard maneuvers have failed, consider these last-resort options. Each carries significant maternal and/or fetal risk.**\n\nZAVANELLI MANEUVER (Cephalic Replacement)\nFirst described by Dr. Zavanelli (1977, Pleasanton, CA).\n• Set up for **emergency cesarean section** first\n• Rotate fetal head to occiput anterior position\n• Flex the head and apply constant firm pressure to push it back into the vagina\n• Administer tocolytics to relax the uterus: [Terbutaline](#/drug/terbutaline/tocolysis) 0.25 mg SQ or [Nitroglycerin](#/drug/nitroglycerin/tocolysis) 0.4 mg SL\n• Perform immediate cesarean section after head replacement\n• O''Leary (1993): 53 of 59 heads replaced; 5-min Apgar <6 in 61%; 2 deaths [14]\n• Sanberg (1999): 77.3% success in 84 cases; complications included fractures, Erb palsy, brain damage [15]\n\nALL-FOURS MANEUVER (Gaskin)\n• Place mother on hands and knees\n• May change the angle of the symphysis relative to the stuck shoulder\n• Bruner (1998): resolved 82% of 82 cases (2–3 min to reposition) [16]\n• Practicality limited: exhausted patient, epidural in place, requires repositioning\n\nDELIBERATE CLAVICLE FRACTURE\n• Theoretically decreases bisacromial diameter\n• In practice the clavicle is difficult to fracture intentionally\n• Risk of great vessel injury, lung damage\n• Most reports involve deceased fetuses\n\nSYMPHYSIOTOMY\n• Transection of symphyseal ligaments gains 2–3 cm pelvic circumference\n• Performed under local analgesia in ~5 minutes\n• Major risk: bladder and urethral injury\n• Reserved for settings remote from cesarean capability [17]\n\nABDOMINAL RESCUE (O''Shaughnessy 1998)\n• Laparotomy + hysterotomy → manually rotate fetal shoulders → complete vaginal delivery\n• Absolute last resort' WHERE id = 'sd-last-resort' AND tree_id = 'shoulder-dystocia';
UPDATE decision_nodes SET body = E'**The most important aspect of resolving shoulder dystocia is having a clear, well-rehearsed sequence of maneuvers in mind before it occurs.** [1]\n\nACOG PROTOCOL (2002, reaffirmed 2015) [1]\n1. McRoberts maneuver + suprapubic pressure\n2. Episiotomy (controversial)\n3. Rotational maneuvers\n4. Delivery of posterior arm\n5. Zavanelli / symphysiotomy if all else fails\n\nGHERMAN USC PROTOCOL (1998) [11]\n1. McRoberts maneuver\n2. Suprapubic pressure\n3. Procto-episiotomy\n4. Wood''s corkscrew maneuver\n5. Posterior arm extraction\n6. Zavanelli / symphysiotomy\n\nKEY EVIDENCE\n• No maneuver has been clearly shown to be superior to any other [13]\n• The number of maneuvers required correlates with injury rate [6]\n• As fetal weight increases, more maneuvers are typically required [6]\n• CNGOF (Sentilhes 2016): episiotomy is NOT routinely required for shoulder dystocia maneuvers [18]\n\nTHREE KEYS TO SUCCESS\n**1. Recognize** the shoulder dystocia\n**2. Know** the maneuvers\n**3. Implement** them in a calm, controlled, organized fashion [1]' WHERE id = 'sd-protocols' AND tree_id = 'shoulder-dystocia';
UPDATE decision_nodes SET body = E'POST-DELIVERY MANAGEMENT\n• **Immediate neonatal assessment** — Pediatrics/NICU should already be present\n• **Apgar scores** at 1 and 5 minutes\n• **Evaluate for injury:**\n  - Brachial plexus palsy (Erb''s) — asymmetric arm movement, "waiter''s tip" posture\n  - Clavicle fracture — crepitus, asymmetric Moro reflex\n  - Humeral fracture — if posterior arm delivery was performed\n• **Maternal assessment** — check for vaginal/cervical lacerations, postpartum hemorrhage\n• **Document thoroughly:**\n  - Time of head delivery and time of body delivery (head-to-body interval)\n  - All maneuvers attempted and in what order\n  - Personnel present and their roles\n  - Neonatal condition at delivery\n  - Estimated blood loss\n\nKEY TAKEAWAY\nSometimes, even in the most expert hands and with relatively mild shoulder dystocias, fetal or maternal injury will occur. Injury does not necessarily indicate substandard care. [1]' WHERE id = 'sd-resolved' AND tree_id = 'shoulder-dystocia';

-- === sodium (28 nodes) ===
UPDATE decision_nodes SET body = E'[Sodium Disorders Steps Summary](#/info/na-summary) — stepwise management of hyponatremia and hypernatremia.\n\nWhat is the serum sodium level?\n\nConfirm result with clinical context. Consider repeating if unexpected or if sample was drawn from an IV-containing arm.' WHERE id = 'na-start' AND tree_id = 'sodium';
UPDATE decision_nodes SET body = E'Assess for neurological symptoms of hyponatremia. Symptom severity — not the sodium number alone — determines urgency of treatment.\n\n**Severe symptoms:**\n• Seizures\n• Obtundation or coma\n• Respiratory arrest\n\n**Moderate symptoms:**\n• Nausea and vomiting\n• Confusion or disorientation\n• Severe headache\n\n**Mild or asymptomatic:**\n• Subtle cognitive changes, gait instability, or fatigue\n• Incidental finding on labs' WHERE id = 'na-hypo-symptoms' AND tree_id = 'sodium';
UPDATE decision_nodes SET body = E'**Order the diagnostic triad simultaneously:**\n\n• **Serum osmolality** — distinguishes true hypotonic hyponatremia from non-hypotonic causes\n• **Urine osmolality** — determines if ADH is active (>100 mOsm/kg) or suppressed (<100)\n• **Urine sodium** — distinguishes renal from extrarenal sodium losses\n\n[Hyponatremia Lab Interpretation](#/info/na-lab-interpretation) — stepwise algorithm for interpreting results\n\n**Additional labs:** BMP, Mg, Phos, TSH, cortisol (AM), glucose, lipid panel, serum protein\n\n**Give empirically:** [Thiamine](#/drug/thiamine/hyponatremia) **100 mg IV** — all patients undergoing sodium correction are at risk for osmotic demyelination syndrome (ODS), and thiamine deficiency dramatically increases this risk. [ODS Risk Factors](#/info/na-ods-risk)\n\n**Check potassium** — concurrent hypokalemia is common and must be corrected simultaneously. [Potassium Disorders](#/tree/potassium)\n\nResults typically return within 1-2 hours. Proceed to etiology once available.' WHERE id = 'na-hypo-initial' AND tree_id = 'sodium';
UPDATE decision_nodes SET body = E'The serum osmolality determines whether this is **true hypotonic hyponatremia** or a non-hypotonic cause.\n\n**Hypotonic (<275 mOsm/kg):** True hyponatremia — excess water relative to sodium. Proceed to urine osmolality.\n\n**Non-hypotonic (≥275 mOsm/kg):** Pseudohyponatremia or translocational hyponatremia. The sodium is artifactually low or diluted by effective osmoles.\n\n[Non-Hypotonic Hyponatremia](#/info/na-non-hypotonic-info) — detailed explanation of translocational and pseudohyponatremia causes' WHERE id = 'na-hypo-etiology' AND tree_id = 'sodium';
UPDATE decision_nodes SET body = E'**This is NOT true hyponatremia.** The measured sodium is low but total body water and sodium balance may be normal.\n\n**Translocational (elevated osm):**\n• Hyperglycemia — correct Na+ by adding **1.6 mEq/L for every 100 mg/dL glucose above 100** (use 2.4 mEq/L if glucose >400)\n• Mannitol, IV contrast, glycine (TURP syndrome)\n• Treatment: correct the underlying osmole\n\n**Pseudohyponatremia (normal osm):**\n• Severe hyperlipidemia (triglycerides >1500)\n• Paraproteinemia (myeloma, Waldenström)\n• Confirm with **point-of-care sodium** (direct ISE, not affected by protein/lipid interference)\n• Treatment: treat the underlying condition\n\n[Non-Hypotonic Hyponatremia](#/info/na-non-hypotonic-info)' WHERE id = 'na-non-hypotonic' AND tree_id = 'sodium';
UPDATE decision_nodes SET body = E'Urine osmolality determines whether ADH (vasopressin) is active.\n\n**Urine Osm < 100 mOsm/kg** — ADH is appropriately suppressed. The kidney is maximally diluting urine. The problem is **excessive water intake or inadequate solute intake** overwhelming the kidney’s diluting capacity.\n\n**Urine Osm > 100 mOsm/kg** — ADH is active (either appropriately or inappropriately). The kidney is concentrating urine when it should be diluting. Proceed to urine sodium to differentiate causes.' WHERE id = 'na-hypo-urine-osm' AND tree_id = 'sodium';
UPDATE decision_nodes SET body = E'**ADH is suppressed — the kidney is doing its job.** The problem is excessive free water intake or severely low solute intake overwhelming diluting capacity (~20 L/day max).\n\n**Causes:**\n• **Primary polydipsia** — psychiatric patients, often on medications that cause dry mouth\n• **Beer potomania** — low-solute diet (beer has minimal protein/electrolytes, so minimal obligate solute excretion)\n• **Tea-and-toast diet** — elderly with inadequate protein/salt intake\n• **Marathon/exercise-associated hyponatremia** — excess hypotonic fluid intake during exercise\n\n**HIGH overcorrection risk.** Once water intake is restricted, the kidney rapidly excretes free water (no ADH to stop it). Na+ can rise dangerously fast.\n\n**Management:**\n• Restrict free water intake\n• For beer potomania/low solute: [Oral Urea](#/drug/oral-urea/siad) 15-30g PO daily to increase obligate water excretion\n• **Proactive DDAVP clamp** strongly recommended: [Desmopressin (DDAVP)](#/drug/desmopressin/ddavp clamp) 2 mcg IV q6-8h to prevent uncontrolled water excretion\n• [DDAVP Clamp-Bolus Protocol](#/info/na-ddavp-clamp) — full protocol\n• Check Na+ every 2 hours — do NOT allow >8-10 mEq/L rise in 24 hours\n• [Overcorrection Rescue Protocol](#/info/na-overcorrection) if overcorrecting' WHERE id = 'na-hypo-water-excess' AND tree_id = 'sodium';
UPDATE decision_nodes SET body = E'Urine sodium differentiates **renal sodium losses** from **extrarenal losses** in the setting of ADH-mediated hyponatremia.\n\n**Urine Na < 30 mEq/L** — The kidney is retaining sodium. Volume depletion (hypovolemic) or edematous states (hypervolemic) with reduced effective arterial blood volume.\n\n**Urine Na > 30 mEq/L** — The kidney is wasting sodium. SIAD, diuretics, adrenal insufficiency, cerebral salt wasting, or renal failure.\n\n**Caveat:** Diuretics can raise urine Na even in hypovolemic patients. Check urine Na **before** or >48 hours after last diuretic dose if possible.' WHERE id = 'na-hypo-urine-na' AND tree_id = 'sodium';
UPDATE decision_nodes SET body = E'The kidney is retaining sodium, indicating **reduced effective circulating volume.** The key distinction is between true hypovolemia and hypervolemic states with reduced effective arterial blood volume.\n\n**Hypovolemic (dry):**\n• GI losses (vomiting, diarrhea)\n• Third-spacing (pancreatitis, burns)\n• Diaphoresis, insensible losses\n• Clinical: tachycardia, orthostatic hypotension, poor skin turgor, dry mucous membranes\n\n**Hypervolemic (edematous):**\n• Heart failure\n• Cirrhosis\n• Nephrotic syndrome\n• Clinical: peripheral edema, ascites, JVD, pulmonary rales' WHERE id = 'na-hypo-low-una' AND tree_id = 'sodium';
UPDATE decision_nodes SET body = E'**Immediate treatment for severe symptomatic hyponatremia** (seizures, coma, respiratory distress).\n\n[3% Hypertonic Saline](#/drug/hypertonic-saline/severe symptomatic) **100-150 mL IV bolus over 10-20 minutes.** Repeat up to 2 additional times (total 3 boluses) if severe symptoms persist.\n\n**Target:** Raise Na+ by **4-6 mEq/L** in the first 1-2 hours — this is sufficient to reverse cerebral edema and stop seizures. Each 100 mL bolus of 3% NaCl raises Na+ approximately **2 mEq/L** in a 70 kg adult.\n\n**Peripheral access is acceptable for boluses** — do NOT delay treatment for central line placement. Central access is preferred only for continuous infusions.\n\n**SALSA Trial (2021):** Bolus 3% NaCl was noninferior to continuous infusion for symptomatic hyponatremia, with lower overcorrection rates.\n\n**Give empirically:** [Thiamine](#/drug/thiamine/hyponatremia) **100 mg IV** now if not already given — thiamine deficiency increases ODS risk.\n\n**After stabilization:** Recheck Na+ at 1 hour. If symptoms improved, proceed to correction limits.' WHERE id = 'na-hypo-emergency' AND tree_id = 'sodium';
UPDATE decision_nodes SET body = E'**Overcorrection causes osmotic demyelination syndrome (ODS)** — a devastating and often irreversible pontine and extrapontine injury.\n\n**Maximum correction rates:**\n• **Standard risk:** ≤10 mEq/L in first 24 hours, ≤18 mEq/L in 48 hours\n• **High risk for ODS:** ≤8 mEq/L in first 24 hours\n\n[ODS Risk Factors](#/info/na-ods-risk) — high-risk populations include: Na+ ≤105, alcohol use disorder, liver disease, malnutrition, hypokalemia, thiamine deficiency\n\n**Key principle:** The goal is to correct enough to stop symptoms (4-6 mEq/L rise), then **slow down.** The acute danger is cerebral edema; the correction danger is ODS.\n\n**If overcorrecting** (Na+ rising faster than target):\n• [Overcorrection Rescue Protocol](#/info/na-overcorrection) — [Desmopressin (DDAVP)](#/drug/desmopressin/overcorrection rescue) 2 mcg IV stat + D5W 3 mL/kg/hr to lower Na+ back to safe trajectory\n\n**Monitor:** Check Na+ every 2 hours during active correction. Use a tracking sheet to plot the correction trajectory.\n\n**Concurrent potassium correction counts toward sodium correction** — if you give 40 mEq KCl, expect Na+ to rise ~1 mEq/L as K+ enters cells and Na+ exits.' WHERE id = 'na-hypo-correction-limits' AND tree_id = 'sodium';
UPDATE decision_nodes SET body = E'The **DDAVP clamp** (also called "proactive DDAVP" or "DDAVP clamp-and-bolus") is the safest approach to controlled sodium correction.\n\n**How it works:** DDAVP locks the kidneys in a maximally concentrating state (prevents free water excretion). This gives the clinician **complete control** over the correction rate — Na+ rises only from administered hypertonic saline boluses, not from unpredictable renal water excretion.\n\n[DDAVP Clamp-Bolus Protocol](#/info/na-ddavp-clamp) — full initiation and monitoring protocol\n\n**Strongest indications for proactive clamp:**\n• Na+ ≤120 mEq/L\n• High ODS risk (alcoholism, liver disease, malnutrition)\n• Reversible cause likely to self-correct (hypovolemia, diuretics, beer potomania)\n• Any situation where overcorrection would be catastrophic' WHERE id = 'na-hypo-ddavp-decision' AND tree_id = 'sodium';
UPDATE decision_nodes SET body = E'**Step 1 — Lock the kidneys:**\n[Desmopressin (DDAVP)](#/drug/desmopressin/ddavp clamp) **2 mcg IV q6-8h** (schedule doses around the clock). This prevents all renal free water excretion.\n\n**Step 2 — Controlled bolus correction:**\n[3% Hypertonic Saline](#/drug/hypertonic-saline/ddavp clamp bolus) **100 mL IV bolus** — each bolus raises Na+ approximately **2 mEq/L** in a 70 kg adult. Give boluses every 4-6 hours as needed to achieve target correction rate.\n\n**Step 3 — Monitor:**\n• Check Na+ **every 2 hours** during active clamp\n• Track cumulative 24-hour correction on a flow sheet\n• Target: 4-6 mEq/L rise in first 24 hours for high-risk patients, up to 10 mEq/L for standard risk\n\n**Step 4 — Discontinue clamp:**\n• Once Na+ >125 mEq/L and underlying cause addressed\n• Taper: extend DDAVP interval to q12h for 24 hours, then stop\n• Continue monitoring Na+ q4-6h for 24 hours after stopping DDAVP\n\n**If Na+ rises too fast despite clamp:** Confirm DDAVP dosing is adequate (urine Osm should be >500). Give **D5W 3 mL/kg/hr** to actively lower Na+ back to safe trajectory.\n\n[DDAVP Clamp-Bolus Protocol](#/info/na-ddavp-clamp) — expanded protocol with discontinuation guidance' WHERE id = 'na-hypo-ddavp-protocol' AND tree_id = 'sodium';
UPDATE decision_nodes SET body = E'Urine Na >30 mEq/L with ADH-mediated hyponatremia. The kidney is actively wasting sodium. The three main causes are:\n\n**SIAD (Syndrome of Inappropriate Antidiuresis):**\n• Most common cause of euvolemic hyponatremia\n• Euvolemic on exam, urine Osm >100, urine Na >30, low uric acid\n• [SIAD Causes & Diagnosis](#/info/na-siad-causes) — medications, malignancy, neurologic, pulmonary\n\n**Diuretic-induced:**\n• Thiazides >> loops (thiazides impair dilution; loops impair concentration)\n• May have UNa >30 despite being volume depleted\n• Check urine Na 48 hours after holding diuretic — if still >30, not solely diuretic\n\n**Adrenal insufficiency:**\n• Primary (Addison) or secondary (pituitary)\n• Cortisol is a tonic inhibitor of ADH — deficiency → unopposed ADH secretion\n• Check AM cortisol and ACTH' WHERE id = 'na-hypo-high-una' AND tree_id = 'sodium';
UPDATE decision_nodes SET body = E'**First-line: Fluid restriction**\n• Restrict to 800-1000 mL/day total fluid intake\n• Effective only if urine Osm < 500 AND urine Osm/serum Osm ratio < 1.0\n• If ratio >1.0, every mL of urine excretes more water than intake replaces — fluid restriction will fail\n\n**Second-line: Oral urea**\n[Oral Urea](#/drug/oral-urea/siad) **15-30g PO daily** (titrate up to 60g/day). Creates obligate osmotic diuresis. Bitter taste — mix with orange juice or cola. Ure-Na brand designed for palatability.\n\n**Third-line: Salt tabs + loop diuretic**\n[Sodium Chloride Tablets](#/drug/nacl-tablets/siad) **1-3g PO TID** + [Furosemide](#/drug/furosemide/siad) **20-40 mg PO daily**. The loop diuretic impairs urinary concentration (breaks the medullary gradient), and salt tabs replace renal sodium losses.\n\n**NOT recommended: Vaptans** (tolvaptan, conivaptan). Unpredictable overcorrection risk, hepatotoxicity, expensive, no mortality benefit. European guidelines and IBCC explicitly recommend against.\n\n**Treat the underlying cause:** Discontinue offending medication (SSRIs, carbamazepine, NSAIDs, opioids). Evaluate for occult malignancy if no obvious cause identified. [SIAD Causes & Diagnosis](#/info/na-siad-causes)' WHERE id = 'na-siad-treatment' AND tree_id = 'sodium';
UPDATE decision_nodes SET body = E'**Thiazide diuretics are the most common medication cause of hyponatremia.** Typically occurs within 2 weeks of initiation, especially in elderly women with low body mass.\n\n**Mechanism:** Thiazides impair the kidney’s diluting segment (distal convoluted tubule) while preserving the concentrating segment. Loops do the opposite — they impair concentration, which is why loop diuretics rarely cause severe hyponatremia and are even used to treat SIAD.\n\n**Management:**\n• **Hold the thiazide immediately** — never rechallenge\n• Replace volume deficit with normal saline if hypovolemic\n• Check and correct potassium and magnesium\n\n**HIGH overcorrection risk.** Once the thiazide is discontinued and volume is restored, the kidney rapidly excretes free water (ADH suppresses, diluting segment recovers). Na+ can rise 15-20 mEq/L in 24 hours without intervention.\n\n• **If Na+ <120:** Proactive [Desmopressin (DDAVP)](#/drug/desmopressin/ddavp clamp) clamp strongly recommended\n• Check Na+ every 2 hours for at least 24 hours after holding the diuretic\n• [Overcorrection Rescue Protocol](#/info/na-overcorrection) if Na+ rising too fast' WHERE id = 'na-hypo-diuretic' AND tree_id = 'sodium';
UPDATE decision_nodes SET body = E'**Cortisol deficiency causes hyponatremia through two mechanisms:**\n• Cortisol tonically inhibits ADH — deficiency leads to unopposed ADH secretion\n• Reduced cardiac output and GFR → nonosmotic ADH release\n\n**Diagnosis:**\n• AM cortisol <3 mcg/dL → virtually diagnostic\n• AM cortisol 3-18 mcg/dL → cosyntropin stimulation test\n• AM cortisol >18 mcg/dL → AI unlikely\n• Check ACTH to distinguish primary (high ACTH) from secondary (low ACTH)\n\n**If hemodynamically unstable:**\n• **Stress-dose hydrocortisone 100 mg IV** immediately — do NOT wait for cortisol results\n• Then 50 mg IV q8h until stable\n• Normal saline for volume resuscitation\n\n**If stable:**\n• Draw cortisol/ACTH, then start hydrocortisone 20 mg AM / 10 mg PM\n• Na+ corrects as cortisol is replaced\n• Monitor for overcorrection — ADH suppresses once cortisol is adequate' WHERE id = 'na-hypo-adrenal' AND tree_id = 'sodium';
UPDATE decision_nodes SET body = E'**Volume depletion triggers nonosmotic ADH release** — the body prioritizes volume over tonicity. ADH retains free water, diluting sodium.\n\n**Common causes:**\n• GI losses (vomiting, diarrhea, NG suction)\n• Third-spacing (pancreatitis, burns, bowel obstruction)\n• Diaphoresis, insensible losses in febrile patients\n• Cerebral salt wasting (post-neurosurgery)\n\n**Management:**\n• **Normal saline (0.9% NaCl)** for volume resuscitation — NS is hypertonic relative to the patient’s serum in severe hyponatremia\n• Replace ongoing losses (NG output, drain output)\n• Correct potassium and magnesium\n\n**HIGH overcorrection risk.** Once euvolemia is restored, ADH suppresses abruptly. The kidney suddenly excretes a large volume of dilute urine ("aquaresis"), and Na+ can rise 15-20 mEq/L in hours.\n\n• **If Na+ <120:** Proactive [Desmopressin (DDAVP)](#/drug/desmopressin/ddavp clamp) clamp before volume resuscitation\n• Watch for sudden increase in urine output — this signals ADH suppression and imminent rapid Na+ rise\n• Check Na+ every 2 hours during resuscitation\n• [Overcorrection Rescue Protocol](#/info/na-overcorrection) at bedside' WHERE id = 'na-hypo-hypovolemic' AND tree_id = 'sodium';
UPDATE decision_nodes SET body = E'**Edematous states with reduced effective arterial blood volume** trigger ADH release despite total body water excess.\n\n**Causes:**\n• **Heart failure** — poor forward flow → baroreceptor-mediated ADH release\n• **Cirrhosis** — splanchnic vasodilation → reduced effective arterial volume\n• **Nephrotic syndrome** — hypoalbuminemia → reduced oncotic pressure\n\n**Management:**\n• **Fluid restriction** 1-1.5 L/day (first-line for all three)\n• [Furosemide](#/drug/furosemide/hypernatremia) **20-40 mg IV** for diuresis — loop diuretics produce dilute urine and help correct Na+\n• Treat the underlying condition (guideline-directed HF therapy, TIPS for cirrhosis)\n• **Sodium restriction** <2g/day\n\n**Avoid:**\n• Normal saline — worsens total body sodium and edema\n• Hypertonic saline — only if severe symptoms (seizures/coma), and only as temporizing bolus\n• Vaptans — unpredictable overcorrection, hepatotoxicity, no mortality benefit\n\n**Prognosis:** Hyponatremia in HF and cirrhosis is an independent marker of disease severity and mortality.' WHERE id = 'na-hypo-hypervolemic' AND tree_id = 'sodium';
UPDATE decision_nodes SET body = E'**Ongoing monitoring during hyponatremia treatment.**\n\n**Active correction (Na+ <125 or symptomatic):**\n• Check Na+ every **2 hours**\n• Plot correction trajectory on flow sheet\n• Track all IV fluids, PO intake, and urine output\n• I&O catheter for accurate urine measurement\n\n**Stable/improving (Na+ 125-130):**\n• Check Na+ every **4-6 hours**\n• Continue fluid restriction or treatment of underlying cause\n\n**ICU admission criteria:**\n• Na+ <120 mEq/L\n• Active DDAVP clamp in progress\n• Severe neurological symptoms\n• Active overcorrection requiring D5W infusion\n• Receiving hypertonic saline\n\n**Step-down from ICU:**\n• Na+ >125 and stable uptrend\n• DDAVP clamp successfully discontinued\n• Underlying cause addressed\n\n**Discharge criteria:**\n• Na+ >130 mEq/L and stable\n• Underlying cause treated or managed\n• Outpatient follow-up with repeat Na+ in 1-2 weeks' WHERE id = 'na-hypo-monitoring' AND tree_id = 'sodium';
UPDATE decision_nodes SET body = E'Hypernatremia (Na+ >145 mEq/L) is **almost always a free water deficit** — either inadequate intake or excessive loss. Rarely, it results from sodium gain.\n\n**Assess volume status and urine output:**\n\n**Volume depleted (most common):**\n• Inadequate water intake (altered mental status, intubated, elderly, infant)\n• GI losses + inadequate replacement\n• Insensible losses (fever, burns, mechanical ventilation)\n• Diuretic use without free water replacement\n\n**Polyuria (>3 L/day):**\n• Diabetes insipidus (central or nephrogenic)\n• Osmotic diuresis (hyperglycemia, mannitol, urea)\n• Post-obstructive diuresis\n\n**Volume overloaded (iatrogenic):**\n• Excessive hypertonic saline, NaHCO₃, or high-Na medications\n• Excess NS resuscitation with inadequate free water\n\n[Hypernatremia Causes](#/info/na-hyper-causes) — 7-category breakdown of all etiologies' WHERE id = 'na-hyper-assess' AND tree_id = 'sodium';
UPDATE decision_nodes SET body = E'**Polyuria with dilute urine (Urine Osm <300 mOsm/kg) suggests diabetes insipidus.**\n\n**Central DI** — deficient ADH production:\n• Post-neurosurgery (pituitary), head trauma, brain death\n• Tumors (craniopharyngioma, metastases)\n• Autoimmune hypophysitis\n• **Diagnostic clue:** Urine Osm rises >50% after DDAVP 2 mcg IV trial\n\n**Nephrogenic DI** — kidney resistant to ADH:\n• Lithium (most common medication cause — up to 40% of long-term users)\n• Hypercalcemia, hypokalemia\n• Sickle cell disease, amyloidosis\n• Pregnancy (placental vasopressinase)\n• **Diagnostic clue:** Urine Osm does NOT rise after DDAVP trial\n\n**DDAVP trial interpretation:**\n• Give DDAVP 2 mcg IV, measure urine Osm at 0 and 2 hours\n• >50% rise → central DI (kidney responds to exogenous ADH)\n• <50% rise → nephrogenic DI (kidney does not respond)' WHERE id = 'na-hyper-di' AND tree_id = 'sodium';
UPDATE decision_nodes SET body = E'**Replace ADH with DDAVP + replace free water deficit.**\n\n**DDAVP replacement:**\n[Desmopressin (DDAVP)](#/drug/desmopressin/central diabetes insipidus) **2 mcg IV q8-12h** (acute inpatient) OR **10 mcg intranasal BID** (stable/outpatient)\n\n**Free water replacement:** Calculate deficit and replace (see next step).\n\n**Post-neurosurgical DI:**\n• Often a **triphasic response:**\n  1. DI phase (days 1-5): polyuria, rising Na+\n  2. SIAD phase (days 5-10): oliguria, falling Na+ (uncontrolled ADH release from dying neurons)\n  3. Permanent DI (if >80% of neurons destroyed)\n• **Critical:** Monitor Na+ closely during transitions — do NOT continue DDAVP blindly into the SIAD phase (will cause dangerous hyponatremia)\n• Check urine output and Na+ q4-6h in the first 2 weeks post-surgery\n\n**Brain death evaluation:** Central DI with polyuria is a supportive finding but not diagnostic alone. If urine output >300 mL/hr with urine Osm <200, strongly suggestive.' WHERE id = 'na-hyper-central-di' AND tree_id = 'sodium';
UPDATE decision_nodes SET body = E'**The kidney does not respond to ADH — DDAVP is ineffective.** Treatment relies on reducing solute load and using pharmacologic tricks.\n\n**Step 1 — Remove the offending agent:**\n• **Lithium** — discuss with psychiatry before discontinuing. Amiloride 5-10 mg BID blocks lithium entry into collecting duct cells (partially protective even if lithium continued)\n• **Hypercalcemia** — treat aggressively (IV saline, calcitonin, bisphosphonates)\n• **Hypokalemia** — correct to >3.5 mEq/L\n\n**Step 2 — Thiazide paradox:**\n• Thiazide diuretic (HCTZ 25 mg daily) + amiloride 5 mg BID\n• **Paradoxical antidiuresis** — thiazides cause mild volume depletion → increased proximal tubular reabsorption → less water delivered to diluting segment → less urine output\n• Combined with low-sodium diet (<2g/day) to enhance the effect\n\n**Step 3 — Large free water volumes:**\n• Patients may require **10-20 liters/day** of free water intake to keep up with urinary losses\n• If unable to drink enough: D5W IV to match urine output + ongoing losses\n• Enteral free water via NG/OG tube if intubated\n\n**NSAIDs** (indomethacin 50 mg TID) can reduce urine output by 25-50% but GI/renal toxicity limits long-term use.' WHERE id = 'na-hyper-nephrogenic-di' AND tree_id = 'sodium';
UPDATE decision_nodes SET body = E'**Calculate the free water deficit (FWD) to guide replacement volume.**\n\n**Formula:** FWD (liters) = TBW × [(Na/140) - 1]\n• TBW = weight (kg) × 0.6 (men) or × 0.5 (women/elderly)\n• Example: 70 kg male, Na+ 160 → TBW = 42L, FWD = 42 × (160/140 - 1) = **6.0 liters**\n\n**The FWD formula underestimates true deficit** — it does not account for ongoing losses (insensible, urinary, GI). Add ~1-1.5 L/day for ongoing losses.\n\n**Fluid choice (order of preference):**\n1. **Enteral free water** (PO or NG/OG tube) — safest, most physiologic\n2. **D5W IV** — if NPO or insufficient enteral intake (D5W = free water once glucose is metabolized)\n3. **0.45% NaCl** — only half is free water; use if concurrent volume depletion\n\n**Correction rate:**\n• **Acute hypernatremia (<48 hours):** Can correct 1 mEq/L/hr safely\n• **Chronic hypernatremia (>48 hours or unknown):** Maximum **10-12 mEq/L per 24 hours** — rapid correction risks cerebral edema\n• Most hypernatremia in hospitalized patients is chronic → correct slowly\n\n**Replace the deficit over 48-72 hours** — not in a single bolus. Divide calculated free water evenly.\n\n**Address the underlying cause simultaneously** — free water alone does not fix DI, ongoing GI losses, or medication causes.' WHERE id = 'na-hyper-fwd' AND tree_id = 'sodium';
UPDATE decision_nodes SET body = E'**Iatrogenic hypernatremia from excessive sodium administration** is increasingly common in ICU patients receiving NS boluses, NaHCO₃, and high-sodium medications.\n\n**Causes:**\n• Large-volume NS resuscitation without free water\n• NaHCO₃ infusions (isotonic bicarb = 150 mEq Na/L)\n• High-sodium medications (piperacillin-tazobactam = 4.7 mEq Na per gram)\n• Hypertonic saline overcorrection during hyponatremia treatment\n\n**Management — natriuretic diuresis + free water:**\n• [Furosemide](#/drug/furosemide/hypernatremia) **20-40 mg IV** — produces hypotonic urine (Na+ ~75 mEq/L), removing more sodium than water\n• Replace urine volume with **D5W or enteral free water** to lower Na+ while diuresing excess sodium\n• Thiazide + amiloride if loop diuretic insufficient\n\n**Target:** Negative sodium balance (remove more Na+ than you give) while maintaining neutral or positive water balance.\n\n**Switch IV fluids** from NS to D5W or 0.45% NaCl for maintenance. Review all sodium-containing medications and minimize where possible.\n\n**Monitor:** Na+ every 4-6 hours. Strict I&O. Daily weights.' WHERE id = 'na-hyper-overload' AND tree_id = 'sodium';
UPDATE decision_nodes SET body = E'**Ongoing monitoring during hypernatremia treatment.**\n\n**Active correction:**\n• Check Na+ every **4-6 hours**\n• Strict intake and output (I&O catheter recommended)\n• Daily weights\n• Monitor for signs of cerebral edema during correction (headache, confusion, seizures)\n\n**Correction targets:**\n• Chronic: maximum 10-12 mEq/L decrease in 24 hours\n• Acute (<48h): can correct 1 mEq/L/hr\n• Target Na+ 140-145 mEq/L\n\n**Overcorrection is RARE in hypernatremia** (unlike hyponatremia). Cerebral edema from overcorrection is theoretical but reported only in aggressive pediatric correction.\n\n**ICU admission criteria:**\n• Na+ >160 mEq/L\n• Hemodynamic instability\n• Active DI with massive polyuria\n• Unable to maintain adequate free water intake\n\n**Hospital-acquired hypernatremia** (Na+ develops during admission) carries mortality up to 40-60% in ICU patients — reflects severity of underlying illness, not sodium toxicity per se.\n\n[Hypernatremia in the Elderly](#/node/na-hyper-elderly) — special considerations for geriatric patients' WHERE id = 'na-hyper-monitoring' AND tree_id = 'sodium';
UPDATE decision_nodes SET body = E'**Hypernatremia in elderly patients is almost always chronic and related to impaired thirst or access to water.**\n\n**Why the elderly are vulnerable:**\n• **Diminished thirst** — aging blunts the thirst response to hypertonicity\n• **Reduced total body water** — TBW factor ~0.45-0.50 (vs 0.60 in younger adults)\n• **Impaired renal concentrating ability** — maximum urine Osm declines with age\n• **Functional limitations** — dementia, immobility, dependence on caregivers for water access\n• **Medications** — diuretics, lithium, laxatives\n\n**Key management differences:**\n• **Usually chronic** → correct slowly (max 10-12 mEq/L/day)\n• **Oral water first** if patient can swallow safely — 200-300 mL PO every 2-4 hours\n• If unable to drink: **D5W IV** or enteral free water via NG tube\n• **ICU is usually NOT needed** unless Na+ >160 or hemodynamically unstable\n• Avoid overdiuresis — elderly have limited renal reserve\n\n**Discharge planning is critical:**\n• Ensure caregivers provide regular water access\n• Set water intake schedule (not reliant on patient requesting water)\n• Review and minimize diuretics\n• Follow-up Na+ in 1 week' WHERE id = 'na-hyper-elderly' AND tree_id = 'sodium';

-- === splinting (16 nodes) ===
UPDATE decision_nodes SET body = E'[General Splinting Principles](#/info/splint-principles) — materials, padding, technique, neurovascular checks.\n[Quick Reference Table](#/info/splint-summary) — all fractures → splint types at a glance.\n\n**Select a body region:**' WHERE id = 'splint-start' AND tree_id = 'splinting';
UPDATE decision_nodes SET body = E'**FRACTURE → SPLINT GUIDE**\n\n• **Proximal humerus** → Sling / cuff and collar [9][10]\n• **Humeral shaft** → Coaptation splint (→ functional brace at 1–2 weeks) [7][8]\n• **Supracondylar (adult)** → Long arm posterior splint or double sugar tong [3][6]' WHERE id = 'splint-humerus' AND tree_id = 'splinting';
UPDATE decision_nodes SET body = E'**INDICATIONS**\n• Proximal humerus fracture (non-displaced or minimally displaced)\n• Greater tuberosity fracture\n• Shoulder dislocation post-reduction\n\n**MATERIALS**\n• Standard triangular arm sling OR cuff and collar\n• Swathe (elastic bandage around torso) for added stability if needed\n\n**APPLICATION**\n1. Arm rests in sling with elbow at 90° flexion\n2. Forearm supported across the body\n3. Wrist should be neutral (not dangling)\n4. If swathe used: wrap elastic bandage around upper arm and torso to prevent arm abduction\n\n**POSITION**\n• Elbow at 90°, arm adducted against the body\n• Allow gentle pendulum exercises (Codman exercises) after 1–2 days to prevent shoulder stiffness\n\n**PEARLS**\n• PROFHER trial (2015): sling alone is equivalent to surgery for most displaced proximal humerus fractures in adults [9]\n• Ensure padding under axilla if swathe is used — prevents skin breakdown\n• Avoid prolonged full immobilization (>2 weeks) — frozen shoulder risk\n• No imaging needed for isolated greater tuberosity fractures with <5mm displacement' WHERE id = 'splint-sling' AND tree_id = 'splinting';
UPDATE decision_nodes SET body = E'**INDICATIONS**\n• Humeral shaft fracture (midshaft diaphyseal)\n• Initial stabilization before functional bracing\n\n**MATERIALS**\n• 6-inch plaster or fiberglass (10–12 layers)\n• Stockinette, 3–4 layers Webril, elastic bandage\n• Arm sling\n\n**APPLICATION**\n1. Measure from axilla, down medial arm, around the elbow, back up lateral arm to the deltoid insertion (U-shape)\n2. Apply stockinette and Webril padding — **extra padding in axilla and over olecranon**\n3. Dip plaster in lukewarm water, squeeze excess, apply in U-shape\n4. Mold plaster snugly around medial arm, elbow, and lateral arm\n5. Secure with elastic bandage — wrap distally to proximally\n6. Place arm in sling with elbow at 90°\n\n**POSITION**\n• Elbow at 90° flexion\n• Arm adducted against torso\n• Forearm in neutral rotation\n\n**TRANSITION TO FUNCTIONAL BRACE**\nAt 1–2 weeks: convert to a prefabricated humeral functional brace. Sarmiento (2000): 98% union rate with functional bracing, mean angulation <8° [8]. FISH trial (2020): functional bracing was non-inferior to surgery for closed humeral shaft fractures [7].\n\n**PEARLS**\n• Do NOT wrap plaster circumferentially — this is a splint, not a cast\n• The U-shape provides medial-lateral stability while allowing swelling\n• A common mistake: splint too short — must extend well above the fracture\n• Check radial nerve function before and after application (wrist drop = radial nerve palsy)' WHERE id = 'splint-coaptation' AND tree_id = 'splinting';
UPDATE decision_nodes SET body = E'**INDICATIONS**\n• Supracondylar fracture (adult)\n• Olecranon fracture (non-operative)\n• Coronoid fracture\n• Proximal radius/ulna fracture\n• Elbow dislocation post-reduction\n\n**MATERIALS**\n• 4-inch plaster or fiberglass (10–12 layers)\n• Stockinette, 3–4 layers Webril, elastic bandage\n\n**APPLICATION**\n1. Measure from proximal palmar crease to mid-upper arm (posterior surface)\n2. Apply stockinette from hand to upper arm\n3. Apply Webril — **extra padding over olecranon and ulnar styloid**\n4. Apply plaster slab along posterior surface of forearm and arm\n5. Mold at the elbow to maintain 90° flexion\n6. Secure with elastic bandage — wrap distally to proximally\n7. Ensure fingers and thumb have full ROM\n\n**POSITION**\n• Elbow at 90° flexion\n• Forearm in neutral rotation (thumb pointing up)\n• Wrist in slight extension (15–20°)\n\n**PEARLS**\n• Splint should be wide enough to cover >50% of the arm circumference for stability\n• Must NOT extend past the proximal palmar crease — allow full MCP flexion\n• For supracondylar fractures: ensure the anterior humeral line bisects the capitellum on lateral x-ray post-splinting\n• Neurovascular check: median, radial, ulnar nerve function + radial pulse + capillary refill' WHERE id = 'splint-long-arm-post' AND tree_id = 'splinting';
UPDATE decision_nodes SET body = E'**FRACTURE → SPLINT GUIDE**\n\n• **Olecranon / coronoid** → Long arm posterior splint\n• **Radius/ulna proximal or midshaft** → Long arm posterior, or double sugar tong (unstable/complex)\n• **Radius distal, isolated** → Thumb spica or volar\n• **Radius/ulna distal, complex** → Sugar tong (**A+P preferred at our institution**) [1][2]\n• **Ulna styloid** → Sugar tong (**A+P preferred**) [1][2]\n\n**INSTITUTION PREFERENCE:** A+P (anterior + posterior) splints are preferred over sugar tong for forearm and distal radius/ulna fractures. Two separate plaster slabs — no wrapping around the elbow — provides equivalent stabilization with less bulk and better patient comfort.' WHERE id = 'splint-forearm' AND tree_id = 'splinting';
UPDATE decision_nodes SET body = E'**INDICATIONS**\n• Distal radius and/or ulna fracture\n• Colles fracture (dorsally displaced distal radius)\n• Smith fracture (volar displaced distal radius)\n• Barton fracture\n\n**MATERIALS**\n• 4-inch plaster (10 layers)\n• Stockinette, 3–4 layers Webril, elastic bandage\n\n**SUGAR TONG APPLICATION**\n1. Measure from dorsal MCP joints, around the elbow, to the palmar crease\n2. Apply stockinette and Webril — **extra padding over olecranon and both styloids**\n3. Apply plaster slab from dorsal hand, along dorsal forearm, around the flexed elbow (90°), along volar forearm to palmar crease\n4. Mold the wrist: slight flexion (10°) + ulnar deviation for Colles; neutral for Smith\n5. Secure with elastic bandage\n6. Ensure thumb and fingers remain free\n\n**A+P SPLINT ALTERNATIVE (PREFERRED)**\nInstead of wrapping around the elbow:\n1. Apply a **posterior slab** from dorsal MCP joints to proximal forearm\n2. Apply an **anterior (volar) slab** from palmar crease to proximal forearm\n3. Secure both with elastic bandage\n4. Provides equivalent AP stability without elbow restriction\n5. Better patient comfort, easier to adjust, less risk of elbow stiffness\n\n**POSITION**\n• Wrist: 10° flexion + ulnar deviation (dorsal displacement)\n• Forearm: neutral rotation\n• Elbow (sugar tong only): 90° flexion\n\n**PEARLS**\n• A+P eliminates the need to wrap around the elbow while maintaining AP stability\n• Sugar tong prevents pronation/supination — use when rotational control is critical\n• For Colles: mold the volar slab into slight flexion and ulnar deviation with 3-point pressure\n• Check capillary refill, sensation, and finger ROM after application\n\n**INSTITUTION NOTE**\nA+P splints preferred over sugar tong — no wrapping around elbow. [1][2]' WHERE id = 'splint-sugar-tong' AND tree_id = 'splinting';
UPDATE decision_nodes SET body = E'**INDICATIONS**\n• Supracondylar fracture with concurrent distal forearm fracture\n• Highly unstable distal radius/ulna fractures requiring rotational and AP control\n• Complex elbow fracture-dislocations (temporary stabilization)\n\n**MATERIALS**\n• 4-inch plaster (10 layers) — TWO separate slabs\n• Stockinette, 3–4 layers Webril, elastic bandage\n\n**APPLICATION**\n1. **First slab (forearm sugar tong):** From dorsal MCP joints, along dorsal forearm, around the elbow, along volar forearm to palmar crease — identical to standard sugar tong\n2. **Second slab (arm sugar tong):** From lateral upper arm, around the elbow, to medial upper arm — provides additional medial-lateral stability at the elbow\n3. Apply stockinette and Webril before EACH slab\n4. Mold the wrist in slight flexion + ulnar deviation (if distal fracture present)\n5. Secure each slab with elastic bandage\n6. Confirm elbow at 90° flexion\n\n**POSITION**\n• Elbow at 90° flexion\n• Forearm in neutral rotation\n• Wrist in slight flexion + ulnar deviation if distal fracture present\n\n**PEARLS**\n• Provides the most stability of any splint for the upper extremity — controls AP, medial-lateral, and rotational forces\n• Bulky and uncomfortable — use only when maximum stability is required\n• Two slabs allow for swelling — safer than circumferential casting in the acute setting\n• Monitor for compartment syndrome — especially with combined fractures\n• Mark the elastic bandage layers clearly so the patient can loosen if swelling increases' WHERE id = 'splint-double-sugar-tong' AND tree_id = 'splinting';
UPDATE decision_nodes SET body = E'**FRACTURE → SPLINT GUIDE**\n\n**Carpal Bones**\n• Scaphoid, trapezium, lunate fracture → Thumb spica [3][6]\n• Lunate dislocation → Sugar tong (**A+P preferred**) [1]\n• Triquetrum, pisiform, trapezoid, capitate, hamate → Volar splint [3]\n\n**Soft Tissue**\n• UCL injury (gamekeeper/skier thumb) → Thumb spica\n• Thumb MCP dislocation → Thumb spica\n• De Quervain tenosynovitis → Thumb spica\n\n**Metacarpals**\n• 1st metacarpal (Bennett, Rolando) → Thumb spica [6]\n• 2nd / 3rd metacarpal → Radial gutter or volar [3]\n• 4th / 5th metacarpal (boxer fracture) → Ulnar gutter [3][6]\n\n**Phalanges**\n• 1st phalanx (thumb) → Thumb spica\n• 2nd / 3rd proximal or middle → Radial gutter or buddy taping\n• 4th / 5th proximal or middle → Ulnar gutter or buddy taping\n• Distal phalanx → Aluminum U-shaped (stack) splint\n\n**BUDDY TAPING:** Tape injured finger to adjacent finger with padding between. Allows protected ROM. Appropriate for stable, non-displaced proximal/middle phalanx fractures.\n\n**ALUMINUM FINGER SPLINT:** Moldable metal splint for distal phalanx fractures and mallet finger. Keep DIP in extension (stack splint). Leave PIP free.' WHERE id = 'splint-wrist-hand' AND tree_id = 'splinting';
UPDATE decision_nodes SET body = E'**INDICATIONS**\n• Scaphoid fracture (confirmed or suspected — snuffbox tenderness)\n• Trapezium fracture\n• Lunate fracture\n• 1st metacarpal fracture (Bennett, Rolando)\n• Thumb MCP dislocation post-reduction\n• UCL injury (gamekeeper/skier thumb)\n• De Quervain tenosynovitis\n• Isolated distal radius fracture (alternative to volar)\n\n**MATERIALS**\n• 4-inch plaster or fiberglass (8–10 layers)\n• Stockinette (with thumb hole cut), 2–3 layers Webril, elastic bandage\n\n**APPLICATION**\n1. Apply stockinette to hand and forearm — **cut a thumb hole**\n2. Apply Webril — **extra padding over radial styloid and 1st MCP joint**\n3. Apply plaster slab along the radial side of the forearm, wrapping around the thumb to include the first metacarpal and thumb to the IP joint\n4. Plaster extends from mid-forearm to just past the thumb IP joint\n5. Mold the plaster around the thumb in a "C" position (thumb abducted and slightly opposed, as if holding a can)\n6. Secure with elastic bandage\n7. Ensure 2nd–5th fingers have full ROM\n\n**POSITION**\n• Wrist in 15–20° extension\n• Thumb: abducted, slightly opposed (functional position)\n• Thumb IP joint included in splint (scaphoid) or free (soft tissue only)\n\n**PEARLS**\n• For suspected scaphoid fracture with negative initial x-rays: immobilize in thumb spica for 10–14 days, then repeat imaging (MRI or repeat x-ray) [3][6]\n• The "anatomical snuffbox" tenderness test has high sensitivity (~90%) but low specificity — err on the side of splinting\n• Distinguish from volar splint: thumb spica immobilizes the thumb; volar does not\n• For UCL injuries: include the thumb MCP but leave IP free to prevent stiffness' WHERE id = 'splint-thumb-spica' AND tree_id = 'splinting';
UPDATE decision_nodes SET body = E'**INDICATIONS**\n• Non-displaced or minimally displaced distal radius fracture\n• Triquetrum fracture (dorsal chip)\n• Pisiform, trapezoid, capitate, hamate fracture\n• 2nd / 3rd metacarpal fracture (alternative to radial gutter)\n• Carpal tunnel syndrome (night splint)\n• Wrist sprain\n• Tendon injury (initial stabilization)\n\n**MATERIALS**\n• 4-inch plaster or fiberglass (8–10 layers)\n• Stockinette, 2–3 layers Webril, elastic bandage\n\n**APPLICATION**\n1. Measure plaster from proximal palmar crease to mid-forearm (volar surface)\n2. Apply stockinette from hand to forearm\n3. Apply Webril — **extra padding over ulnar styloid**\n4. Apply plaster slab along volar surface of forearm\n5. Mold with gentle pressure — maintain wrist in slight extension\n6. Secure with elastic bandage — wrap distally to proximally\n7. Ensure thumb and all fingers have full ROM\n\n**POSITION**\n• Wrist in 15–20° extension (position of function)\n• Fingers free — must be able to make a full fist\n• Thumb completely free\n\n**PEARLS**\n• The simplest and most commonly applied ED splint\n• Does NOT control pronation/supination — if rotational control needed, use sugar tong or A+P\n• For buckle (torus) fractures in adults: volar splint with ortho follow-up in 1 week\n• Ensure splint does NOT extend past the proximal palmar crease — blocking MCP flexion causes finger stiffness\n• Can be converted to a short arm cast at follow-up if needed' WHERE id = 'splint-volar' AND tree_id = 'splinting';
UPDATE decision_nodes SET body = E'**INDICATIONS**\n• 4th metacarpal fracture\n• 5th metacarpal fracture (boxer fracture)\n• 4th / 5th proximal phalanx fracture\n• 4th / 5th middle phalanx fracture (non-displaced)\n\n**MATERIALS**\n• 4-inch plaster or fiberglass (8–10 layers)\n• Stockinette, 2–3 layers Webril, elastic bandage\n• Finger separator padding (cotton between 3rd and 4th fingers)\n\n**APPLICATION**\n1. Place cotton padding between 3rd and 4th fingers\n2. Apply stockinette from fingertips (4th and 5th digits) to mid-forearm\n3. Apply Webril — **extra padding over ulnar styloid and 5th MCP**\n4. Apply plaster slab along the ulnar side of the forearm and hand, extending from mid-forearm to the fingertips of the 4th and 5th digits\n5. Mold the plaster around the ulnar border of the hand\n6. Ensure the MCP joints are in **70–90° flexion** (critical!)\n7. IP joints in slight flexion (10–20°) or comfortable position\n8. Secure with elastic bandage\n\n**POSITION**\n• Wrist in 20–30° extension\n• **MCP joints at 70–90° flexion** — this is the most important positioning element\n• IP joints in slight flexion\n\n**WHY 70–90° MCP FLEXION?**\nThe collateral ligaments of the MCP joints are taut in flexion and lax in extension. Immobilizing in extension allows the ligaments to shorten → permanent MCP stiffness ("intrinsic minus" hand). [3][6]\n\n**PEARLS**\n• Boxer fractures (5th MC neck) with <40° angulation and no rotational deformity: ulnar gutter splint with ortho follow-up [6]\n• Always check for rotational malignment: have the patient flex fingers into a fist — all fingertips should point toward the scaphoid tubercle\n• The "fight bite" rule: ANY laceration over the MCP from a punch is an open joint until proven otherwise → irrigate, antibiotics, hand surgery consult\n• 3rd finger should be left free when possible to improve function' WHERE id = 'splint-ulnar-gutter' AND tree_id = 'splinting';
UPDATE decision_nodes SET body = E'**INDICATIONS**\n• 2nd metacarpal fracture\n• 3rd metacarpal fracture\n• 2nd / 3rd proximal phalanx fracture\n• 2nd / 3rd middle phalanx fracture (non-displaced)\n\n**MATERIALS**\n• 4-inch plaster or fiberglass (8–10 layers)\n• Stockinette, 2–3 layers Webril, elastic bandage\n• Finger separator padding (cotton between 3rd and 4th fingers)\n\n**APPLICATION**\nMirror image of the ulnar gutter splint, applied to the radial side:\n1. Place cotton padding between 3rd and 4th fingers\n2. Apply stockinette from fingertips (2nd and 3rd digits) to mid-forearm\n3. Apply Webril — **extra padding over radial styloid and 2nd MCP**\n4. Apply plaster slab along the radial side of the forearm and hand, extending from mid-forearm to the fingertips of the 2nd and 3rd digits\n5. Mold plaster around the radial border of the hand\n6. Ensure MCP joints at **70–90° flexion**\n7. IP joints in slight flexion (10–20°)\n8. Secure with elastic bandage\n\n**POSITION**\n• Wrist in 20–30° extension\n• **MCP joints at 70–90° flexion**\n• IP joints in slight flexion\n\n**PEARLS**\n• Same principles as ulnar gutter — MCP flexion is critical to prevent collateral ligament contracture\n• Always check for rotational malignment before splinting\n• 2nd and 3rd metacarpal fractures tolerate LESS angulation than 4th/5th (more rigid carpometacarpal joints)\n• If 2nd or 3rd MC is significantly angulated (>10°) → ortho referral, may need operative fixation\n• Can also use a volar splint for non-displaced 2nd/3rd MC fractures if gutter splint is not available' WHERE id = 'splint-radial-gutter' AND tree_id = 'splinting';
UPDATE decision_nodes SET body = E'**FRACTURE → SPLINT GUIDE**\n\n• **Distal tibia or distal fibula** → Posterior short leg (± stirrup for added stability) [3][6]\n• **Ankle sprain grade 2/3** → Stirrup splint [3]\n• **Talus, calcaneus, navicular, cuboid, cuneiform** → Posterior short leg [3][6]\n• **Metatarsal (2nd–5th)** → Posterior short leg or hard-soled shoe [3]\n• **Lisfranc** → Posterior short leg (non-weight bearing, ortho follow-up) [6]\n\n**5th METATARSAL SPECIAL CASES:**\n• Zone 1 (tuberosity/pseudo-Jones) → Hard-soled shoe, weight bear as tolerated\n• Zone 2 (Jones fracture, metaphyseal-diaphyseal junction) → Posterior short leg, non-weight bearing, ortho follow-up (high nonunion risk)\n• Zone 3 (shaft stress fracture) → Posterior short leg, non-weight bearing' WHERE id = 'splint-lower-ext' AND tree_id = 'splinting';
UPDATE decision_nodes SET body = E'**INDICATIONS**\n• Distal tibia fracture (non-operative)\n• Distal fibula (lateral malleolus) fracture\n• Bimalleolar / trimalleolar ankle fracture (initial stabilization)\n• Talus, calcaneus, navicular, cuboid, cuneiform fracture\n• Metatarsal fracture (non-displaced)\n• Jones fracture (5th MT zone 2)\n• Lisfranc injury\n• Achilles tendon rupture (initial, with ankle in plantarflexion)\n\n**MATERIALS**\n• 6-inch plaster (12–15 layers for adults)\n• Stockinette, 3–4 layers Webril, elastic bandage\n\n**APPLICATION**\n1. Patient prone with knee flexed to 90° (foot accessible) or seated with foot hanging off stretcher\n2. Apply stockinette from toes to mid-calf\n3. Apply Webril — **extra padding over malleoli, calcaneus, and Achilles tendon**\n4. Measure plaster from toe base to just below the knee on the posterior surface\n5. Dip plaster in lukewarm water, squeeze, apply along posterior leg from toes to tibial tuberosity\n6. Fold plaster at the toes to create a smooth edge and foot plate\n7. **Mold the ankle at 90° dorsiflexion** (neutral) — this is the critical position\n8. Smooth plaster with flat palms\n9. Secure with elastic bandage — start at toes, wrap proximally\n\n**POSITION**\n• **Ankle at 90° (neutral dorsiflexion)** — prevents equinus contracture\n• Subtalar joint in neutral (not inverted or everted)\n• Exception: Achilles rupture — 20° plantarflexion\n\n**ADDING A STIRRUP**\nFor additional medial-lateral stability (bimalleolar/trimalleolar fractures):\n• Apply a U-shaped plaster slab from medial mid-calf, under the heel, to lateral mid-calf\n• Apply over the posterior slab before elastic bandage\n\n**PEARLS**\n• This is the workhorse lower extremity ED splint — covers almost everything\n• Must extend to the toes to prevent metatarsal/forefoot fractures from shifting\n• Extra Webril over Achilles prevents pressure necrosis (a common complication)\n• Plaster slab should be wider than the posterior leg — wrap the edges around the sides for better contouring\n• Always assess: dorsalis pedis pulse, posterior tibial pulse, sensation in all foot compartments' WHERE id = 'splint-post-short-leg' AND tree_id = 'splinting';
UPDATE decision_nodes SET body = E'**INDICATIONS**\n• Ankle sprain grade 2 (moderate — partial ligament tear)\n• Ankle sprain grade 3 (severe — complete ligament tear)\n• Isolated lateral malleolus fracture (stable, non-displaced)\n• Supplemental stability for posterior short leg splint\n\n**MATERIALS**\n• 4-inch plaster (8–10 layers)\n• Stockinette, 2–3 layers Webril, elastic bandage\n\n**APPLICATION**\n1. Apply stockinette from toes to mid-calf\n2. Apply Webril — **extra padding over both malleoli**\n3. Measure plaster from medial mid-calf, under the heel, to lateral mid-calf (U-shape)\n4. Dip plaster, squeeze excess\n5. Apply U-shaped slab: medial leg → under heel → lateral leg\n6. **Mold at 90° dorsiflexion** — maintain neutral ankle position\n7. Secure with elastic bandage\n8. Toes should remain visible and mobile\n\n**POSITION**\n• Ankle at 90° (neutral dorsiflexion)\n• Subtalar joint neutral — not inverted or everted\n\n**STIRRUP ALONE vs. WITH POSTERIOR SLAB**\n• **Stirrup alone:** Grade 2/3 ankle sprains — provides medial-lateral stability while allowing some plantarflexion/dorsiflexion for early mobilization\n• **Stirrup + posterior slab:** Fractures — maximum stability, prevents all ankle motion\n\n**PEARLS**\n• For ankle sprains: stirrup alone allows early protected motion, which improves healing compared to rigid immobilization [3]\n• The U-shape prevents inversion/eversion — the mechanism of most ankle sprains\n• Air splint (Aircast) can be substituted for stable grade 2 sprains and is easier for the patient to remove for icing and exercises\n• Ottawa Ankle Rules: no splint needed if rules are negative — patients can weight-bear with support\n• Always assess: anterior drawer test, squeeze test (syndesmosis), and base of 5th metatarsal (associated fracture)' WHERE id = 'splint-stirrup' AND tree_id = 'splinting';

-- === status-epilepticus (26 nodes) ===
UPDATE decision_nodes SET body = E'[SE Steps Summary](#/info/se-summary) — time-critical escalating treatment pathway.\n\n**Status epilepticus (SE)** is defined as a seizure lasting >5 minutes or recurrent seizures without recovery between episodes.\n\nSE that persists despite first-line and second-line treatments often necessitates intubation and anesthetic infusions. Underrecognition and delays in treatment increase morbidity and mortality.\n\n**Key principle:** Benzodiazepines become less effective the longer SE persists — GABAA receptors are internalized from the cell surface during prolonged seizure activity. Early, adequate-dose treatment is critical.\n\n**Up to 30% morbidity and mortality** in adults. Etiology drives ~80% of SE-related mortality.' WHERE id = 'se-start' AND tree_id = 'status-epilepticus';
UPDATE decision_nodes SET body = E'**Convulsive SE:** Generalized tonic-clonic activity >5 min, or recurrent seizures without recovery of consciousness between episodes.\n\n**Subtle / late SE:** After prolonged generalized seizure, motor activity may diminish — look for subtle signs: facial twitching, nystagmus, eye deviation.\n\n**Key history:** Duration of seizure activity, witnessed motor features, prior seizure history, current medications, recent drug/alcohol use, trauma, pregnancy status.\n\nPhysical exam: lateral tongue lacerations suggest seizure over syncope. Check for meningeal signs, focal neurologic deficits, signs of trauma.' WHERE id = 'se-is-this-se' AND tree_id = 'status-epilepticus';
UPDATE decision_nodes SET body = E'**Airway:** Position in left lateral decubitus if actively seizing. Suction available. Nasopharyngeal airway if needed — do NOT use bite block or oral airway (risk of obstruction and provider injury). Do NOT attempt intubation during active tonic-clonic seizure unless airway compromise.\n\n**Breathing:** High-flow O2 via non-rebreather. Monitor SpO2 continuously. Respiratory failure can occur from seizure itself or from benzodiazepines.\n\n**Circulation:** Cardiac monitor, IV access × 2. Vital signs including temperature.\n\n**Protect from injury** — pad side rails, remove hazards. Do NOT restrain.\n\n**Start the clock** — time from seizure onset drives treatment decisions.' WHERE id = 'se-abcs' AND tree_id = 'status-epilepticus';
UPDATE decision_nodes SET body = E'**Fingerstick glucose STAT** — hypoglycemia is a common, easily reversible seizure trigger.\n• If glucose <60 mg/dL: D50W 25 g IV (adults) or D10W 2-5 mL/kg (peds)\n\n[SE Diagnostic Workup](#/info/se-labs) — complete lab panel and imaging guide.\n\n**Priority labs:** BMP (Na, Ca, Mg, Phos), CBC, lactate, VBG, urine drug screen, serum tox, ASM levels (if on therapy), troponin, CK, pregnancy test.\n\n**Imaging:** CT head non-contrast after stabilization — evaluate for structural cause. MRI when stable.\n\n**EEG:** Order early if available — 48% of patients with altered consciousness post-SE have ongoing NCSE on EEG.\n\n**Lumbar puncture:** If signs of meningitis, fever with no clear source, or immunocompromised.' WHERE id = 'se-glucose-labs' AND tree_id = 'status-epilepticus';
UPDATE decision_nodes SET body = E'Route of administration determines first-line benzodiazepine choice.\n\n**IV access preferred** but should NOT delay treatment. If IV is not immediately available, give IM midazolam — the RAMPART trial showed IM midazolam is non-inferior to IV lorazepam and faster to administer.\n\nUnderdosing of benzodiazepines leads to poor response and increased likelihood of refractory SE.' WHERE id = 'se-iv-access' AND tree_id = 'status-epilepticus';
UPDATE decision_nodes SET body = E'[Lorazepam](#/drug/lorazepam/status epilepticus) 0.1 mg/kg IV (max 4 mg/dose), push over 2 min.\n\n**May repeat once** in 5-10 minutes if seizure persists. Total max: 8 mg.\n\n**Alternative if lorazepam unavailable:**\n• [Diazepam](#/drug/diazepam/status epilepticus iv) 0.15-0.2 mg/kg IV (max 10 mg), repeat once\n\nLorazepam is preferred over diazepam — higher seizure termination rate (65% vs 56%) and longer duration of action.\n\n**Monitor for respiratory depression** — have bag-valve mask and suction at bedside. Patients who received multiple BZD doses from EMS are at higher risk.' WHERE id = 'se-iv-bzd' AND tree_id = 'status-epilepticus';
UPDATE decision_nodes SET body = E'[Midazolam](#/drug/midazolam/status epilepticus im) 0.2 mg/kg IM (max 10 mg) into deltoid or vastus lateralis.\n\n**RAMPART trial:** IM midazolam terminated seizures in 73% vs 63% for IV lorazepam (p<.001). Faster time to treatment offset the slightly slower IM onset.\n\n**Weight-based dosing:**\n• ≥40 kg: 10 mg IM\n• 13-40 kg: 5 mg IM\n\n**Alternative routes:**\n• Intranasal midazolam: 0.2 mg/kg via mucosal atomizer (less effective than IM per Guterman et al)\n• [Diazepam](#/drug/diazepam/status epilepticus rectal) 0.2-0.5 mg/kg PR (max 20 mg) — no longer recommended as first-line\n\n**Continue attempting IV access** — will be needed for 2nd-line agents if BZD fails.' WHERE id = 'se-no-iv-bzd' AND tree_id = 'status-epilepticus';
UPDATE decision_nodes SET body = E'Assess **5 minutes** after BZD administration. Up to 2 doses of first-line BZD may be given.\n\nIf second dose given, reassess after 5 additional minutes.\n\n**Seizure terminated** = cessation of all motor activity AND progressive improvement in consciousness. Subtle motor signs (facial twitching, nystagmus) may indicate ongoing SE.' WHERE id = 'se-bzd-response' AND tree_id = 'status-epilepticus';
UPDATE decision_nodes SET body = E'Seizure terminated with first-line benzodiazepine therapy.\n\n**Post-seizure management:**\n• Monitor for recurrence — recurrence risk is significant\n• Complete diagnostic workup (labs, imaging, EEG if available)\n• Determine etiology — drives 80% of outcome\n• Consider ASM loading for seizure prophylaxis if first unprovoked seizure with high recurrence risk, known epilepsy with subtherapeutic levels, or structural lesion identified\n• [Levetiracetam](#/drug/levetiracetam/status epilepticus) 20-60 mg/kg IV (max 4500 mg) is preferred for ASM loading\n\n**If patient does not return to baseline within 30-60 min**, consider ongoing NCSE — obtain urgent EEG.' WHERE id = 'se-bzd-success' AND tree_id = 'status-epilepticus';
UPDATE decision_nodes SET body = E'Before selecting 2nd-line antiseizure medication, identify if the patient belongs to a special population that changes management.\n\nIf none apply, proceed directly to standard 2nd-line ASM selection.' WHERE id = 'se-special-pop' AND tree_id = 'status-epilepticus';
UPDATE decision_nodes SET body = E'BZD-refractory convulsive SE. Administer within **5-10 minutes** of BZD failure.\n\n**ESETT trial (2019):** Levetiracetam, fosphenytoin, and valproate had **equivalent efficacy** (~47% seizure cessation at 60 min). No significant difference in adverse events between the three agents.\n\nChoice should be tailored to patient''s comorbidities and contraindications.\n\n[2nd-Line ASM Comparison](#/info/se-asm-comparison) — side-by-side efficacy, contraindications, and side effects.' WHERE id = 'se-2nd-line-choice' AND tree_id = 'status-epilepticus';
UPDATE decision_nodes SET body = E'[Levetiracetam](#/drug/levetiracetam/status epilepticus) 60 mg/kg IV (max 4500 mg) over 10-15 min.\n\n**ESETT:** 47% seizure termination at 60 min (equivalent to fosphenytoin and valproate).\n\n**Advantages:**\n• No cardiac effects — no telemetry requirement during infusion\n• No hepatic metabolism — no drug interactions\n• Safe in renal impairment (dose adjust if CrCl <50)\n• Safe in pregnancy (Category C, low teratogenicity — preferred 2nd line in pregnant patients)\n• Minimal drug-drug interactions\n\n**Side effects:** Psychiatric symptoms (irritability, agitation), drowsiness. Use with caution in patients with mood disorders.' WHERE id = 'se-levetiracetam' AND tree_id = 'status-epilepticus';
UPDATE decision_nodes SET body = E'[Valproate](#/drug/valproate/status epilepticus) 40 mg/kg IV (max 3000 mg) over 10 min.\n\n**ESETT:** 46% seizure termination at 60 min.\n\n**Contraindicated in:**\n• Pregnancy (teratogenic — neural tube defects, Category X)\n• Hepatic disease / liver failure\n• Mitochondrial disorders (Alpers syndrome — fatal hepatotoxicity)\n• Known or suspected urea cycle disorders\n• Pancreatitis\n\n**Cautions:**\n• Thrombocytopenia / coagulopathy — check platelets\n• May cause hyperammonemia — check ammonia if altered mental status persists after seizure cessation\n• Well-tolerated even with larger doses and faster rates of infusion' WHERE id = 'se-valproate' AND tree_id = 'status-epilepticus';
UPDATE decision_nodes SET body = E'[Fosphenytoin](#/drug/fosphenytoin/status epilepticus) 20 mg PE/kg IV (max 1500 mg PE) at max rate 150 mg PE/min.\n\n**ESETT:** 45% seizure termination at 60 min.\n\n**Requires cardiac monitoring** during and for 20 min after infusion — risk of:\n• Hypotension\n• Cardiac arrhythmia (bradycardia, QT prolongation)\n• AV block\n\n**INEFFECTIVE** for drug/alcohol-induced seizures — phenytoin''s selective action on voltage-gated sodium channels is insufficient for diffuse CNS toxicity.\n\n**Contraindicated in:**\n• Sinus bradycardia, SA/AV block, Adams-Stokes syndrome\n• Decompensated heart failure\n\n**Note:** Fosphenytoin (water-soluble prodrug) is preferred over phenytoin — no risk of purple glove syndrome, can be given IM. Dosed in **PE (phenytoin equivalents)**.' WHERE id = 'se-fosphenytoin' AND tree_id = 'status-epilepticus';
UPDATE decision_nodes SET body = E'Assess **20 minutes** after start of infusion.\n\nIf seizure persists or recurs, this is now **refractory status epilepticus (RSE)**.\n\n~30-40% of patients fail 2nd-line therapy. As SE duration increases, GABAA receptor internalization progresses and benzodiazepine/ASM resistance increases.\n\nIf the first 2nd-line agent fails, guidelines recommend either:\n• Adding another 2nd-line ASM, OR\n• Proceeding directly to anesthetic infusions' WHERE id = 'se-2nd-line-response' AND tree_id = 'status-epilepticus';
UPDATE decision_nodes SET body = E'[Phenobarbital](#/drug/phenobarbital/status epilepticus) 15-20 mg/kg IV at max rate 50-100 mg/min. Max single dose: 2000 mg.\n\n**Use when ESETT agents (levetiracetam, valproate, fosphenytoin) are unavailable** or contraindicated.\n\n**Significant risks:**\n• Respiratory depression — may precipitate need for intubation\n• Hypotension\n• Excessive sedation\n\n**Have intubation supplies ready** before administration.\n\n**Also first-line for:**\n• Neonatal seizures\n• Benzodiazepine-resistant alcohol withdrawal seizures\n\nWhen benzodiazepines are completely unavailable, phenobarbital IV 15-20 mg/kg may be used as first-line emergent therapy.' WHERE id = 'se-phenobarbital' AND tree_id = 'status-epilepticus';
UPDATE decision_nodes SET body = E'Seizure terminated with 2nd-line antiseizure medication.\n\n**Critical: Monitor for NCSE** — ESETT data showed 48% of patients with altered consciousness post-SE had ongoing nonconvulsive seizures on EEG.\n\n**Post-seizure management:**\n• Continuous EEG monitoring recommended — minimum 24h\n• Continue maintenance dosing of the ASM that terminated seizure\n• Complete etiology workup (labs, imaging, LP if indicated)\n• Consider adding a second ASM for prophylaxis if high recurrence risk\n• ICU admission for close monitoring' WHERE id = 'se-2nd-success' AND tree_id = 'status-epilepticus';
UPDATE decision_nodes SET body = E'**Refractory SE (RSE)** = failure of first-line BZD AND adequate second-line ASM.\n\nOccurs in ~30-40% of SE presentations.\n\n**Immediate actions:**\n• Secure airway with rapid sequence intubation\n• Avoid prolonged paralysis — use short-acting agent (succinylcholine preferred over rocuronium) to allow clinical seizure assessment\n• Arterial line for continuous BP monitoring\n• Central venous access for vasopressors if needed\n• **Continuous EEG monitoring — MANDATORY** (cannot assess seizure activity in paralyzed/sedated patient)\n\n[RSE Management Principles](#/info/se-rse-principles) — intubation considerations, EEG targets, weaning protocol.\n\n**Consider adding another 2nd-line ASM** (e.g., [Lacosamide](#/drug/lacosamide/status epilepticus) 200-400 mg IV) as adjunct before or concurrent with anesthetic infusion.' WHERE id = 'se-rse-prep' AND tree_id = 'status-epilepticus';
UPDATE decision_nodes SET body = E'**Goal:** EEG seizure suppression or burst suppression for 24-48 hours before weaning attempt.\n\nNo large RCTs demonstrate clear superiority between agents. Choice based on clinical factors.\n\nAll agents require mechanical ventilation and ICU-level care.\n\n[Continuous Infusion Comparison](#/info/se-infusion-comparison) — dosing, hemodynamic effects, and unique risks for each agent.' WHERE id = 'se-rse-infusion' AND tree_id = 'status-epilepticus';
UPDATE decision_nodes SET body = E'**Continuous EEG targets:**\n• Burst suppression (3-10 sec bursts, <50% suppression ratio)\n• OR complete seizure suppression (depending on clinical scenario)\n\n**Maintenance:** 24-48 hours of seizure suppression before first wean attempt.\n\n**Weaning protocol:**\n• Reduce infusion by 25% every 4-6 hours with continuous EEG\n• If seizures recur on wean → restart at effective dose, extend 24h, retry\n\n**Super-refractory SE (SRSE):** SE persists or recurs despite 24 hours of anesthetic therapy.\n\n**SRSE options:**\n• Switch to different anesthetic agent\n• [Lacosamide](#/drug/lacosamide/status epilepticus) as adjunct\n• Immunotherapy if autoimmune etiology suspected (IVIG, steroids, plasmapheresis)\n• Therapeutic hypothermia (32-35°C)\n• Ketogenic diet\n• Neurology and neurointensive care consultation essential\n\n**NORSE (new-onset refractory SE):** No prior seizure history, no identifiable cause. ~50% remain cryptogenic. Consider autoimmune/paraneoplastic encephalitis panel.' WHERE id = 'se-rse-monitoring' AND tree_id = 'status-epilepticus';
UPDATE decision_nodes SET body = E'**All SE patients require ICU admission.**\n\n**Monitoring:**\n• Continuous EEG monitoring × minimum 24-48h\n• Detect NCSE, guide treatment, monitor for recurrence\n\n**Workup to complete:**\n• MRI brain (when stable) — superior to CT for structural causes\n• LP if infectious or autoimmune etiology suspected\n• Autoimmune encephalitis panel if no clear etiology (NMDA-receptor Ab, LGI1, CASPR2)\n• ASM levels (therapeutic drug monitoring)\n\n**Maintenance ASM:**\n• Continue the agent(s) that terminated SE\n• [Levetiracetam](#/drug/levetiracetam/status epilepticus) is most commonly used for maintenance\n\n**Goals of care:** Discuss with family early if RSE/SRSE — prognosis depends primarily on underlying etiology.\n\n**Neurology consultation** for all SE patients.' WHERE id = 'se-disposition' AND tree_id = 'status-epilepticus';
UPDATE decision_nodes SET body = E'**First question: Is this eclampsia or epilepsy?**\n\n**Eclampsia** if: hypertension, proteinuria, edema, >20 weeks gestation, or new-onset seizure in pregnancy without prior seizure history.\n\n**Eclampsia treatment:**\n• [Magnesium Sulfate](#/drug/magnesium-sulfate/eclampsia) 4-6 g IV over 15-20 min, then 1-2 g/hr infusion\n• If seizures persist despite magnesium → benzodiazepines (lorazepam)\n• **OB consultation STAT** — consider emergent delivery\n• Fetal monitoring\n\n**Epilepsy in pregnancy (breakthrough SE):**\n• Standard BZD first-line\n• For 2nd-line: **prefer [Levetiracetam](#/drug/levetiracetam/status epilepticus)** — 89% of neurologists chose it as first-line after BZD in pregnancy\n• **AVOID [Valproate](#/drug/valproate/status epilepticus)** — teratogenic (neural tube defects), Category X\n• Fosphenytoin acceptable if needed (teratogenic risk mainly with chronic exposure, less concern for acute SE)\n• Refractory SE: midazolam or propofol infusion + consider early delivery\n\n**All pregnant patients with new seizure** should receive empiric magnesium while further workup obtained.' WHERE id = 'se-pregnancy' AND tree_id = 'status-epilepticus';
UPDATE decision_nodes SET body = E'**9% of SE cases are substance-induced.**\n\n**Isoniazid (INH) toxicity:**\n• [Pyridoxine (Vitamin B6)](#/drug/pyridoxine/inh toxicity) is the specific antidote\n• Dose: gram-for-gram to amount ingested, OR 5 g IV empiric if amount unknown\n• INH depletes pyridoxine → GABA synthesis fails → refractory seizures\n• Standard ASMs are ineffective without pyridoxine\n\n**Alcohol withdrawal:**\n• Benzodiazepines are first-line (high-dose may be needed)\n• [Phenobarbital](#/drug/phenobarbital/status epilepticus) is effective adjunct\n• Fosphenytoin/phenytoin INEFFECTIVE for alcohol withdrawal seizures\n\n**Sympathomimetic toxicity** (cocaine, methamphetamine, MDMA):\n• BZDs first-line\n• Avoid phenytoin\n\n**General principle:** Phenytoin/fosphenytoin is often **ineffective** for drug-induced seizures — phenytoin''s selective action on voltage-gated sodium channels cannot overcome diffuse CNS toxicity from other drug mechanisms.\n\n**Treat the underlying toxidrome** alongside seizure management.' WHERE id = 'se-substance' AND tree_id = 'status-epilepticus';
UPDATE decision_nodes SET body = E'**Same treatment algorithm as adults** — BZD first-line, then 2nd-line ASM, then anesthetic infusions.\n\n**BZD dosing (weight-based):**\n• IV Lorazepam: 0.1 mg/kg (max 4 mg), repeat × 1\n• IM Midazolam: 13-40 kg → 5 mg; ≥40 kg → 10 mg (0.2 mg/kg, max 10 mg)\n• Rectal Diazepam: 0.2-0.5 mg/kg (max 20 mg)\n\n**2nd-line ASM:** Same agents and weight-based dosing as adults (per ESETT, which included pediatric patients).\n• EcLiPSE and ConSEPT trials confirmed levetiracetam and phenytoin are equivalent in pediatric convulsive SE\n\n**Pediatric-specific considerations:**\n• **Pyridoxine-dependent epilepsy** (age <2 yr): Give [Pyridoxine](#/drug/pyridoxine/pyridoxine dependent epilepsy) 100 mg IV if SE is refractory and no clear etiology — especially neonates with refractory seizures\n• **Febrile SE:** Most common etiology in children — workup directed at fever source\n• **Inborn errors of metabolism:** Consider in neonates/infants with unexplained SE\n• **Phenobarbital** remains first-line for neonatal seizures\n\n**Weight estimation:** <1 yr: (months × 0.5) + 3.5 kg | 1-10 yr: (years × 2) + 10 kg | >10 yr: (years × 2) + 20 kg' WHERE id = 'se-peds' AND tree_id = 'status-epilepticus';
UPDATE decision_nodes SET body = E'NCSE accounts for up to **48% of patients with altered consciousness post-SE** (ESETT data).\n\n**Suspect NCSE if:**\n• Unexplained altered mental status after convulsive SE\n• Subtle motor signs: eye deviation, nystagmus, lip smacking, eyelid fluttering, myoclonus\n• Failure to return to baseline after initial seizure treatment\n• Acutely ill ICU patients (especially on neurotoxic medications: cephalosporins, methotrexate, baclofen, lithium, opioids)\n\n**Diagnosis:** Requires **EEG** — cannot diagnose clinically.\n\n[NCSE Diagnostic Criteria](#/info/se-ncse-criteria) — Salzburg criteria and BZD trial protocol.\n\n**BZD trial (diagnostic + therapeutic):**\n• Administer lorazepam 1-2 mg IV while monitoring EEG\n• Clinical AND EEG improvement → confirms NCSE diagnosis\n\n**Treatment:** Same escalating algorithm as convulsive SE (BZD → 2nd-line → anesthetic infusions), but **urgency of aggressive treatment is debated** — weigh risks of anesthetic agents and intubation against ongoing nonconvulsive seizure activity.\n\nNCSE generally has lower mortality than convulsive SE, but delay in diagnosis worsens outcomes.' WHERE id = 'se-ncse' AND tree_id = 'status-epilepticus';
UPDATE decision_nodes SET body = E'**Common SE mimics:**\n\n• **Psychogenic nonepileptic seizures (PNES):** Most common mimic. Features suggesting PNES: side-to-side head movements, pelvic thrusting, forced eye closure (seizures: eyes open), emotional outbursts, asynchronous limb movements, waxing/waning pattern, absence of postictal confusion. Video EEG is definitive.\n\n• **Syncope with myoclonus:** Brief jerking movements after loss of consciousness — self-limited, resolves when horizontal. Lasts seconds (not minutes).\n\n• **Movement disorders:** Dystonic reactions (from dopamine-blocking medications), oculogyric crisis (20-30 min, no loss of consciousness), tremor, myoclonus.\n\n• **Metabolic encephalopathy:** Uremia, hyperammonemia, hepatic encephalopathy, myxedema coma.\n\n• **Drug toxicity / intoxication:** Alcohol, delirium tremens, serotonin syndrome.\n\n• **Locked-in syndrome:** Anterior pontine infarction — appears unresponsive but conscious. Test with vertical eye movements.\n\n• **Decerebrate/decorticate posturing:** From structural brain injury — not rhythmic.\n\n**Key differentiators:**\n• Lateral tongue laceration suggests seizure over syncope\n• Lactate >2.45 mmol/L: 88% sensitivity, 87% specificity for GTC seizure vs syncope/PNES\n• Prolactin elevated 10-20 min post-seizure: 53% sensitivity, 93% specificity for convulsive SE\n\n**If uncertain, treat as SE** until effectively ruled out — delayed treatment worsens outcomes.' WHERE id = 'se-differential' AND tree_id = 'status-epilepticus';

-- === stemi (23 nodes) ===
UPDATE decision_nodes SET body = E'[STEMI Steps Summary](#/info/stemi-summary)\n\n**Obtain 12-lead ECG within 10 minutes of first medical contact.**\n\nClassic presentation: chest pain/pressure ± radiation to arms, jaw, or back, with diaphoresis, nausea/vomiting, or dyspnea.\n\n**High-risk features:**\n• Chest pain + diaphoresis = highest likelihood ratio for STEMI [1]\n• Radiation to both arms — 96% specific (but only 11% sensitive) [2]\n• 8.4% of ACS presents WITHOUT chest pain — dyspnea, diaphoresis, nausea, syncope most common [3]\n\n**STEMI is an ECG diagnosis.** Do NOT delay for troponin. A negative troponin does NOT rule out STEMI.' WHERE id = 'stemi-start' AND tree_id = 'stemi';
UPDATE decision_nodes SET body = E'**STEMI criteria:** New J-point elevation in ≥2 contiguous leads:\n• ≥1 mm in all leads EXCEPT V2-V3\n• V2-V3: ≥2 mm in men ≥40y, ≥2.5 mm in men <40y, ≥1.5 mm in women\n\nAlso look for reciprocal changes — [PAILS Mnemonic](#/info/stemi-reciprocal)\n\nWhat does the 12-lead ECG show?' WHERE id = 'stemi-ecg-pattern' AND tree_id = 'stemi';
UPDATE decision_nodes SET body = E'**Immediately activate cardiac catheterization laboratory.**\n\n**Identify territory by STE distribution:**\n• **Anterior:** V1-V4 — LAD occlusion\n• **Inferior:** II, III, aVF — RCA (85%) or LCx (15%)\n• **Lateral:** I, aVL, V5, V6 — LCx occlusion\n• **Posterior:** V7-V9 STE (± V1-V3 ST depression) — LCx\n\n**If inferior STEMI:** Get right-sided leads to assess for RV involvement (→ avoid nitrates, volume-dependent)\n\nSee [Vascular Territories](#/info/stemi-vascular-territories) | [Pericarditis vs STEMI](#/info/stemi-pericarditis-diff)\n\nStart initial therapies immediately while preparing for reperfusion.' WHERE id = 'stemi-confirmed' AND tree_id = 'stemi';
UPDATE decision_nodes SET body = E'ST depression in V1-V3 with upright T waves and prominent R wave suggests posterior (inferobasal) STEMI.\n\n**Obtain posterior leads V7, V8, V9:**\n• V7 — posterior axillary line at level of V6\n• V8 — tip of scapula\n• V9 — halfway between V8 and left paraspinal muscles\n\n**Diagnostic criteria:** STE ≥0.5 mm in any posterior lead (≥1 mm in men <40y has higher specificity)\n\nPosterior STEMI accounts for ~3% of acute MIs and is frequently missed. Per ESC guidelines, manage as STEMI. [7][8]' WHERE id = 'stemi-posterior' AND tree_id = 'stemi';
UPDATE decision_nodes SET body = E'In LBBB or ventricular pacing, standard STEMI criteria cannot be applied. Use [Sgarbossa Criteria](#/calculator/sgarbossa) to evaluate.\n\n**Sgarbossa Criteria (any ONE positive = STEMI):**\n• Concordant STE ≥1 mm in leads with positive QRS (5 pts)\n• Concordant ST depression ≥1 mm in V1-V3 (3 pts)\n• Discordant STE ≥5 mm in leads with negative QRS (2 pts)\n\n**Modified Sgarbossa (Smith criteria):**\n• Replace 3rd criterion with ST/S ratio < −0.25\n• Significantly more accurate than original 3rd criterion [9]\n\nScore ≥3 = 98% specificity for STEMI. [10]\n\nPer 2017 ESC guidelines: LBBB + ongoing ischemic symptoms → manage as STEMI regardless of whether LBBB is old or new. [8]' WHERE id = 'stemi-lbbb' AND tree_id = 'stemi';
UPDATE decision_nodes SET body = E'STE in aVR with ≥1 mm ST depression in multiple leads may suggest:\n• **Left main coronary artery** stenosis or occlusion\n• Triple vessel disease\n• Diffuse subendocardial ischemia\n\n**Important:** Only 10% of patients with this pattern have acute thrombotic coronary occlusion. [11] Clinical context is critical.\n\nAssess hemodynamic status — instability strongly favors emergent catheterization.' WHERE id = 'stemi-avr' AND tree_id = 'stemi';
UPDATE decision_nodes SET body = E'Obtain serial ECGs at **15- to 30-minute intervals** for the first 1–2 hours.\n\n• 8% of all STEMIs are identified only on repeat ECG [12]\n• Dynamic ST changes are expected in evolving AMI\n• Use fixed electrode positions for comparison\n\n**Consider bedside echo:** RWMA present in 93% of AMI patients (but also in 43% without AMI — sensitive but not specific) [13]\n\n**STEMI is an ECG diagnosis.** Do NOT wait for troponin to make treatment decisions. [4]\n\nSee [STEMI Mimics](#/info/stemi-mimics)' WHERE id = 'stemi-serial' AND tree_id = 'stemi';
UPDATE decision_nodes SET body = E'STEMI criteria not met but ACS remains on differential.\n\n• Serial troponins q3–6h\n• Continuous cardiac monitoring\n• [Aspirin](#/drug/aspirin/acs) 162–325 mg if not already given\n• Consider anticoagulation per NSTEMI protocol\n• Consult cardiology for risk stratification\n\nSee [NSTEMI Management](#/tree/nstemi) for full NSTEMI decision pathway.' WHERE id = 'stemi-nstemi-workup' AND tree_id = 'stemi';
UPDATE decision_nodes SET body = E'ST elevation identified as non-ACS etiology.\n\n**Common STEMI mimics:**\n• Pericarditis — diffuse concave STE, PR depression, no reciprocal changes\n• Hyperkalemia — peaked T waves, wide QRS, pseudo-STEMI pattern\n• Left ventricular hypertrophy — strain pattern\n• Benign early repolarization\n• Takotsubo cardiomyopathy — apical ballooning\n• Brugada syndrome\n\nSee [Pericarditis vs STEMI](#/info/stemi-pericarditis-diff)\n\nManage underlying condition appropriately.' WHERE id = 'stemi-alt-dx' AND tree_id = 'stemi';
UPDATE decision_nodes SET body = E'Start simultaneously with cath lab activation:\n\n**Antiplatelet:**\n• [Aspirin](#/drug/aspirin/acs) 162–325 mg chewed (if not given prehospital)\n• P2Y12 inhibitor loading — select agent next\n\n**Pain / Symptom management:**\n• [Nitroglycerin](#/drug/nitroglycerin/acs) 0.4 mg SL q5min × 3 (avoid if SBP <90, suspected RV infarct, or PDE-5 inhibitor use within 24–48h)\n• O₂ only if SpO₂ <90% — routine O₂ may INCREASE infarct size [15]\n• [Morphine](#/drug/morphine/acs) 4–8 mg IV only if refractory pain — may delay P2Y12 absorption and increase mortality [16][17]\n\n**Beta blocker:**\n• [Metoprolol](#/drug/metoprolol/acs) within 24h if no contraindications (do not need to start in ED)' WHERE id = 'stemi-initial-tx' AND tree_id = 'stemi';
UPDATE decision_nodes SET body = E'Load with ONE P2Y12 inhibitor before or at time of PCI. Discuss with interventional cardiologist.\n\n**[Prasugrel](#/drug/prasugrel/acs)** 60 mg loading → 10 mg daily\n• More potent platelet inhibition, lower 30-day and 1-year mortality vs clopidogrel/ticagrelor [18]\n• **CONTRAINDICATED:** prior stroke/TIA\n• **No benefit:** age >75y, weight <60 kg\n\n**[Ticagrelor](#/drug/ticagrelor/acs)** 180 mg loading → 90 mg BID\n• Fewer stent thromboses and lower death rate vs clopidogrel [19]\n• Higher stroke/ICH risk vs clopidogrel\n\n**[Clopidogrel](#/drug/clopidogrel/acs)** 600 mg loading → 75 mg daily\n• Variable metabolism (CYP2C19)\n• Use if CI to prasugrel AND ticagrelor, or high bleeding risk\n\nAll three are Class I, Level B recommendations. [5]' WHERE id = 'stemi-p2y12' AND tree_id = 'stemi';
UPDATE decision_nodes SET body = E'**For primary PCI:**\n• [UFH](#/drug/ufh/stemi) 70–100 units/kg IV bolus (without GP IIb/IIIa) OR 50–70 units/kg (with GP IIb/IIIa)\n• [Bivalirudin](#/drug/bivalirudin/acs) 0.75 mg/kg IV bolus then 1.75 mg/kg/hr — preferred if high bleeding risk\n\n**For fibrinolytic therapy** (minimum 48 hours):\n• [UFH](#/drug/ufh/stemi) weight-based bolus + infusion\n• [Enoxaparin](#/drug/enoxaparin/stemi) — alternative (age-adjusted dosing)\n• [Fondaparinux](#/drug/fondaparinux/stemi) 2.5 mg SC daily — alternative\n\nSee [Anticoagulation Details](#/info/stemi-anticoag-detail)' WHERE id = 'stemi-anticoag' AND tree_id = 'stemi';
UPDATE decision_nodes SET body = E'Primary PCI is preferred over fibrinolysis.\n\nSee [Reperfusion Decision Pathway](#/info/stemi-reperfusion-pathway)\n\n**Time targets:**\n• FMC-to-device ≤90 min at PCI-capable facility\n• FMC-to-device ≤120 min for transfer patients\n• DIDO (door-in–door-out) ≤30 min at referring hospital\n• Door-to-needle ≤30 min for fibrinolytics\n\nIs PCI available within target timeframes?' WHERE id = 'stemi-reperfusion-q' AND tree_id = 'stemi';
UPDATE decision_nodes SET body = E'**Goal: First medical contact-to-device ≤90 minutes.**\n\n• Indicated for symptom onset <12 hours\n• Between 12–24 hours: reasonable if clinical or ECG evidence of ongoing ischemia\n• >24 hours, asymptomatic, stable: PCI NOT recommended (no benefit) [22]\n\n**Advantages over fibrinolysis:**\n• Higher infarct artery patency rates\n• Lower rates of recurrent ischemia, reinfarction, ICH, and death\n\n**Potential complications:** access site problems, contrast reactions, reperfusion arrhythmias, stent thrombosis.\n\n**Reperfusion arrhythmias** are common after successful PCI — assess next.' WHERE id = 'stemi-pci' AND tree_id = 'stemi';
UPDATE decision_nodes SET body = E'**Goal: Total FMC-to-device ≤120 minutes. DIDO ≤30 minutes.**\n\n• Consider helicopter EMS to reduce transport time\n• Continue anticoagulation during transport\n• Prehospital cath lab activation reduces FMC-to-balloon time\n• Bypass non-PCI facilities if transport time <30 min to PCI center [5]\n\n**If transfer cannot achieve 120 min:** Switch to fibrinolytic strategy.\n\n**Cardiogenic shock or severe HF:** Transfer immediately regardless of time delay from MI onset. [5]' WHERE id = 'stemi-transfer' AND tree_id = 'stemi';
UPDATE decision_nodes SET body = E'**Door-to-needle ≤30 minutes.** Fibrin-specific agents preferred.\n\nCheck [Fibrinolytic Contraindications](#/info/stemi-lytic-contraindications)\n\n**Agents** (see [Fibrinolytic Dosing](#/info/stemi-lytic-agents)):\n• [Tenecteplase](#/drug/tenecteplase/stemi) — single weight-based IV bolus (preferred)\n• [Alteplase](#/drug/alteplase/stemi) — accelerated 90-min regimen\n• [Reteplase](#/drug/reteplase/stemi) — 10 + 10 unit double bolus\n\n**Age >75 years:** Consider half-dose tenecteplase (reduced ICH risk) [23]\n\n**After fibrinolysis:** Transfer to PCI center. Angiography within 3–24 hours (NOT within first 2–3 hours). [5]\n\nAny contraindications to fibrinolysis?' WHERE id = 'stemi-lytics' AND tree_id = 'stemi';
UPDATE decision_nodes SET body = E'**After administering fibrinolytic:**\n\n**1. Anticoagulation** (minimum 48 hours):\n• [UFH](#/drug/ufh/stemi) weight-based bolus + infusion, OR\n• [Enoxaparin](#/drug/enoxaparin/stemi) (age-adjusted), OR\n• [Fondaparinux](#/drug/fondaparinux/stemi) 2.5 mg SC daily\n\n**2. Transfer** to PCI-capable center for angiography:\n• Within 3–24 hours (NOT within first 2–3 hours after lytics)\n• Rescue PCI if fibrinolysis fails (persistent symptoms/STE)\n\n**3. Monitor for reperfusion signs:**\n• Pain resolution\n• ≥50% ST-segment resolution within 60–90 min\n• Reperfusion arrhythmias (PVCs, AIVR)\n\n**AIVR** (accelerated idioventricular rhythm) — well-tolerated, self-limited. Do NOT treat with antidysrhythmics (may cause hemodynamic collapse). [24]' WHERE id = 'stemi-post-lytics' AND tree_id = 'stemi';
UPDATE decision_nodes SET body = E'Assess for STEMI complications:\n• **Cardiogenic shock** (5–10% of AMI) — hypotension, cool skin, AMS\n• **RV involvement** (33–50% of inferior STEMIs) — hypotension with clear lungs\n• **Reperfusion arrhythmias** — PVCs, VT, AIVR, AF, VF\n• **AV block** (7% with thrombolytics) [25]\n• **Mechanical complications** — VSD, papillary muscle rupture, free wall rupture' WHERE id = 'stemi-complications' AND tree_id = 'stemi';
UPDATE decision_nodes SET body = E'Cardiogenic shock complicates 5–10% of AMI. [26]\n\n**Immediate management:**\n• **PCI regardless of time from MI onset** (Class I)\n• Volume resuscitation if no pulmonary edema\n• Vasopressors to maintain coronary perfusion (norepinephrine preferred)\n• Consider mechanical circulatory support (IABP, Impella, ECMO)\n\n**Do NOT withhold vasopressors** for fear of worsening ischemia — the goal is coronary perfusion until revascularization.\n\nIf at non-PCI center: **transfer immediately regardless of time delay.**' WHERE id = 'stemi-shock' AND tree_id = 'stemi';
UPDATE decision_nodes SET body = E'33–50% of inferior STEMIs involve the right ventricle. [27]\n\n**Diagnosis — get right-sided leads:**\n• STE ≥1 mm in V4R is diagnostic\n• Place V1R-V6R as mirror image of standard precordial leads\n\n**Management — volume-dependent:**\n• **AVOID nitrates** (reduce preload → hemodynamic collapse)\n• **AVOID diuretics**\n• Volume resuscitation with NS boluses (250–500 mL, reassess)\n• If hypotensive despite fluids: dobutamine or milrinone for RV support\n• Reperfusion via PCI remains the priority' WHERE id = 'stemi-rv' AND tree_id = 'stemi';
UPDATE decision_nodes SET body = E'Most common reperfusion arrhythmias: PVCs, VT, AIVR, AF, VF. [24]\n\n**AIVR (Accelerated Idioventricular Rhythm):**\n• Regular wide-complex rhythm, rate 50–110 bpm\n• Usually a SIGN OF SUCCESSFUL REPERFUSION\n• Well-tolerated and self-limited\n• **Do NOT treat with antidysrhythmics** — may cause hemodynamic collapse\n• Resolves when sinus rate exceeds ventricular focus\n\n**VT/VF:** Defibrillate per ACLS protocol\n\n**AV block:** Incidence 7% with thrombolytic therapy. Manage bradycardia (atropine, transcutaneous pacing). [25]\n\n**Atrial fibrillation:** Rate control, see [A-Fib RVR](#/tree/afib-rvr) consult if needed.' WHERE id = 'stemi-arrhythmia' AND tree_id = 'stemi';
UPDATE decision_nodes SET body = E'**Women:**\n• Less likely to present with central chest pain [28]\n• Same risk factors and treatment as men\n• CV mortality has remained higher in women since 1980s\n\n**Elderly (>75 years):**\n• More atypical presentations (dyspnea, syncope, nausea)\n• Higher complication rate, more contraindications to reperfusion\n• Age alone is NOT a reason to withhold reperfusion [29]\n• Consider half-dose tenecteplase if fibrinolysis indicated\n\n**Cocaine-associated STEMI:**\n• PCI strongly preferred over fibrinolysis (higher ICH risk with lytics)\n• Benzodiazepines for chest pain, HR, and BP control\n• **Avoid pure beta-blockers** (unopposed alpha stimulation); consider [Labetalol](#/drug/labetalol/acs) if beta-blockade needed [30]\n\n**Post-cardiac arrest with STEMI:**\n• Early cath for sustained ROSC with STEMI or new LBBB\n• 2–3× higher favorable survival with early cath lab access [31]\n• Consider ECMO for refractory VF/pVT' WHERE id = 'stemi-special' AND tree_id = 'stemi';
UPDATE decision_nodes SET body = E'**All STEMI patients are admitted** after reperfusion (PCI or fibrinolysis).\n\n**In-hospital management:**\n• Continuous cardiac monitoring for reperfusion arrhythmias\n• [Metoprolol](#/drug/metoprolol/acs) within 24h if no CI (HR, BP permitting)\n• [Atorvastatin](#/drug/atorvastatin/acs) 80 mg (start immediately)\n• ACE inhibitor/ARB within 24h if EF ≤40%, HTN, or diabetes\n• DAPT: Aspirin 81 mg + P2Y12 inhibitor × 12 months\n\n**Goals of care discussions** should be held for elderly patients and those with severe comorbidities. DNR/POLST/advance directives do NOT necessarily preclude intervention. [29]\n\n**Cardiac rehabilitation** referral before discharge (25% reduction in CV mortality). [5]' WHERE id = 'stemi-dispo' AND tree_id = 'stemi';

-- === stroke (20 nodes) ===
UPDATE decision_nodes SET body = E'[Ischemic Stroke Steps Summary](#/info/stroke-summary) — time-critical reperfusion pathway.\n\nWe do not yet know if this is ischemic or hemorrhagic. If ICH (intracerebral hemorrhage) is highly suspicious, rule out with **CT head non-contrast** before proceeding.\n\nEstablish **last known well** time.\n\n**Immediate actions:**\n• Fingerstick glucose (only pre-tPA lab required)\n• Obtain [NIHSS (NIH Stroke Scale) score](#/calculator/nihss)\n• Establish IV access × 2\n• Activate stroke team if not already done\n• [MRI vs CT Stroke Protocol](#/info/stroke-imaging) — determine best imaging modality\n\nAll other labs (CBC, BMP, coags, troponin) should be drawn but should NOT delay thrombolysis in patients without known coagulopathy.' WHERE id = 'stroke-start' AND tree_id = 'stroke';
UPDATE decision_nodes SET body = E'Is a **disabling deficit** present?\n\nUse the NIHSS calculator below to score the deficit. **NIHSS >5 = disabling.**\n\nDisabling = deficit that would impair activities of daily living (e.g., limb weakness, aphasia, neglect, visual field cut, gait impairment).\n\nNondisabling = isolated minor symptoms (e.g., mild sensory change, mild dysarthria, isolated facial droop without other deficits).' WHERE id = 'stroke-deficit' AND tree_id = 'stroke';
UPDATE decision_nodes SET body = E'How long since the patient was **last known well** (not time of symptom discovery)?\n\nFor wake-up strokes or unknown onset: treat as time from when last seen normal. MRI DWI-FLAIR mismatch may help identify candidates within 4.5h window.' WHERE id = 'stroke-timing' AND tree_id = 'stroke';
UPDATE decision_nodes SET body = E'Review [Thrombolysis Contraindications](#/info/stroke-contraindications) before proceeding.\n\n**BP requirement:** Must be <185/110 mmHg\n• [Labetalol](#/drug/labetalol) 10–20 mg IV bolus (first-line)\n• [Nicardipine](#/drug/nicardipine) 5 mg/hr IV infusion (second-line)\n\nIf BP cannot be controlled to <185/110, thrombolysis is contraindicated.\n\n**Labs:** Do NOT wait for coags unless patient is on anticoagulants or has known coagulopathy. Fingerstick glucose is the only required pre-treatment lab.' WHERE id = 'stroke-ivt-check' AND tree_id = 'stroke';
UPDATE decision_nodes SET body = E'**Preferred:** [Tenecteplase](#/drug/tenecteplase) 0.25 mg/kg IV bolus (max 25 mg) — single dose over 5 seconds.\n\n**Alternative:** [Alteplase](#/drug/alteplase) 0.9 mg/kg IV (max 90 mg) — 10% bolus over 1 min, remainder over 60 min.\n\nTenecteplase is preferred per current guidelines due to equivalent efficacy, single bolus administration, and simpler dosing.\n\n[Patient Consent Info](#/info/stroke-consent)\n\n**Post-thrombolysis orders:**\n• BP <180/105 × 24h ([Labetalol](#/drug/labetalol) or [Nicardipine](#/drug/nicardipine))\n• Neuro checks q15min × 2h, then q30min × 6h, then q1h × 16h\n• No antithrombotics × 24h\n• No arterial/central lines, NG tube, or Foley × 24h if possible\n• Any neuro decline → emergent NCCT' WHERE id = 'stroke-ivt-treat' AND tree_id = 'stroke';
UPDATE decision_nodes SET body = E'Review CTA results. Is a **large vessel occlusion (LVO)** present?\n\nLVO targets for EVT:\n• ICA (internal carotid artery)\n• M1 segment of MCA (middle cerebral artery)\n• M2 (proximal) MCA — may be considered\n• Basilar artery' WHERE id = 'stroke-lvo-check' AND tree_id = 'stroke';
UPDATE decision_nodes SET body = E'IVT is contraindicated. However, **EVT is NOT contraindicated by thrombolysis exclusion criteria** — patients with contraindications to IVT may still qualify for mechanical thrombectomy.\n\nObtain CTA if not already done.' WHERE id = 'stroke-no-ivt' AND tree_id = 'stroke';
UPDATE decision_nodes SET body = E'Perfusion imaging is required to determine eligibility.\n\nSee [Stroke Imaging Guide](#/info/stroke-imaging) for details on CT perfusion and MRI protocols.\n\n**EXTEND trial criteria:**\n• DWI-FLAIR (diffusion-weighted imaging / fluid-attenuated inversion recovery) mismatch on MRI (DWI+, FLAIR− suggests <4.5h)\n• OR CT perfusion showing salvageable tissue\n• Ischemic core <70 mL\n• Penumbra/core mismatch ratio >1.2' WHERE id = 'stroke-extended-ivt' AND tree_id = 'stroke';
UPDATE decision_nodes SET body = E'**Anterior circulation (DAWN/DEFUSE-3 criteria):**\n• NIHSS ≥6\n• ICA or M1 occlusion on CTA\n• Small ischemic core on CT perfusion (<70 mL at 6–16h; <21 mL at 16–24h)\n• Large penumbra with mismatch ratio >1.8\n\n**Posterior circulation (basilar artery):**\n• NIHSS ≥10\n• Basilar artery occlusion on CTA\n• PC-ASPECTS ≥6\n• Up to 24h from onset (ATTENTION trial)' WHERE id = 'stroke-evt-window' AND tree_id = 'stroke';
UPDATE decision_nodes SET body = E'**Endovascular thrombectomy (EVT) indicated.**\n\nGoal: arterial puncture within 60 minutes of arrival.\n\n• Bridging IVT: If within 4.5h and no IVT contraindications, administer [Tenecteplase](#/drug/tenecteplase) or [Alteplase](#/drug/alteplase) before/during transfer to angio suite — do NOT delay EVT for thrombolytic infusion to complete\n• NPO for sedation/general anesthesia\n• Continuous BP monitoring (arterial line)\n• Goal BP post-recanalization: <180/105 (same as post-IVT)\n\nHERMES meta-analysis: EVT achieved functional independence in 46% vs 27% with medical therapy alone (NNT ~5).' WHERE id = 'stroke-evt-eligible' AND tree_id = 'stroke';
UPDATE decision_nodes SET body = E'>24 hours from last known well.\n\nNot a candidate for IVT or EVT. Focus on:\n• Antiplatelet initiation\n• Stroke etiology workup\n• Secondary prevention\n• Admission for neuro monitoring and rehab evaluation' WHERE id = 'stroke-late' AND tree_id = 'stroke';
UPDATE decision_nodes SET body = E'NIHSS 0–5, nondisabling deficit.\n\nMRI with DWI is preferred (identifies small infarcts missed on CT).\n\n**ABCD2 Score** (TIA risk stratification):\nAge ≥60 (+1), BP ≥140/90 (+1), Clinical features: unilateral weakness (+2) or speech impairment (+1), Duration ≥60min (+2) or 10–59min (+1), Diabetes (+1).\n\nInfarct on imaging or ABCD2 ≥4 = higher risk of recurrent stroke.' WHERE id = 'stroke-minor' AND tree_id = 'stroke';
UPDATE decision_nodes SET body = E'**Loading (Day 1):**\n• [Aspirin](#/drug/aspirin) 325 mg + [Clopidogrel](#/drug/clopidogrel) 300 mg\n\n**Maintenance:**\n• Aspirin 81 mg + Clopidogrel 75 mg daily × 21 days\n• Then single antiplatelet (either agent)\n\n**Alternative (CYP2C19 poor metabolizer):**\n• [Ticagrelor](#/drug/ticagrelor) 180 mg load + Aspirin 325 mg, then Ticagrelor 90 mg BID + Aspirin 81 mg × 30 days\n\nPOINT trial: DAPT (dual antiplatelet therapy) reduced 90-day stroke from 6.5% to 5.0% (NNT 38). Duration beyond 21 days increases bleeding without additional benefit.\n\nAlso initiate statin (high-intensity) and complete stroke workup (telemetry, echo, vascular imaging).' WHERE id = 'stroke-dapt' AND tree_id = 'stroke';
UPDATE decision_nodes SET body = E'[Aspirin](#/drug/aspirin) 160–325 mg within 24–48h of symptom onset, then 81 mg daily.\n\nComplete stroke workup:\n• Telemetry / cardiac monitoring × 24h minimum\n• Echocardiogram (TTE (transthoracic); TEE (transesophageal) if suspected PFO (patent foramen ovale) or valve pathology)\n• Lipid panel → high-intensity statin\n• HbA1c\n• Extended cardiac monitoring if etiology unclear (14–30 day event recorder)' WHERE id = 'stroke-single-antiplatelet' AND tree_id = 'stroke';
UPDATE decision_nodes SET body = E'**BP management × 24h:**\n• Target <180/105 mmHg\n• [Labetalol](#/drug/labetalol) bolus ± infusion (first-line)\n• [Nicardipine](#/drug/nicardipine) infusion (alternative)\n• [Clevidipine](#/drug/clevidipine) (if faster titration needed)\n\n**Neuro checks protocol:**\n• Every 15 min × 2h\n• Then every 30 min × 6h\n• Then hourly × 16h\n• Any decline → emergent NCCT\n\n**Antithrombotics:**\n• NO aspirin, heparin, or anticoagulants × 24h post-thrombolysis\n• Repeat NCCT at 24h\n• If no hemorrhage: start antiplatelets' WHERE id = 'stroke-post-treatment' AND tree_id = 'stroke';
UPDATE decision_nodes SET body = E'**If no IVT given:**\n• [Aspirin](#/drug/aspirin) 160–325 mg within 24–48h of onset\n\n**If post-IVT:**\n• Wait 24h, obtain NCCT first\n• If no hemorrhage: start aspirin 81–325 mg\n\nConsider DAPT (aspirin + [clopidogrel](#/drug/clopidogrel)) for minor stroke with high-risk features (see minor stroke pathway).' WHERE id = 'stroke-antiplatelet-start' AND tree_id = 'stroke';
UPDATE decision_nodes SET body = E'Determine stroke mechanism to guide secondary prevention.\n\n**Standard workup:**\n• Continuous telemetry (≥24h, ideally ≥48h)\n• Echocardiogram (TTE ± TEE)\n• Carotid/vertebral imaging (CTA or duplex)\n• Lipid panel, HbA1c, BMP\n• Hypercoagulability panel if age <60 and cryptogenic' WHERE id = 'stroke-etiology' AND tree_id = 'stroke';
UPDATE decision_nodes SET body = E'**DOAC (direct oral anticoagulant) preferred over warfarin** (unless mechanical valve or moderate-severe mitral stenosis).\n\nRecommended agents:\n• [Apixaban](#/drug/apixaban/atrial fibrillation) 5 mg BID (preferred for stroke prevention, ARISTOTLE trial)\n• [Rivaroxaban](#/drug/rivaroxaban/atrial fibrillation) 20 mg daily with food\n\n**Timing of anticoagulation initiation** (based on stroke severity):\n• TIA: 1–3 days\n• Minor stroke (NIHSS <8): 4–7 days\n• Moderate stroke (NIHSS 8–15): 7–14 days\n• Severe stroke (NIHSS >15 or large infarct): ≥14 days\n\n**Do NOT bridge with heparin** — no benefit over delayed DOAC, increases bleeding.\n\nDiscontinue antiplatelet when DOAC initiated (unless concurrent ACS/stent).' WHERE id = 'stroke-afib' AND tree_id = 'stroke';
UPDATE decision_nodes SET body = E'**Antiplatelet:**\n• [Aspirin](#/drug/aspirin) 325 mg daily (or DAPT × 21–90 days for intracranial stenosis)\n\n**Statin:**\n• High-intensity statin (atorvastatin 40–80 mg or rosuvastatin 20–40 mg)\n• Target LDL <70 mg/dL\n\n**Carotid stenosis management:**\n• Symptomatic 70–99% stenosis: CEA (carotid endarterectomy) within 2 weeks (Class I)\n• Symptomatic 50–69%: CEA is reasonable (Class IIa)\n• CEA preferred over CAS (carotid artery stenting) for most patients\n\n**Intracranial stenosis 70–99%:**\n• DAPT (aspirin + [clopidogrel](#/drug/clopidogrel)) × 90 days\n• Then single antiplatelet\n• Aggressive risk factor management (BP <140/90, LDL <70)' WHERE id = 'stroke-atherosclerotic' AND tree_id = 'stroke';
UPDATE decision_nodes SET body = E'**Antiplatelet:**\n• [Aspirin](#/drug/aspirin) 81 mg daily\n\n**Statin:**\n• High-intensity statin regardless of baseline LDL\n\n**Blood pressure:**\n• Target <130/80 mmHg (after acute phase)\n• Initiate antihypertensive before discharge if stable\n\n**Extended cardiac monitoring:**\n• If cryptogenic: 14–30 day ambulatory cardiac monitor\n• Detects paroxysmal AF in ~12% of cryptogenic strokes\n• If AF detected: transition to anticoagulation\n\n**PFO closure:**\n• Consider if age <60, PFO with atrial septal aneurysm or large shunt, and cryptogenic stroke\n• Refer cardiology for RESPECT/CLOSE trial-based evaluation\n\n**Lifestyle:**\n• Smoking cessation\n• Exercise: moderate intensity ≥40 min, 3–4x/week\n• Mediterranean or DASH diet\n• Weight management (BMI <25)' WHERE id = 'stroke-other-prevention' AND tree_id = 'stroke';

-- === syncope (23 nodes) ===
UPDATE decision_nodes SET body = E'[Syncope Evaluation Steps Summary](#/info/syncope-summary)\n\nPatient presents with transient loss of consciousness. First priority: **exclude immediately life-threatening conditions.**\n\nAre any of the following present?\n• Persistent abnormal vital signs (hypotension, tachycardia, bradycardia, hypoxia, tachypnea)\n• Neurologic deficit or headache\n• Chest pain or dyspnea\n• Abdominal pain or pulsatile mass\n• Evidence of hemorrhage or hypovolemia' WHERE id = 'sync-start' AND tree_id = 'syncope';
UPDATE decision_nodes SET body = E'**TLOC with persistent abnormalities is NOT simple syncope until serious diagnoses are excluded.** [1,2]\n\nEvaluate based on clinical findings:\n• Hypotension + tachycardia → hemorrhage, PE, sepsis, AAA\n• Chest pain → ACS, aortic dissection, PE, tension pneumothorax\n• Headache + neuro deficit → SAH, stroke, ICH\n• Abdominal pain → ruptured AAA, ectopic pregnancy\n• Hypoxia + tachypnea → PE, pneumothorax\n• Persistent bradycardia → high-grade AV block, sick sinus\n\nObtain ECG, targeted labs, and imaging as indicated. **Do not diagnose syncope until life-threatening causes are excluded.**' WHERE id = 'sync-life-threat' AND tree_id = 'syncope';
UPDATE decision_nodes SET body = E'Bystanders often call any convulsive activity a "seizure." **Syncope commonly causes myoclonic jerks** (especially if patient cannot lie flat). [4,5]\n\n**Features favoring seizure:**\n• Prolonged postictal disorientation (>few seconds)\n• Tongue laceration (lateral)\n• Head-turning, unusual posturing\n• >20 rhythmic jerks\n\n**Features favoring syncope:**\n• Presyncope (lightheadedness, diaphoresis, palpitations)\n• Loss of consciousness with prolonged standing/sitting\n• <10 jerks, brief duration\n• Rapid return to baseline\n\nUrinary incontinence does NOT distinguish between seizure and syncope. [6]\n\nDoes the clinical picture suggest seizure?' WHERE id = 'sync-true-syncope' AND tree_id = 'syncope';
UPDATE decision_nodes SET body = E'Clinical features suggest **seizure rather than syncope.** Evaluate and manage per seizure pathway.\n\n**Pearl:** Elevated serum lactate within 2 hours of the event is superior to CK for distinguishing seizure from syncope (positive LR 5.8). [7]\n\nIf seizure is excluded after further workup, return to syncope evaluation.' WHERE id = 'sync-seizure' AND tree_id = 'syncope';
UPDATE decision_nodes SET body = E'**ECG is mandatory for ALL syncope patients** — even those with suspected vasovagal syncope. [1,2]\n\nPlace on continuous telemetry. In low-risk patients, 50% of arrhythmic causes are detected within 2 hours; 6 hours for medium/high-risk. [8]\n\nReview ECG carefully for:\n• Nonsinus rhythm or significant ectopy\n• Conduction abnormalities (AV block, BBB, pre-excitation)\n• QTc prolongation (>460 ms concerning, >500 ms high-risk)\n• ST changes or Q waves suggesting ischemia\n• [High-risk ECG patterns](#/info/syncope-ecg) (Brugada, HCM, epsilon waves)\n\nIs the ECG abnormal?' WHERE id = 'sync-ecg' AND tree_id = 'syncope';
UPDATE decision_nodes SET body = E'**Abnormal ECG is a high-risk feature in all syncope risk stratification tools.** [1,2,10]\n\nECG findings associated with serious cardiac arrhythmias within 30 days: [9]\n• Nonsinus rhythm\n• Mobitz II or third-degree AV block\n• Bundle branch block (especially new LBBB)\n• QTc >460 ms\n• Pre-excitation (WPW)\n• Brugada type 1 pattern\n• Epsilon waves (ARVC)\n• "Dagger" Q waves (HCM)\n• ST depression or T-wave inversions\n\nAtrial fibrillation, IVCD, LVH, and ventricular pacing are independent predictors of mortality. [11]\n\nContinue to history assessment — ECG findings will factor into risk stratification.' WHERE id = 'sync-abnormal-ecg' AND tree_id = 'syncope';
UPDATE decision_nodes SET body = E'**The history is the single most important tool** in identifying the cause of syncope. [1,2]\n\n[Historical Features by Etiology](#/info/syncope-history-features)\n\nAssess:\n• **Activity at onset:** position, exertion, triggers (pain, blood, emotional)\n• **Prodrome:** nausea, sweating, lightheadedness, palpitations, tunnel vision\n• **During event:** duration, witnessed movements, skin color\n• **After event:** orientation, confusion duration, injuries\n• **Prior episodes:** recurrent? same triggers? prior workup?\n• **Medications:** new or changed? antihypertensives, QT-prolonging drugs?\n• **Cardiac history:** heart failure, CAD, valvular disease, prior arrhythmia?\n• **Family history:** sudden cardiac death, drowning, unexplained MVCs in young relatives?\n\nDoes the history suggest a **clear benign etiology** (vasovagal, situational, orthostatic)?' WHERE id = 'sync-history' AND tree_id = 'syncope';
UPDATE decision_nodes SET body = E'**Labs are low-yield unless directed by history/exam.** [1,2]\n\nConsider in patients without clear benign diagnosis:\n• **CBC** — anemia (but initial Hgb may be normal in acute hemorrhage)\n• **BMP** — electrolytes, renal function, glucose\n• **Pregnancy test** — all women of childbearing age\n• **Troponin (hs-cTnT)** — elevated troponin is an independent predictor of 30-day mortality [13]\n• **BNP/NT-proBNP** — elevated BNP confers ~8× increased risk of serious outcomes; may distinguish cardiac from vasovagal [14,15]\n• **Lactate** — if seizure vs syncope unclear (within 2 hours)\n\n**Do NOT routinely obtain:**\n• D-dimer (unless PE otherwise suspected by PERC/Wells)\n• Head CT (unless neuro deficit or head trauma)\n• EEG (unless seizure suspected)\n• Stress testing (unless exertional syncope with ischemia concern)' WHERE id = 'sync-labs' AND tree_id = 'syncope';
UPDATE decision_nodes SET body = E'**Most common identified cause of syncope.** Good long-term prognosis. [17,18]\n\n**Subtypes:**\n• **Vasovagal** — triggered by pain, blood, emotions, medical procedures; prodrome with nausea, sweating, warmth. More common age <40.\n• **Situational** — Valsalva, post-exercise, coughing, swallowing, defecation\n• **Carotid sinus** — head-turning, shaving (age >40)\n\n**For unexplained syncope in patients >40 years**, consider carotid sinus massage (AHA/ESC recommendation) — diagnostic in up to 60% of appropriate candidates. [19]\n\n**Recurrence:** Common but not a predictor of mortality. [20,21]\n\n**If ECG is normal** and history is classic, this is a **low-risk diagnosis.**' WHERE id = 'sync-vasovagal' AND tree_id = 'syncope';
UPDATE decision_nodes SET body = E'Orthostatic hypotension = **SBP drop >20 mmHg upon standing**, or symptoms with position change. [1]\n\nMost common cause: **medications** (~40% of cases). [22]\n\n**Drug-related causes:**\n• Antihypertensives (ACEi, ARBs, beta-blockers, CCBs)\n• Diuretics\n• Alpha-blockers (tamsulosin, doxazosin)\n• Nitrates\n• Antidepressants (TCAs, MAOIs)\n• Antipsychotics\n\n**Other causes:** volume depletion, autonomic failure (diabetes, Parkinson), adrenal insufficiency\n\n**Important:** Orthostatic hypotension does NOT exclude more serious causes, especially in the elderly. One study found no difference in 30-day serious outcomes between elderly patients with normal vs abnormal orthostatic vitals. [23]\n\nIs the orthostatic hypotension clearly **medication-related or volume-related** with an otherwise reassuring workup?' WHERE id = 'sync-orthostatic' AND tree_id = 'syncope';
UPDATE decision_nodes SET body = E'**Medication or volume-related orthostatic syncope** with otherwise reassuring evaluation.\n\n**Management:**\n• IV fluids if volume-depleted\n• Review and adjust offending medications\n• Educate on slow position changes\n• Compression stockings and increased salt/fluid intake for recurrent episodes\n• PCP follow-up for medication adjustment\n\n**Important:** In elderly patients, identifying orthostasis allows modification of fall risk factors (medications), but orthostasis alone should NOT be the sole factor in risk stratification. [23,24]' WHERE id = 'sync-orthostatic-disposition' AND tree_id = 'syncope';
UPDATE decision_nodes SET body = E'**Cardiac syncope carries the highest morbidity** of all causes. Patients with underlying cardiac disease + syncope have higher all-cause mortality. [25]\n\n**Features suggesting cardiac syncope:**\n• Syncope during exertion\n• Palpitations immediately before syncope\n• Syncope while supine\n• Syncope without prodrome (abrupt)\n• History of structural heart disease (HF, CAD, valvular)\n• Family history of sudden cardiac death or inherited arrhythmia\n• Abnormal ECG\n\n**Arrhythmias** are the most common cardiac cause — and may have resolved by ED evaluation. [1,2]\n\n**Structural causes** (PE, aortic stenosis, HCM, aortic dissection) typically persist and are more easily identified.\n\nDoes the patient have **known structural heart disease or heart failure?**' WHERE id = 'sync-cardiac-suspect' AND tree_id = 'syncope';
UPDATE decision_nodes SET body = E'**Structural heart disease + syncope = HIGH RISK.** [1,2,25]\n\n**Recommended ED workup:**\n• Continuous telemetry monitoring (minimum 6 hours for high-risk) [8]\n• Troponin (hs-cTnT) — elevated is independent predictor of 30-day mortality [13]\n• BNP/NT-proBNP — aids in recognition of cardiac syncope [14,15]\n• Echocardiography — high yield when HF, CAD, abnormal ECG, or elevated biomarkers present [26]\n\n**Consider echocardiography** if:\n• History of heart failure\n• Coronary artery disease\n• Abnormal ECG\n• Elevated hs-cTnT or NT-proBNP\n\nOtherwise, echo has low yield for most syncope patients. [26,27]' WHERE id = 'sync-cardiac-workup' AND tree_id = 'syncope';
UPDATE decision_nodes SET body = E'**Arrhythmias are the most common cause of cardiac syncope** — and typically resolve before ED arrival. [1,2]\n\n**Clues to arrhythmic syncope:**\n• Abrupt onset without prodrome\n• Syncope while sitting or supine\n• Palpitations preceding the event\n• Abnormal ECG (bundle branch block, prolonged QTc, pre-excitation, Brugada pattern)\n• Known cardiac device (pacemaker/ICD)\n\n**ED monitoring:**\n• Continuous telemetry — 50% of arrhythmic causes detected within 2 hours (low-risk); 6 hours (medium/high-risk) [8]\n• Consider early referral for ambulatory monitoring — higher diagnostic yield if initiated within 15 days of event [28]\n\n**If arrhythmia captured on telemetry** → manage per specific rhythm.\n\n**If no arrhythmia detected** → proceed to risk stratification for disposition.' WHERE id = 'sync-arrhythmia' AND tree_id = 'syncope';
UPDATE decision_nodes SET body = E'For patients with **unexplained syncope** after history, exam, and ECG — apply risk stratification. [1,2]\n\n**Risk stratification tools** do not consistently outperform clinical judgment, but help identify high-risk features. [29,30]\n\nUse the calculators below to aid disposition:\n• **CSRS** — Canadian Syncope Risk Score (best validated, multicenter) [31,32]\n• **SFSR** — San Francisco Syncope Rule (simple binary screening) [33]\n\n[Syncope Differential Diagnosis](#/info/syncope-ddx)\n\nDoes the patient have **any high-risk features?**\n\n**High-risk (ESC):** [2]\n• Major structural or coronary artery disease\n• Clinical or ECG features suggesting arrhythmic syncope\n• Syncope causing severe injury\n• Important comorbidities (severe anemia, electrolyte disturbance)' WHERE id = 'sync-risk-stratify' AND tree_id = 'syncope';
UPDATE decision_nodes SET body = E'**Approach mirrors adults.** History, exam, and ECG are the most useful components. [34]\n\n**80% of pediatric syncope is neurally mediated** — vast majority have benign etiology. Most cardiac syncope can be diagnosed by history, exam, and ECG. [34]\n\n**Features suggesting cardiac cause in children:**\n• Exertional syncope\n• Syncope without prodrome\n• Syncope while supine\n• Family history of sudden cardiac death\n• Syncope associated with a loud noise → evaluate for **long QT syndrome** [35]\n\n**Common problem:** Excessive testing in pediatric syncope — one study found 58% received head CT with very low yield. 10% are admitted, but very few ultimately diagnosed with cardiac syncope. [36]\n\n**Bottom line:** Unless cardiac features are present, pediatric syncope can be managed conservatively with ECG and PCP follow-up.' WHERE id = 'sync-pediatric' AND tree_id = 'syncope';
UPDATE decision_nodes SET body = E'**Particularly challenging** — many present with unexplained falls rather than syncope. [37,38]\n\n**Key points:**\n• 25-50% of unexplained falls in elderly may be syncope-related [37,39]\n• Almost half of elderly with dementia referred for unexplained falls receive a syncope diagnosis [40]\n• Neurally mediated syncope is still common in this age group [37]\n• QTc prolongation occurs in 25% of elderly — QTc >500 ms predicts 30-day and 1-year mortality [41,42]\n\n**Hospitalization controversy:**\n• Older adults often have multiple risk factors and worse outcomes overall\n• However, for unexplained syncope WITHOUT a serious ED diagnosis, **hospitalization does not improve 30-day adverse outcomes** [43]\n• Age >65 alone and unexplained syncope are NOT independent predictors of mortality [44,45]\n• Mortality is related primarily to **underlying comorbidities**, not the syncope itself [43,46]\n\nHospitalization may increase likelihood of identifying a serious diagnosis, but does not appear to improve mortality.' WHERE id = 'sync-elderly' AND tree_id = 'syncope';
UPDATE decision_nodes SET body = E'**Hospital admission or observation unit recommended.** [1,2]\n\n**Indications for admission:**\n• Sustained or symptomatic ventricular tachycardia\n• Symptomatic conduction system disease or high-grade AV block\n• Symptomatic bradycardia or sinus pauses (not reflex-mediated)\n• Symptomatic SVT\n• Pacemaker/ICD malfunction\n• Inheritable cardiovascular conditions predisposing to arrhythmias\n• Cardiac ischemia\n• Severe aortic stenosis\n• Cardiac tamponade\n• Hypertrophic cardiomyopathy\n• Aortic dissection\n• Pulmonary embolism\n• Significant hemorrhage\n\n**Monitoring:**\n• Continuous telemetry\n• Cardiology consultation\n• Echocardiography if not already obtained\n• Consider electrophysiology referral' WHERE id = 'sync-disposition-high' AND tree_id = 'syncope';
UPDATE decision_nodes SET body = E'**Shared decision-making recommended.** [1,2]\n\n**Intermediate-risk factors:** [1]\n• Age ≥50 years\n• Prior history of cardiac disease\n• Cardiac device without dysfunction\n• Family history of early sudden cardiac death\n• Symptoms not consistent with reflex-mediated syncope\n\n**Key point:** Patients with risk factors by PMH (CAD, HF) but with a **benign cause identified in the ED** (e.g., dehydration) may be discharged safely. [47]\n\n**If observation/discharge:**\n• Structured ED observation protocol may reduce admissions [48]\n• Ensure close follow-up (PCP, cardiology)\n• Consider referral for:\n  - Ambulatory ECG monitoring (Holter, event monitor)\n  - Tilt-table testing\n  - Implantable loop recorder\n  - Electrophysiology evaluation [1]\n\n**If admitted:**\n• Telemetry monitoring\n• Targeted workup based on risk profile' WHERE id = 'sync-disposition-intermediate' AND tree_id = 'syncope';
UPDATE decision_nodes SET body = E'**Low-risk patients should generally be discharged**, even with unexplained syncope. [1,2]\n\n**Low-risk features (ESC):** [2]\n• Young age with typical features of reflex syncope\n• No history of cardiac disease\n• Syncope only when standing\n• Identifiable trigger (pain, blood, prolonged standing)\n• Normal ECG\n• Normal vital signs\n\n**Discharge counseling:**\n• Explain diagnosis and expected benign prognosis\n• Counsel on avoidance of known triggers\n• Counterpressure maneuvers (leg crossing, hand gripping) for prodromal symptoms\n• Adequate hydration and salt intake\n• Review fall risk and injury prevention\n\n**Recurrence:** ~9% recurrence within 6 months; 3+ lifetime episodes most predictive of future recurrence [49]\n\n**Driving:** Be familiar with state laws regarding driving after syncope. Consider referral before return to work for commercial drivers or high-risk occupations. [50]\n\n**Follow-up:** PCP for recurrent or unexplained syncope.\n\n[Discharge Instructions](#/info/syncope-discharge) — shareable patient handout' WHERE id = 'sync-disposition-low' AND tree_id = 'syncope';
UPDATE decision_nodes SET body = E'**ACEP "Choosing Wisely" recommendation:** Avoid head CT in asymptomatic patients with syncope, minimal trauma, and a normal neurologic examination. [16]\n\n**Evidence:**\n• Head CT has very low yield (<0.1%) in determining the cause of syncope [51]\n• Commonly ordered despite lack of utility — one study found 58% of pediatric syncope patients received head CT [36]\n• No neurological symptoms + no head trauma + normal neuro exam = **no head CT needed** [16,51]\n\n**Only obtain head CT if:**\n• Significant head trauma from the fall\n• Neurological deficit on examination\n• Suspicion for SAH (thunderclap headache)' WHERE id = 'sync-no-head-ct' AND tree_id = 'syncope';
UPDATE decision_nodes SET body = E'**PE is uncommon among syncope patients.** [52,53]\n\nExisting clinical decision rules (PERC) adequately identify syncope patients with PE. [52]\n\n**Routine D-dimer is NOT indicated** in syncope patients without independent indications for PE evaluation. [54,55]\n\n**When to consider PE:**\n• Unexplained persistent tachycardia, hypotension, tachypnea, or hypoxia in ED\n• Recent surgery, immobilization, or other VTE risk factors\n• Syncope + dyspnea + pleuritic chest pain\n\n**Apply standard PE rules** (PERC → Wells → CTPA) only when clinically indicated — do NOT screen all syncope patients for PE.' WHERE id = 'sync-pe-screening' AND tree_id = 'syncope';
UPDATE decision_nodes SET body = E'**AHA and ESC recommend carotid sinus massage** in patients >40 years with undiagnosed syncope after initial evaluation. [1,2]\n\nDiagnostic in up to 60% of patients (increasing with advanced age). [19]\n\n**Positive result (carotid sinus hypersensitivity):**\n• Syncope reproduced, OR\n• Asystole >3 seconds, OR\n• AV block, OR\n• SBP drop ≥50 mmHg\n\n**Contraindications:**\n• Carotid bruit\n• Known carotid stenosis >70%\n• History of TIA or stroke within 3 months\n• MI within 3 months\n• History of VT or VF\n\n**Complication rate:** ~0.1% neurologic complications — careful patient selection is important. [56]\n\nPerform with **appropriate monitoring and resuscitation equipment** readily available.' WHERE id = 'sync-carotid-massage' AND tree_id = 'syncope';

-- === uti-peds (28 nodes) ===
UPDATE decision_nodes SET body = E'**Inclusion criteria:** Pediatric patient with suspected urinary tract infection.\n\n**UTI definition:** >50,000 CFU/mL in catheter-obtained specimen OR ≥100,000 CFU/mL in clean catch specimen, with pyuria on urinalysis.\n\n**Note — Exclusion criteria:** Immunocompromised patients, indwelling urinary catheter, known complex urologic anatomy (unless first presentation), and patients <7 days of life should be managed off-pathway with specialist consultation.' WHERE id = 'uti-start' AND tree_id = 'uti-peds';
UPDATE decision_nodes SET body = E'This pathway applies to infants **<48 weeks postmenstrual age** and **>7 days of life** with UTI defined as >50,000 CFU/mL in catheter-obtained specimen.\n\n**Exclusion criteria:**\n• History of Candida infection (consult Infectious Disease)\n• Concomitant bacteremia or meningitis\n• >48 weeks PMA\n• <7 days of age\n\nAlter antibiotic therapy based on culture-specific antimicrobial susceptibility.\n\n**DO NOT repeat urine culture for test of cure UNLESS Candida or ESBL.**' WHERE id = 'uti-neo-dx' AND tree_id = 'uti-peds';
UPDATE decision_nodes SET body = E'**Assess probability of UTI >1%:**\n\n**Females** — 2 or more risk factors:\n• Non-Black race\n• Temperature ≥39°C\n• Fever ≥2 days duration\n• No apparent source of infection\n• Age <12 months\n\n**Males (uncircumcised):** Any febrile male — screen.\n**Males (circumcised):** 3 or more risk factors:\n• Non-Black race\n• Temperature ≥39°C\n• Fever ≥2 days duration\n• No apparent source of infection\n• Age <6 months\n\nAlso screen if: prior history of UTI or fever ≥2 days without identified source.' WHERE id = 'uti-infant-screen' AND tree_id = 'uti-peds';
UPDATE decision_nodes SET body = E'**Screen all patients with:**\n• Symptoms referable to the urinary tract (dysuria, frequency, urgency, abdominal/flank pain, new incontinence)\n• Prior history of UTI with fever ≥2 days\n• Prolonged fever (≥5 days) without identified source\n\n**Collection method:** Clean catch UA with micro.\n\nInclude additional tests if STI is being considered.' WHERE id = 'uti-older-screen' AND tree_id = 'uti-peds';
UPDATE decision_nodes SET body = E'Order UA with Micro.\n\n**Collection:**\n**OPTION 1:** Catheter or suprapubic aspirate (preferred)\n**OPTION 2:** Bag specimen\n\n[UTI Definitions & Urinalysis](#/info/uti-definition-info)\n\n**Positive UA:** Leukocyte esterase OR nitrites OR microscopic WBC/bacteria.' WHERE id = 'uti-ua-cath' AND tree_id = 'uti-peds';
UPDATE decision_nodes SET body = E'Obtain clean catch urine analysis with micro.\n\nInclude additional tests if STI is being considered.\n\nIf UA positive, **must obtain catheter or clean catch specimen for culture** — bag specimens are not acceptable for culture.\n\n[UTI Definitions & Urinalysis](#/info/uti-definition-info)' WHERE id = 'uti-ua-clean' AND tree_id = 'uti-peds';
UPDATE decision_nodes SET body = E'Negative UA. Discharge with PCP or ED follow-up in 24–48 hours.\n\nClose clinical follow-up recommended. Consider alternative diagnoses for fever source.' WHERE id = 'uti-ua-neg' AND tree_id = 'uti-peds';
UPDATE decision_nodes SET body = E'**MUST be obtained from clean catch, catheter, or suprapubic aspirate.**\n\nIf bag sample was previously tested, another specimen must be obtained for culture.\n\nCase manager follow-up on culture results.' WHERE id = 'uti-culture' AND tree_id = 'uti-peds';
UPDATE decision_nodes SET body = E'**Assess for hospital admission criteria.**\n\n**Inpatient criteria:**\n• Ill-appearing (SIRS/sepsis)\n• Dehydration requiring IV or NG fluids\n• Persistent vomiting / inability to tolerate PO antibiotics\n• Social indicators affecting compliance or follow-up\n• Failure of outpatient treatment' WHERE id = 'uti-admit-assess' AND tree_id = 'uti-peds';
UPDATE decision_nodes SET body = E'**First Line:** [Cephalexin](#/drug/cephalexin) 50 mg/kg/day divided TID–QID | Max 1 g/dose\n\n**Alternative:** [Amoxicillin-Clavulanate](#/drug/amoxicillin-clavulanate) 20–40 mg/kg/day divided BID | Max 875 mg/dose\n\n**If IgE-mediated allergy to penicillins AND cephalosporins:** [Ciprofloxacin](#/drug/ciprofloxacin) 20 mg/kg/day divided BID | Max 750 mg/dose\n\n**Medication intolerant, concern for compliance, or age <6 months:** Consider single dose [Ceftriaxone](#/drug/ceftriaxone/pediatric uti) 75 mg/kg IV or IM prior to discharge | Max 2 g/dose\n\n**Total duration:**\n• <6 months: IV + PO = **10 days**\n• ≥6 months: IV + PO = **7 days**\n\nTMP-SMX should be used with caution — only 71% susceptible among E. coli isolates.' WHERE id = 'uti-ed-abx' AND tree_id = 'uti-peds';
UPDATE decision_nodes SET body = E'**First Line:** [Cefazolin](#/drug/cefazolin) 50 mg/kg/day divided q8h | Max 2 g/dose\n\n**If IgE-mediated allergy to penicillins AND cephalosporins:** Aztreonam 90 mg/kg/day divided q8h | Max 2 g/dose, plus Gentamicin 5–7 mg/kg/day q24h\n\n**If concern for CNS involvement:** [Ceftriaxone](#/drug/ceftriaxone/pediatric uti) 100 mg/kg/day divided q12h | Max 2 g/dose\n\n**Transition criteria:** 24–48 hours of IV therapy with clinical improvement. Assess susceptibility and narrow spectrum.\n\n**Total IV + PO = 7 days.**' WHERE id = 'uti-inpatient-abx' AND tree_id = 'uti-peds';
UPDATE decision_nodes SET body = E'Treatment is based on whether UTI is **complicated or uncomplicated**.\n\n**Complicated UTI criteria:**\n• Functional or anatomic abnormality\n• Indwelling catheter\n• Recent instrumentation\n• Recent antibiotics\n• Immunosuppression' WHERE id = 'uti-neo-abx' AND tree_id = 'uti-peds';
UPDATE decision_nodes SET body = E'**IV:** [Cefazolin](#/drug/cefazolin) 50 mg/kg/day divided q8h\n\n**Transition to PO** if term (by PMA), once sensitivities completed:\n[Cephalexin](#/drug/cephalexin)\n• ≤28 days of life: 75 mg/kg/day divided q8h\n• ≥29 days of life: 100 mg/kg/day divided q6h\n\n**Duration: 7 days**\n\nAlter therapy based on culture susceptibility.\n\n**DO NOT repeat urine culture for test of cure unless Candida or ESBL.**' WHERE id = 'uti-neo-rx' AND tree_id = 'uti-peds';
UPDATE decision_nodes SET body = E'Same antibiotic regimen as uncomplicated but **Duration: 10 days**.\n\n**IV:** [Cefazolin](#/drug/cefazolin) 50 mg/kg/day divided q8h\n\n**Transition to PO:**\n[Cephalexin](#/drug/cephalexin)\n• ≤28 days of life: 75 mg/kg/day divided q8h\n• ≥29 days of life: 100 mg/kg/day divided q6h\n\nAlter therapy based on culture susceptibility.\n\n**DO NOT repeat urine culture unless Candida or ESBL.**' WHERE id = 'uti-neo-rx-comp' AND tree_id = 'uti-peds';
UPDATE decision_nodes SET body = E'Obtain **renal and bladder ultrasound (RBUS)** following UTI treatment completion.\n\n*If fever persists >48 hours after start of antibiotics or unusually severe clinical illness, obtain RBUS sooner.' WHERE id = 'uti-neo-imaging' AND tree_id = 'uti-peds';
UPDATE decision_nodes SET body = E'**Are any of the following present?**\n• Atypical pathogen (non-E. coli)\n• Family history of VUR or CAKUT\n• Complex clinical course\n• Any prior UTI' WHERE id = 'uti-neo-rbus-risk' AND tree_id = 'uti-peds';
UPDATE decision_nodes SET body = E'**Obtain VCUG.** Obtain renal functional panel. Consult Urology. Consider Nephrology consult.\n\nPatients with **grade IV or V VUR** are at increased risk of future complications.' WHERE id = 'uti-neo-rbus-abnl' AND tree_id = 'uti-peds';
UPDATE decision_nodes SET body = E'RBUS normal, no risk factors. Complete antibiotic course.\n\nNo further evaluation is necessary.' WHERE id = 'uti-neo-complete' AND tree_id = 'uti-peds';
UPDATE decision_nodes SET body = E'Discharge with PCP or ED follow-up in **24–48 hours**.\n\nCase manager follow-up on urine culture.\n\n**If culture positive:** Assess antibiotic susceptibility and adjust as necessary with PCP involvement.\n\n**If culture negative:** Contact PCP with results.' WHERE id = 'uti-ed-followup' AND tree_id = 'uti-peds';
UPDATE decision_nodes SET body = E'**Discharge criteria:**\n• Non-toxic appearing\n• Well-hydrated\n• Can tolerate oral antibiotics and fluids\n• Normal genitourinary anatomy\n• RBUS reviewed if performed\n• Quality follow-up within 24–48 hours\n• Clinically stable for home' WHERE id = 'uti-inpatient-dc' AND tree_id = 'uti-peds';
UPDATE decision_nodes SET body = E'**RBUS criteria:**\n• Age 2–24 months with first febrile UTI\n• Children >24 months: pathogen other than E. coli, family history of renal/urologic disease, hypertension, poor growth, no improvement after 48h empiric therapy\n\n**Timing:**\n• Outpatient: order RBUS >48h of antibiotics\n• Inpatient: order after 36h (no less than 24h)' WHERE id = 'uti-imaging' AND tree_id = 'uti-peds';
UPDATE decision_nodes SET body = E'**Assess for:**\n• Hydronephrosis (pelvocaliectasis)\n• Renal parenchymal loss\n• Kidney size discrepancies independent of SFU grade\n• Radiologist recommendation for further imaging' WHERE id = 'uti-rbus-result' AND tree_id = 'uti-peds';
UPDATE decision_nodes SET body = E'**Criteria for obtaining VCUG:**\n• Hydronephrosis\n• Scarring\n• Dilated pelvis\n• Dilated ureter\n• Recommended by reviewing pediatric radiologist\n• Chronic hypertension +/- poor growth\n• Urinary pathogen other than E. coli\n• ESBL-producing E. coli' WHERE id = 'uti-vcug' AND tree_id = 'uti-peds';
UPDATE decision_nodes SET body = E'Consider Urology consult if abnormal VCUG.\n\nPatients with **grade IV or V VUR** are at increased risk of future complications.' WHERE id = 'uti-vcug-result' AND tree_id = 'uti-peds';
UPDATE decision_nodes SET body = E'Antibiotic course complete. Ensure PCP follow-up within 24–48 hours.\n\nMonitor for recurrent UTI symptoms.' WHERE id = 'uti-complete' AND tree_id = 'uti-peds';
UPDATE decision_nodes SET body = E'UTI likelihood ≤1% based on risk factor screening.\n\nManage off-pathway with close clinical follow-up. Consider alternative diagnoses for fever source.' WHERE id = 'uti-low-risk' AND tree_id = 'uti-peds';

COMMIT;